INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_3204$$, $$0605502N$$, $$3204$$, $$SBIR CRP - USMC$$, 0, $$Originally established in Section 252 of the 2006 NDAA Public Law No. 109-163, the Commercialization Readiness Program (CRP) may not use more than up to 1% of the SBIR to be used for payment of expenses incurred to administer CRP. 15 USC 638(y) authorizes the DoD to administer a Commercialization Readiness Program to accelerate the transition of SBIR/STTR-developed technologies, products, and services to Phase III, including the acquisition process.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604601N_0267$$, $$0604601N$$, $$0267$$, $$Mine Improvements$$, 130000, $$Naval mines are used to deter or control adversary movements, including surface ships and submarines. Funding supports the capability to maintain effectiveness of mines facing new threat targets with increasing emphasis on major regional conflicts and near peer threats. The three major project areas are: 1) Quickstrike (QS) Mod 3: QS MOD 3 improves effectiveness of existing mines against modern threats by using a programmable Target Detection Device (TDD) MK-71. QS MOD 3 utilizes modeling and analysis to improve target detection and response by developing optimized mine settings and firing algorithms. Minefield planning improvements include new targeting algorithms, mine settings, and corresponding damage data for weapon /target pairs into existing minefield planning software. 2) QS-ER: QS-ER adds GPS-enabled tail kit and a wing kit to the (QS) series to reduce risk to delivery aircraft by enabling precision mine placement and mid-range standoff delivery. Aerial delivery development efforts address capabilities required by a Joint Emergent Operational Needs Statement (JEONS). 3) Clandestine Delivered Mine: Clandestine Delivered Mine MK68 (CDM MOD 0) provides a required capability by converting legacy mining systems for delivery by Extra Large Unmanned Undersea Vehicles (XLUUV) and/or alternate platform in support of JEONS. This capability allows access to contested environments and reduces risk by using unmanned platforms. Upgrades to CDM incorporate the programmable TDD MK-71 and adds iterative command and control enhancements (MODs 1 and 2) through future upgrades for increased operational flexibility and safety for emplaced minefields. Additional efforts include transitioning an explosive section design into the CDM program that is in development under the Compact Encapsulated Effector (C-ENCAP) effort that is managed by the Office of Naval Research (ONR).$$, 130000, NULL, NULL, NULL, NULL, 292660000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604601N_2993$$, $$0604601N$$, $$2993$$, $$Encapsulated Effector$$, 0, $$The Encapsulated Effector, Hammerhead, program complements existing shallow-water mines by providing maritime mining capability in deeper water depths. Based on the urgency of the requirement, the Hammerhead program utilizes Section 804 authority to streamline acquisition of an initial capability. The system uses existing kinetic payloads to engage enemy targets and provides a wide area of coverage per each weapon. The program uses a self-contained, propelled weapon to engage the target when a target is detected. The system uses modern sensing and processing technology to enable accurate targeting at increased range and maintains minefield resilience even as weapons are expended against targets. The result is expanded operating areas to restrict or deny adversary access to the intended area while using fewer weapons than traditional mines. Additional efforts include; transitioning an encapsulation system with different end effectors under the Compact Encapsulated Effector (C-ENCAP) future naval capability (FNC) that is managed by the Office of Naval Research (ONR).$$, 0, NULL, NULL, NULL, NULL, 93687000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604601N_9999$$, $$0604601N$$, $$9999$$, $$Congressional Adds$$, 0, $$Conduct operational demonstrations of notional powered mine delivery systems. FY25 Enacted Congressional Add.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604602F_653133$$, $$0604602F$$, $$653133$$, $$Bombs & Fuzes$$, 1571000, $$The Bombs & Fuzes project improves conventional weapons/munitions (kinetic and non-kinetic), fuzes, and height-of-burst sensors (HOBS), and develops and integrates complementary common weapon components, data links, position, navigation, and timing (PNT) capabilities (i.e. GPS, non-GPS, optical, passive, active, etc.) using modern acquisition best practices, to include digital acquisition practices (e.g. government-owned open system architectures, Model Based Systems Engineering (MBSE) and agile software development). It also provides for the development and testing necessary for a suitable manufacturing base of conventional warheads, fuzes, HOBS, and munitions materiel handling equipment (MMHE). Bombs & Fuzes also provides research, development, testing, and guidance of conventional warheads, fuzing, HOBS modifications, and anti-personnel anti-materiel (APAM) weapons to improve lethality and survivability against area, mobile, hard and deeply buried, and fixed targets. Finally, this project provides an opportunity to quickly insert emerging technologies into existing and developing aircraft munitions and fuzes and supports strategic planning to achieve compliance of AF munitions with Department of Defense insensitive munitions (IM) standards. - Munitions Materiel Handling Equipment (MMHE): MMHE is a continuing project to develop and improve the standardization and commonality of munitions handling and armament equipment to preclude duplication. Efforts are primarily the study, design, and development of MMHE and armament control systems; however, support may be provided to other functional areas as requested. Procurement will be performed and funded by the applicable weapons system project. - Medium Caliber Ammunition project assesses, refines, and develops medium caliber ammunition, to include, but not limited to, conducting 25mm (F-35) qualification testing, comparative testing, and mitigating ammunition inventory health issues. - Insensitive Munitions (IM) and Emerging Technologies: IM projects support AF IM strategic planning to achieve IM compliance IAW U.S. Code, Title 10, Subtitle A, Part N, Chapter 141, Section 2389, ensuring safety regarding insensitive munitions. Develops and validates IM models against current munition performance, addresses IM explosive fill deficiencies and develops munition modifications to improve the response of conventional weapons to unplanned stimuli. This project also explores and develops Emerging Technology by analyzing and evaluating current systems to integrate new technologies for both future and existing munitions. New technologies include but are not limited to improve guidance kits, case materials, new weapon designs, energetics and fuze capabilities to improve lethality, survivability, penetration, accuracy, and reliability in accordance with the National Defense Strategy roadmap. - DSU-43/B Cockpit-selectable Height-Of-Burst Sensor (C-HOBS): The C-HOBS will be a replacement for the current DSU-33D/B proximity sensor. C-HOBS will replace the single factory height-of-burst setting with the addition of multiple height-of-burst options selectable via both manual switches and a cockpit interface. These selection options allow flexibility during flight to address a wide array of targets. The C-HOBS is intended to interface with Combat Air Forces (CAF) aircraft and provide proximity height-of-burst functionality to general and special purpose weapons (to include NGAAWs).$$, 1571000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604602F_655361$$, $$0604602F$$, $$655361$$, $$Stores-Aircraft Interface$$, 5682000, $$The Armament Ordnance Development program funds open standards development and maturation for adoption by USAF, Joint, and Coalition weapon systems for rapid integration, support, and operational use of the full range of armament capabilities. Weapons and weapon systems implementation of open armament interface standards provides rapid integration of software-defined capabilities, reduces development timelines, lowers life-cycle cost, and ensures interoperability with emerging capabilities. The Stores-Aircraft Interface project conducts stores-aircraft interface upgrades and standards development to include the Universal Armament Interface (UAI). This budget funds the Universal Armament Interface (UAI), a matured DAF-owned standard, that provides the continuous development, characterization, and improvements required to ensure integration for current, future, and legacy munitions, ammunitions, delivery systems, and subsystems. The UAI delivers the standards needed to integrate new weapon capabilities on platforms at the speed of software, independent of aircraft Operational Flight Program (OFPs) cycles; thus, reducing costly regression testing for flight safety critical aircraft software. Planned implementations include Joint Strike Fighter (JSF/F-35), F-15EX, F-16 F-47, CCA, B-21, B-1, B-2, B-52, MQ-9, Advanced Anti-Radiation Guided Missile - Extended Range (AARGM-ER), Joint Air-to-Surface Standoff Missile (JASSM), Joint Direct Attack Munition (JDAM), SDB I & II, Stand-in Attack Weapon (SiAW), Long Range Anti-Ship Missile (LRASM), Grey Wolf, Select Precision Effects At Range Capability 3 (SPEAR3), Joint Strike Missile (JSM), and Next-Generation Open Mission Services (NOMS) for mission planning. Funding directly supports the development, enhancement, and sustainment of open armament standards to support the emerging needs of the above adopting platforms and more. That ensures technical currency, support to coalition/joint interoperability efforts for weapons-platform interface, certification tools, and implementation support to aircraft and weapons. Funding also supports the integration of the Common Flexible Weapon Interface (CFWI), providing a unified interface standard for air- to-air and air-to-ground weapons. Additionally, funding supports innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. In October 2024, the Armament Ordnance Development program that managed this funding transitioned to the Architecture and Systems Engineering (ASE) group, Air Force Life Cycle Management Center (AFLCMC), Wright Patterson AFB. In addition to this PE, the ASE group will continue execution of these related activities under the following PEs: 0305206F / Airborne Reconnaissance Systems (672003 / Sensor Open Systems Architecture) 0605056F / Open Architecture Management (656060 / Standards Management) This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F.$$, 5682000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604604A_H07$$, $$0604604A$$, $$H07$$, $$Family Of Med Tac Veh$$, 18503000, $$The FMTVA2 Production and Engineering Change Proposal (ECP) modernization effort restores vehicle performance that was lost due to the addition of armor protection kits as the threat to tactical vehicles and the Family of Medium Tactical Vehicles (FMTV) has increased. The FMTVA2 also addresses Space, Weight, Power, and Cooling (SWaP-C) constraints from having to host an increasing amount of C4ISR and Counter-IED equipment. PD MTV is executing the FMTVA2 effort documented in a signed Acquisition Decision Memorandum by the AAE on 16 November 2015. The FMTVA1P2 ended production in FY 2021 and represents the highest density FMTV model with over 40,000 vehicles fielded to date. The FMTVA1P2 will remain in the tactical vehicle fleet until 2040 and beyond. To ensure supportability of the FMTVA1P2 through FY 2040 and beyond, the PD MTV, as lifecycle managers for the system, shall address potential obsolescence issues with the powertrain and Material Handling Equipment used on the FMTV. Increasing survivability and crew protection of the FMTVA1P2 comes at the expense of decreased vehicle mobility and performance in soft soil and winter environments. The FMTVA1P2 is being asked to carry more weight than what it was originally designed for. Low risk, highly commercial improvements to the FMTVA1P2 driveline, suspension, and tires can be made to minimize the loss in mobility performance. FY 2026 Project H07 Base funds in the amount of $3.503 million will be used for development and integration of Improved Vehicle Safety Technologies, including active safety technologies such as front collision warning, collision mitigation, lane keeping assist, adaptive cruise control, and 360-degree situational awareness. FY 2026 Project H07 Base funds in the amount of $15.000 million will be used for development and integration of Vehicle Integrated Power Kits (VIPK) that provide exportable power generated by FMTV platforms to improve mobility and agility for rapid emplacement/displacement of dismount operations and fire support.$$, 18503000, NULL, NULL, NULL, NULL, 17561000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604604F_653166$$, $$0604604F$$, $$653166$$, $$Joint Smart Munitions$$, 3502000, $$Project Chicken Little (PCL) continues providing superior rapid reaction signature exploitation capabilities for use on both the traditional and the asymmetrical battlefield. PCL delivers vital one-of-a-kind research, development, test, and evaluation (RDT&E) expertise directly to the warfighter, capability developer, and allied/coalition forces. From its inception in 1985, PCL constantly advances the state-of-the-art for developmental smart munitions, seekers/sensors, and their platforms. PCL also focuses its capability against today's networked weapons, emerging weapon concepts, and assists development of innovative targeting technologies to be employed against a wide variety of vehicle targets, theater air defense units, and an extensive array of associated equipment. Combat systems and support equipment exhibit physical characteristics (i.e. signatures) and present certain vulnerabilities, which can be exploited by various targeting technologies leading to the elimination or incapacitation of the threat through the application of force (e.g. smart munitions or directed energy) or application of intelligence, surveillance, reconnaissance (ISR) methods. PCL collects physical, functional, and signature attributes of real foreign threat systems and related equipment; this data feeds high-fidelity models used to predict detection, classification, vulnerability, and effectiveness performance for ISR sensor and weapon system design. PCL collects high resolution signature data using a variety of ground, air, and space-based sensors against both new and existing (obtained, sustained, and maintained to be signature representative) foreign targets; with and without the presence of camouflage, concealment, and deception materials; and operated using enemy tactics/Concept of Operations (CONOPS). The resulting highly reliable, realistic data directly support munitions/targeting development programs and helps mitigate overall acquisition risk. PCL serves as a major focal point for joint signature exploitation, collection, and dissemination within the DoD. PCL is a prime contributor in the time critical process to rapidly exploit, assess, and determine US and allied weapon/targeting performance against high value targets. Customers include: the major Defense and Service Intelligence Centers, all Services, the Joint Technical Coordinating Group (JTCG) who develop the Joint Munitions Effectiveness Manuals (JMEMs), Combatant Commands, AF Major Commands, US Air Force Weapons School curriculum support, and others. Current projects include, but are not limited to: target signature exploitation, target geometric modeling (for identifying vulnerabilities), improving air capabilities against protected structures (specifically hard and deeply buried targets), and the testing of multiple seekers, sensors, and targeting technologies in representative environments against Combatant Command/Major Command/Intelligence Community high value targets. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0604604F / Submunitions Development & Demonstration (SDD)$$, 3502000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604609F_640011$$, $$0604609F$$, $$640011$$, $$Architecture & Integration Core$$, 9873000, $$This BPAC focuses on Planning for Development activities including concept selection, risk reduction, and integration in preparation for transition to a Program of Record (PoR) prior to the establishment of a program management office. Capability Based Assessments (CBA), Analysis of Alternatives (AoA) and similar studies support these activities by providing an evaluation of stakeholder-focused warfighting capabilities via candidate concept technical descriptions. These technical descriptions include open systems and industrial base inputs and analysis to support and enable acquisition, test, and training for current and emerging capability concepts. This includes pre-Milestone A risk reduction, integration, and acquisition planning activities, such as initial product support planning, developing capability concepts, high- confidence initial designs, performance estimation, risk identification, and additional concept refinement in coordination with Department of the Air Force (DAF) priorities. These funds may be used for program management support costs, including, but not limited to, hardware, software, travel, contractor support services, civilian pay, supplies, facilities, and infrastructure. This effort falls under Budget Activity 4, ACD&P, because these efforts are necessary to evaluate integrated technologies, representative modes, or prototype systems in a high-fidelity and realistic operating environment. This program element may include necessary civilian pay expenses required to manage, execute, and deliver RACM capabilities. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F.$$, 9873000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604797D8Z_631$$, $$0604797D8Z$$, $$631$$, $$Joint Energetics Transition Office$$, 3000000, $$The FY 2024 National Defense Authorizations Act (NDAA) directs The Under Secretary of Defense for Acquisition and Sustainment (USD(A&S)) and Under Secretary of Defense for Research and Engineering (USD(R&E)) to select the Head and Deputy Head of Joint Energetics Transition Office (JETO), respectively. JETO will establish and manage a DoD field activity dedicated to systems engineering associated with energetic materials. Additionally, JETO has been assigned strategic roles, tactical roles, coordination responsibilities, and directed studies. This new joint office is intended to improve the transition of energetic materials and technologies to programs of record. It will also result in cost savings through economies of scale and lower barriers for additional suppliers entering the market.$$, 3000000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604609F_646090$$, $$0604609F$$, $$646090$$, $$Hard and Deeply Buried Targets$$, 10012000, $$This BPAC conducts an OSD-directed, Air Force-led effort addressing the Hard and Deeply Buried Targets (HDBT) problem set and recommendations in the National HDBT Strategy. A broad-scope weaponeering analysis and concept refinement effort to develop a threat-informed, technically rigorous, and disciplined understanding of how current and emerging strike capabilities can be combined effectively to engage sophisticated underground military complexes, as reported by the Intelligence Community. Informs DoD-wide intelligence, operational, and acquisition decision space to enable a full spectrum counter-HDBT kill chain, expanding the range of options to hold the most difficult HDBTs at risk. The data and analysis generated may be used in a future Analysis of Alternatives (AoA). Evaluation of the current inventory baseline as well as near-term acquisitions will also drive focused S&T demand signals for desired attributes that will be captured and distributed via appropriate channels. These funds may cover, but are not limited to, hardware, software, travel, personnel and other costs needed to accomplish the mission. This also includes program support and operational support costs necessary to further the program up until the standup of a PoR. This program element may include necessary civilian pay expenses required to manage, execute, and deliver HDBT capabilities. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F.$$, 10012000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604610N_1412$$, $$0604610N$$, $$1412$$, $$HAAWC$$, 0, $$The HAAWC development program was cancelled due to the restructuring of the MK 54 MOD 2 program to an incremental approach.$$, 0, NULL, NULL, NULL, NULL, 22782000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604610N_2234$$, $$0604610N$$, $$2234$$, $$Lightweight Hybrid Torpedo$$, 12565000, $$The program designs, integrates and tests the LWT MK 54. The LWT provides performance improvements in shallow water, counter-measure environments. The MK 54 MOD 1 program consists of two increments: (1) Increment 1 consisting of Advanced Processor Build (APB) 5 / Tech Insertion 1 (TI-1); and (2) Increment 2, consisting of APB-6 software upgrade. FY 2026 funding is for continued development of MK 54 MOD 1 Increment 2 APB 6 developmental builds, conducting in-water developmental test runs, and Weapons Analysis Facility (WAF) system testing. FY 2026 funding also for continued development of a Fleet Exercise Section (FES) instrumentation subsystem to be compatible with the MK 54 MOD 1 obsolescence upgraded hardware being produced under BLI 3215. FY 2026 also funds emergent and stop gap capability needs.$$, 12565000, NULL, NULL, NULL, NULL, 437182000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604610N_3418$$, $$0604610N$$, $$3418$$, $$Advanced Anti-Submarine$$, 0, $$The MK 54 MOD 2 program is continuing incremental development of lethality required to prosecute challenging adversary submarines. FY 2025 funding will be used to complete the POD designs, and receive delivery of the POD hardware and the Technical Data Package (TDPs), and commence development efforts of an Adapter section that enables the assembly of the MOD 2 Forebody sections with the legacy MK 54 MOD 0/1 OTTO Fuel Afterbody. FY 2026 funding will be used to award a contract to an industry Prime, funding the Rapid Prototyping of the INC 1 All-Up-Round (AUR), which combines the MOD 2 Forebody sections with the legacy OTTO Fuel Afterbody. Funding will also be used to conduct INC 1 AUR integration, which will mate POD sections, the new Adapter section, and the legacy OTTO Fuel Afterbody. The program will also continue operational software development and modeling and simulation verification, and continue derisking efforts for INC 2, ensuring the Stored Chemical Energy Propulsion System (SCEPS) Afterbody design is mature and ready for Rapid Prototyping at the commencement of the INC 2 phase.$$, 0, NULL, NULL, NULL, NULL, 395783000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604611A_499$$, $$0604611A$$, $$499$$, $$Javelin (AAWS-M)$$, 9810000, $$The Javelin Advanced Anti-Tank Weapon System-Medium (AAWS-M) is a man-portable, fire-and-forget, medium-range missile with enhanced situational awareness and precision direct-fire effects to defeat armored vehicles, fortifications, and soft targets in a range of military operations. Javelin has a high kill rate against a variety of targets at extended ranges under day/night, battlefield obscurants, adverse weather and multiple counter-measure conditions. The system's soft launch feature permits firing from a fighting position or an enclosure. Javelin uses a modular design to allow the system to evolve to meet changing threats and requirements via both software and hardware upgrades. The system consists of a reusable Command Launch Unit (CLU) with a built-in-test (BIT), and a modular missile encased in a disposable launch tube assembly. The system also includes training devices for tactical training and classroom training. Javelin's fire-and-forget technology allows the gunner to fire and immediately take cover, to move to another fighting position, or to reload. The Javelin provides enhanced lethality through the use of a tandem multi- purpose warhead which will defeat all known armor threats. It is effective against both stationary and moving targets. This system also provides defensive capability against attacking/hovering helicopters. The CLU can also be used as a stand-alone surveillance and target acquisition asset. Javelin can be adapted for use on a variety of platforms and remote weapon stations using the Javelin Vehicle Platform Adapter Kit (JVPAK). The Javelin weapon system is an Army-led, Acquisition Category (ACAT) IC Major Defense Acquisition Program (MDAP) that has joint interest with United States forces and international partners. Research, Development, Test & Evaluation (RDT&E) funding provides for system improvements in accordance with the Javelin Capabilities Production Document objectives and user priorities for future development. FY 2026 dollars in the amount of $9.810 million will continue Javelin system improvements to address emerging threats, improve engagement timeline, and increase lethality.$$, 9810000, NULL, NULL, NULL, NULL, 7541000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604617F_652895$$, $$0604617F$$, $$652895$$, $$Civil Engineering Readiness$$, 21697000, $$This Civil Engineering (CE) Readiness project develops Airbase Technologies (ABT), Airfield Damage Repair (ADR), Airfield Protection (AP), Energy & Utilities (E&U), and CE Materials (CEM) solutions for in-garrison, expeditionary, and contingency installations and airbases. This includes: technologies for airfield assessment, pavement repair and unexploded ordnance identification and mitigation to enable rapid recovery and regeneration of airfield operations; infrastructure design criteria, construction methods, hardened shelters, evaluation tools, materials, aviation firefighting, force protection, expeditionary energy, waste water recycling/treatment, CE materials applications and systems for improved resiliency and rapid recovery of airbase and airfield operations following an attack. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY2025 $0.000 was expended for civilian pay expenses in this program element, and in FY2026 $0.000 is forecast for civilian pay expenses in this program element.$$, 21697000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604798A_DY7$$, $$0604798A$$, $$DY7$$, $$Army Systems Engineering,$$, 24318000, $$This project is advancing its modernization efforts by digitally transforming across the Program Executive Offices (PEOs) in support of the Assistant Secretary of the Army (Acquisition, Logistics and Technology)'s (ASA(ALT)) Mission. This project focuses on integrating data, engineering, and software practices to transform modernization planning and accelerate the delivery of mission-critical capabilities. By implementing CI/ CD models, adaptable System of Systems (SoS) engineering, interoperability and technical risk analysis, ASA(ALT) is ensuring the rapid fielding of minimal viable products (MVPs) that meet the evolving needs of the force. Key digital transformation efforts include the development of flexible engineering processes, integrated SoS architecture products, and risk mitigation planning to optimize the Army's materiel portfolio. These efforts are enabled by the establishment of modern engineering policies, requirements aligned to CI/CD models, and synchronization of resources and acquisitions to address cross-portfolio challenges. A key focus is placed on cyber security and interoperability to ensure that all systems are secure by design, resilient against cyber threats, and seamlessly integrated across the Army's digital ecosystem. ASA(ALT)'s digital transformation initiatives are revolutionizing how capabilities are developed, delivered, and integrated to meet the demands of modern warfare. data reference architectures are enabling decision dominance by providing commanders with timely, actionable data while eliminating institutional barriers to Continuous Integration/Continuous Delivery (CI/CD) adoption. Modern software practices, such as secure coding principles and Development, Security, and Operations (DevSecOps) methodologies, ensure the delivery of adaptable, cyber-resilient capabilities that are secure by design. Interoperability assessments and compliance frameworks are embedded into the engineering process to guarantee seamless operation across joint and coalition environments, enhancing mission effectiveness and operational cohesion. As the Army embraces digital transformation, data-centricity becomes the backbone of battlefield communication, enabling faster and more informed decision- making. Modernized software practices streamline operational capabilities, while digital engineering ensures seamless integration and adaptability across systems as requirements and technologies evolve. Leading this transformation is the Deputy Assistant Secretary of the Army for Data, Engineering, and Software (DASA(DES)), formerly the Office of the Chief Systems Engineer (OCSE). DASA(DES) is spearheading the development of unified, government-owned data architectures that prevent vendor lock-in, govern the acquisition of data-centric capabilities, and empower commanders with the information they need, when they need it. DASA(DES) is spearheading the implementation of modern software techniques, such as agile development and Development, Security, and Operations (DevSecOps), to deliver faster, more secure, and more effective capabilities. Additionally, ASA(ALT) is driving Digital Engineering as a holistic approach to complex system design that leverages models, data, and modern software practices-to revolutionize how the Army approaches software, data architecture, and product development. Cybersecurity is embedded throughout these efforts, ensuring that systems are protected against adversarial threats while maintaining operational integrity.$$, 24318000, NULL, NULL, NULL, NULL, 21750000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_EU6$$, $$0604802A$$, $$EU6$$, $$155mm HE Rocket Assist Project$$, 16302000, $$The 155 millimeter (mm) Next Generation Rocket Assisted Projectile (NGRAP) supports the modernization priorities identified in the Army's Cannon Transformation Strategy. This Project develops an innovative rocket design with a lethal warhead that is compatible with unguided and guided fuzes to meet extended range and accuracy requirements. The NGRAP will first deliver a solution to increase ranges from 30km to 40km in current 39 caliber systems. The NGRAP develops improved accuracy, lethality, and ranges utilizing 39 and Extended Range Cannons. FY (Fiscal Year) 2026 funding will support engineering efforts to assess technical designs and maturation in support of the Engineering and Manufacturing Development (EMD) phase of NGRAP.$$, 16302000, NULL, NULL, NULL, NULL, 27722000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604617F_654910$$, $$0604617F$$, $$654910$$, $$Aeromedical Readiness$$, 1777000, $$Aeromedical Readiness provides key aeromedical devices, life-saving capabilities and quality of life technologies and equipment. This program enables the critical care of combat casualties by further developing and optimizing existing technologies for ground Expeditionary Medical Systems (EMEDS) and aeromedical evacuation systems. EMEDS and aeromedical evacuation systems provide the urgent care needed to treat deployed injured warfighters and return them to duty while in country, and to treat combat casualties that need to be safely transported to a stateside hospital for follow on treatment. The program also supports critical capabilities development in the multi-disciplinary areas for light-weight, durable, and rapidly deployable medical equipment to ensure the Air Force is poised to meet future medical readiness and operational requirements, to include but not limited to Endovascular Aortic Control (EVAC), Pathogen Detection Capability, Automated Vision Testing, Whole Blood Transport and other FDA approved medical treatment devices. This program supports projects ranging from research efforts to optimize human physiologic, modernizing the standards used to measure aircrew, crew stations, and personal protective equipment and cognitive performance for Air Combat Command, to development of patient isolation and transportation devices for Air Mobility Command that enable aeromedical evacuation of patients suffering with highly infectious diseases. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY2024 0.0M was expended for civilian pay expenses in this program element, and in FY 2025 0.0M is forecasted for civilian pay expenses in this program element.”$$, 1777000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604622A_659$$, $$0604622A$$, $$659$$, $$Family Of Hvy Tac Veh$$, NULL, $$No mission requirements for Project 659 in FY 2025 and FY 2026. Funds were transferred to Project DG7 / Common Tactical Truck, for execution. In accordance with Section 1815 of the FY 2008 National Defense Authorization Act (P.L. 110-181), these items are necessary for use by the active and reserve components of the Armed Forces for homeland defense missions, domestic emergency responses, and providing military support to civil authorities.$$, NULL, NULL, NULL, NULL, NULL, 4825000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604622A_DG7$$, $$0604622A$$, $$DG7$$, $$Common Tactical Truck$$, 16788000, $$The Common Tactical Truck (CTT) program is a Family of Vehicles (FoV) that will replace the M915 Line Haul Tractor (LHT), Palletized Load System (PLS), and Heavy Expanded Mobility Tactical Truck (HEMTT) by leveraging best commercial practices and mature commercially available technology, including Predictive Logistics, Advanced Driver Assistance Systems (ADAS), and autonomy ready, resulting in lower procurement costs through economies of scale FY 2026 Project DG7 Base funds in the amount of $16.788 million supports Autonomy Interoperability Profile Instantiation, CTT Autonomy Development, CTT Exportable Power and Energy study, CTT mobility study and Program Management support. The FY 2026 cost of the Common Tactical Truck (CTT) Middle Tier of Acquisition effort is $11.3 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. In accordance with Section 1815 of the FY 2008 National Defense Authorization Act (P.L. 110-181), these items are necessary for use by the active and reserve components of the Armed Forces for homeland defense missions, domestic emergency responses, and providing military support to civil authorities.$$, 16788000, NULL, NULL, NULL, NULL, 22767000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604622A_EZ8$$, $$0604622A$$, $$EZ8$$, $$Leader/Follower$$, 30276000, $$The Leader Follower (LF) funding line supports the Autonomous Transport Vehicle-System (ATV-S) effort that equips Tactical Wheeled Vehicles with autonomous behaviors. Additionally, the capability gives convoy commanders flexibility to leverage the six levels of automated driving that range from Level 0 (Fully Manual) to Level 5 (Fully Autonomous), and any combination therein to conduct convoy operations. Autonomous driving behaviors enable increased operational efficiency of tactical wheeled vehicles resulting in an increase of sustainment throughput while reducing Soldier exposure to hostile threats. The FY 2026 cost of the Autonomous Transport Vehicle-System (ATV-S) Middle Tier of Acquisition effort is $16.8 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. FY 2026 RDTE in the amount of $30.276 million funds Phase 3 vendor award, Operational Demonstration, test support, vendor support and program support.$$, 30276000, NULL, NULL, NULL, NULL, 12583000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604633A_586$$, $$0604633A$$, $$586$$, $$Air Traffic Control$$, NULL, $$The Tactical Airspace Integration System (TAIS) is the Army's program of record for Airspace Control (AC) and enroute Air Traffic Services (ATS). TAIS provides Airspace Management, planning, and dynamic execution capabilities at all echelons above Brigade, and enroute flight following air traffic services. TAIS is the only Army system with direct interface to the U.S. Air Force Air Operations Center (AOC) Weapon System for submission of the Army's requests for airspace from the Battlefield Coordination Detachment (BCD). Airspace Coordinating Measure Requests (ACMREQs) received from other mission command systems are passed to TAIS for approval or higher coordination. TAIS software supports U.S. Army commanders, airspace users, airspace managers, Army air traffic controllers, Joint organizations, and Unified Action Partners (UAP) by providing digitized, multi-echelon planning and execution of airspace management and Air Traffic Services. TAIS provides AC planning and enhanced AC execution; improved theater, intra-, and inter-Corps/Division Air Traffic Services (ATS) support; effective battlespace synchronization; and direct links to the Theater Air Ground System (TAGS) through interface with the automated airspace planning and communications systems of the Joint Force Air Component Commander (JFACC). Integrated Mission Planning and Airspace Control Tools (IMPACT) is the software convergence product for TAIS AC requirements. IMPACT contributes to four of the Army's six modernization priorities: future vertical lift, long range precision fires, the network, and air and missile defense. IMPACT also directly supports the National Military Strategy Joint force task of integrating capabilities rapidly and Next Generation Command and Control (NGC2). IMPACT is the software convergence of AC and will provide interoperability with Army Mission Command, Joint, and UAP systems. This will facilitate AC capabilities, enhance situational understanding, reduce risks, and provide more effective Air-Ground Integration to enable NGC2, Multi-Domain Operations (MDO), Joint All Domain Operations (JADO), and Joint All Domain Command and Control (JADC2). IMPACT will be instantiated across Command Post Computing Environment (CE), Mounted CE, and Mobile/Handheld CE and will extend AC services to the tactical edge. Any changes driven by the C2 Pivot and Fix strategy will be assessed in terms of cost, schedule, and performance impacts to product development. The modernized software baseline is following Continuous Integration/Continuous Deployment (CI/CD) tenants of the Software Acquisition Pathway (SWP) of the Adaptive Acquisition Framework (AAF) to leverage the shift to more Agile acquisition to mirror modern Agile development and delivery. This includes use of Government owned Software Factories and DEVSECOPS processes to ensure that products are tested early and often to mitigate cyber and other vulnerabilities to delivery hardened code from the Minimum Viable Product (MVP) through all successive Minimum Viable Capability Releases (MVCR). IMPACT plans to leverage Air Space Total Awareness for Rapid Tactical Execution (ASTARTE) technology. ASTARTE provides artificial intelligence and machine learning algorithms which will allow IMPACT to achieve more rapid synchronization of airspace planning and dynamic execution. This will enable commanders to maximize airspace usage, increase freedom of maneuver in the 3rd dimension, enhance safety and fratricide prevention, and enable seamless integration / deconfliction of fires and aviation operations in highly congested and complex environments during Large Scale Combat Operations (LSCO). Persistent experimentation events like Project Convergence and COCOM sponsored exercises continue to confirm the existence of airspace planning and management challenges that are only increasing in complexity. IMPACT has been part of Project Convergence and Experimental Demonstration Gateway Event (EDGE) events in demonstrating critical mission threads showing a measurable reduction in sensor to shooter timelines.$$, NULL, NULL, NULL, NULL, NULL, 11093000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604636N_2073$$, $$0604636N$$, $$2073$$, $$DRAKE 2.0 C-UAS Afloat$$, 12031000, $$The DRAKE Counter Unmanned Aircraft Systems (CUAS) is an Electronic Warfare (EW) Force Protection system designed to detect, identify, track, and defeat small Unmanned Aircraft Systems (sUAS) for afloat naval forces. The DRAKE system will be upgraded with improved radios, processors, and display units to meet the non-kinetic requirements established in the OPNAV DRAKE Top Level Requirement (TLR). The program will utilize Commercial Off-The-Shelf (COTS) hardware for the display and custom, software and hardware in the Increment 1 tech refresh. Increment 1 upgrades will focus on refreshing the core technology to replace legacy hardware with the latest processors/controllers, which will significantly increase signal processing speed and bandwidth (NextGen SDR). These improvements will enable the system to counter more advanced commercial sUAS efficiently. A COTS tablet-like Graphical User Interface (GUI) called the Control Display Unit (CDU) 2.0 will replace the legacy CDU, providing enhanced visual tracking and identification data of UAS. This upgrade will ultimately improve situational awareness and signal analysis for the warfighter. In Increment 2, the DRAKE system will be integrated with ships' Command and Control with optimized antennas for C-sUAS mission to enhance ships' situational awareness and prosecution of UAS threats. Prior to FY23, DRAKE C-UAS funding can be found in PE 0603654N/Project 3177.$$, 12031000, NULL, NULL, NULL, NULL, 5783000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604636N_3241$$, $$0604636N$$, $$3241$$, $$Counter Unmanned Aircraft Systems$$, 4658000, $$The Counter small Unmanned Aerial Systems (C-sUAS) Family of Systems (FoS) program was funded to provide initial material solutions to SECNAV-prioritized locations CONUS and OCONUS with baseline electronic warfare (EW) capabilities to detect, track, identify, and defeat sUAS over a large coverage area. Following initial material deployment, the program continues to expand the capabilities of select, high priority systems and adapt new solutions to defeat evolving threats. The initial material solution included CORIAN, Ninja, DroneDefender, and DroneBuster. Expanded solutions include EO/IR, radar, C2, new EW detect/defeat capabilities, alternative sensors, and additional kinetic and non-kinetic mitigations needed to prepare, maintain, and upkeep force protection, self-defense and operational capabilities against the ever-evolving sUAS threat. Funding is provided to protect high-value and/or critical Navy assets and support public safety against threats by inadvertent or unlawful misuse of sUAS. FY26 increase provides for C-sUAS implementation of the first phase for hardware tech refresh to identify solutions for the End of Life (EoL) hardware fielded at CORIAN sites. This funding will provide system assessments, intra-service technology capitalization, and refinement of open architecture solutions and interoperability standards for a C-sUAS FoS. It will also align with Joint C-sUAS Office (JCO) currently funded efforts, allowing the Program the ability to resource to identify and develop additional capabilities to detect and deter threats against the Fleet that can be integrated into C-sUAS FoS. Funding also provides for government engineering support for the technology development and acquisition strategy for fielding material solutions.$$, 4658000, NULL, NULL, NULL, NULL, 12416000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604804A_L46$$, $$0604804A$$, $$L46$$, $$Maintenance Support Equipment$$, 2259000, $$Mobile Maintenance Equipment provides state of the art, deployable, vehicle-mounted, Soldier portable and containerized shelter tool systems supporting the readiness of the Joint warfighter directly supporting Soldier Lethality, Next Generation Combat Vehicle (NGCV) and Long Range Precision Fires (LRPF), as well as, addressing GAPs 10 and 17. These systems are equipped with industrial quality tools required for Two Level Maintenance that reduce common tool redundancy, provide tool standardization, minimize transportation requirements, reduce logistical footprint, and are backed by a Lifetime Warranty/Replacement Program which reduces sustainment costs. This is accomplished by employing a system of systems approach to maintenance acquisition. The System of Systems approach builds a maintenance capability upon each system, allowing a logical and natural approach to the Army's overall two level maintenance strategy. These inter-connected systems distributed throughout the Army at multiple levels and echelons provide a holistic repair capability in all scenarios and environments. These systems provide the Maintenance and Combat Commanders an unprecedented capability to repair wheeled, tracked, aviation, ground support and weapons systems on site at one location at one time. This approach to maintenance acquisition increases efficiencies and supports the current force while providing modular configurations designed to meet the specific needs of the Army maintainer in today's complex transforming environment. The need to develop and maintain a System of System maintenance approach is critical for maintaining readiness due to the growing complexity of today's military equipment, operational tempo, modularity, and current and evolving Tactics Techniques and Procedures (TTPs). The individual maintenance systems are comprehensive, interconnected and capable of solving and repairing any maintenance problems. The System of Systems approach does not advocate specific tools, methods or practices; instead it seeks to promote a streamlined comprehensive set of systems for solving maintenance challenges where the interactions of doctrine, technology, time and tactics techniques and procedures are the primary drivers. Funding for projects shall include test article procurement and testing of Soldier portable maintenance Sets, Kits, and Outfits (SKOs), load banks and refrigeration tool kit; investigation of new technologies for next generation mobile maintenance equipment shop sets including the Shop Equipment Welding (SEW) and Shop Equipment Contact Maintenance (SECM); development of additional Standard Automotive Tool Set (SATS) maintenance modules, Armament Repair Shop Set (ARSS), Refrigeration Tool Kit (RTK), Mobile Ammunition Processing Facility (MAPF), Forward Repair System (FRS), Special Tools initiatives, shelter mounted system development; packaging development; and technical support for emerging Joint Capabilities Integration and Development System (JCIDS) materiel requirements documents. Additive Manufacturing increased capabilities to the Metal Working and Machining Shop Set (MWMSS) to include a polymer and metal printing and associated digital library capability. Modernization upgrades increase effectiveness while improving efficiency, reliability and maintainability while supporting emerging Army systems as well as using lower cost set components. Funding supports modernization of the current Ordnance equipment by investigating technology insertions due to but not limited to obsolescence and technology innovations. Funding also supports developing initial prototypes to enable refinement of Operational Requirements and early user feedback to support future sustainment and operational movement concepts.$$, 2259000, NULL, NULL, NULL, NULL, 1258000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604636N_9999$$, $$0604636N$$, $$9999$$, $$Congressional Adds$$, 0, $$The DRAKE Counter Unmanned Aircraft Systems (CUAS) is an Electronic Warfare (EW) Force Protection system designed to detect, identify, track, and defeat small Unmanned Aircraft Systems (sUAS) for afloat naval forces. To meet the non-kinetic requirements established in the OPNAV Top Level Requirement (TLR) for Afloat CUAS, the DRAKE system will be upgraded with improved radios, processors, and display units. The program will utilize Commercial Off-The-Shelf (COTS) hardware, software, and advanced techniques to develop, test, and integrate into DRAKE. Increment 1 upgrades will focus on refreshing the core technology to replace legacy hardware with the latest COTS processors/controllers, which will significantly increase signal processing speed and bandwidth (NextGen SDR). These improvements will enable the system to counter more advanced commercial sUAS efficiently. A COTS tablet- like Graphical User Interface (GUI) called the Control Display Unit (CDU) 2.0 will replace the legacy CDU, providing enhanced visual tracking and identification data of UAS. This upgrade will ultimately improve situational awareness and signal analysis for the warfighter. In Increment 2, the DRAKE system will be integrated with ships' Command and Control with optimized antennas for C-sUAS mission to enhance ships' situational awareness and prosecution of UAS threats.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604641A_CF5$$, $$0604641A$$, $$CF5$$, $$Robotic Combat Vehicle (BA5) NGCV-$$, NULL, $$This funding line is directly aligned to the Next Generation Combat Vehicle Army Modernization Priority. The Robotic Combat Vehicle (RCV) is a transformational capability that will forever change ground maneuver warfare. The RCV enables commanders to dictate the terms of the first human engagement by leveraging the RCV to shape and degrade threats across the multi-domain battlefield. The RCV will operate as a system of systems including a Manned Control Vehicle (MCV) outfitted with multiple Control Stations and unmanned RCV platforms outfitted with Modular Mission Payloads (MMPS) that commanders can tailor to their mission requirements. The Robotic Combat Vehicle (RCV) Middle Tier Acquisition-Rapid Prototype (MTA-RP) program was funded through RDT&E appropriation via lines 643645EV7, 644107CF4 and 654641CF5. The total investment of the program prior to Army Transformation Initiative (ATI) Executive Order (EXORD) directing to cease development of RCV Hardware was $225M Base-Year 2025 (BY25) dollars. Future development efforts focused on Software Pathway (SWP), as well as autonomous and unmanned system initiatives, will be funded under RDT&E lines 644017FD9 and 655053FB3.$$, NULL, NULL, NULL, NULL, NULL, 136937000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604642A_E40$$, $$0604642A$$, $$E40$$, $$LTV Prototype$$, NULL, $$The Army's High Mobility Multipurpose Vehicle (HMMWV) is a lightweight, high performance four-wheel drive, air transportable and air droppable family of tactical vehicles. The vehicle comes armored and unarmored with several different configurations: Command and Control; Cargo/Shelter Carrier; Weapons Carrier and Ambulance and is capable of performing multiple mission roles for personnel and payloads across the full spectrum of military operations. HMMWV Occupancy Protection supports an All Belts to Seats (ABTS) effort which would mitigate occupant injuries during rollover events, integrate air bags/air belts, and significantly minimize head contact with the roof and doors. Efforts within the Program Element includes Infantry Squad Vehicle (ISV), and HMMWV Occupancy Protection. The Army Infantry Squad Vehicle (ISV), through enhanced tactical mobility, will motorize the Brigade Combat Teams (BCT's) and the 75th Ranger Regiment with their associated equipment to move quickly around the battlefield. This capability is required across the range of military operations conducting crisis response, initial entry, and selected decisive action missions. ISV deploys worldwide by sea, air, and land modes to support strategic deployment and operational maneuver in accordance with Army and Joint doctrine. This capability provides flexibility for entry operations (permissive and non-permissive) to counter threat anti-access strategies by using multiple austere entry points to bring in combined arms configured units. ISV enables infantry squad to operate dispersed and cover greater distances that will achieve positions of advantage and enables platoons and companies to transport and power enabling capabilities at the speeds, distances, and survivability required to support ISV enabled infantry squads and other supporting mission payloads. The ISV enables charging of critical capabilities through increased export power, pushing forward of Class I&V resupply, and enabling CASEVAC. Supports modernization of the current Wheeled Vehicle fleets by investigating technology insertions including, but not limited to: predictive logistics, vetronics, Victory Architecture, autonomous operations and other emerging technologies and variants. Funding also supports developing initial prototypes to enable refinement of Operational Requirements and early user feedback to support future sustainment and operational movement operating concepts. PE 06044642A has no FY26 funding request.$$, NULL, NULL, NULL, NULL, NULL, 3394000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604645A_EV8$$, $$0604645A$$, $$EV8$$, $$Mobile Protected Firepower$$, 16593000, $$Infantry Brigade Combat Teams (IBCTs) currently lack the mobile, protected firepower capability necessary to defeat enemy prepared positions, destroy enemy armored vehicles, close with the enemy through fire and maneuver, and ensure freedom of maneuver and action in close contact with the enemy. The M10 Booker (formerly, Mobile Protected Firepower (MPF)) will provide the Army's IBCTs a protected, long range, precision direct-fire capability to ensure freedom of movement during offensive operations and defeat attacking enemy during defensive operations. As a result of the Army Transformation Initiative (ATI) EXORD, the Army has given direction to cease procurement of M10 Booker and inactivated all M10 Booker Battalions. FY 2026 Base RDTE funds in the amount of $16.593 million will be utilized for contract close-out and realigned to Army Transformation Initiative priorities.$$, 16593000, NULL, NULL, NULL, NULL, 95580000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604654N_1829$$, $$0604654N$$, $$1829$$, $$Expl Ord Disp Proc$$, 8740000, $$This program, aligned with the National Defense Strategy, provides Joint Service Explosive Ordnance Disposal (EOD) and the supported Combatant Commanders with information superiority by providing for the development of Unexploded Explosive Ordnance (UXO), Improvised Explosive Devices (IED), Weapons of Mass Destruction (WMD), and weapons systems Technical Manuals (TMs). TMs, which provide key identification features, hazardous materials, and safety information, are paramount to the success of EOD Mission to detect, locate, access, identify, Render Safe/Neutralize, and dispose or recover both foreign and domestic explosive threats that pose a threat to military operations, installations, personnel, and materials. In addition, EOD Render Safe Procedures (RSP) and Disposal Procedures must be developed prior to fielding in the case of U.S. weapons and ordnance and as soon as possible after gaining knowledge of existence as it pertains to foreign ordnance and other explosive threats. These efforts require collection, exploitation, and analysis of the ordnance items and associated components, e.g., fuzing, prior to the development of EOD procedures. As defined in DOD Directive 5160.62, assigns the Secretary of the Navy (SECNAV) the responsibility of Executive Agent for Explosive Ordnance Disposal (EOD) Technology and Training (T&T). The Executive Agent for EOD T&T is to provide for the preparation, technical development, validation, Joint Service approval, and distribution of all EOD procedures and countermeasures to include; publications, manuals, bulletins, texts, and graphic aids. This program is a non-acquisition program (without traditional acquisition milestones) with ongoing, continuous delivery of urgent and periodic documented procedures and publications for mines, ordnance items, weapons systems, Improvised Explosive Devices, Weapons of Mass Destruction, and related explosive hazards.$$, 8740000, NULL, NULL, NULL, NULL, 321880000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604657M_7400$$, $$0604657M$$, $$7400$$, $$Combat Capability Development$$, 17377000, $$Organic Precision Fires (OPF) is a Marine Corps modernization priority and will provide multiple echelons of the Fleet Marine Force with an organic, loitering, beyond- line-of-sight precision strike capability. OPF will deliver precision effects as well as surveillance before and during target strike, while reducing the potential for collateral damage. Multiple materiel solutions are required to provide the envisioned capabilities to the Fleet Marine Force. OPF-Light will procure an existing, light-weight loitering munition for use by dismounted elements. It provides a dismounted, lightweight, man-packable, loitering munition that extends the capability of the infantry squad/platoon to engage targets to the maximum range of organic Intelligence, Surveillance, and Reconnaissance (ISR) assets at that level. OPF-Light will provide a counter-defilade, anti-personnel and anti-materiel capability. Primary target sets for this system will be enemy personnel, crew- served weapons, and Command and Control (C2) nodes. This will be principally a platoon/squad level asset. In FY 2025, the program completed Developmental Testing 1 (DT1) and initiated Developmental Testing 2 (DT2). In FY 2026, OPF-Light will complete DT2, conduct operational testing, and begin development and testing of OPF capability enhancements. OPF capability enhancements will provide greater lethality effects over the base capability including upgrades for target recognition and warhead performance.$$, 17377000, NULL, NULL, NULL, NULL, 108620000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604659N_1600$$, $$0604659N$$, $$1600$$, $$High-Speed Long Range Maritime$$, 105864000, $$This is a FY 2026 New Start. Multi-mission Affordable Capacity Effectors (MACE), which will provide launch platforms extended standoff capability, maximize weapon load-out, and constrain unit costs to permit large production quantities and optimum inventory levels. MACE will achieve increased range at a lower costs by leveraging investments by the Department of Defense (DoD) Science and Technology enterprise; potential to integrate a high-maturity propulsion system with proven payloads. To minimize costs, maximize affordability, and extend capability relevance, MACE will be designed with government-directed interface standards to permit rapid and affordable future incremental upgrades and enable multi-variant production.$$, 105864000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604659N_3378$$, $$0604659N$$, $$3378$$, $$Next Generation Strike Weapons$$, 2065000, $$Funding is provided for the Next Generation Strike Weapon (NGSW) Family of Systems (FoS) based on the NGLAW Analysis of Alternatives (AoA) completed with results briefed out to OSD. NGSW FoS more accurately reflects the surface/submarine capabilities for land-attack and maritime strike that the AoA results identified for the most capable and economic solutions fielding incrementally between 2020 and 2032. NGSW FoS Increments I and II will leverage mature as well as emerging technologies vice developing a single weapon. NGSW funding will maintain the security environment (enclave), facility, and study team to enable continuing analysis efforts across the FoS. The NGSW enclave ensures the Navy is able to maintain the most up to date modeled threats and validate the effectiveness of current US weapons, offensive and defensive, as well as future systems and concepts developed by industry and other DoD organizations. Maintaining this capability allows expedited analysis of systems and fully informed investment decisions. Further funding supports investment for technologies which enable Increment II capabilities (additional details are held at a higher classification).$$, 2065000, NULL, NULL, NULL, NULL, 48355000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604659N_3409$$, $$0604659N$$, $$3409$$, $$Advanced Aerial Refueling Store$$, 1723000, $$The Advanced Aerial Refueling Store (AARS) is a collection of modifications to individual Aerial Refueling Store (ARS) components that will improve performance and readiness. The ARS updates will package new technologies into the existing store that will support both manned and unmanned (automated) aerial refueling from platforms such as the F/A-18 and MQ-25. These technologies include drogue stabilization, drogue positioning sensors, advanced health and diagnostic capability and real time receiver situational awareness for the unmanned mission operator. These updates will increase safety of flight, facilitate unmanned tanking operations to both manned and unmanned receivers and improve overall ARS reliability. The Digital Controller Upgrade (DCU) with Optical Reference System (ORS) is a hardware and software update to existing components which will provide increased flight safety through monitoring/diagnostic capabilities and enhanced situational awareness to reduce mission aborts. Drogue Stabilization incorporates hardware and software updates to improve the Aerial Refueling Stores ability to hold the drogue in position for refueling actions, and also improve the ability for the receiving platform to maneuver into position for refueling which decreases the risk of refueling mishaps, reduces mission aborts which improves operational efficiency and safety. Hydraulic System Improvements will update hardware to increase hydraulic efficiency by eliminating high failure rate components, improving fuel offload and reducing power demands on the Ram Air Turbine (RAT).$$, 1723000, NULL, NULL, NULL, NULL, 11151000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604659N_3411$$, $$0604659N$$, $$3411$$, $$CAD/PAD Digital Twin Modeling$$, 420000, $$Cartridge Actuated Devices/ Propellant Actuated Devices (CAD/PAD) Digital Twin Modeling will develop and validate models and algorithms for the Department of the Navy (DoN). Digital Twin is a software model that predicts service life of a components' energetic material. This will be used to move towards a Condition Based Maintenance Model vice restrictive service life. The development will be phased over three efforts, specific to Navy AirCrew Common Ejection Seats (NACES). These models will be used as a starting point for a condition-based service life for CAD/PAD. A condition-based service life will result in long term cost savings for the DoN by enabling CAD/PAD to be installed for full useful service life. These models will also be used to support initial service life decisions, service life extension decisions and address obsolescence.$$, 420000, NULL, NULL, NULL, NULL, 1853000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604659N_9999$$, $$0604659N$$, $$9999$$, $$Congressional Adds$$, 0, $$SLCM-N is a theater nuclear system intended to expand the President's options for responding to limited nuclear use and strategic non-nuclear attacks. SLCM-N enables a persistent, survivable regional nuclear presence without dependence on allied host nations that provides assurance to U.S. allies of a credible U.S. theater nuclear response. The SLCM-N program was established per the Acquisition Decision Memorandum (ADM) dated March 15, 2024. The ADM designated SLCM-N an ACAT ID Major Defense Acquisition Program with the Navy as the lead component, as well as authorized the program's entry into the Materiel Solutions Analysis (MSA) phase. SLCM- N program is planning to achieve Initial Operational Capability (IOC) by FY2034 per the FY2024 NDAA. SLCM-N Enterprise System is composed of the SLCM-N Weapon system and Integrated Product Support (IPS). It requires the aggregation of both the Weapon System and IPS to produce the required capability of the SLCM-N program. Nuclear Weapon Surety (Safety, Security, and Use Control) applies across the entire SLCM-N Enterprise System. The SLCM-N Weapon System is the composition of the flight vehicle, warhead, capsule, canister, fire control, enabling platform equipment, and multiple canister launcher that will function onboard a launch platform. The FY2025 funding supports comprehensive program planning and execution activities necessary for the development and delivery of the Nuclear-Armed Sea- Launched Cruise Missile (SLCM-N) System. This includes acquisition, logistics, fleet integration, and Engineering/Professional Support Services (ESS/PSS). There is no baseline funding for SLCM-N in FY 2026. FY 2026 funding should be allocated to new SLCM-N PE0105519N/ PU 3449. As the SLCM-N program has matured, it has refined the allocation of funding across cost categories to better align with evolving priorities. As a result, the share of funding, contract vehicles and program schedule have also become more defined. SLCM-N (PU C880) FY2025 R-2A cost categories include: 1.) Missile Systems 2.) Shipboard Systems 3.) Test and Evaluation 4.) Warhead and Warhead Integration Unit 5.) Weapon Integration and Systems Engineering$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604668F_646682$$, $$0604668F$$, $$646682$$, $$JTMS DEVELOPMENT$$, 129626000, $$This initiative fields a commercial-off-the-shelf (COTS) Enterprise Resource Planning (ERP) solution that will fuse the transportation and financial domains throughout the Joint Deployment and Distribution Enterprise (JDDE) to achieve auditability, transparency, and optimized resource allocation. The program will deliver integrated, streamlined transportation and financial data and processes, supporting the Joint Deployment and Distribution Enterprise (JDDE). Services and DoD agencies will have a system to automate the linkage between transportation action tasks and transportation business related tasks across the full spectrum of financial activity, from obligations through general ledger accounting. It will also close all major gaps that prevent auditability within the transportation spend across DoD and achieve significant gains in two of the focus areas of the Department of Defense's Data Strategy: Senior Leader Decision Support and Business Analytics. Through the JTMS's ability to seamlessly integrate financial data and information with transportation operations in the joint domain, it will give JDDE users the ability to see to the transactional level in a resilient transportation network while reducing duplicate capabilities. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system like capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 the program expended $6.7 million for civilian pay in this program element, and in FY25 the program forecasts $8.92 million for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604668F / Joint Transportation Management System (JTMS) Component Development & Prototypes (ACD&P)$$, 129626000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604669D8Z_832$$, $$0604669D8Z$$, $$832$$, $$Microelectronics Research Maturation$$, 0, $$This project focuses on advanced prototyping activities of the Commons. Additionally, it focuses on providing cost-effective ways to capture and incentivize domestic R&D for various semiconductor technologies in a low-volume production environment and transition them for DOD and commercial market applications. Specifically, it works to transition developments from Commons Hubs resulting from technology identification and research funded by Commons PEs 0602669D8Z and matured by activities funded by Commons PE 0603669D8Z. The project also supports the establishment of the Commons Hubs, which will be networks of regional capabilities organized in collaboration with the CM to address DoD and commercial needs and requirements. The Hubs may include existing academic facilities augmented to enhance intrinsic specializations in emerging areas of microelectronics. Each Hub will concentrate on one of six technical areas including: Secure Edge Computing, 5G/6G Technology, Artificial Intelligence Hardware, Quantum Technology, Electromagnetic Warfare, and Commercial Leap Ahead Technologies. Core Facilities (i.e., fabs) are integral parts of the Hubs network that will provide key fabrication capabilities that are required to demonstrate prototypes with the volume and characteristics required to ensure reduced risk for full manufacturing production.$$, 0, 0, 0, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604679D8Z_893$$, $$0604679D8Z$$, $$893$$, $$Office of Strategic Capital (OSC)$$, 382000, $$In support of the Department of Defense, Office of Strategic Capital’s (OSC) mission is to attract and scale private capital to technologies critical to the national and economic security of the United States. The National Defense Authorization Act for Fiscal Year 2024 (FY2024 NDAA) states OSC shall: • Develop, integrate, and implement capital investment strategies proven in the commercial sector to shape and scale investment in critical technologies and assets; • Identify and prioritize promising critical technologies and assets that require funding and have the potential to benefit DoD; and • Make eligible investments in such technologies and assets, such as supply chain technologies, not always supported through direct investment. To accomplish its mission, OSC uses loans, loan guarantees, and technical assistance – an efficient use of taxpayer dollars – to crowd in investment by aligning government and private sector incentives. The office’s tools take advantage of the power of markets and competition to support DoD needs. OSC’s investments are guided by its FY2025 Investment Strategy, which describes that competition between the United States and its adversaries occurs over the: (i) control of economic chokepoints; (ii) scaling of key industries, and (iii) commercialization of critical technologies. OSC investments will provide the Department of Defense advantages in all these competitive arenas, especially by securing critical supply chains and rebuilding the industrial base. These activities directly align with the administration’s priorities communicated through the Interim National Defense Strategic Guidance (INDSG), and other forthcoming authoritative documents such as the National Security Strategy of the United States (NSS), Interim National Defense Strategy (NDS) and Defense Planning Guidance (DPG). Specifically, the program will: • Develop new financial products, such as direct equipment finance loans for manufacturers, project finance loans to support capital intensive projects, working capital loans for businesses in need of short-term financing, and loan guarantees through private banks. • Provide loans, loan guarantees and technical assistance to businesses, funds, and other entities within the 33 Covered Technology Categories prescribed by Congress in line with the objectives described by the FY25 Investment Strategy, INDSG, NSS, NDS, and DPG. • Identify and prioritize areas for investment through engagements with the Services, Combatant Commands, National Security Council, and other interagency partners. • Create new data tools to map economic networks to determine chokepoints that impact U.S. national and economic security. • Increase private capital investment to enhance the commercialization of DoD and United States Government (USG) science & technology investments.$$, 382000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604682D8Z_104$$, $$0604682D8Z$$, $$104$$, $$Wargaming & Support for Strategic$$, 2776000, $$This program supports the Office of the Director, Cost Assessment & Program Evaluation (CAPE). It funds activities that help CAPE to implement the vision of the Deputy Secretary of Defense to support new approaches to campaign analysis. CAPE will accomplish this by leading studies and developing analytic tools to think about future capabilities and posture. This program provides for analytical research across a spectrum of issues and concerns. The research agenda is focused on near to long-term problems identified by the Deputy Secretary of Defense, and addresses difficult and complex questions linked to program alternatives for current and future capabilities and forces in order to enhance the senior leadership's deliberations and decision-making. This program provides the scientific and technical engineering services needed for research studies in the development of models and simulations and the evaluation of current analytical tools and scientific methods used to evaluate and assess future scenarios and concepts of operations for a wide range of warfighting environments and scenarios. Deliverables from this program will include reports, briefings, and analyses designed to illuminate findings and assessments. Outcomes include the compilation and campaign analyses data to support the DoD capabilities to the challenges of a near-peer warfight and strategic and programmatic options for post INF treaty weapons options.$$, 2776000, NULL, NULL, NULL, NULL, 3089000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604710A_L67$$, $$0604710A$$, $$L67$$, $$Soldier Night Vision Devices$$, 5227000, $$This project develops, improves and miniaturizes high performance electro-optics, thermal and laser systems. It also provides for systems integration of related multi- sensor suites to enable near to long-range target acquisition and engagement as well as improved battlefield command and control in around-the-clock combat operations. It focuses on adapting demonstrated technologies that bring improvements to the dismounted Soldiers' equipment. This project develops or enhances equipment that provides the individual Soldier's day/night situational awareness and individual targeting capability and supports the Situational Awareness Strategy (SAS). This project includes cost associated with efforts for the development, integration and interface of products on Soldiers head, body and weapons. Funding in this project supports the Army's Soldier Lethality Cross Functional Teams (SL CFT) initiatives. Funding in this project aligns with the Army's priorities in support of the National Defense Strategy.$$, 5227000, NULL, NULL, NULL, NULL, 2949000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604703N_1822$$, $$0604703N$$, $$1822$$, $$Manpower Pers & Human Fact$$, 6703000, $$This program is funded under RDT&E operationals systems development because it encompasses engineering and development of new end-items prior to production approval decision along with the enhancement and upgrading of existing Manpower, Personnel, Training, and Education decision support systems, tools, and models. This non-acquisition category program provides funds for continued R&D for broader application of advanced technlogies to transition successful research proof-of- concept demonstrations into operational use. This PE provides funding to support the transition of models and decision support tools from RDT&E funded to production and into the hands of analysts and program managers throughout the MyNavyHR enterprise. The PE also supports the application and adaptation of proven industry models, tools, and technologies to Navy MPTE problems where GOTS solutions are insufficient or non-existent. The second goal of the PE is to successfully implement 90% of the industry-standard tools that are attempted to be used in Navy applications. In FY23, there is a continued need to advance the engineering development of emerging MyNavyHR business systems, technologies, and models from the Navy War Centers, coordinate with other Navy Labs and Research Institutions, and fiscally participate in the transition of MyNavyHR-domain products out of the S&T research environments (e.g. ONR). Per FNC guidance, the S&T programs are to have funding split among resource sponsors and stakeholders using a shared cost model (i.e. 30/50/100%) over the engineering development timeline.$$, 6703000, NULL, NULL, NULL, NULL, 18135000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604707N_2356$$, $$0604707N$$, $$2356$$, $$Maritime Concept Generation &$$, 6866000, $$Maritime Concept Generation and Development (MCGD) funding provides naval warfare subject matter expertise, experiment planning expertise, Modeling and Simulation (M&S) support, and analysis expertise to execute fleet experiments (and the individual experiment initiatives contained within) focused on critical warfighting capabilities and the development of Distributed Military Operations and other emerging Naval concepts. Typical deliverables for each experimental effort include: - Experiment control plan - Data Collection and Analysis Plan (DCAP) - Experiment Analysis Summary Reference Document - Experiment Engineering Plan - Final Experiment Report (with Doctrine, Organization, Training, Materiel, Leadership and Education, Personnel, Facilities - Policy (DOTMLPF-P) recommendations) - New/refined doctrine/Tactics, Techniques and Procedures (TTP). The MCGD project funds four main efforts: (1) Provides critical concept development and experimentation manpower, and warfighting subject matter expertise aligned with the Concept Generation/Concept Development (CG/CD) program. The priorities for the CG/CD program are to develop concept of operations and explore near/far-term technological and non- technological solutions to war fighting gaps across all naval warfare areas. The associated experimentation efforts include planning, systems engineering and integration, modeling and simulation support, event execution, data collection, analysis, and assessment for a wide-range of experimentation efforts including the examination of prototypes, tactical development and evaluation, support for Science and Technology (S&T) innovation, and program of record system development; venues such as workshops, seminars, war games, limited objective experiments, limited technical experiments, and live at-sea events are used to execute these experimentation efforts. (2) Provides naval warfare subject matter expertise, experiment planning expertise, and analysis expertise to plan, execute, and assess experimentation for the fleets and warfighting development centers (WDC) at the operational and tactical levels. This includes a focus on WDC integration role, maritime command and control (C2), advanced cross-domain warfighting, and maritime operations centers (MOCS)/operational level of war (OLW) lines of operations. Seeks to solve fleet-identified warfighting gaps (referenced within the Integrated Prioritized Capability Lists (IPCL), Urgent Operational Needs Statements (UONS), Fleet Commander's Guidance, etc.). The experimentation and prototyping efforts support the "last tactical mile" of many Navy S&T programs by supporting those programs where the technology is mature enough, but requires evaluation on or by a "fleet asset" - ships, airplanes, submarines, and sailors. (3) Provides Modeling and Simulation (M&S) support to Navy experimentation efforts. M&S is used to stimulate decision making during seminar-style and system war gaming experiments and provides the simulated operational environment and capabilities with high-fidelity models such as the Joint Semi-Automated Force (JSAF) program. Additionally, where$$, 6866000, NULL, NULL, NULL, NULL, 70211000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604710A_BQ6$$, $$0604710A$$, $$BQ6$$, $$Visual Augmentation System Eng Dev$$, 308038000, $$This project focuses on transitioning demonstrated technologies that bring improvements to provide Soldiers and Squads a single platform for increased lethality, mobility, and situational awareness to achieve overmatch against our current and future adversaries. Funded efforts will accelerate the implementation of components, Heads Up Display (HUD) improvements, terrain shared coordinate data and processing, algorithms including machine learning/artificial intelligence, human machine integration, and demonstrations in support of the next generation augmented vision and situational awareness. Efforts will provide rapid decision making and targeting capabilities with the integration of external video and data sources such as weapon sights, air and ground platforms, unmanned air and ground assets, and other data sources enabled by edge computing devices, advanced network services, and open resilient architecture. This project will provide data driven analytics to optimize unit performance and enhance lethality and to enable training in a mixed reality environment. This project includes costs for efforts associated with edge computing devices, movement of information and high-level processing, integration, and interface of products with the Soldiers' head, body, weapon, and platforms. To enable such data movement and integration, this project funds the establishment and baselining of a situational awareness architecture. Funding for this project aligns with the Army's Continuous Transformation priorities and National Defense Strategy. This project supports the Soldier Lethality Cross Functional Team. The FY 2026 cost of the Integrated Visual Augmentation System (IVAS) Middle Tier of Acquisition effort is $85.5 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission.$$, 308038000, NULL, NULL, NULL, NULL, 108766000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604710A_DI5$$, $$0604710A$$, $$DI5$$, $$FALCONS$$, 10734000, $$Future Advanced Long-range Common Optical/Netted-fires Sensor (FALCONS) is the next generation sensor for Reconnaissance and Fires missions to enhance lethality and survivability of Brigade Combat Teams (BCTs) in Large Scale Combat Operations (LSCO). FALCONS provides interoperability between ground platforms and dismounted personnel through a Common Operational Picture (COP) of the battlefield and interchangeable components. The enhanced capabilities of FALCONS provide the ability to detect threats at greater distances in full spectrum conflict, terrain, and weather conditions with greater image resolution to develop civil considerations. It is envisioned FALCONS capabilities will be part of the system of systems approach enabled by current or future data sharing networks and transport layers to transmit target quality data to effectors in operational and tactical environments maintaining overmatch in the 2030 and 2040 timeframe. FALCONS equipped systems will be part of an Army 2030/2040 force that is decisive in varying operations against threats in environments of national interest. The Army requires FALCONS equipped forces be operationally responsive and able to adapt and exploit patterns of operations faster than the enemy, while dominating situations and adversaries. FALCONS equipped systems are a key entity of maneuver and fires tactical forces, and provides versatility, agility, and lethality.$$, 10734000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604756N_2077$$, $$0604756N$$, $$2077$$, $$Afloat C-UAS$$, 39407000, $$Afloat Counter Unmanned Aerial Systems (C-UAS) was established to meet an urgent operational need and funds the acquisition, testing, integration, and fielding of prototype C-UAS's to provide a lower cost defense in-depth solution to negate the UAS threats. The FY 2026 discretionary $39.407 million will fund long lead items for the C-UAS systems. Once additional funds are received, the Navy will accelerate new capability integration and fielding to the Fleet.$$, 39407000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604710A_L70$$, $$0604710A$$, $$L70$$, $$Night Vision Dev Ed$$, 14695000, $$The project supports the 3rd Generation Forward Looking Infrared (3GEN FLIR) B-Kit program, which incorporates the next generation of forward-looking infrared technologies. The 3GEN FLIR program provides a common 3GEN FLIR B-Kit for integration into US Army FLIR sensor systems in accordance with the approved Improved Forward Looking Infrared (I-FLIR) Capability Development Document (CDD). The common 3GEN FLIR B-Kit will integrate with XM30, FALCONS, and future platforms; with potential 3GEN FLIR component utilization opportunities for future reconnaissance and airborne applications. The 3GEN FLIR B-Kit provides Mid Wave Infrared and Long Wave Infrared digital video and the electronic interfaces required to integrate the 3GEN FLIR technology with the host platform sensor. When integrated in platform sensor packages, 3GEN FLIR technology enhances the warfighters' survivability and lethality through increased identification range performance, while enabling the detection of difficult or obscured targets and faster threat detection through automated processes. Executing Army guidance to implement advancements in digital processing and artificial intelligence has positioned 3GEN FLIR as the lead sensor to provide the Army's path forward for AI/ML capabilities for ground platforms. The 3GEN FLIR B-Kit program is key to the maintenance of the Army's FLIR industrial base.$$, 14695000, NULL, NULL, NULL, NULL, 10137000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604710A_L79$$, $$0604710A$$, $$L79$$, $$Joint Effects Targeting Systems$$, 12580000, $$The Joint Effects Targeting System (JETS) is an Army Program, which addresses the one-man, hand-held precision targeting gap identified by the Fires Center of Excellence (FCoE). JETS is a light-weight, handheld system that will provide the single dismounted observer with a common, enhanced day and night thermal capability to rapidly acquire, accurately locate, positively identify, and precisely designate targets. JETS can interface with existing and future Forward Entry Systems (FESs) and will be able to operate in environments where Global Positioning System (GPS) capabilities are degraded or denied, and will integrate Military-code (M-Code) GPS receivers. This project will develop and integrate improved precision targeting components to reduce size, weight, power, and cost of systems for dismounted precision Fires mission. Funding in this project aligns with the Army's priorities in support of the National Defense Strategy.$$, 12580000, NULL, NULL, NULL, NULL, 23283000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604713A_548$$, $$0604713A$$, $$548$$, $$Mil Subsistence Sys$$, 1557000, $$This Project enables system development and demonstration of Joint Service combat rations and field feeding equipment/systems designed to improve warfighter performance and reduce the logistics burden of subsistence support. Efforts funded in this Project support all four Services, the Special Operations Command, and the Defense Logistics Agency (DLA). The Army serves as the Executive Agent for this Department of Defense (DoD) program, with oversight and coordination provided by the DoD Combat Feeding Research and Engineering Board (CFREB) as required by DoD Directive (DoDD) 3235.02E. Centralized execution of the DoD Combat Feeding Research and Engineering Program (CFREP) with Joint Service review and approval eliminates unnecessary duplication of efforts across the Services and maximizes use of common materiel solutions.$$, 1557000, NULL, NULL, NULL, NULL, 2170000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604713A_EL2$$, $$0604713A$$, $$EL2$$, $$Army Field Feeding Equipment$$, 4097000, $$This Project supports the development, demonstration and Non-Developmental Item (NDI) Commercial Off-The Shelf (COTS) evaluation of combat feeding equipment to enhance Soldier efficiency, improve Soldier survivability, and reduce food service logistics requirements for the Army. Planned efforts support the rapidly deployable, organically maintained and provisioned field food service equipment initiatives. Operations also support the Engineering and Manufacturing Development (EMD) phase of programs to improve equipment, enhance safety in food service, reduce environmental impact, and decrease fuel and water requirements. This effort develops critical enablers that support the Army's Strategic Planning Guidance by developing and integrating critical expeditionary capabilities that maintain readiness, providing effective solutions that reduce the resource and operational energy footprint, providing modernized deployable kitchen equipment for Army 2030, and enhancing the field Soldier's well-being. This project reduces sustainment requirements, related Combat Support/ Combat Service Support (CS/CSS) demands on lift, the combat zone footprint, and costs for logistical support. FY2026 funds will be utilized for the development of test-ready RU (refrigeration unit) prototypes and the subsequent conduct of performance, qualification, and MTRCS (Multi-Temperature Refrigerated Container System) Integration testing and following assessment.$$, 4097000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604715A_241$$, $$0604715A$$, $$241$$, $$Nstd Combined Arms$$, 19063000, $$The Common Training Instrumentation Architecture (CTIA) program is the foundation architecture of the Live Training Transformation Family of Training Systems (LT2- FTS). The program contains critical core product-line architecture which provides commonality across training instrumentation systems and interoperability across Live, Virtual, Constructive Integrated Training Environment (LVC-ITE) and joint training systems. CTIA includes Army owned software components, architecture services, standards, protocols and governance used by domain-specific Live Training Transformation (LT2) and Live Training Systems (LTS) to include instrumented Force-On- Force (FOF) and Force-On-Target (FOT) training requirements. The CTIA also provides Post Deployment Software Support (PDSS) and technology refresh for the LT2 family of LTS supporting over 23 live instrumented training products which are fielded at over 200 CONUS and OCONUS sites across the Army. Combat Training Center Instrumentation System (CTC-IS) funds the continued development of the existing Instrumentation Systems (IS) at the National Training Center (NTC), Joint Readiness Training Center (JRTC) and Joint Multinational Readiness Center (JMRC). CTC-IS funds the development of the Integrated Tactical Network Communication System integration into the CTC-IS and development and integration of new warfighting capabilities into the CTC-IS to provide high-fidelity live, virtual, and constructive brigade training rotations which prepare Brigade Combat Teams (BCTs), Joint partners, and supporting units to deploy in support of the Army Sustainable Readiness Model (SRM). The CTCs primary goal is to develop agile and adaptive leaders at the tactical, operational, and strategic levels while providing BCTs the core training necessary to conduct decisive action in a dynamic operating environment. The Instrumentable-Multiple Integrated Laser Engagement System (I-MILES) program provides realistic, real-time casualty effects for force-on-force tactical engagement training scenarios. Its ability to integrate into training instrumentation systems provides for high fidelity combined arms combat exercises supporting Readiness and closely aligns with the Modernization priority of Soldier Lethality. I-MILES is required for use at Home Stations, the Combat Training Centers (CTCs) and in theater of operations to meet force-on-force training requirements. I-MILES program funding provides for the Development and Integration of new vehicle and dismount weapon systems meeting the Common Operating Environment (COE) requirements, as well as embedded Tactical Engagement Simulation System (TESS) development. This includes development efforts of the Live Training Engagement Composition (LTEC) / Live Player Area Network (LPAN) Development of Legacy software patches that incorporate the Government owned LTEC operating system software. This creates a common architecture that provides the ability to develop new services to adapt to evolving Army requirements (i.e. Changes in weapon platforms, technologies, Pk Table Updates). The Home Station Instrumentation Training System (HITS) currently provides a high-fidelity deployable instrumented training capability to support platoon thru battalion ground-based Soldiers and vehicles in Force-on-Force Training. HITS tracks location of soldiers and vehicles and simulates weapons' effects and engagements, allowing units to "Train as they Fight" against live opponents. HITS provides accurate feedback to training units. HITS consists of light deployable components that can be rapidly assembled/disassembled and transported to support deployed training. HITS is a member of the Live Training Transformation (LT2) product line of training systems implementing hardware and software reuse with other Instrumentation Systems (IS). HITS provides the only Live training component for the large scale Live- Virtual-Constructive (LVC) military training exercises.$$, 19063000, NULL, NULL, NULL, NULL, 20585000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604727N_2068$$, $$0604727N$$, $$2068$$, $$Joint Standoff Weapon (JSOW)$$, 895000, $$The Joint Standoff Weapon (JSOW) is an air-to-ground weapon designed to attack a variety of targets during day, night, and adverse weather conditions. JSOW enhances aircraft survivability by providing the capability for launch aircraft to standoff outside the range of most target area surface-to-air threat systems. The JSOW launch-and-leave capability will allow several target kills per aircraft sortie. The JSOW program first developed a baseline weapon for use against fixed area targets. JSOW is a Navy led joint Navy/Air Force program. JSOW utilizes a "common truck" for both AGM-154A and AGM-154C variants. Through adherence to international standards for weapons interfaces, weight, and dimension considerations, JSOW is compatible with Air Force and North Atlantic Treaty Organization aircraft.$$, 895000, NULL, NULL, NULL, NULL, 943505000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604735F_652286$$, $$0604735F$$, $$652286$$, $$Combat Training Range$$, 139499000, $$COMBAT TRAINING RANGES (CTR): Portfolio provides electronic warfare equipment and support to Air Force combat training ranges for training, testing, and evaluation of aircrews. Development and integration efforts include: aircraft pods, radar emitters, advanced radar emitters, communication jammers, command and control and debrief capability, and instrumentation equipment. All development efforts support USAF aircraft for Joint, Coalition, and Live Virtual Constructive (LVC) training events. This program leverages digital acquisition tenets of open, agile, and digital. This program will develop Common component in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. It will also invest in analytical, information management, data management, digital environments, networks, facilities, and security infrastructure upgrades directly supporting development and sustainment of this program's capabilities, while leveraging DoD and DAF enterprise IT solutions. ADVANCED RADAR THREAT SYSTEM (ARTS): ADVANCED RADAR THREAT SYSTEM (ARTS): The ARTS family of systems program is currently focused on the ARTS-V1 and ARTS-V3 variants. ARTS-V1 is currently in the Production Phase, having achieved IOC with its Production Representative Article (PRA) at Nellis Test and Training Range, and is preparing to enter into full sustainment in FY28 following delivery of the 2 production units. ARTS-V3 is a software defined digital radar currently in the Engineering and Manufacturing Development Phase. ARTS-V3 is developing a state-of-the-art digital active electronically scanned radar system that will be used to simulate the latest foreign Surface-to-Air Missile (SAM) radar and Electronic Warfare (EW) threat systems. ARTS-V3 systems are a critical part of the Operational Training and Test Infrastructure (OTTI) plan for developing future Tactics, Techniques and Procedures (TTPs) for potential conflicts. These systems are also a critical component of the DoD's testing capabilities for validation of advanced airpower capabilities against threat-representative radar systems. Efforts include, but are not limited to: anechoic chamber research, digital twin, and open-air testing technology development, software development, and collaborative test and development infrastructures. ARTS V3 will validate open-air characteristics of advanced threat systems to develop realistic physics-based threat models for virtual high- end training environments including the Joint Synthetic Environment. MODERNIZATION RANGE THREATS SYSTEMS (RTS): The RTS program supports upgrading and modifying legacy range threat systems to provide combat training relevancy and enhanced systems capabilities. Legacy systems include Multiple Threat Emitter System (MUTES), Miniature Multiple Threat Emitter System (Mini- MUTES), Modular Threat Emitter (MTE) system, Tactical Radar Threat Generator (TRTG) system, Band Simulator, Unmanned Modular Threat Emitter (UMTE) system, and Joint Threat Emitter (JTE) system. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System          PE 0604735F / Combat Training Ranges Development & Demonstration (SDD) LIVE MISSION OPERATIONS CAPABILITY (LMOC): LMOC is an effort to modernize range control centers with common hardware and software that can support live- synthetic training missions. LMOC will provide a node-based enterprise that integrates all range system capabilities, including pre/post mission coordination, in a multi- level secure environment to enable blended live-synthetic training for 4th/5th generation aircraft and aircrew. P6 Combat Training Systems (P6CTS) will resolve existing critical training capability gaps and will enable comprehensive, realistic air combat training. Key upgrades include a trusted operating system, Multiple Level Security (MLS) architecture, Type 1 encryption of over-air data, and increased processing capability. P6CTS investment will support a robust Air-to-Air and Air-to-Ground combat training environment and provide a growth path to Blended Training capability. The P6CTS is comprised of airborne participant subsystem, ground system/subsystem and ancillary range communication infrastructure. P6CTS Initial Operating Capability (IOC) on F-15 at Nevada Test and Training Range (NTTR) is targeted for FY27. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 3.8M was expended for civilian pay expenses in this program element, and in FY25 4.775M is forecasted for civilian pay expenses in this program element. The programs in the civilian pay requirement are ARTS-V3, P6CTS and LMOC. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, 139499000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604741A_126$$, $$0604741A$$, $$126$$, $$PEO Electronic Protect$$, NULL, $$Army Long-Range Persistent Surveillance (ALPS) is a passive sensor that provides long-range surveillance against Cruise Missile (CM), Fixed Wing (FW), Rotary Wing (RW), and Unmanned Aircraft System (UAS) threats.$$, NULL, NULL, NULL, NULL, NULL, 13548000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604756N_9081$$, $$0604756N$$, $$9081$$, $$Phalanx CIWS SEARAM$$, 7214000, $$The MK 15 MOD 40 Close in Weapon System (CIWS) RAM Defense Capability (CRDC) configuration is fielded aboard Nimitz Class Carriers (CVN). It is a fast reaction, rapid fire, computer-controlled radar system that employs the Rolling Airframe Missile (RAM) as an effector for Anti-Ship Missile (ASM) defense. The MK 15 MOD 40 CIWS (CRDC) configuration was fielded in FY 2020, limited to the RAM BLK 2 missile variant. The purpose of this project is to develop and integrate the latest RAM missile variant (BLK 2B) into the MK 15 MOD 40 baseline. The RAM Block 2B missile defends against highly maneuverable Anti-Ship Cruise Missile (ASCM) threats and emerging complex raid attacks utilizing an advanced infrared (IR) seeker and Missile-to-Missile Link (MML) while maintaining all the proven capabilities of previous RAM variants (BLK 2): accurate terminal guidance, proven lethality, and post-launch fire and forget capability. Without this effort the Nimitz class carriers will be unable to utilize the latest and most capable RAM Block 2B missile which entered production in FY 2023.$$, 7214000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604741A_146$$, $$0604741A$$, $$146$$, $$Air & Msl Defense Planning Control$$, 13892000, $$This funding line is a key enabler of the Army Modernization Priorities in support of Air and Missile Defense. The Air Missile Defense Planning and Control System (AMDPCS) provides integration of air and missile defense operations at all echelons. AMDPCS is comprised of the following major subsystems: Air Missile Defense Work Station (AMDWS) ensures updated interfaces for interoperability between Air Defense and the rest of the force, allowing the Commander the visibility and situational understanding of the airspace; tools in AMDWS afford Soldiers horizontal and vertical collaborative planning with adjacent units. Common Data Link Interface-Module (CDLI-M) serves as a joint tactical datalink gateway/air picture. Forward Area Air Defense (FAAD), correlates the joint and local air picture and when displayed on AMDWS, provides a near real time, three-dimensional air picture for the Commander. Joint Tactical Terminal (JTT) provides Soldiers Theater Ballistic Missile (TBM) early warning allowing them to take appropriate actions. AMDPCS are currently fielded to Army Air and Missile Defense Commands (AAMDC), Air Defense Artillery Brigades, (ADA BDE), Air and Missile Defense Battalions (AMD BN) and Terminal High Altitude Area Defense Batteries (THAAD BTRY). Air Defense Airspace Management (ADAM), a variant of AMDPCS, are fielded to Corps, Divisions, Brigade Combat Teams (BCTs) and multi-functional support brigades. AMDPCS is being procured to support Maneuver Short Range Air Defense (M-SHORAD) growth. As part of the capability and technology reuse, AMDWS external interfaces are being leveraged by Integrated Battle Command System (IBCS) to avoid redevelopment of existing capabilities. AMDWS, CDLI-M, and FAAD are core components of the Air and Missile Defense system-of-systems currently deployed in combat zones. FY 2026 Base dollars in the amount of $13.892 million fund development, cyber security compliance, net-readiness and certification of AMDWS, CDLI-M and FAAD software, as well as accreditation of AMDPCS family-of-systems shelters and software.$$, 13892000, NULL, NULL, NULL, NULL, 25385000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604741A_FG5$$, $$0604741A$$, $$FG5$$, $$Counter Unmanned Aerial Systems$$, NULL, $$Counter Small Unmanned Aircraft Systems (C-sUAS) funding supports ongoing efforts to provide forces at all echelons with cross-domain capabilities to identify, classify, track, and defeat Groups 1-3 UAS threats, while supporting joint operational requirements. These combined arms solutions support the full kill-chain and result in solutions addressing fixed/semi-fixed, mounted/mobile, dismounted, and handheld missions. Development efforts are aligned with the C-sUAS Capability Development Document (CDD) and Annexes, which codify the threshold and objective capability requirements for C-sUAS development. Fixed/Mobile System Development: Funds rapid component prototyping, facilitates operational assessments, pursues development and integration of mature hardware, addresses obsolescence, and tests performance improvements of existing fixed and mobile systems against current and near-term threats. Initiates activities required to transition the current mobile C-sUAS solution to field level sustainment. Tech Refresh: Funds technology refreshes of C-sUAS capabilities supporting deployed systems, to keep pace with evolving threats in response to existing Joint Urgent Operational Need (JUON) CC-0558. C-sUAS CDD Pre-Planned Product Improvement (P3I): Funds prototyping, development, and integration of emerging technologies, and testing performance improvements against future threats for C-UAS programs. C-sUAS Emergent Requirements: Funds development, testing, integration, and continuous improvement to accelerate emerging C-sUAS capabilities, such as the Next Generation C-sUAS Missile (NGCM), C-UAS non-kinetic interceptor, and Unit Common and Soldier Common solutions.$$, NULL, NULL, NULL, NULL, NULL, 48057000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604742A_361$$, $$0604742A$$, $$361$$, $$Intelligence Simulation Systems$$, 7790000, $$Project 361 funds the development, integration and testing of the Intelligence Electronic Warfare Tactical Proficiency Trainer (IEWTPT). IEWTPT is a Non-System Training Device (NSTD) which supports home-station training by simulating and stimulating Military Intelligence (MI) and Electronic Warfare (EW) organic or surrogate equipment. It enables training of critical individual, crew, and collective MI tasks/skills and is the core of the U.S. Army Intelligence Center of Excellence (USAICoE) Military Intelligence (MI) holistic training strategy supporting mission command, targeting, and MI Soldier and multi-domain army readiness. IEWTPT provides a realistic simulation intelligence target environment for multi-intelligence disciplines such as All Source Analysis, Signals Intelligence (SIGINT), Imagery Intelligence (IMINT), Open-Source Intelligence (OSINT), Human Intelligence (HUMINT), Geospatial Intelligence (GEOINT) and EW in support of multi-domain operations (MDO) training. IEWTPT provides training for analyst and system operators to exploit intelligence and EW data during training, just as they would in "Real World" operations. The IEWTPT Technical Control Cell (TCC) is composed of two components: the Lower Enclave (LE) which supports exercise planning and scenario development and drives the All Source and GEOINT (and emerging EW) training tasks and the Upper Enclave (UE) which supports all SIGINT related training and operates at the Top Secret / Sensitive Compartmented Information (TS/SCI) classification level. FY 2026 funding will be used for improving multi-intelligence and electronic warfare (EW) scenario development tools, increasing and enhancing threat modeling representation at theater and national echelons, and building and integrating intelligence training capabilities into cloud-ready applications. Base funding will establish enterprise level business processes and services enabling IEWTPT to efficiently develop, operate, and secure capabilities in accordance with OSD Digital Engineering and Army Digital Transformations Strategies. Funding promotes software integration and synergies and efficiencies between training and testing of intelligence platform systems. Promote re-use of common assets and services for Army modernization and defense priorities.$$, 7790000, NULL, NULL, NULL, NULL, 7586000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604742A_362$$, $$0604742A$$, $$362$$, $$Jnt Land Component Constructive$$, NULL, $$The Joint Land Component Constructive Training Capability (JLCCTC) supports Army Title X training worldwide for Army Commanders and their staff at Mission Training Complexes (MTCs), Training and Doctrine Command (TRADOC) facilities, and other customer locations. JLCCTC trains Commanders and their staff in Decisive Actions to include offensive, defensive, stability, and civil support operations. JLCCTC is a software modeling and simulation capability that contributes to Army Training Mission Area by providing appropriate levels of modeling and simulation resolution and fidelity to support unit collective and combined arms training. JLCCTC provides a composable federation configurable to any combination of models and simulations, as required by training exercise intent/design. JLCCTC provides accurate representations of tactically and operationally relevant land warfare operations executed in a contemporary Joint operating environment/context and in support of Army Training and Readiness. NGC enables collective training to be conducted for Corps and down, while increasing efficiency in planning, preparing, and executing training events. Funding will continue development of the Intel, Sustainment, Cyber, and Maneuver/Protection Warfighting Functions, STE Core Service in support of NGC development in accordance with validated STE-SW ICD FY 2025, AvSE development/integration; Development, Security, and Operations, DEVSECOPS implementation/execution; Technical Assessments, Soldier Touch Points (STPs), test planning events, and migration to a cloud environment.$$, NULL, NULL, NULL, NULL, NULL, 22268000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604761N_3103$$, $$0604761N$$, $$3103$$, $$Intelligence Engineering$$, 7023000, $$The details of this program element are classified and are submitted annually to Congress in the classified budget justification books.$$, 7023000, NULL, NULL, NULL, NULL, 19169000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604761N_3421$$, $$0604761N$$, $$3421$$, $$Non-Kinetic Countermeasure Support$$, 0, $$The details of this program element are classified and are submitted annually to Congress in the classified budget justification books.$$, 0, NULL, NULL, NULL, NULL, 58306000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_EU4$$, $$0604802A$$, $$EU4$$, $$40mm HV Improved High Explosive$$, NULL, $$40 millimeter (mm) High Velocity (HV) High Explosive Dual Purpose - Air burst (HEDP-AB) is a new capability identified as a Warfighter counter-defilade requirement in the 40mm High Velocity Improved High Explosive Dual Purpose Cartridge Capability Development Document (CDD) and will provide the Mk19 Mod 3 Grenade Machine Gun (GMG) an airburst capable cartridge with the ability of achieving required lethal effects against enemy targets in the open and in defilade while maintaining the capability to defeat unarmored and lightly armored vehicles. XM1176 HEDP-AB cartridges are manufactured by de-fuzing legacy M430A1 cartridges and installing a new airburst capable fuze onto the M430A1 warhead. In FY 2024, Project EU4 / 40mm HV Improved High Explosive Dual Purpose was a Skip-Year. In FY 2026 there is no funding request.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604746A_L59$$, $$0604746A$$, $$L59$$, $$Diagnost/Expert Sys$$, 6183000, $$This Project funds development of system enhancements for the Maintenance Support Device (MSD). The MSD is a general-purpose automatic test system (ATS) that provides test and diagnostic capabilities required to support current and future weapons and combat support systems across the Cross-Functional Teams (CFTs) in the Army Futures Command (AFC) and will facilitate retirement of aging, obsolete and non-cyber secure test equipment that imposes increasing logistics and operations and support cost burdens. The MSD is the Army's standard at-system tester and requires continuing technology insertions to support modernization and emergence of the supported weapon systems. This Project funds development efforts to insert the most current relevant technology into the next generation MSD, supports capability enhancement of at-platform test adapters, develops and standardizes capabilities to minimize or eliminate Army dependence on expensive proprietary software to support tactical vehicles, and maintains compatibility with emerging platform hardware bus technology and software interface requirements. The Department of Defense has identified the need for Intermittent Fault Detection (IFD) testers to aid in the identification of intermittent faults in difficult to troubleshoot platforms, mitigate No Evidence of Failures (NEOF) to reduce unit costs of unnecessary line replaceable unit (LRU) requisitions, and improve unit operational readiness in support of multi- domain operations, large- scale combat operations and the Indo-Pacific Command which will be funded in part by this Project. The test and diagnostic systems and procedures developed under this Project are essential for ensuring the operational readiness, accuracy and effectiveness of the Army's warfighting systems. This Project funds the development of NGATS General Purpose Test Program Sets (TPS) to expand NGATS capabilities beyond the currently Fielded Abrams and Bradley systems while consolidating systems into a smaller logistics footprint by leveraging Modular Open Systems Approach (MOSA) and providing a more cost effective and repairable capability to the Warfighter. This effort will lead to expanding the overall NGATS platform support capability while reducing the equipment that would have traditionally been fielded. The NGATS program will also look at reducing the footprint of the NGATS core station by modernizing to the new MOSA PXI standard to replace the older and larger VXI standard. Finally, the logistics package for the New Electro Optic NGATS capability will be developed to provide the Warfighter with a more modern and capable electro-optics test capability to keep pace the development of weapons systems optics enhancements. These efforts enhance Fix Forward capabilities in Denied Areas of Operation and align to support Large Scale Combat Operations.$$, 6183000, NULL, NULL, NULL, NULL, 6609000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604746A_L65$$, $$0604746A$$, $$L65$$, $$Test Equipment Development$$, 3329000, $$This project directly supports the Army's modernization priorities by enhancing the reliability and responsiveness of Test, Measurement, and Diagnostic Equipment (TMDE) across the lifecycle of critical weapon systems and combat support platforms. Focused on alignment with the PEO and Army Futures Command (AFC) initiatives, this effort accelerates the integration of advanced technologies including automation and reconfigurable open architectures, leveraging emerging capabilities in artificial intelligence (AI) to improve diagnostic accuracy and efficiency into Army calibration systems. This will improve the speed and fidelity of system validation, contributing to enhanced warfighter lethality and readiness in increasingly contested environments. Specifically, the project develops and prototypes advanced calibration software and capabilities spanning signal measurement domains (DC to microwave), electro- optical, chemical, biological, radiological, nuclear (CBRN), as well as physical and mechanical parameters such as torque, pressure, and temperature. These advancements address critical capability gaps, ensuring the operational readiness and safety of Army systems while simultaneously reducing logistical burdens through minimized equipment footprints and improved deployability. By fostering early user feedback and iterative prototype development, this project informs future TMDE acquisitions, ensuring alignment with evolving operational needs in multi-domain operations and contributing to a data-centric approach to sustainment.$$, 3329000, NULL, NULL, NULL, NULL, 6520000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604755N_2178$$, $$0604755N$$, $$2178$$, $$QRCC$$, 153389000, $$The QRCC project (PU 2178) implements an evolutionary acquisition of improved ship self-defense capabilities against Anti-Ship Cruise Missiles (ASCMs), and improved multi-warfare capabilities, for Aircraft Carriers and Amphibious Class ships. SSDS MK 2 integrates a diverse set of fire control loop sensors and weapons and C4I systems for each ship class (CVN 68/78, LHA 6, LHD 1, LPD 17, and LSD 41/49). SSDS MK 2 provides combat direction, and joint interoperability via the Cooperative Engagement Capability (CEC) and Tactical Digital Information Link (TADIL)-J/Link 16. System design emphasizes commonality and a single source software library that are major mechanisms for cost control and avoidances. SSDS uses a physically distributed, open system architecture computer network consisting of common hardware such as the CPS/CDS and common Computing Infrastructure. SSDS MK 2 integrates new combat system war-fighting capabilities and improvements via incremental capability packages and computing infrastructure (previously Technology Insertion) improvement deliveries. PU 2178 efforts are divided into two major functional areas: SSDS Product Development/Combat Systems Integration, and Test and Evaluation/Certification. SSDS Product Development encompasses systems engineering efforts, technology and capability insertion/integration, and cyber-security, including the development and integration of SSDS Build 10 with the required Technology Insertion TI12/12H computing and display configuration and the development and integration of SSDS Build 12 with the required TI16 computing and display configuration. SSDS Product Development will provide warfighter upgrades including implementation of common software components for System Track Management; integration of CPS and CDS; expansion of SSDS MK 2 Local Area Network (LAN) to a Combat System LAN; integration of new Combat System/C4I elements (SPY-6(V)2, SPY-6(V)3, SLQ-32(V)6 SEWIP BLK 2, starting in FY26 SLQ-32(V)7 SEWIP BK 3, CEC Increment 1 and 2 (CG 2/3), starting in FY 2026 CEC Increment 2 (CG 4/5), RAM Block 2A/2B, ESSM Block 2, CIWS, and CANES); implementation of shared, inheritable CS-level cybersecurity capabilities and Total Ship Training Capability. Capabilities beyond SSDS Build 12 will transition to development by third party software developers and a Common Software construct. SSDS Build 10 is fielded on CVN 78, CVN 70/72, LHD 2, LSD 46/47, LHD 4, and LPD 22/23. To improve efficiency and reduce SW build proliferation, the SSDS design has started migrating an initial release of Build 12 with Advanced Training Domain capability to the TI-16 hardware configuration. First Certified build has deployed. SSDS Build 12 is installed on CVN 71/73/79, LHD 7, and LPD 28/29. SSDS Build 12 development will continue with additional releases to implement SSDS improvements to integrate the SPY-6 variants, ESSM Block 2, SEWIP Softkill Coordination Subsystem (SKCS) and Global Positioning System (GPS) based Positioning, Navigation, and Timing Service (GPNTS) and includes system engineering, critical experiments, software development, operating environment, cyber-security software, hardware/software integration, factory qualification testing, land-based engineering testing, system/software Test, Analyze, and Fix (TAAF) effort in support of CS, logistics products and ashore training course development to be backward for all compatible Baseline 12 ships. FY 2025 and FY 2026 efforts include continuing ongoing transition to production for the next SSDS hardware configuration, establishing a Common Computing Infrastructure allowing for targeted obsolescence and computing scaling upgrades vice wholesale modernization for ships so equipped. Capability development beyond SSDS Build 12 begins to explore utilization of a Common Software construct for development activities and scales with development capacity availability.$$, 153389000, NULL, NULL, NULL, NULL, 996125000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604755N_3172$$, $$0604755N$$, $$3172$$, $$Joint Non-Lethal Weapons$$, 2789000, $$The Navy Non-Lethal Effects (NNLE) program develops non-lethal weapon systems in support of anti-terrorism/force protection missions. Technologies include, but are not limited to: ocular interrupters, vessel propeller occlusion systems, and acoustic hailing devices. Current efforts are focused on the Long-Range Ocular Interrupter (LROI), Maritime Vessel Stopping (MVS) technologies, and Acoustic Hailing Devices (AHD). The LROI is intended to provide the U.S. Navy with the capability to deliver a bright light producing a dazzling or glare effect on a closing target to warn and/or suppress potential threats through increasing levels of visual degradation. LROI will generate a non-lethal, eye safe laser that will provide warning and suppression effects. The extended range capability of LROI will effectively increase tactical decision-making time in support of escalation of force (EoF) tactics, techniques and procedures (TTP) across a broad range of military operations (ROMO). Further, the LROI will enhance Joint Force operations in determining the intent of a potential threat as early as possible. The MVS technologies are systems designed to temporarily disable, slow, or stop waterborne vessels of varying degrees of size and different propulsion types in order to effectively execute escalation of force and intent determination procedures. The MVS technologies will provide the U.S. Navy with lightweight, compact, and reversible solution which will stop or slow marine platforms by occlusion of any type of marine propeller or propulsion. Acoustic Hailing Devices project intelligible speech out to extended ranges. In addition to long-range projection of speech for warning or instructional purposes, the devices are also capable of transmitting loud tones that can distract or deter personnel from approaching U.S. positions or vessels.$$, 2789000, NULL, NULL, NULL, NULL, 32462000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604755N_3358$$, $$0604755N$$, $$3358$$, $$SSDS Training Improvement$$, 11533000, $$SSDS Training Improvement Program provides enhancements and upgrades to the SSDS Total Ship Training Capability (TSTC) components within the combat system, combat system elements, Battle-Force Tactical Training (BFTT), and Advanced Training Domain (ATD) to address needs for increased training capability and functionality in conjunction with SSDS MK2 incremental capability packages, Far-Term Interoperability Improvement Project (FTIIP), Task Force Cyber Awakening (TFCA) Boundary Defense Capability (BDC), and Technical Insertion efforts under PU 2178 (QRCC). These enhancements will address current and future training requirements by implementing new functionality to enable the individual warfighter through distributed battle group events to engage in more complex training requirements to support fleet required training certification events. Capability Development and integration are related to Self Defense, Underwater, Surface, and other warfare areas. Capability enhancements and upgrades include development of re-useable common components that can be leveraged by SSDS MK2 combat systems, and/or integration of re-usable common components developed by the TSTC/BFTT Program and AEGIS Advanced Training Domain (ATD)/TSTC Total Ship Training Capability (TSTC) projects to meet AEGIS combat system training requirements. TSTC continues to integrate and update, as new tactical capabilities are being introduced, to enable crew operator proficiency training for basic and sustainment level training events, through distributed strike group certification fleet synthetic training (FST) events and including COMPTUEX FST at-Sea integration into Live, Virtual and Constructive (LVC) environment. Continued Development is required to integrate new capabilities and interfaces to provide training for AEGIS and SSDS combat system capability upgrades, and to address the Fleet's Live, Virtual and Constructive (LVC) Fleet Training Wholeness initiative. Additionally, modernization is needed to support the DoD Training Transformation Plan, the Chief of Naval Operations Fleet Response Plan and Commander United States Fleet Forces Command Fleet Readiness Training Plan. The Advanced Training Domain (ATD) is being developed to combine BFTT and the AEGIS Combat Training System (ACTS) into a common system that integrates with AEGIS BL 9.2.2AF, and SSDS BL 12xAF. ATD is being hosted along with the AEGIS and SSDS combat system on TI-16 common processing and display hardware. ATD is being designed to be the core of the Total Ship Training Capability, and is projected to be more reliable, simpler to use, and architecturally extensible to meet interoperability and capability enhancement challenges in the future. BFTT is being updated to maintain integration and capability enhancements developed for the Cooperative Engagement Capability (CEC), Surface Electronic Warfare Improvement Program (SEWIP), and the Carrier Tactical Support Center (CV-TSC), and SSDS Fire Control Loop Improvement Program. TSTC provides realistic joint warfare training across the spectrum of armed conflict, realistic unit level team training in all warfare areas (e.g. NIFC-CA and BMD missions to support IAMD). TSTC provides ships' Commanding Officers and Battle Group/Battle Force Commanders with the ability to conduct coordinated realistic, high stress, combat system level team training as an integral part of the Afloat Training Organization, the Tactical Training Groups and C2F/C3F FST/LVC events.$$, 11533000, NULL, NULL, NULL, NULL, 64968000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604756N_0167$$, $$0604756N$$, $$0167$$, $$5in Rolling Airframe Missile$$, 15183000, $$The Rolling Airframe Missile (RAM) program is an international cooperative program with the government of the Federal Republic of Germany. The purpose of this program is to develop, test, and field a surface-to-air self-defense system consisting of both a missile and launcher. The latest fielded variant, the RAM Block 2B, defends against highly maneuverable Anti-Ship Missile (ASM) threats and emerging complex raid attacks utilizing an advanced seeker and missile-to-missile link while retaining all the proven capabilities of previous RAM variants (Block 0/1/1A/2/2A); accurate terminal guidance, proven lethality, and post-launch fire and forget capability. FY 2026 through FY 2030 efforts are as follows: 1) Complete integration of the latest RAM Guided Missile Weapon System (GMWS) into the Ship Self-Defense System (SSDS) Baseline (BL) 12 and Aegis Combat System. This will enable the fleet to deploy the full capability of the RAM Block 2B missile which entered production in FY 2023. 2) Continue the RAM "Performance Lab" which identifies improvements for incorporation through real-world events, trade studies, modelling and simulation, experiments, and test firings. 3) Continue the RAM Software Factory to provide end users with rapid missile software updates to address emerging threats. 4) Develop the Ship to Missile Uplink/Downlink (Stowed Kill Improvement Project (SKIP)). SKIP will utilize missile uplinks to provide the missile with continuous data from the combat system to improve mid-course and increase the probability of kill against complex raids. SKIP downlink will provide data back to the combat system to improve kill assessment fidelity. These system performance and efficiency improvements will be leveraged to decrease the required missiles per threat therefore increasing stowed kills per launcher. This capability will apply to both the MK 49 RAM launcher and the MK 15 SeaRAM launcher.$$, 15183000, NULL, NULL, NULL, NULL, 376267000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604756N_0173$$, $$0604756N$$, $$0173$$, $$NATO Sea Sparrow$$, 81372000, $$This project encompasses eight (8) primary efforts to enhance ship self-defense: 1. ESSM System Integration and Test: Evolved SEASPARROW Missile (ESSM) Blk 1 and Block 2 is a cooperative effort among the 12 NATO SEASPARROW Project Consortium Nations including the U.S. to provide crucial battlespace defense and fire power against the fast, low altitude, highly maneuverable Anti-Ship Cruise Missile (ASCM) threat. Modifications were made to increase capacity by employing a four ESSM QuadPack in a single MK 41 Vertical Launch System (VLS) cell on DDG 51 Class Guided Missile Destroyers, CG 47 Class Guided Missile Cruisers, and the NATO SEASPARROW Surface Missile System (NSSMS) fielded onboard CVN 68 and CVN 78 Class Aircraft Carriers, LHD 1 and LHA 7 Class Multipurpose Amphibious Assault Ships. Major testing campaigns this year includes ESSM Block 2 Initial Operational Test and evaluation (IOT&E) Phase 2, which will continue the IOT&E test campaign, leading to the Full Rate Production Decision. Enterprise testing with SSDS BL 12 on the Self Defense Test Ship and lead ships CVN 79 and LHA 8. Both ESSM Block 1 and ESSM Block 2 will be used for Enterprise testing. 1.1 Block 2 Follow-on Test & Evaluation (FOT&E): The ESSM Blk 2 Milestone Decision Authority (MDA) mandated that ESSM Block 2 conduct FOT&E on Ship Self-Defense System (SSDS) platform and fully support DDG Flight III operational testing. There will be planning efforts to support US Combat Systems integration verification and flight testing including but not limited to: AEGIS Baselines 9 and 10, SSDS Baseline 12 (on SDTS CVN 79 and LHA 8), and FFG platform integration testing. All integration verification testing includes support with appropriate ESSM Block 2 Missile Simulator Unit (MSU) with operator support. 2. NATO SEASPARROW Technical Direction Agent (TDA): The MK 57 NATO SEASPARROW Surface Missile Systems (NSSMS) provides a rapid response, integrated, self-defense missile capability. The TDA provides systems engineering and technical support for the MK 9 Tracker-Illuminator System (TIS), and MK 29 Guided Missile Launching System (GMLS). The TDA is tasked with providing studies, analysis, prototyping, and evaluations of hardware and software improvements. This task encompasses requirements development and assessment, artifact and document reviews, technical meeting participation, test requirement development, analysis for test and system integration events, and post-test analysis. 3. ESSM Technology Roadmap Analysis & Prototyping support: The ESSM Block 2 Missile completed development in 2021, achieved Initial Operational Capability in December 2021 and transitioned to production and in-service phases. In order to achieve performance not realized during the execution of Engineering and Manufacturing Development (EMD), pace the threat, and remain a viable weapon system, the ESSM Block 2 and its supporting combat system components require continual improvements. This effort will perform studies to identify technology candidates, explore new manufacturing techniques and technologies, and determine applicability to the NATO SEASPARROW Project Office (NSPO) managed Combat System Elements for future hardware or software improvements to either the Consortium's combat systems or the missile, or both. Tasking includes development and maintenance of an ESSM System roadmap and support specific studies to determine candidate combat system and/or missile performance and manufacturing efficiency improvements. Computer simulation updates will be needed to support the performance studies for future improvements.$$, 81372000, NULL, NULL, NULL, NULL, 229817000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604756N_2070$$, $$0604756N$$, $$2070$$, $$OTH Missile$$, 1831000, $$Over-The-Horizon (OTH) Missile funds competitive acquisition, testing, integrating and fielding of a modern, technologically mature Over-the-Horizon Missile Launch System (OTH-MLS) surface to surface missile capability will be installed onto commissioned and in-production Littoral Combat Ship Variants/Frigate(LCS/FFG)beginning FY 2019.$$, 1831000, NULL, NULL, NULL, NULL, 75757000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604757N_0954$$, $$0604757N$$, $$0954$$, $$Shipboard EW Improvement Program$$, 17178000, $$EW Rapid Capability Insertion Process (RCIP) identifies system and mission capability gaps by analyzing EW baseline and fleet requirements, prioritizes those gaps based on fleet input and critical technology maturity, and develops upgrades to the AN/SLQ-32(V) product line to address those gaps. RCIP also integrates Future Naval Capability (FNC) programs into SEWIP. The Surface Electronic Warfare Improvement Program (SEWIP) provides incremental upgrades to the AN/SLQ-32 and consists of Blocks 1A, 1B, 2, and 3, the Soft Kill Coordination System (SKCS), SEWIP Lite, and Scaled Onboard Electronic Attack (SOEA). Scaled Onboard Electronic Attack (SOEA) is an incremental development program that initiated under PU 0954 in FY 2024 and was moved under PU 3469 in FY 2025 and out to provide an advanced Electronic Attack (EA) capability against anti-ship missiles. The FY 2026 budget request supports continued development, test, and integration of SKCS with AEGIS Baseline (BL) 9 and BL 10, continues RCIP #8 to improve anti-ship missile defense capability of SLQ-32(V)6/7 when operating with other netted EW sensors and effectors, continues RCIP #6 efforts to implement Built In Test, and Signal Processing and continues RCIP #10, #11, and #12 Measurement Based Adaptive Response, the Electronic Warfare (EW) Planning Aid, and the Tactical Simulator (TACSIM) Technology Refresh. Since the FY25 budget request, RCIP #13 Mk 59, SLQ-32(V)6 and (V)7 Integration have been added.$$, 17178000, NULL, NULL, NULL, NULL, 119351000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604757N_2190$$, $$0604757N$$, $$2190$$, $$NULKA Decoy$$, 5575000, $$The Offboard Active Decoy (Nulka) is a joint cooperative program between the United States and Australia that developed an active offboard decoy that utilizes a broadband radio frequency repeater mounted atop a hovering rocket. Nulka counters a wide variety of present and future radar guided Anti-Ship Missiles (ASMs) by radiating a large radar cross section while flying a ship-like trajectory. The United States developed the electronic payload and fire control system, while Australia developed the hovering rocket. The FY 2026 budget request includes Decoy Launcher Processor (DLP) Nulka Objective Architecture, Decoy Launch Message Converter (DLMC) backward compatibility technology with Soft Kill Coordination System (SKCS). The Objective Architecture development will continue which provides improved Nulka decoy deployment as well as SKCS integration.$$, 5575000, NULL, NULL, NULL, NULL, 70178000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604757N_3068$$, $$0604757N$$, $$3068$$, $$Long Endurance Electronic Decoy$$, 145456000, $$The Long Endurance Electronic Decoy (LEED) program will deliver an expendable long endurance autonomous off-board decoy Countermeasure system, comprised of a flight vehicle and Radio Frequency (RF) payload with modular capability allowing for rapid modification of the Electronic Warfare (EW) payload. LEED development executes under a middle tier rapid prototyping acquisition strategy pursuant to Section 804 of the FY16 National Defense Authorization Act. LEED will integrate with SLQ-32 and address EW gaps in response to a fleet requirement to counter Anti-Ship Missile (ASM) threats. LEED will provide the fleet with enhanced EW coordination and capability, including the ability to stretch engagement timelines and counter heterogeneous missile attacks. The overarching LEED strategy consists of two phases including a Middle Tier of Acquisition Rapid Prototyping (MTA RP) phase followed by Major Capability Acquisition. The MTA RP phase will include Preliminary and Integrated Countermeasure Prototype Development (FY 2021-FY 2025) and Integrated System Testing (FY 2025 - FY 2026). The MTA RP phase includes the development and test of operational-level Countermeasure prototypes, launch systems, and control software that demonstrate and validate critical capabilities, including flight performance, control, and payload functionality. Data collected from the initial prototypes will be used to develop Engineering Development Models (EDMs) for Qualification Testing to support a Milestone C decision for Low Rate Initial Production (LRIP) as LEED enters the Major Capability Acquisition phase. LEED will be developed alongside the Office of Naval Research (ONR) Long Endurance Airborne Platform (LEAP) Project, which began in FY 2021. LEED will leverage technologies developed and matured under the ONR LEAP Project. FY 2026 funding request supports continued LEED integrated countermeasure development at the prime contractor, including material purchases, system/subsystem integration, integrated system demonstration testing and system performance testing, system of systems interoperability integration and testing, training and maintenance curriculum development, and cybersecurity advancement. Funding request also includes material purchases and integration of prototype shipset(s) (each shipset consists of 24 countermeasure, 4 launchers, and all supporting equipment). Funding request also supports development of the LEED Block 2 All-Up Round (AUR) payload in line with the program's required insertion of rapid EW capability and modularity concept.$$, 145456000, NULL, NULL, NULL, NULL, 48717000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604757N_3316$$, $$0604757N$$, $$3316$$, $$Advanced Offboard EW$$, 0, $$The Advanced Offboard EW (AOEW) program was for the development of long duration off-board decoys integrated with onboard systems for EW coordination to counter identified EW gaps (additional details classified) in response to an urgent operational need. Divestment of AOEW is starting in FY 2026. AOEW Capability Development Document (CDD) was cancelled and requirements were transferred to other programs.$$, 0, NULL, NULL, NULL, NULL, 379333000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604757N_3321$$, $$0604757N$$, $$3321$$, $$SEWIP Block 3$$, 6460000, $$SEWIP Block 3 is developing an advanced Electronic Attack (EA) capability to keep pace with the evolving Anti-Ship Missile (ASM) threat and counter-targeting required for the AN/SLQ-32(V) system. SEWIP Block 3 will provide the AN/SLQ-32(V)7 system for all surface ships (CVN, DDG, LHD) outfitted with the active variant of the AN/ SLQ-32, mainly the (V)3 and (V)4, as well as select new construction platforms. The SEWIP Block 3 Acquisition leverages technology developed under the Office of Naval Research's (ONR) Integrated Topside (InTop) Science and Technology (S&T) effort. SEWIP Block 3 will continue to expand the integrated shipboard combat system by providing new integrated EA transmitter, arrays, and associated EA techniques. The AN/SLQ-32(V)7 integrates the new EA countermeasure (SEWIP Block 3) with the AN/SLQ-32(V)6. The AN/SLQ-32(V)6 includes an Electronic Support (ES) receiver (SEWIP Block 2), a High Gain High Sensitivity (HGHS) receiver (SEWIP Block 1B3), a Specific Emitter Identifier (SEI) receiver (SEWIP Block 1B2), display console, and backend electronics. SEWIP Block 3 includes the government software development and integration effort for a SoftKill Coordinator (SKC) to manage EA engagements. SEWIP Block 3 is developing an Electronic Warfare Test Bed (EWTB) to validate system performance via modeling and simulation. SEWIP Block 3 is also investigating higher efficiency Gallium Nitride (GaN) High Power Amplifiers (HPA). GaN HPAs are used in maritime advanced technology radar and surface electronic warfare systems. For radar and electronic warfare systems, this will yield technology to incorporate and integrate into radar and electronic warfare Transmit/ Receive Module designs, with a beneficial impact of improved Power Added Efficiency (PAE) for these systems resulting in a reduction in power draw from ship's service electrical power for the same radar and electronic warfare system performance. To keep pace with evolving ASM threats and counter-targeting, SEWIP Block 3 will incorporate capability improvements via a technology insertion plan. This capability improvement plan will mature and develop technologies and software/firmware to expand and improve capability for insertion into SEWIP Block 3. Technology solutions will result in technical data packages and tactical software with Government-owned data rights. Solutions will be incorporated into the SEWIP Block 3 technical data packages and tactical software for incorporation into future production and/or back-fit of fielded systems. The FY 2026 funding request for SEWIP Block 3 will focus on the conduct of Full Rate Production Decision Review (FRP DR), continued Software and Hardware baseline upgrades, capability improvement design and development and associated testing, training curriculum development and EW Testbed model upgrades.$$, 6460000, NULL, NULL, NULL, NULL, 289466000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604771D8Z_771$$, $$0604771D8Z$$, $$771$$, $$Joint Information and Capability$$, 10527000, $$Provide in-depth technical, engineering, integration support, and system of system analysis for space, missile defense, cyber, C4MD, NC3, and nuclear delivery system modernization program portfolio management. - C4ISR: Develop and maintain a roadmap to improve data link interoperability, data link waveform standards, and global enterprise capabilities, enabling resilient, survivable federated networks. -NC3 and Strategic Deterrence: Execute NC3 Enterprise Capability Portfolio Management on behalf of the OUSD(A&S). Provides acquisition expertise to recapitalize the nation's nuclear deterrent and reduce risk in nuclear and NC3 modernization programs. - SMD: Provides acquisition expertise to inform synchronized modernization and fielding of space and missile defense systems, including Space Control, Remote Sensing, SATCOM, PNT, launch, and homeland and regional missile defense capabilities.$$, 10527000, NULL, NULL, NULL, NULL, 200853000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604757N_3469$$, $$0604757N$$, $$3469$$, $$Scaled Onboard Electronic Attack$$, 57699000, $$Scaled Onboard Electronic Attack (SOEA) is an incremental development program that initiated under PU 0954 in FY 2024 and was added under PU 3469 in FY 2025 and and out, to provide an advanced Electronic Attack (EA) capability against anti-ship missiles. SOEA will assimilate into the Surface Electronic Warfare Improvement Program (SEWIP) family of shipboard Electronic Warfare systems. The program is intended to be scalable for Surface Combatants with size, weight, power, and cooling (SWaP-C) constraints that cannot support AN/SLQ-32(V)7 installation; however, it is not meant as a replacement for AN/SLQ-32(V)7. SOEA development executes under a Middle Tier Rapid Prototyping acquisition strategy pursuant to Section 804 of the FY 2016 National Defense Authorization Act. The SOEA Middle Tier of Acquisition (MTA) leverages technology developed by the Office of Naval Research (ONR) and Naval Research Laboratory (NRL). SOEA's acquisition strategy consists of two phases: Rapid Prototyping and Rapid Fielding. SOEA Phase 1 includes prototyping of critical technology elements (CTEs) via Defense Microelectronics Agency (DMEA) contract agreements to prove out and validate critical performance capability, system architecture functionality, supportability requirements and improvements that build on the CTEs. SOEA Phase 2 will focus on fielding initial capability through the production of the Phase 1 prototype, continuing hardware and software improvements to meet full capability objectives, continuing external interfaces for system and platform integration, continuing training module development via the Surface Electronic Warfare Tactical Trainer (SEWTT) and completing Modeling & Simulation (M&S) to support further testing. SOEA will continue to expand the integrated shipboard combat system by providing new integrated EA capability and will be integrated with AN/SLQ-32(V)6. SOEA also includes a government software development and integration effort for a Soft-Kill Coordinator System (SKCS) to manage EA engagements. The FY 2026 budget request for SOEA supports continuation of Phase 1 Rapid Prototyping, including rapid prototype development, qualification and performance testing. The FY 2026 budget request also supports the initiation of SOEA Phase 2 Rapid Fielding which continues platform integration activities, SEWTT training module development, Modeling & Simulation (M&S) to support further testing, SKCS integration, and to acquire additional prototype units.$$, 57699000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604759A_983$$, $$0604759A$$, $$983$$, $$Reagan Test Site (RTS) T&E$$, 8255000, $$This Project funds improvement and modernization (I&M) for the Ronald Reagan Ballistic Missile Defense Test Site (RTS) instrumentation systems. The Reagan Test Site with its remote location and one of kind instrumentation systems provides a strategic test environment that cannot be replicated. In order to continue its critical mission of testing missile systems that are of paramount importance to the defense of the nation, the RTS instrumentation systems must be continuously updated and upgraded to support the emerging technologies being developed by the Department of Defense (DOD) such as hypersonics and other advanced weapons systems. Without modernization, these instrumentation systems face obsolescence or degraded capability and the inability to provide the critical data needed for continued materiel development. Without instrumentation on par with the technologies being utilized in emerging systems, the materiel developer will be unable to complete their test programs or pass programmatic milestones toward deployment. These funds provide modernization of the radar, telemetry, optics, range safety, communications, command/control and other equipment essential to meet test and evaluation requirements of the Services and DoD agencies. The RTS instrumentation is required to support data collection for test & evaluation assessments and operational decisions that have strategic implications for the Army, Navy, Air Force, United States Strategic Command (STRATCOM), Missile Defense Agency (MDA), Defense Advanced Research Projects Agency (DARPA), National Aeronautics and Space Administration (NASA), and other customers. RTS, located in the Republic of the Marshall Islands, is a remote, secure activity of the Major Range and Test Facility Base (MRTFB). Funding will enable RTS to meet customer objectives and sustain the required instrumentation suite. FY25 funding in the amount of $3.269 million is in support of the Pacific Defense Initiative.$$, 8255000, NULL, NULL, NULL, NULL, 8095000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604759A_984$$, $$0604759A$$, $$984$$, $$Major Developmental Testing$$, 30581000, $$This Project develops and acquires major test instrumentation to perform developmental testing of weapon systems at United States Army Test and Evaluation Command's (ATEC) activities which include: Yuma Test Center (YTC), AZ; Aberdeen Test Center (ATC), MD; Electronic Proving Ground (EPG), AZ; White Sands Test Center (WSTC), NM; Redstone Test Center (RTC), AL; Cold Regions Test Center (CRTC), AK. Projects are designated as a major test program based on their visibility, assessed relative technical risk (medium high), schedule risk, cost (greater than $1.500 Million per year or $7.500 Million for the total Project) and applicability to other mission areas or services. These Projects are technically demanding, state of the art, unique instrumentation assets or suites to meet technology shortfalls, and generally result from development programs managed by a professional project management team. All projects are designed to support both test and training requirements, as applicable. Test Enterprise Network Modernization (TENM) will upgrade existing test data networks to ensure infrastructures are capable of providing reliable and secure transport of data and communications for ATEC test activities, as well as a revitalized fiber network. Due to limited commercial infrastructure, the cold regions have limited network connectivity. Therefore, TENM requires an edge capability along with a permanent fiber backbone on Army test ranges to ensure advanced weapon systems can operate flawlessly in extreme cold. Applied Environments Modernization (AEM) program will upgrade antiquated labs for temperature and dynamic testing with new cascade refrigeration units, temperature chambers, vibration test systems, x-ray cameras, a real-time radiography system and full spectrum solar lights, and an outdoor wind and dust machine. Telemetry Systems Modernization (TSM) will modernize outdated telemetry systems with new equipment designed to enhance the technical and spectral capabilities currently available. This new telemetry equipment will also provide for a remote controlled operational geography. In support of the National Defense Strategy, each of these programs supports the following Army Cross Functional Teams: Long Range Precision Fires, Next Generation Combat Vehicle and Future Vertical Lift, and Air and Missile Defense.$$, 30581000, NULL, NULL, NULL, NULL, 32308000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604759A_986$$, $$0604759A$$, $$986$$, $$Major Operational Test$$, 13038000, $$This Project funds the development, acquisition, and integration of major operational test instrumentation for the U.S. Army Test and Evaluation Command's Operational Test Command and supporting test activities at test and training ranges. Requirements for instrumentation are identified through a long-range survey of project managers, Research Development and Engineering Centers (RDECs), and Battle Laboratories developing future weapon systems and the test programs that support these systems. Project focus is to address Director Operational Test and Evaluation (DOT&E) identified Army test realism shortfalls. Base funding will establish enterprise level business processes and services for test instrumentation to develop, operate, and secure capabilities in accordance with OSD and Army Digital Engineering and Software Modernization Strategies. Efforts will promote synergies between the training and testing enablers to improve product development, integration, and cyber activities, and to promote re-use of common assets and services to meet Army modernization priorities. Projects are designated as a major test program based on their visibility, assessed relative technical risk (medium-high), schedule risk, cost (greater than $1.500 million per year or $7.500 million for the total project) and applicability to other mission areas or services. These projects are technically demanding, state-of-the-art, unique instrumentation assets or suites to meet technology shortfalls, and generally result from development programs managed by a professional project management team. The DOT&E annual report to Congress identified shortfalls in the Army's abilities to create realistic operational environments. The Expeditionary Live Virtual Constructive Command Center (XLCC) project addresses multiple shortfalls identified by DOT&E. XLCC is a portfolio of related development efforts that will deliver a system of systems to provide Test Monitoring & Control (TMC) for the Common Operating Picture (COP) for Exercise Control (EXCON) for the Multi-Domain Operations Environment (MDOE). XLCC will provide Real Time Casualty Assessment (RTCA) and instrumentation suite that delivers a high fidelity, realistic, real-time capability to measure the System Under Test (SUT). XLCC also allows the U.S. Army to test all Current-to-Future weapon systems in a realistic Future Operating Environment (FOE). XLCC will transition Research, Development, Test and Evaluation (RDTE) performance enhancements and technology upgrades to the Operational Test Command to include control, communications, communications network, weapons system interfaces, vehicle and dismounted-troop kits and peripherals. XLCC will enable sufficient data collection and analysis tools to collect, store and analyze Decision Driven Data (DDD). Improvements will enable the XLCC system of systems to measure and record accrued battle damage assessment (BDA), levels of exposure, effects of countermeasures, evasive action, and instrument threat vehicles for effect After Action Reviews (AAR). This capability is required by the operational test community to create an adequately realistic representation of a MDO combat environment across all Signature Modernization Efforts to support Army modernization priorities and other operational tests.$$, 13038000, NULL, NULL, NULL, NULL, 20784000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604759A_EY9$$, $$0604759A$$, $$EY9$$, $$Range Radar Replacement Program$$, 48003000, $$In order to effect strategic overmatch on current and future battlefields, it is essential that the United States (U.S.) Army provide advanced radar system instrumentation for developmental testing. Since existing range radar instrumentation is aged beyond useful life and cannot adequately support emerging test requirements, the Range Radar Replacement Program (RRRP) recapitalizes and develops modern instrumentation radars to replace obsolete tracking and surveillance radars at U.S. Army Test and Evaluation Command's (ATEC) activities, which include: Aberdeen Test Center (ATC), MD; White Sands Test Center (WSTC), NM; and Yuma Test Center (YTC), AZ. RRRP will deliver capability in three (3) block increments: Block I will recapitalize or replace existing radar systems, Block II will develop a Long Range Radar (LRR) which is compliant with ATEC's Test Capability Requirements Document (TCRD), and Block III will develop LRRs and Medium Range Radars (MRRs) to meet ATEC Block III TCRD Addendum. The acquisition of modern instrumentation radar systems will provide the Army with critical testing data essential for the development of next generation technology and advanced system capabilities. The RRRP provides the test centers with improved radar resolution, sensitivity, accuracy, clutter suppression, and reliability. The planned solution to meet program requirements consists of four primary items: Long Range Single Object Tracking Radars (SOTR), Long Range Multiple Object Tracking Radars (MOTR), Medium Range Radars (MRR), and Short Range Radars (SRR). The resulting systems will not only reduce operation and sustainment costs for the ranges, but will improve data collection, thus enhancing development of Army systems being tested at these ranges. The current fleet of instrumentation radars located at ATC, WSTC, and YTC has become antiquated to the extent that they are not able to support the test needs of the test centers. Funds in the amount of $48.003 Million will procure Modified Commercial Off-the-Shelf (MCOTS) radars for LRR, MRR and SRR solutions, and a combination of recapitalization and MCOTS replacement for the Long Range SOTRs and MOTRs.$$, 48003000, NULL, NULL, NULL, NULL, 25393000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604771N_0933$$, $$0604771N$$, $$0933$$, $$Medical/Dental Equipment Dev$$, 7629000, $$The purpose of this program is to develop biomedical equipment and related techniques to reduce morbidity; to enhance the logistic feasibility of modern medical care for combat casualties; to sustain casualties for evacuation to fixed medical facilities for definitive care; and to ensure that personnel are medically qualified for military duty. Each work unit undertaken in this project has a military requirement. Efforts are justified based upon military payoff and cost benefit. There is a strong potential for dual use, technology transfer, and biotechnology firms/industry participation in the projects. The purpose of this program is to develop, test, and evaluate expeditionary medical systems and equipment to save warfighter lives, facilitate movement of patients up the roles of care, and return warfighters to the fight, especially in the Distributed Maritime environment. Each work unit undertaken in this program has a military requirement. Efforts are justified based upon military payoff and cost benefit. There is a strong potential for dual use, technology transfer, and biotechnology firms/ industry participation in the projects.$$, 7629000, NULL, NULL, NULL, NULL, 25681000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604771N_9999$$, $$0604771N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional Adds$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604759A_FF1$$, $$0604759A$$, $$FF1$$, $$Cyber Blue Team$$, 1150000, $$In 2016 the Army Acquisition Executive (AAE) designated the Program Manager for Cyber, and Training (PM CT2) as the Office of Primary Responsibility for Cyber Acquisition Blue Teams (CABT) certifications and standards program. This Project executes the establishment and management of certification standards for CABT and coordination of requirements on behalf of the Assistant Secretary of the Army for Acquisition, Logistics, and Technology (ASA (ALT)). PM CT2 will establish certification standards, certify Blue Teams, and maintain a vulnerabilities/lessons learned repository. PM CT2 will work with Blue and Red Teams to establish processes which facilitate open network tests under the red team authority, coordinate with Program Managers on CABT efforts on behalf of ASA(ALT) and report to ASA(ALT) on new cyber vulnerabilities. Blue teams will work cooperatively with acquisition programs to make sure all security measures are taken throughout the program's lifecycle, ensuring cyber resiliency. Blue teams are essential to help military operators assess, protect and defeat the presence of cyber security threats across Army Acquisition Programs. Will focus on the continuation of certifying candidate teams. The goal is to certify enough teams to allow acquisition programs the flexibility to find a certified Blue Team that meet their program's schedule and cost and can be incorporated early on in the program. CABT vulnerability assessments will provide data analytics to report trends and lessons learned. A web portal will serve as a one-stop shop for both candidate and certified Blue teams to obtain and maintain their certification.$$, 1150000, NULL, NULL, NULL, NULL, 1107000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604759F_664597$$, $$0604759F$$, $$664597$$, $$AF Test Investments$$, 156915000, $$This PE provides planning, improvements, and modernization for test capabilities within Air Force Test Center (AFTC) Major Range and Test Facility Base (MRTFB) organizations: 96 Test Wing (TW) at Eglin AFB FL, the 412TW at Edwards AFB CA, and Arnold Engineering Development Complex (AEDC) at Arnold AFB TN. The 704th Test Group (TG) at Holloman AFB NM is aligned under AEDC as part of the management consolidation of Ground test capabilities. The Improvement and Modernization (I&M) requirements are defined through the AF Test Investment Planning & Programming (TIPP) Process. All projects have been reviewed through the Tri-Service Reliance Process (to communicate AF efforts to the other services and avoid unwarranted duplication of effort) and are documented in the Technology Development Acquisition Program (TDAP) database. Each project has its own planning, development, equipment acquisition, equipment installation, and checkout phases which often require significant differences in funding from one year to the next. As such, the changes in category funding from year-to-year does not necessarily indicate program growth, but rather a planned phasing of I&M efforts. The test capabilities at these locations enable testing through all phases of weapon system acquisition, from system concept exploration through component and full-scale integrated weapon system test to operational test. The 96TW conducts and supports Developmental Test and Evaluation (DT&E) of non-nuclear air armaments; Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance, Reconnaissance (C5ISR) systems; target acquisition and weapon delivery systems; determines target/test item spectral signatures; and provides cyber testing capabilities as part of the Avionics Cyber Range (ACR). The 412TW conducts and supports DT&E and Operational Test and Evaluation (OT&E) of aircraft and aircraft systems, aerospace research vehicles, unmanned aerial vehicles, cruise missiles, parachute delivery/recovery/systems, and cargo handling systems. AEDC provides pre-flight reliability environmental test support for DoD aero propulsion, flight systems, and space and missile programs. AEDC has 72 test facilities providing: aerodynamic testing of scale model aircraft, missiles, and space systems; testing of large and full-scale satellites, sensors, and space vehicles in a simulated space environment; altitude environmental testing for aircraft, missile, and spacecraft propulsion systems; testing of large-scale models such as space boosters together with their propulsion systems. The 704TG provides flight test and test support for joint, international and commercial customers in advanced avionics and weapons, inertial navigation systems, Global Positioning System (GPS) and other integrated aircraft and missile navigation systems. They test subsonic through hypersonic ground performance of aircraft and missiles in a flight-representative, highly instrumented environment while also coordinating and scheduling all USAF test operations at White Sands Missile Range. The 704TG OL-AC at Wright-Patterson AFB, OH provides independent DT&E in support of aircraft survivability and evaluation of full- scale aircraft landing gear, tires and brakes. They also provide an independent capability for component qualification. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                                Date: June 2025 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E              PE 0604759F / Major T&E Investment Management Support In order to align the strategic capability goals set forth in the National Defense Strategy and the mission of the AFTC, funding has been assigned to these five mission area categories: T&E Range Asset Modernization, Hypersonics, Directed Energy, Cyberspace and Avionics Cyber, and Autonomy. 1) T&E Range and Test Asset Modernization refers to those capabilities required to acquire the ability to test long range, high-speed, highly instrumented, high-data rate weapons in a crowded and restricted spectrum, while operating at multiple classification and cybersecurity levels. Also included in this mission area is the ability to collect, analyze and store big data and the ability to do multi-domain testing across the enterprise with realistic threat scenarios at multiple classification level up to Special Access Program (SAP). 2) Hypersonics refers to the ability to test and evaluate flight-representative hypersonic engines, materials, warheads and fuses in all portions of the employment envelope and conduct flight testing both in simulation and open-air ranges with sufficient space, telemetry, photo-optics and Time Space Position Information (TSPI) to appropriately inform decision-makers fielding such systems. 3) Directed Energy/Electronic Combat acquires the ability to characterize irradiance and beam properties on aircraft, small UAVs and ground targets and create realistic environments to simulate adversary air defense capabilities in the year 2030. Enables 5th-6th generation weapon testing/tactics development in a threat-realistic Anti- Access Area Denial (A2AD) environment using a combination of indoor and open-air ranges. 4) Cyberspace and Avionics Cyber is the advancement of cybersecurity/resiliency test capability for network, C5ISR, and airborne weapon platforms and includes development of tools, techniques and hardware-in-the-loop capabilities focused on cybersecurity and cyber-resiliency. 5) Autonomy refers to the ability to test autonomous aerial and ground systems with hundreds of independent vehicles. Must be able to monitor system-under-test locations and states with the ability for soft and hard termination. Must develop techniques and processes to test systems with artificial intelligence. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E          PE 0604759F / Major T&E Investment Management Support$$, 156915000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604759N_2195$$, $$0604759N$$, $$2195$$, $$T & E Investment$$, 61946000, $$This project corrects major deficiencies, improves Test & Evaluation (T&E) capabilities, and increases T&E support effectiveness at Navy Major Range and Test Facility Base ranges and facilities. The T&E Investment project improves, modernizes and adds new test capabilities at the following test facilities: the Naval Undersea Warfare Center Division Newport Atlantic Undersea Test and Evaluation Center (AUTEC), Andros Island, Bahamas; the Nanoose and Dabob ranges of the Naval Undersea Warfare Center Division Keyport, Keyport, WA; the Sea Range, Land Ranges, Target Operations, Ordnance T&E Facility, Test Wing Pacific located at the Naval Air Warfare Center Weapons Division, Point Mugu, CA and China Lake, CA; and the Atlantic Test Range, Air Combat Environment T&E Facility, Electromagnetic Environmental Effects, Air Vehicle Modification and Instrumentation facility, Test Wing Atlantic, Target Operations, and the Propulsion Systems Evaluation Facility located at the Naval Air Warfare Center Aircraft Division, Patuxent River, MD and the test and evaluation capabilities located at the Pacific Missile Range Facility, Kauai, HI.$$, 61946000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604759N_9999$$, $$0604759N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional Add$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604760A_C74$$, $$0604760A$$, $$C74$$, $$Devel Simulation Tech$$, 1021000, $$Project C74 funds the Headquarters, Department of Army (HQDA) chartered mission of the Simulation-to-Mission Command Interoperability (SIMCI) Overarching Integrated Product Team (OIPT) in support of Army Training and Readiness. The SIMCI OIPT mission is to provide policy recommendations to Army senior leadership to improve organizations by allowing Soldiers to train as they fight. This is accomplished by interoperability between Mission Command (MC) systems and the Modeling and Simulation (M&S) systems the Army uses to stimulate MC systems for training Soldiers and their Leaders. SIMCI also invests in targeted solutions to critical problem areas that exist between legacy and developing MC systems and Simulations, such as Next Generation Constructive (NGC) and Next Generation Command and Control (NGC2). The SIMCI OIPT provides the following: (1) Advisor to Army Leadership--improve MC and M&S interoperability programs, policies, directives, resourcing, and procedures; (2) Technical Investment--sponsor/support initiatives that seek common solutions to critical interoperability issues surrounding MC and M&S systems; (3) Outreach--conduct & participate in interoperability outreach activities. SIMCI investments consist primarily of cost-sharing initiatives, leveraging initial system solutions of acquisition programs to enhance the interoperability of multiple systems in the Joint Operational Environment. SIMCI investments accelerate implementation within MC and M&S systems, of common data models and information exchanges that are used by other Services and coalition nations. FY 2026 base funding in the amount of $1.021 million continues progress with embedding simulation into Mission Command Systems, continues management of the SIMCI OIPT's Army-wide collaborative, interoperability enhancement activities, including architecture alignment, data model alignment, common standards, components, and products. It is focused first on reducing costs and improving capabilities in the areas of automating Operational Plans, Orders, and Reports in support of Army, Joint, and Coalition operations. Objectives are: identify and articulate to HQDA senior leadership specific standards that require Army-wide implementation; co-develop data standards, architecture standards, implementation specifications and Joint/Coalition products; continue transition of SIMCI knowledge and proof-of-principle products to Army and Joint acquisition programs.$$, 1021000, NULL, NULL, NULL, NULL, 993000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604760A_C77$$, $$0604760A$$, $$C77$$, $$Army Geospatial Data Master Plan$$, NULL, $$The Army Geospatial Enterprise (AGE) provides the geospatial foundation, consisting of accurate, robust, and timely 2D and 3D geospatial data, robust tools and services, in support of mission command, intelligence, training, mission-rehearsal and other mission-applications. It addresses the implementation and acceleration of Army modernization objectives focused on enhancing situational awareness to the warfighter. This effort provides a geospatial standards-based framework that enables the management, dissemination, and update of 2D and 3D geospatial data and services within the Army Geospatial Enterprise (AGE) across Mission Command, all Cross-Functional Team (CFT), and with our National and UAP partners ensuring a common operational picture enhancing soldier situational awareness and increasing mission success. Provides support to synthetic training environment, network and soldier lethality cross functional teams. Establishes a geospatial enterprise architecture framed around geospatial standards that enable address geospatial data, services, and application interoperability from National to tactical as required by as Department of Defense Instruction (DoDI) 5000.56, AR 525-95 - Army Geospatial-Intelligence and Geospatial Information and Services, Geospatial Annex to COE IP, Net-Enabled Mission Command ICD, OMB-Circular A-119 and A-130, the FY17 NDAA (National Defense Authorization Act), section 875, 10 U.S. Code 2223, Public Law 108-237, Standards Development Organization Advancement Action of 2004 and Public Law 108-113, National Technology Transfer and Advancement Act of 1995 and Public Law 82-436. Key lines of effort include Ground-Warfighter Geospatial Data Model (GGDM), development and maintenance of geospatial Standards, and integration with the Army Modelling and Simulation Enterprise.$$, NULL, NULL, NULL, NULL, NULL, 1096000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604760A_C78$$, $$0604760A$$, $$C78$$, $$One Semi-Automated Forces$$, 6703000, $$One Semi-Automated Forces (OneSAF) develops and delivers a software application that represents activities of units and forces in simulation to support Army Training and Readiness. The application is used by Army agencies to support the concept evaluation, experimentation, materiel acquisition and training. The focus of this project is systems/software engineering and design for development and evolution of the architecture and software tools for a universal system of Army computer-generated forces -- OneSAF. OneSAF is a high fidelity brigade-and-below SAF that represents a full range of operations, systems and control processes in support of stand-alone and embedded training and Research, Development and Acquisition (RDA) simulation applications. OneSAF is fully interoperable with the Army's virtual, live, and division-and-above constructive simulations. FY 2026 base funding in the amount of $6.703 million allows for continued development of the software product line Prioritized Improvements. This funding also provides for the management of the infrastructure, equipment, laboratories, and processes needed to develop, test, and release the required product baseline.$$, 6703000, NULL, NULL, NULL, NULL, 6392000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604774D8Z_774$$, $$0604774D8Z$$, $$774$$, $$Defense Readiness Reporting System$$, 8552000, $$This funding supports the Defense Readiness Reporting System - Strategic (DRRS-S), the comprehensive readiness reporting system for the Department of Defense mandated under Title 10 U.S. Code. The system measures, in an objective, accurate, and timely manner, the capability of the armed forces to carry out the National Security Strategy prescribed by the President, as well as the defense planning guidance provided by the Secretary of Defense, and the National Military Strategy prescribed by the Chairman of the Joint Chiefs of Staff. DRRS-S hosts information and applications used to support the Geographic and Functional Combatant Commanders, the Services, Combat Support Agencies, the Joint Staff and the Office of the Secretary of Defense. DRRS-S is the evolution of readiness reporting to a more comprehensive system, better able to meet the Department’s current and future readiness information challenges. Included in these challenges is the expansion in scope of the entities who can and do report readiness. Shifting from solely resource centric readiness reporting, to a resource informed mission and capabilities-based reporting system, oriented towards the National Military Strategy (NMS), makes substantially more complex demands on readiness reporting, but portrays a far more relevant and holistic picture of readiness. The challenges associated with sourcing and evaluating the readiness of our forces engaged in on-going real operations mean that force managers need applications that will query the entire Department for suitable, available organizations to meet current needs. DRRS-S continues to incorporate more data and develop more capable functionality to meet the evolving needs of both the operational employers of the Force, but also those responsible for Force Generation. The National Defense Authorization Act for FY 2019 made revisions to Title 10 U.S. Code directing the Department of Defense to take actions which required growth in the DRRS-S program. The legislation identified the program’s need to achieve and maintain the technical currency necessary to quickly meet future challenges associated with providing senior leaders with relevant and timely information. Such initiatives include implementing the complex data structures and visualization tools required to operationalize the Department’s Enterprise Force Structure, (formerly referred to as Global Force Management - Data Initiative, GFM DI)) and reporting at lower organizational levels consistent with how the Department’s forces are employed.$$, 8552000, NULL, NULL, NULL, NULL, 83380000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604776F_630004$$, $$0604776F$$, $$630004$$, $$Deployment and$$, 28316000, $$In partnership with Services, Combatant Commands, OSD, select Defense Agencies, industry, and academia, this program collaboratively pursues the development, integration, field demonstration and assessment of contested logistics Joint Deployment and Distribution Enterprise (JDDE) and Joint Petroleum (JPE) capabilities. Contested logistics challenges include innovative projection and sustainment capabilities, seaport and airfield improvements, inventory/cargo management, materiel handling, cargo/container security, secure collaboration with commercial/interagency/coalition partners, and distributed global mobility C4. Intent is to improve the efficiency and effectiveness of logistics operations in support of the joint warfighter. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0604776F / Deployment & Distribution Enterprise R&D Technology Development (ATD)$$, 28316000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604777N_0253$$, $$0604777N$$, $$0253$$, $$Nav & Electro-Optical Supt$$, 0, $$AN/BVY-1 Integrated Submarine Imaging System (ISIS) will continue to add new capabilities via Technical Insertion (TI)/Advanced Processing Build (APB) process while working across Submarine Warfare Federated Tactical System (SWFTS) programs to develop according to Development Security Operations (DevSecOps) software processes and a cloud based architecture. The Navy is pursuing a transformation across SWFTS to maximize cyber-resiliency and the speed of capability delivery. The Navigation and Electro-Optical (E-O) program enables littoral operations by procuring ISIS, production of low profile masts (Low Profile Photonics Mast (LPPM), Type 20, and Type 24), maintenance and sustainment of periscope and legacy photonic masts, production and sustainment of Universal Modular Mast Systems and Dip Loops, and development of the ISIS inboard processing component of Submarine Warfare Federated Tactical Systems (SWFTS). The Department of the Navy established the ISIS to rapidly field the Type 18 periscope, RADAR rangefinder, Type 8 Mod 4 Infra-Red (IR) periscope systems, and integrate existing periscope imagery systems into a single imaging system for installation on board SSN 688 class and SEAWOLF class submarines. The ISIS baseline also includes the Imaging System with the Photonics mast (PM) and all configurations of low profile masts onboard VIRGINIA and Photonics Mast Variant (PMV) onboard SSGN class submarines and ISIS on SSBN class submarines. The PM, LPPM, and PMV design exploit a wide portion of the electro-magnetic spectrum through advanced E-O and thermal imaging and Electronic Warfare Support (ES)/communications intercept. The Common Submarine Imaging System (CSIS) capability development document (CDD), that covers both ISIS and Legacy Imaging systems was approved 22 Dec 2011 with an updated CDD approved on 15 Mar 2018. The CDD Annex for Low Profile Digital Photonics Mast, approved on 02 Dec 2019, provides additional specifications for the development of low profile masts within the ISIS system.$$, 0, NULL, NULL, NULL, NULL, 182969000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604777N_0676$$, $$0604777N$$, $$0676$$, $$Improve ID Development$$, 1957000, $$Reliable and secure navigation and positive identification (ID) systems are essential elements of battle management in the naval environment. In addition to providing platform identification for weapons employment, the Navy requires secure, jam resistant Identification Friend or Foe (IFF) systems for battle group air defense management and Air Traffic Control. The Improved ID Development project addresses the Mark XIIA Mode 5 and Mode Select (S) upgrades to the existing AN/ UPX-29(V) Mark XII family of systems that is Joint and North Atlantic Treaty Organization interoperable, as well as modernization of the DDG 1000 Zumwalt Class IFF Sensor Suite. The AN/UPX-29(V) Interrogator System is comprised of the Interrogator Set AN/UPX-24(V), OE-120()/UPX Antenna Group, and Mark XII or Mark XIIA equipment including but not limited to AN/UPX-41(C), AN/UPX-45(C), or AN/UPX-50(C) Digital Interrogators (DI) and associated equipment. The DDG 1000 IFF Sensor Suite is comprised of three electronically scanned array (ESA) antennas, one UPX-42(C) Interrogator, and three RT-1912(C)/APX Transponders. Additionally, the Improved ID Development project may include product improvements designed to be installed through upgrade and deficiency correction studies, which in turn become engineering changes to other IFF solutions.$$, 1957000, NULL, NULL, NULL, NULL, 76791000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604777N_1253$$, $$0604777N$$, $$1253$$, $$Combat Ident System$$, 1767000, $$MARK (MK) XIIA Mode 5 provides secure cooperative combat identification via Identification Friend or Foe (IFF). Mode 5 was developed in cooperation with North Atlantic Treaty Organization, with the DoD implementation governed by AIMS 03-1000A, AIMS 03-1000B and USN requirements defined in ORD # 577-06-01. IFF product improvements are designed to be installed through obsolescence mitigations, upgrades, technical refreshes, and deficiency correction studies, which in turn become engineering changes to IFF interrogators and transponders and their associated cryptographic material. Standards governed by AIMS 17-1000 and Crypto Modernization (CM) are required to be incorporated in future engineering changes. The Navy MK XIIA Mode 5 program was approved for entry in Systems Development and Demonstration phase in August 2003 and into the Production and Deployment Phase and Low Rate Initial Production in July 2006, and Full Rate Production July 2012. The Navy Mode 5 program achieved Initial Operational Capability (IOC) in 2012 in accordance with the ORD. Mode 5 capable equipment was fielded in USN/USMC platforms in accordance with Joint Requirements Oversight Council Memorandums (047-07, 122-08 and 108-13) in support of Joint Mode 5 IOC in 2014 and Joint Full Operational Capability in FY2020. In order to maintain cooperative encrypted Combat Identification (CID) capabilities across the fleet, sustainment and new development efforts must continue into the foreseeable future. Studies for future leading-edge non- cooperative CID technologies are being investigated. RDTE articles include Mode 5 cryptographic modules and associated hardware and software changes for IFF interrogators and transponders, including, but not limited to: AN/APX-118/123, AN/APX-119, AN/APX-111, RT-2087/ZPX, and all associated test and support equipment. RDTE units are required for government and contractor labs to support aircraft and ship integrations, test sites, test aircraft, and unmanned aircraft systems.$$, 1767000, NULL, NULL, NULL, NULL, 195551000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604777N_9999$$, $$0604777N$$, $$9999$$, $$Congressional Adds$$, 0, $$MARK (MK) XIIA Mode 5 provides improved secure cooperative combat identification via Identification Friend or Foe (IFF). Mode 5 is developed in cooperation with the North Atlantic Treaty Organization, with the DoD implementation governed by AIMS 03-1000A, AIMS 03-1000B and USN requirements defined in ORD # 577-06-01. Research, development, and acquisition is to support a micro IFF transponder/interrogator with Mode 5 which meets the space, weight, and power (SWaP) requirements for Group 2 and 3 Unmanned Aerial Vehicles (UAVs) and other unmanned systems. The development of a Mode 5 Micro-IFF capability for deconfliction and equipping air assets, including UASs and other small aircraft (such as weight critical helicopters), delivers an Assured Position Navigation Time (APNT) reporting system that enables continuity of battlespace situational awareness and operational safety and effectiveness, while also reducing potential for fratricide is critical to mission of the USN.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604786N_3337$$, $$0604786N$$, $$3337$$, $$Offensive Anti-Surface Warfare$$, 8590000, $$Offensive Anti-Surface Warfare (OASuW) is an offensive weapon system that can be air, surface, and subsurface launched in the maritime battle space environment. OASuW is a vital component of the Joint Force Anti-Surface Warfare capability and incorporate new and emergent technologies to support an increased offensive future strike capability. Due to emerging threats, the fleet issued an Urgent Operational Needs Statement (UONS) that identified a capability gap for a long-range anti-ship missile to be filled by 2018. Directly supporting this UONS and significantly reducing Joint Force warfighting risks, the U.S. Navy initiated OASuW Increment 1 (OASuW-1), which leverages the Defense Advanced Research Projects Agency (DARPA)/Office of Naval Research Long Range Anti-Ship Missile (LRASM) demonstration program to deliver an Early Operational Capability (EOC) in the required timeframe. LRASM fills the most urgent air-launched capability gap to complement existing ASuW weapon systems and positions the Department of Defense to address evolving surface warfare threats. LRASM is integral to realizing the National Defense Strategy of combat-credible military forces to deter war, protect the security of our nation and to enable the Joint Force to win should deterrence fail. The development and acquisition of LRASM has been structured to be fielded at a pace relevant to maintain overmatch against long-term strategic competition. Specifically, LRASM directly contributes to building a more lethal force and is a critical enabler for joint lethality in contested environments; deterring adversaries from aggression; ensuring common domains remain open and maintaining favorable regional balances of power. OASuW-1 includes efforts to develop, integrate and test navigation software improvements and to develop mission validation tools to facilitate Network Enabled Weapon (NEW) employment.$$, 8590000, NULL, NULL, NULL, NULL, 1512785000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604786N_3343$$, $$0604786N$$, $$3343$$, $$Offensive Anti-Surface Warfare$$, 59587000, $$The Department of the Navy is developing Offensive Anti-Surface Warfare Weapon Increment 2 (OASuW Inc 2), (PU 3343) to address weapon system requirements based on the OASuW Analysis of Alternatives (AoA). OASuW Inc 2 will be a carrier-suitable, higher-speed, longer-range, air-launched weapon system providing superior Anti-Surface Warfare capabilities. The program is part of the Navy's Long Range Fires investment approach to meet objectives of the National Defense Strategy. As a key component of this strategy, OASuW Inc 2 will address advanced threats from engagement distances that allow the Navy to operate in, and control, contested battle space in littoral waters and Anti-Access/Area Denial (A2/AD) environments. The program will leverage and further advance foundational achievements in the joint Science and Technology (S&T) enterprise, making targeted investments in Navy integration of critical system attributes. User priorities, in the form of pacing the evolving maritime threat, will be the centerpiece of the system requirements and the associated development and fielding schedule. Additional details are Classified.$$, 59587000, NULL, NULL, NULL, NULL, 147061000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604786N_3466$$, $$0604786N$$, $$3466$$, $$LRASM C-3$$, 157596000, $$The LRASM C-3 (PU 3466) is established to enhance the Navy's OASuW and incorporate a future long range strike capability into the Navy's arsenal derived from the Navy's AGM-158C-1 LRASM and the Air Force's AGM-158 JASSM-ER. The Navy will integrate an AGM-158 derived weapon with extended range, enhanced radio and survivability onto F/A-18 aircraft and partner with USAF to further the capabilities of the AGM-158 product line. This funding line resources requirements for future Navy strike mission integration and employment by upgrading the existing AGM-158C product to respond to rapidly changing threats.$$, 157596000, NULL, NULL, NULL, NULL, 115714000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604790D8Z_790$$, $$0604790D8Z$$, $$790$$, $$Rapid Defense Experimentation$$, 0, $$The RDER program focuses on a campaign of joint experimentation on rapid capabilities that address our most complex military challenges. The Secretary of Defense established RDER in the Defense Planning Guidance to enable multi-component joint experimentation through a campaign of learning and to establish a body of evidence to support rapid adoption by the Services. RDER enables the Services, agencies, industry, and other organizations to identify “best of breed” capabilities to be prototyped in large-scale joint experiments and validate and/or refine the Joint Warfighting Concept (JWC). OUSD(R&E)’s process for incubating promising prototypes starts with a novel experimental design based on a web of interconnected systems addressing specific Defense Planning Scenarios. This approach is unique from other experimentation that focuses on determining individual system efficacy. Additionally, the experimental design is unique in using the web of systems to explore new warfighting concepts that capitalize on contributions of multiple Services as a true joint force. The experimentation yields live data that the OUSD(R&E) analyzes against the performance predicted in modelling and simulation. OUSD(R&E) manages the Department’s multiple RDER experimentation events and conducts integration activities with the Joint Force. OUSD(R&E) oversees an integrated selection process with the Joint Staff, Services, and Combatant Commands that incorporates the most promising innovative prototypes into existing exercise venues such as: Project Capstone, Northern Edge, Valiant Shield, Talisman Sabre, Grey Flag, Joint Battle Problem, and TREX. RDER utilizes funding to plan, integrate, and oversee joint experiments; provide assessments on project viability; and, deliver the results to the Deputy Secretary of Defense management action group to facilitate decisions on transitioning promising capabilities with the Services.$$, 0, NULL, NULL, NULL, NULL, 24033000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604791D8Z_122$$, $$0604791D8Z$$, $$122$$, $$Multi-Domain Joint Operations$$, 20343000, $$MDJO facilitates identification and transition of priority joint capabilities to the Military Services and Agencies. MDJO completes this through persistent, proactive stakeholder engagement with continuous transition risk assessment, development of technology transition plans, and coordination across the Department of Defense. Project identification activities inform the specific focus areas for the ASD(MC) Mission Engineering and Prototyping & Experimentation activities. Concurrently, project transition activities accelerate the fielding of successfully demonstrated joint capabilities. MDJO’s core mission is to align Joint Force efforts to the interim National Defense Strategy priorities. Additionally, MDJO conducts and chairs TMTRs to review the health of research and development portfolios to identify promising technologies to address warfighter gaps and support investment decisions.$$, 20343000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_3205$$, $$0605502N$$, $$3205$$, $$SBIR CRP - ONR$$, 0, $$Originally established in Section 252 of the 2006 NDAA Public Law No. 109-163, the Commercialization Readiness Program (CRP) may not use more than up to 1% of the SBIR to be used for payment of expenses incurred to administer CRP. 15 USC 638(y) authorizes the DoD to administer a Commercialization Readiness Program to accelerate the transition of SBIR/STTR-developed technologies, products, and services to Phase III, including the acquisition process.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_BQ3$$, $$0604802A$$, $$BQ3$$, $$155mm Artillery Propulsion XM654$$, NULL, $$155MM Artillery Propulsion Supercharge funding will support the Army's Cannon Transformation Strategy, which includes Paladin Integrated Management (PIM) Armament Upgrade and Next Generation Cannon, and all utilized cannons that are 52-calibers or longer. Supercharge is a stand-alone top-zone 155 millimeter (mm) propelling charge required to achieve maximum range requirements beyond 50 kilometers (km) from Self-Propelled Howitzer (SPH) equipped with cannon length greater than 52-calibers. Supercharge will achieve lethality overmatch out to 70km from future US-developed and produced Long Range Precision Fires Weapon Systems using both existing and developmental extended range projectiles and will potentially increase range with compatible legacy projectiles up to thirty percent. Supercharge is composed of an earlier bag variant and later combustible cartridge case, integral metal stub case, electrically initiated primer, and advanced artillery propellant. This Project supports the Urgent Materiel Release (UMR) Supercharge (bag configuration) qualification required for fielding an initial capability of two battalions, and also supports the development of the Full Materiel Release (FMR) Supercharge that will address high technology and integration risks unique to achieving extended range to include improved design opportunities for pressure temperature curve, cannon tube wear and ensure fielding robustness. This project does not have an FY 2026 budget request.$$, NULL, NULL, NULL, NULL, NULL, 15895000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_BY1$$, $$0604802A$$, $$BY1$$, $$Next Generation Combat Vehicle$$, 3305000, $$50x228 millimeter (mm) family of ammunition is a critical technology development in response to the Next Generation Combat Vehicle (NGCV) Abbreviated Capability Development Document for weapon qualification, platform integration, and fielding of the XM30 Mechanized Infantry Combat Vehicle (MICV) primary weapon system (XM913). This effort includes the development of three capabilities: The XM1202 Target Practice with Tracer (TP-T); the XM1203 Armor Piercing Fin Stabilized Discarding Sabot with Tracer (APFSDS-T); and the XM1204 High Explosive Airburst with Trace (HEAB-T). The training cartridge will allow the Warfighter to train in a cost-effective manner and the tactical cartridges will provide enhanced lethality at increased ranges when engaging personnel threats in the open, defilade, and under the cover of urban structures, Anti-Tank Guided Missiles (ATGM) teams, and current and projected future peer armored materiel threats. This effort is operating under Middle Tier Acquisition authority for rapid prototyping to qualify the three munitions in order to support the NGCV Cross Functional Team (CFT) timeline for First Unit Equipped (FUE). Fiscal Year (FY) 2026 funding supports Developmental Test and Evaluation (DT&E) and Milestone C documentation. The total cost of the Next Generation Combat Vehicle Ammunition (NGCV) Middle Tier of Acquisition effort is $122.610 million RDT&E from FY2021 to FY2025. The program is fully funded across the Future Years Defense Program (FYDP).$$, 3305000, NULL, NULL, NULL, NULL, 35786000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_CE3$$, $$0604802A$$, $$CE3$$, $$Precision Munition (Sniper)$$, 4527000, $$The Precision Munition (Sniper) project is a critical technology development in response to the Precision Munition Capabilities Development Documents (CDD) for the ammunition required to support the Precision Sniper Rifle (PSR) / sniper weapons systems. The objective is to transfer the latest lethality technology into the suite of ammunition used by snipers. The Precision Munition improvement is split into three capability areas: Anti-Materiel (AM), Improved Performance Round (IPR), and Subsonic. The AM and IPR capabilities will enhance lethal effects at greater distances. The Subsonic capability will increase soldier survivability at close range by providing a low-sound signature munition that is undetectable to the enemy. FY 2026 will continue Engineering and Manufacturing Development activities to include a user assessment, Production Qualification Test build and the commencement of Production Qualification Testing (PQT). In FY 2024, Project CE3 / Precision Munition (Sniper) was a Skip-Year.$$, 4527000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_DC9$$, $$0604802A$$, $$DC9$$, $$30mm MMPA M-SHORAD INC 3$$, 17797000, $$30mm Multi-Mode Proximity Airburst (MMPA) Maneuver Short Range Air Defense Increment 3 (M-SHORAD INC 3): The 30mm MMPA M-SHORAD INC 3 / Project DC9 funds the development of the 30mm XM1223 MMPA munition and respective weapon contact setter under the Middle Tier of Acquisition (MTA) authority for rapid prototyping. The objective is to enhance the operational effectiveness of the M-SHORAD Inc 3 platform, Mobile-Low, Slow, Small Unmanned Aircraft Integrated Defeat System (M-LIDS) and any other Joint Force platforms that are equipped with a 30mm weapon system and have a Counter Unmanned Aerial Systems (C-UAS) mission. The programmable fuze modes in the munition include proximity airburst to defeat personnel in the open and small Unmanned Aerial System (UAS) targets, proximity airburst delay to defeat personnel in defilade, gated proximity airburst to minimize collateral damage in cluttered environments, mechanical point detonate to defeat light materiel targets, and self-destruct to minimize collateral damage. The XM1223 will allow the platforms to conduct counter-UAS missions while retaining the ability to quickly transition to ground targets without having to swap ammunition. FY 2026 funds support conducting a Critical Design Review (CDR) and initiating the ammunition build for Developmental Test and Evaluation (DT&E). The FY 2026 cost of the XM1223 30mm Multi-Mode Proximity Airburst (MMPA) Middle Tier of Acquisition effort is $17.9 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission.$$, 17797000, NULL, NULL, NULL, NULL, 20245000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_DK8$$, $$0604802A$$, $$DK8$$, $$155mm Artillery Propulsion Mod - Sys$$, 11687000, $$155mm Artillery Propulsion Modernization (System Demonstration) supports the US Army's Cannon Transformation Strategy and system demonstration as well as modernization of propulsion systems for multiple platforms. The propulsion systems under development and modernization include propelling charge, modular charge, propellant, ignition system, and packaging solutions. The propulsion solutions will be integrated into a system of systems capability to ensure interoperability closing fires capability gaps to destroy or neutralize artillery target out to 70 kilometers. The propulsion system program(s) combined with cannon/projectile/fuze enhancements will enable the next generation of propelling charge and ignition systems to extend firing range, improve rate-of-fire and resupply, improve ammunition suitability, enhance lethality of current and future conventional munitions, and enable artillery units to be safe, effective, suitable, and survivable. Novel propulsion technologies will be developed, matured, integrated, and tested into the components of the propelling charges and ignition systems to advance and innovate artillery firing performance and enhance manufacturability of the industrial base. Fiscal Year (FY) 2026 funding will support system demonstration to integrate, verify maturity and iterate enhancement of propelling charge and ignition systems for improvement of the propellant effectiveness, cannon life, primer and charge ignition performance, system-level handling and rates-of-fire, and overall propulsion suitability and survivability.$$, 11687000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_EC4$$, $$0604802A$$, $$EC4$$, $$Non-Standard Simulator Munitions$$, 412000, $$Project EC4 Non-Standard Simulator Munitions will standardize various pyrotechnics that simulate battlefield effects, develop, demonstrate, and qualify various screening effects in grenades, vehicle launched effects, unmanned aerial vehicles, smoke pots, signals, counter sensors, and countermeasures. The Army's Combat Training Centers (CTCs) are currently using non-standard munitions to replicate both conventional and asymmetric warfare battlefield effects. These modified commercial-off-the-shelf products have not been type-classified or material released and are not safe or sustainable for use by Soldiers. This effort will develop and demonstrate various pyrotechnic simulators, replicating both conventional and asymmetric warfare effects and munitions such as: - Black smoke signature (burning vehicles, buildings, and equipment); - Yellow smoke signature (chemical, biological or nuclear effects); - Mini Blast to simulate hostile fire and small Improvised Explosive Devices (IEDs) during mounted operations in urban terrain; - Micro pyrotechnics to simulate indoor hostile fire and IED effects that are capable of being integrated into existing facilities; - Rocket Propelled Grenade (RPG) simulators to replicate the flight of a Rocket Propelled Grenade; - Macro Pyro to simulate hostile fire, booby trap, and IED simulations both indoor and outdoors; - High Order Blast Effect (HiOBE) used to replicate a Vehicle Borne Improvised Explosive Device (VBIED), building explosions, and other significant explosive events; - Artillery airburst simulator to replicate indirect fire; - Antitank Guided Missile and Rocket (AGMR) simulator to replicate surface to air missile or shoulder launched rocket; - Tracer Fire-back simulator to replicate enemy small arms fire and anti-aircraft fire; - Electrically initiated smoke pots and smoke grenades of various colors; - Multi-spectral and screening effects of grenades, vehicle launched effects, smoke pots, chaff, signals for unmanned systems, unmanned aerial vehicles, ground vehicles, and decoys. - Counter sensor effects Standardization will reduce training costs, eliminate redundancies between systems, mitigate environmental concerns and safety risks associated with realistic scenario- based training and improve screening effects.$$, 412000, NULL, NULL, NULL, NULL, 2108000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_EL9$$, $$0604802A$$, $$EL9$$, $$Ammunitions Logistics Prototyping$$, 1073000, $$This Project supports the future force by maturing and integrating prototypes and Commercial Off-The-Shelf (COTS) technologies fully endorsed by the Warfighter and associated Combat developers following a system of systems approach. The selected capabilities for continued investment have been proven successful through Warfighter exercises and Soldier touch points to materially improve elements of tactical ammunition transportation, distribution, inventory management, availability, and survivability as logistics system enablers within the formation. These enablers will improve the efficiency and effectiveness of ammunition operations, to include retrograde, while reducing the logistics footprint on the battlefield. This project enhances the operational effectiveness of the ammunition logistics system to ensure the distribution of reliable ammunition to the Warfighter. Funding will be focused on integrating mature technologies into ammunition resupply enablers and developing interfaces with applicable Program of Records (PoR) as recommended by the Contested Logistics, Long Range Precision Fires, Next Generation Combat Vehicles, and Soldier Lethality Cross Functional Teams (CFTs).$$, 1073000, NULL, NULL, NULL, NULL, 1013000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_EP2$$, $$0604802A$$, $$EP2$$, $$Shoulder-Launched Munitions$$, NULL, $$The XM919 Individual Assault Munitions (IAM) effort will combine the capabilities of the existing M141 Bunker Defeat Munition (BDM) and the M136 Anti-Tank 4 Confined Space - Reduced Sensitivity (AT4CS RS), eliminating the mission risk associated with having to choose between two different capability Shoulder-Launched Munitions (SLMs), reducing the logistics and training burdens associated with multiple systems. IAM consists of the tactical XM919 IAM munition and training devices including the XM922 sub-caliber trainer (SCT), sub-caliber tracer ammunition (SCT Ammo), Field Handling Trainer (FHT), Synthetic Training Environment Live Training System (STE LTS) and Soldier Virtual Trainers (SVT). JPEO A&A is collaborating with PEO STRI to plan for STE LTS and SVT integration within PEO STRI platforms under the SS PEG. The tactical XM919 IAM supports the close fight in urban and complex terrain, allowing Soldiers a fire-from-enclosure (FFE) capability to defeat field expedient structures such as earth and timber bunkers, reinforced concrete, adobe and triple brick walls with behind the wall lethality effects as well as defeating light armored vehicles. The IAM training devices provide an affordable training capability to increase the Soldier's proficiency and integration of the XM919 tactical system into combat operations. The XM919 IAM supports the Army's Soldier Lethality Modernization Line of Effort (LOE) by providing multi-target capability and reducing training & logistics burden associated with two systems, while providing tactical innovation capable of extending overmatch against peer/near-peer adversaries in a joint, multi-domain, high-intensity conflict.$$, NULL, NULL, NULL, NULL, NULL, 2458000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_EP4$$, $$0604802A$$, $$EP4$$, $$One-Way Luminescence for Small$$, NULL, $$The One Way Luminescence (OWL) project is a critical technology development in response to the 7.62 millimeter (mm) and 5.56mm Families of Ammunition Capabilities Development Documents (CDD). Current small caliber ammunition tracer rounds are a pyrotechnic tracer mix which provides a visible light signature through its trajectory with a limited view during its early trajectory. The visible signature provides visibility of fire out to 900 meters and a limited view visible signature to the shooter only for 300m. The OWL projects objective is to develop and field a full tracer round, replace the current pyrotechnic cartridges with trace cartridges that are only visible to the shooter and soldiers in close proximity, increasing soldier survivability, and increasing lethality by incorporating Enhanced Performance Round (EPR) technology into the new tracer ammunition. 7.62mm and 5.56mm are the immediate focus; later followed by 6.8mm Family of Ammunition. There is no FY 2026 request as program transitions from development to production.$$, NULL, NULL, NULL, NULL, NULL, 2980000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_EP7$$, $$0604802A$$, $$EP7$$, $$Aviation Airborne Expendable$$, 5720000, $$Aviation Airborne Expendable Countermeasures (AAECM) will support Integrated System Design (ISD), System Capability (SC) and Manufacturing Process Demonstrations (MPD) on expendable countermeasure flares and decoys to include the XM215 Infrared (IR) countermeasure Flare and XM20 Radio Frequency (RF) expendables. These expendable countermeasures systems are an essential part of survivability equipment for Army aircraft. Army Research Development Technology & Evaluation (RDT&E) efforts are coordinated with Program Executive Office (PEO) Aviation to address the AAECM capability, a critical enabler for enduring aircraft and the Future Vertical Lift (FVL) - Aircraft Survivability Equipment (ASE) Cross Functional Team (CFT) within Army's Top modernization priorities. These advanced decoys will address deficiencies in Army aircraft protection and the safety of its aircrews against advanced Man-Portable Air Defense Systems (MANPADS) and Surface-to-Air Missiles (SAM) systems. The project will also support ISD, SC and MPD on new expendable countermeasure munitions that will protect Army aircraft from advanced and proliferated current guided missile threats. Activities include modeling and simulation, flight testing, qualification testing, environmental considerations, safety enhancements, manufacturing enhancements, qualification of other service and foreign munitions that could meet current requirements, product improvements, insertion of new technologies to increase performance, and enhancement of current flare solutions for new and existing aircraft. Systems include impulse cartridges and aircraft expendables (to include RF expendables).$$, 5720000, NULL, NULL, NULL, NULL, 3077000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_EW1$$, $$0604802A$$, $$EW1$$, $$40mm Low Velocity Ammunition$$, NULL, $$The 40 millimeter (mm) Low Velocity High Explosive Air Burst (HEAB) is a new capability identified as a Warfighter counter-defilade requirement in the Capability Development Document (CDD), 40mm Low Velocity (LV) Family of Ammunition Annex. The HEAB tactical cartridge allows the Warfighter to engage targets at increased effective ranges using the 40mm M320 Grenade Launcher. The HEAB cartridge provides the grenadier with a higher probability of achieving a first shot kill against enemy personnel, coupled with the ability to defeat personnel targets in defilade positions. When deployed against point and area targets, the cartridge inflicts incapacitating effects against personnel beyond those offered by the current M433 High Explosive Dual Purpose (HEDP) cartridge. The cartridge provides lethal effects against targets with improved accuracy and greater standoff ranges resulting in increased soldier survivability. In FY 2026 there is no funding request.$$, NULL, NULL, NULL, NULL, NULL, 79000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_FA6$$, $$0604802A$$, $$FA6$$, $$30mm Lethality$$, 9863000, $$The 30 millimeter (mm) Lethality project funds the development of the family of 30mm cartridges, to provide anti-personnel effects, counter defilade, anti-materiel and counter unmanned aerial systems (C-UAS). This ammunition will increase the effectiveness and lethality for all platforms equipped with a medium caliber 30mm weapon system to include the Stryker Infantry Carrier Vehicle (ICV) and proposed Next Generation Combat Vehicle (NGCV) variants. The tactical Armor Piercing cartridge will provide an organic direct fire capability to support infantry at a greater range and will improve lethality when engaging light-to-medium armored vehicles. The airburst cartridge will provide the Warfighter with increased lethality against troops in the open, counter defilade, Anti-Tank Guided Missile (ATGM) teams, troops behind urban structures and counter unmanned aerial systems . The training cartridges will be ballistically matched to the tactical cartridges, allowing the Warfighter to train in a cost- effective manner, and on CONUS and OCONUS training ranges. In FY 2026, this project FA6 / 30mm Lethality will support Developmental Test and Evaluation (DT&E), Live Fire Test and Evaluation (LFT&E), and Milestone C preparation for the Armor Piercing (AP) cartridge and obtain test hardware, conduct Live Fire Test and Evaluation (LFT&E), and Lethality Assessment Capstone Event (LACE) for the High Explosive Airburst (HEAB) cartridge.$$, 9863000, NULL, NULL, NULL, NULL, 2904000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_FJ4$$, $$0604802A$$, $$FJ4$$, $$Cannon-Delivered Area Effects$$, NULL, $$The Cannon-Delivered Area Effects Munitions (C-DAEM) Project will provide United States (U.S.) ground forces with the capability to engage area personnel through armored targets, while denying threat forces full operational freedom within the targeted area. An Analysis of Alternatives (AoA) was completed in January 2018 to inform Army acquisition and investment decisions regarding replacement of the current stockpile of 155 millimeter (mm) Dual Purpose Improved Conventional Munitions (DPICM) with Department of Defense (DoD) policy compliant munitions and address anti-armor and extended range capability requirements. The Army validated two materiel solutions for C-DAEM to be pursued in parallel to support the Army's modernization priorities: C-DAEM Armor and C-DAEM DPICM Replacement. C-DAEM Armor will destroy moved and moving self-propelled howitzers, infantry fighting vehicles and tanks. C-DAEM DPICM Replacement will destroy personnel through soft- skinned targets. This Project does not have a Fiscal Year (FY 2026) Budget Request.$$, NULL, NULL, NULL, NULL, NULL, 81966000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_FL4$$, $$0604802A$$, $$FL4$$, $$Small Caliber Ammo for Next Gen$$, 23081000, $$The Small Caliber Ammo for Next Gen Squad Weapons project is a critical technology development in response to the Soldier Lethality Cross Functional Team (SL CFT) Initial Capability Document (ICD) for the ammunition required to support the rapid prototyping, development, and fielding of the Next Generation Squad Weapons (NGSW) under the Middle Tier of Acquisition (MTA) authority for rapid prototyping/rapid fielding. The objective is to develop and Full Materiel Release (FMR) the new 6.8mm ammunition in parallel with the NGSW rifle and automatic rifle. The 6.8mm ammunition is split into multiple ammunition variants, the General Purpose (GP), the Special Purpose (SP), the Reduced Range Ammunition (RRA), Tracer Ammunition, Blank Ammunition, the Close Combat Mission Capability Kit (CCMCK) training ammunition, Drill Dummy Inert (DDI) cartridge, and High-Pressure Test (HPT) cartridge. FY 2026 funding will support SP Live Fire Test and Evaluation (LFT&E), RRA production qualification build and testing, CCMCK prototype build and developmental tests, optimization efforts, and activities in preparation for transition from Middle Tier of Acquisition (MTA) to Major Capability Acquisition (MCA). The total cost of the Small Caliber Ammo for Next Gen Squad Weapons Middle Tier of Acquisition effort is $156.7M million RDTE from FY 2020 to FY 2028.$$, 23081000, NULL, NULL, NULL, NULL, 26659000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_MS1$$, $$0604802A$$, $$MS1$$, $$Battalion Mortar System$$, 28297000, $$The Battalion Mortar System Modernization Project supports the development of modernized Mortar Weapon Systems to support Infantry Brigade Combat Teams (IBCTs) and Armored Brigade Combat Teams (ABCTs). Efforts include development and qualification of modernized mortar systems and their required components to include fire control and ammunition that will increase lethality, survivability, mobility and readiness. The weapon and fire control will be used as a standalone man- portable system with digital fire control capability or as a modular system that can be hoisted onto light tactical vehicles such as the High Mobility Multipurpose Wheeled Vehicle (HMMWV), the Infantry Squad Vehicle (ISV) and/or Joint Lightweight Tactical Vehicle (JLTV) when a mobility kit is utilized. This modernized system will increase survivability, maneuverability, and provide tactical advantage to the Warfighter when matched with pacing threat for direct and indirect fire and will provide overmatching capabilities. Initial characterization efforts will establish a firm foundation for proposed advanced indirect fire systems while allowing for incremental improvements and updates as technologies continue to mature, which will maintain and enhance performance, improve lethality, responsiveness, and reliability of indirect fire systems across the required spectrum of military operations. Fiscal Year (FY) 2026 funding will support the design and development of a next generation 81mm mortar weapon and fire control system that can be hosted on a light tactical vehicle when integrated with a mobility system.$$, 28297000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_S36$$, $$0604802A$$, $$S36$$, $$Precision Guidance Kit$$, 13005000, $$The Precision Guidance Kit (PGK) Project supports development efforts that will qualify state of the art technologies for a course correcting fuze that provides precision accuracy at extended ranges for current and future 155-millimeter (mm) High Explosive (HE) projectiles by eliminating a portion of the inherent errors associated with ballistic firing solutions, which effectively reduces the number of projectiles required to execute fire missions. The precision course correcting fuze will support projectile operation in Global Positioning System (GPS) degraded environments in support of the Army's Cannon Transformation Strategy. All 39-caliber weapon systems and modernized Self-Propelled and Towed Howitzer weapon systems with cannon lengths greater than or equal to 52-caliber and new long-range projectiles require the precision course correcting fuze to meet lethality requirements. FY 2026 funding will continue to support the fabrication of LR-PGK hardware, safety and development testing.$$, 13005000, NULL, NULL, NULL, NULL, 47339000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604802A_XT6$$, $$0604802A$$, $$XT6$$, $$Medium Caliber Anti-Personnel and$$, 15275000, $$The Anti-Personnel and Counter Unmanned Aerial Systems (UAS) munitions provide increased lethality through proximity airburst effects against personnel, small Unmanned Aerial Systems (UAS), and small boats without requiring modification to the platform. Airburst capability is identified as a threshold Key System Attribute (KSA) in Apache Block 3 Capability Production Document (CPD) - Approved 14 June 2017, and counter-UAS capability is identified in other cannon caliber Operational Need Statements (ONSs) and Capability Development Documents (CDDs). Fiscal Year (FY) 2026 funds support procuring long lead materials for munition development, conduct preliminary design review, and live fire design engineering test of 30x113mm Aviation Proximity Explosive (APEX) munition in support of Full Materiel Release and technology maturation, munition development, prototype builds, conduct engineering tests for 25mm Bradley Aerial Defeat Ground Enhanced Round (BADGER) munition in support of Urgent Materiel Release, and achievement of Milestone B (MS-B).$$, 15275000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604804A_194$$, $$0604804A$$, $$194$$, $$Engine Driven Gen Ed$$, 6154000, $$This funding line is a key enabler for multiple Army Modernization Priorities by providing adaptable and efficient electrical power sources for network modernization, soldier lethality, long range precision fires, and air & missile defense. The main efforts are integrating standardized power solutions supporting specific programs and modernizations within the CPI2 command post, Soldier power battery charging, and precision fires and air & missile defense systems. This project supports the Tactical Electric Power (TEP) programs (2kW-900kW Generators and Associated Equip) which is established to develop a modernized, standard family of Mobile Electric Power (MEP) systems to include MEP Generating Sources (MEPGS), MEP Distribution Systems (MEPDS), MEP Storage Systems (MEPSS) and MEP Management Systems (MEPMS) for all Services throughout the Department of Defense IAW DoDI 4120.11. Building on the device/component evaluations conducted in PE 0603804A project G11, this project supports the system development and demonstration of a series of innovative mobile electric power systems that are essential to the development and eventual fielding of modernized MEPGS, MEPMS, MEPSS and MEPDS. This project also supports Army modernization priorities, specifically Combat Support/Combat Service Support (CS/CSS) demands in Network / Command, Control, Communications & Intelligence (C3I), Soldier Lethality, Air & Missile Defense and Long Range Precision Fires, field hospital power, and reduces sustainment requirements. Power Distribution Illumination Systems Electrical (PDISE) provides reliable, modular designed power distribution equipment that is critical to deploying power networks. PDISE Expansion will add power distribution greater than 60kW and a universal controller that can connect multiple power sources. The Prime Power Distribution Systems (PPDS) effort will fulfill prime power (medium voltage, 4160 Volts Alternating Current (VAC)) distribution shortfalls to support 249th Engineer Battalion (Prime Power) and Force Provider Expeditionary (FPE) requirements. PPDS will provide modernized power distribution capabilities for the U.S. Army Deployable Power Generation and Distribution System (DPGDS), the FPE Prime Power Connection Kit (PPCK), and the U.S. Air Force Basic Expeditionary Airfield Resources (BEAR) power systems. The PPDS will incorporate advanced capabilities and include three primary components: an improved Primary Switching Center (iPSC), secondly, an improved Secondary Distribution Center (iSDC), and last, a Tactical Prime Power Transformer (TPPT). The Universal Power Gateway (comprised of a Universal Power Electronic Secondary Controller and advanced energy storage) will enable a seamless alternating current/direct current (AC/DC) power grid to connect multiple sources (generator, energy storage, vehicle power, renewable), giving the warfighter maximum operational flexibility, greater operational reliability, and reduced logistics footprint. STEP is a modernization program for existing legacy small power generation systems, that will provide expeditionary, durable and reliable tactical electric power capabilities less than 5kW, to support operations in the austere environments of today's battlefield. The STEP program is a critical enabler to the Army modernization priorities under Army Futures Command Soldier Lethality Cross Functional Team (CFT) and Network CFT. It will provide battery charging power sources for Soldier borne sensors, lasers and optics. The Hybrid AMMPS Power Source (HAPS), renamed from Integrated Fire Control Network (IFCN) in FY 2024, activities include the development and integration a 10kW bi-directional power converter to include the integration of 6T format Lithium Ion (Li-Ion) batteries on a IFCN platform system.$$, 6154000, NULL, NULL, NULL, NULL, 12338000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604804A_EJ9$$, $$0604804A$$, $$EJ9$$, $$Maneuver Support Vessel (MSV)$$, 6722000, $$This project line supports the family of Maneuver Support Vessels (MSV) which enable Dynamic Force Repositioning (DFR) by providing the Combatant, Multi-Domain Operations (MDO) and Joint All Domain Operations (JADO) Commanders with the ability to access multiple entry points via littorals and inland waterways (waterborne corridor) to sustain forces within an anti-access/area denial (A2/AD) bubble. The family of MSV include the Maneuver Support Vessel (Light) and other systems both manned and autonomous and enablers which support INDOPACOM operational plans and Army Title 10 requirements to prepare for land combat and provide watercraft support in a theater of operations in support of Geographic Combatant Commands (GCC). MSV connectors will provide Surge, Precision and Dispersed Logistics to move and maneuver tailored forces, combat ready troops, platforms, equipment, and supply bulk fuel and water across the full spectrum of operations. MSV connectors mitigate A2/AD threats by providing access to shallow coastal waters, rivers, in narrow inland waterways in support of dispersed force elements in austere environments and where mature ports or road networks are unavailable. The MSV(L) provides upgraded capabilities such as higher operational speed, reduced draft and increased payload to support expeditionary movement and maneuver of tailored forces and combat power to mitigate the Anti-Access/Area Denial (A2/AD) operational environment. Capable of delivering a combat configured Abrams, Stryker or Bradley Fighting Vehicles along with critical sustainment missions including delivery of food, water, fuel, and ammunition. MSV(L) is the first new development program which will displace the Army's aging Landing Craft Mechanized-8 (LCM-8) class of vessels. The LCM-8 does not have the speed, functional draft (shallow water capability), interoperability, or maneuver capability to move today's Army Maneuver Platforms. The MSV(L) prototype will undergo contractor and government testing through FY 2026, with limited Reliability and Maintainability (RAM) testing in FY 2027. Following prototype testing the prototype vessel may be used as a test bench for future modifications and or a training asset. The MSV(L) low-rate initial production vessels will complete RAM, Production Verification Testing, and Initial Operational & Evaluation in FY 2027-2030. The family of MSV will also include interim capabilities and enablers to facilitate the range of pulsed operations in the littorals. FY 2026 RDTE dollars in the amount of $6.722 million support the family of Maneuver Support Vessels requirements development process with analysis and concept design, including potential autonomous solutions, to address approved requirements and testing.$$, 6722000, NULL, NULL, NULL, NULL, 7541000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604804A_FG4$$, $$0604804A$$, $$FG4$$, $$Ultra-Lightweight Camouflage Net$$, 6781000, $$ULCANS provides increased survivability against multi-spectral visual, infrared and radar threats, thermal signature suppression and significant thermal/solar reduction capability. ULCANS is capable of use in all types of weather and climatic conditions except in heavy snow and winds. ULCANS variants are integrated systems that are very lightweight, easily deployable, versatile, user friendly and tailored to the equipment meeting the requirements of operations for combat systems, command and control equipment, logistic support sites, tactical facilities, and fixed facilities. RDT&E funding for ULCANS Increment I program supports formal development for necessary technology/signature enhancements of three ULCANS Increment I variants (Woodland, Arctic, Desert/Urban) to replace current legacy ULCANS variants (Woodland and Desert). Mobile Camouflage System (MCS) provides Full Spectrum Signature Management for Vehicles from ground, aerial, and satellite. MCS enables combat vehicle protection and survivability against current peer and near-peer threats; defeats enemy targeting and surveillance systems through multi-spectral concealment (UV, VIS, NIR, SWIR, Thermal, Radar); enables multi-domain operations in A2/AD environment and provides operational units layered protection and concealment against long- range precision fires, drones, ground, aerial, and satellite threats. Funding supports modernization of current camouflage net systems by investigating technology insertions that decrease Soldier and ground combat vehicle detection from threat sensors. Funding also supports developing initial prototypes to enable refinement of operational requirements and early user feedback to maintain overmatch signature reduction against future threat sensors from peer competitors. FY26 funding in the amount of $6.781M supports the development of vehicle platforms including the Abrams and Bradley Fighting Vehicle. MCS is a congressional interest program.$$, 6781000, NULL, NULL, NULL, NULL, 5000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604804A_H01$$, $$0604804A$$, $$H01$$, $$Combat Engineer Eq Ed$$, 2319000, $$This project supports the engineering, manufacturing, and development of combat engineer equipment used in support of horizontal and vertical engineer construction missions, and to develop a variety of enabling systems that will support and improve mobility for Engineers in the Brigade Combat Teams (BCT), Combat Support Brigade (CSB), and Multi-Roll Bridge Company (MRBC) forces. This project also supports the development of enabling systems to meet critical capabilities of joint interdependence through Air and Ground Line of Communication and Rapid Tactical Earthmoving repair and construction which increase the operational reach of modular forces. Systems that support BCT and CSB forces include: High Mobility Engineer Excavators, Scrapers, Scoop Loaders, Skid Steer Loaders, Dozers, Cranes (ATEC and Family of All Terrain Cranes), Graders and Engineer Rapid Airfield Construction Capability (ERACC). Systems that support the MRBC included the Hydraulic Excavators (HYEX), Dozer, High Mobility Engineering Excavator (HMEE), and the All-Terrain Crane. Funds pre-milestone efforts for emerging combat engineer and construction equipment programs and capabilities. Funding supports development efforts to include integration, software development, contractor data gathering, logistic product development, training devices, test articles, development of prototypes and government/contractor testing. FY 2026 RDTE in the amount of $2.319 million provides funding for development and program support for Combat Engineer Equipment.$$, 2319000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604804A_L39$$, $$0604804A$$, $$L39$$, $$Field Sustainment Support Ed$$, 17195000, $$This project supports the Engineering and Manufacturing Development (EMD) of critical capabilities for cargo aerial delivery for identified theater distribution and services capability gaps, improve unit sustainability, and increase combat effectiveness. Project supports the demonstration of engineering development models and Type Classification of cargo parachutes, airdrop containers, sling load equipment, and other aerial delivery equipment to improve safety, effectiveness, and efficiency of airborne operations. This project develops critical enablers that support the Army in executing future movement and maneuver operations and distributed sustainment support and the Army's Modular Force Capabilities by maintaining readiness through fielding and integrating new equipment. This project also ensures Army Expeditionary Forces are capable of rapid deployment by providing aerial delivery initiatives and reduces sustainment requirements, related Combat Support/ Combat Service Support (CS/CSS) demands in lift, combat zone footprint, and costs for logistical support. Funding supports modernization of cargo aerial delivery portfolio, enabling contested logistics aerial delivery in anti-access/area denial (A2/AD) by dramatically increasing range of aerial delivery vehicles and allowing them to be employed in contested environments. Additionally, funding supports developing initial prototypes to enable refinement of operational requirements and early user feedback to support future sustainment and operational movement concepts.$$, 17195000, NULL, NULL, NULL, NULL, 4648000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604804A_L41$$, $$0604804A$$, $$L41$$, $$Water And Petroleum Distribution - Ed$$, 6431000, $$This project supports engineering and manufacturing development efforts as well as the Production Qualification Testing (PQT) and First Article Testing (FAT) efforts to provide all services with ample supply of clean fuel and water, supporting all types of missions. The Army has the mission to supply fuel for all land-based forces, including the Marines and the Air Force, and for supplying bulk drinking water to Soldiers. These programs enable the Army to improve maneuver sustainment operations to meet the demands of Army units and the Future Force. The mission includes receiving and transferring petroleum from trucks, ships, pipelines, and permanent and temporary storage facilities; moving petroleum from storage to and within corps and division areas; fuel quality surveillance testing; and dispensing in support of tactical operations, including rapid refueling of aircraft. This project also supports development and analysis of technologies designed to increase survivability of petroleum and water systems that may operate or be transported in hostile environments. The mission covers water purification and wastewater treatment, reutilization, storage, distribution, alternative water source acquisition, disposal, and quality control. These research and development missions support the development and enhancement of rapidly deployed Petroleum and Water equipment, which enables the Army to achieve its vision by providing a highly mobile and self-sustaining systems in hostile joint operations areas. Programs funded on this Project includes: Tactical Fuel Distribution System (TFDS), Bulk Fuel Distribution System (BFDS), Petroleum Expeditionary Analysis Kit (PEAK), Water Bison and Water Bison Light, Water Storage and Distribution System (WSDS) , 3K Tactical Water Purification System (TWPS), Early Entry Fluid Distribution System (E2FDS) and Pipeline Trace Tool - Software Development, Load Handling System (LHS) - Compatible Water Tank-rack System (HIPPO), Small Unit Water Purifier (SUWP) and Chemical Biological Radiological Nuclear (CBRN) Water Hauler. This Project provides for the modernization of current Petroleum and Water System fleets by investigating technology insertions including, but not limited to: condition- based maintenance, Vectronics, Victory Architecture, autonomous operations and other emerging technologies. Funding also supports market research, developing and testing initial prototypes, and production representative articles to enable refinement of Operational Requirements and early user feedback to support future sustainment and operational movement operating concepts. Funding supports non-traditional and middle tier acquisitions to include Other Transaction Authority (OTA) and 804. FY 2026 Base RDTE $6.431 million provides for Small Unit Water Purifier (SUWP), Unit Water Trailer (Bison), 3k Tactical Water Purification System (3k TWPS), Tactical Fuel Distribution System (TFDS), and Chemical Biological Radiation Nuclear (CBRN) Water Hauler developmental testing and program support. The 3k TWPS program will achieve Milestone 'C' (MS C) in FY 2025, award Low-Rate Initial Production (LRIP) hardware and start Production Qualification Testing (PQT) in FY 2026. Bison achieved MS C and awarded LRIP hardware (Dec 2024) and will start PQT in FY 2025. TFDS achieved MS C March 2025 and awarded LRIP hardware. TFDS will start PQT in FY 2025. CBRN will achieve MS C and award LRIP hardware in FY 2026 and start PQT in FY 2027.$$, 6431000, NULL, NULL, NULL, NULL, 7268000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604804A_L47$$, $$0604804A$$, $$L47$$, $$Improved Environmental Control Units$$, 1162000, $$This line supports the Army Network Modernization Strategy Line of Effort #4 (Command Post). Program develops/integrates Improved Environmental Control Units (IECUs) supporting existing and new requirements including the Command Post Integrated Infrastructure (CPI2), the Army Standard Family of Rigid Wall Shelters (ASFRWS) and other applications. In addition, it supports the development of critical Chemical Biological Radiological and Nuclear (CBRN) modifications required to support the Chemically Protected Deployable Medical System and other systems requiring this capability. The IECUs will provide improved cooling, heating and dehumidification to Soldiers and critical equipment systems in combat, combat support, combat service support units, and field hospitals. The IECUs are required to replace the currently fielded ECUs in order to comply with statutory and regulatory mandates on the use of Class II ODCs (such as HCFC-22) and address increasing restrictions on high GWP chemicals. Technical improvements over existing ECUs will yield fuel and weight savings, reduction in scheduled maintenance and increased reliability. Funding also provides applications engineering support to integration development for shelter/trailer platforms to assist users and help further standardize cooling units in the field. Funding also supports developing initial prototypes to enable refinement of operational requirements and technology refreshment, and design improvements to address issues and support future sustainment. Expansion of product variants will further accommodate replacement of aging legacy ECUs. FY26 funding in the amount of $1.162M supports the continuation of developing solution for implementation into platform integrated systems.$$, 1162000, NULL, NULL, NULL, NULL, 1062000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604804A_VR7$$, $$0604804A$$, $$VR7$$, $$Combat Service Support Systems$$, 1171000, $$This project supports Engineering and Manufacturing Development (EMD) of critical soldier support and sustainment systems that provide more endurance and agility to combat operations, enabling success of Army Expeditionary Forces in future multi-domain scenarios. Project includes highly mobile shelter systems (rigid and soft wall), expeditionary base camp subsystems, field service systems, mortuary affairs equipment, field heaters, and other combat service support equipment. These systems will fill identified theater capability gaps, improve safety, improve unit sustainability, improve resource and energy efficiency; address environmental impacts, and increase combat effectiveness. This project supports Engineering and Manufacturing Development (EMD), Prototyping, and testing of critical tactical support systems that allow mobile Joint Service command and control, as well as medical, force projection, and maintenance platforms. This project develops critical enablers that support a number of strategic initiatives, including the Army Campaign Plan, the Army Modernization Strategy, and the Army Arctic Strategy. This project ensures Army Expeditionary Forces are capable of rapid deployment while reducing sustainment requirements, related Combat Support/Combat Service Support (CS/ CSS) demands in lift, combat zone footprint, and costs for logistical support. Specifically, shelters developed under these efforts will be better insulated, thus reducing environmental control requirements, energy demand, and fuel usage. Therefore, they will reduce the Army's logistics and carbon footprint and lengthen the resupply interval in contested, support-constrained environments. Additionally, better insulated shelter systems allow for operational viability in extreme environments such as the Arctic.$$, 1171000, NULL, NULL, NULL, NULL, 19439000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604805A_593$$, $$0604805A$$, $$593$$, $$Joint Battle Command - Platform$$, NULL, $$Project 593 funding in FY 2026 and beyond was realigned to PE 0604818A / Army Tactical Command & Control Hardware & Software, Projects EJ6 and EK9, in support of the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems, for the Data and Application Layers. The capability being developed under this project remains critical and relevant to the Warfighter. This capability, along with its resources and requirement will transition under the overarching NGC2 capability to create a unified and streamlined ecosystem. Project 593 includes the Mounted Mission Command (MMC) Family of Systems (FoS), including both the MMC Transport (MMC-T) and Software (MMC-S) programs. The MMC programs provide the replacement for Blue Force Tracking (BFT) hardware and software capability, by employing hardened cyber/electronic warfare advancements that will improve data sharing and enhance C2 on-the move (C2OTM) functionality, resulting in more reliable communications anytime, anywhere, in all domains. The MMC-T program provides next-generation transceivers, encryption devices, and satellite communication waveforms (which are hosted in the transceiver). MMC-T provides a significant improvement over the existing BFT-2 capability by enabling smart routing across multiple network paths (Geosynchronous Equatorial Orbit (GEO), Low-Earth Orbit (LEO), and Line of Sight (LoS)) to mitigate risks posed by denied environments or signal jamming. New encryption devices provide protections against electronic warfare (EW) and cyber-attacks. The MMC-S program replaces JBC-P software on vehicles and in command posts by providing next generation C2/SA software that offers simplicity, intuitiveness, and enhanced capabilities over the legacy software. MMC-S utilizes the Tactical Assault Kit (TAK), a Government-owned application, to enable convergence of Warfighting Functions and utilizes an agile Continuous Integration/Continuous Delivery (CI/CD) approach for software development.$$, NULL, NULL, NULL, NULL, NULL, 47965000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604805A_DH4$$, $$0604805A$$, $$DH4$$, $$CMOSS Mounted Form Factor$$, 30945000, $$This funding supports the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems, Transport Layer. Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Modular Open Suite of Standards (CMOSS) Mounted Form Factor (CMFF) delivers Software Defined Radio (SDR) cards, Cryptographic Subsystem (CSS) cards, Digital Radiohead (DRH), and Victory Audio Adapters (VAX) required by the CMOSS Mounted Form Factor (CMFF) Abbreviated Capability Development Document (A-CDD) for the Ground and Aviation's tactical communication requirements. CMFF provides simultaneous transmission and reception of multiple waveforms across multiple channels in a single or multiple SDR card(s) integrated in the CMFF chassis with NSA certifiable CSS and interoperable with the Digital Radiohead. CMFF will introduce a Blocking Strategy roadmap. Block 1 starts with TSM and future blocks will build upon Block 1; Block 2 includes Single Channel Ground and Airborne Radio System (SINCGARS), VHF/UHF Line of Sight (VULOS) / Air Traffic Control (ATC), Warrior Robust Enhanced Network (WREN), initial Cryptographic Subsystem Card (CSS), Digital Radiohead (DRH), and Victory Audio Adapter and future advanced networking waveforms; Block 3 includes but is not limited to Mobile User Objective System (MUOS), Link-16, High Frequency (HF), HAVEQUICK (HQ), Second generation Anti-jam Tactical UHF Radio for NATO (SATURN), Demand Assigned Multiple Access (DAMA) and final CSS, DRH, and Victory Audio Adapter and future advanced networking waveforms. FY 2026 funds in the amount of $30.945 million supports Program Management Support, Hardware and Software Development (SDR card, CSS card, Digital Radiohead and Victory Audio Adapter), and Test, Integration and Evaluation.$$, 30945000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_3213$$, $$0605502N$$, $$3213$$, $$NAVAIR STTR Program$$, 0, $$The Small Business Technology Transfer (STTR) program requires Federal agency that has an extramural budget for Research and Development (R&D) in excess of $100,000,000 to set aside 0.45% for STTR. This funds cooperative R&D between small businesses and research institutions. The goal of the STTR program is to facilitate the transfer of technology developed by a research institution through the entrepreneurship of a small business concern.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604805A_DH5$$, $$0604805A$$, $$DH5$$, $$CMOSS Mounted Form Factor$$, 27415000, $$This funding supports the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems, Transport Layer. Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Modular Open Suite of Standards (CMOSS) is a defined suite of open architecture and Army standards that facilitate the reduction of system size, weight, and power-cooling (SWaP-C) and ensure commonality across multiple vehicles and platforms. Sharing of hardware and software components is enabled within the CMFF Mounted Common Infrastructure (MCI) Chassis, which will help move the implementation of C5ISR/Electronic Warfare (C5ISR/EW) capabilities away from costly and complex separate "stove-piped boxes" onto individual platforms. The use of open standards will make it simpler and more cost-effective to upgrade capabilities and/or keep pace with commercial technology by eliminating complex integration challenges and proprietary interfaces. The CMFF capability can only be realized when paired with the development of associated capability cards for integration into the chassis and peripheral enabling devices, such as antennae and appropriate user interfaces. Other programs are responsible for funding and developing the capability cards and peripheral devices; the CMFF MCI Chassis program is responsible for chassis development, system of system integration of capability cards and external resources into the chassis and platform integration. FY26 funding in the amount of $27.415 million will provide for CMFF MCI Chassis hardware and software development, vehicle and platform integration and prototype manufacturing for the chassis leading into its first test event in FY26.$$, 27415000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604805A_DL9$$, $$0604805A$$, $$DL9$$, $$APNT Cards C5ISR Mounted Form$$, 5365000, $$The CMFF APNT Card provides the solutions required by the CMFF Abbreviated Capability Development Document and distributes APNT data to payloads within the CMFF chassis and external systems as needed. The CMFF APNT card provides trusted PNT by utilizing multiple PNT sources and leveraging multiple open architectures. The CMFF APNT Card prototyping, and software development will be conducted in accordance with Modular Open Systems Approach (MOSA) (Reference House Report 116-442, 2020). The CMFF APNT Card complies with the PNT Reference Architecture and MOSA compliant hardware; CMOSS and software frameworks (PNT Operating System (pntOS)), to ensure a plug and play capability. Fiscal Year (FY) 2026 Base funds in the amount of $5.365 million continues the CMFF APNT Card prototype integration engineering support into the CMFF Mounted Common Infrastructure Chassis.$$, 5365000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604807A_832$$, $$0604807A$$, $$832$$, $$Field Medical Systems Engineering$$, 6252000, $$This Project funds the engineering and manufacturing development of medical products for enhanced combat casualty care and follow-on care. Commercially available medical products are also evaluated for military use. This project funds pivotal (conclusive) human clinical trials or mechanical engineering evaluations for effectiveness of devices or biologics (products derived from living organisms) to fulfill unique military requirements. Project Managers also consider reductions to the medical sustainment footprint through smaller weight and cube volume, or equipment independence from supporting materiel. This work is frequently completed through a laboratory/contractor team with the contractor obtaining the U.S. Food and Drug Administration (FDA) licensure for sale of the product.$$, 6252000, NULL, NULL, NULL, NULL, 10984000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604808A_016$$, $$0604808A$$, $$016$$, $$Close Combat Capabilities ENG DEV$$, 7970000, $$Project 016 / Close Combat Capabilities covers multiple programs: Prototype Integration for Multi-Domain Operations, Enhanced Robotics Payload - Render Safe (ERP- RS), Mine Clearing Line Charge (MICLIC) Wireless Initiation, and the Arresting Cable Release Mechanism (ACRM). Enhanced Robotics Payload - Render Safe (ERP-RS) will enable EOD teams to access, render safe, and dispose of explosive ordnances (EO) while removing Soldiers from the direct effects of explosive blast and fragmentation. ERP-RS consists of three modules that will mount on existing Host Unmanned Ground Vehicles (HUGVs) in EOD units: (1) Highly Dexterous Manipulation System (HDMS) that has increased lift capacity and dexterity over current manipulators, using dual arm manipulation, will contribute to access, render safe, and disposal of sensitive EO, (2) a Multi-Shot Disruptor (MSD) module that provides remote selectable and precise disruption of surface laid or suspended EO, and (3) a Precision Aim Module (PAM) to provide accurate disruption of surface laid or suspended EO with the Multi-Shot Disrupter Module. These ERP-RS capabilities will provide a level of access, render safe, and disposal of EO that would currently require a Soldier to expose themselves to explosive hazards. Mine Clearing Line Charge (MICLIC) Wireless Initiation effort is a reliability enhancement to the current MICLIC system. The MICLIC is a legacy heavy minefield breaching capability consisting of a trailer mounted launcher that deploys the M58A4 Linear Demolition Charge via the MK22 Mod 4 Rocket. The system has historically suffered from poor detonation reliability traced primarily to the fuze or command wires leading to it. By eliminating the wired connections and replacing the fuze with a system based on the fielded M152 Remote Activation Munition System (RAMS), system reliability in command detonation mode will be maximized. Wireless initiation is also a key enabler for remote/robotic employment of current and future breaching systems to remove Soldiers from the breach as described in emerging breaching requirements such as the Common Engineer Chassis. If emerging requirement(s) is approved, effort will pivot to initiation system, development and integration activities on that replacement program. The Arresting Cable Release Mechanism (ACRM) is a derived requirement of the M1150 Assault Breacher Vehicle (ABV) which employs the MICLIC ammo components. The arresting cable of the M58A4 Linear Demolition Charge is an entanglement hazard to the M1150. Currently a crew member must dismount the vehicle to remove it after M58A4 detonation which violates the crew protection requirements of the ABV. The ACRM will automatically disconnect the arresting cable while under tension, throwing the cable clear of the vehicle immediately prior to M58A4 detonation. This functionality is critical to the ABV-Remote Control System$$, 7970000, NULL, NULL, NULL, NULL, 30753000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604808A_CS2$$, $$0604808A$$, $$CS2$$, $$Render Safe Sets Kits and Outfits$$, 1892000, $$Project CS2: Explosive Ordnance Disposal Render Safe - Sets Kits and Outfits (EOD RS-SKO) provides for the demonstration and evaluation of emerging technologies within requirements trade-space and capabilities needed for Explosive Ordnance Disposal (EOD) teams to Render Safe (RS) US and foreign ordnance and improvised explosive devices. Technical refresh of capabilities ensures Army 2030 formations maintain overmatch capability. EOD RS-SKO equips EOD teams with a suite of 11 capabilities needed to safely and effectively render safe explosive threats. Lessons learned from the Ukraine conflict show that the enemy/threat changes constantly so EOD RS-SKO capabilities must keep pace to ensure overmatch. Near term technical refresh priorities include improved load sets for the Electronic Countermeasures (Modi and AN/PLT-6(v)1) to ensure the most current threats are being countered allowing EOD Techs to safely approach/render safe explosive threats and enhanced deep-buried explosive hazard detection to allow EOD Techs to quickly and effectively clear their pathway and/or identify threats for render safe missions. This project will continue to support cross-service initiatives to increase commonality among information reporting and control systems.$$, 1892000, NULL, NULL, NULL, NULL, 971000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604827A_FK4$$, $$0604827A$$, $$FK4$$, $$Soldier Borne Sensor (SBS)$$, NULL, $$Project FK4 - Soldier Borne Sensor (SBS): The SBS is a small unmanned aerial vehicle. The SBS provides a near term solution to three Army War-fighting Challenges at the Infantry Squad level: develop situational understanding, conduct air-ground reconnaissance, and conduct joint combined arms maneuver. The system is simple to deploy and use to support the squad leader's decision-making process. The system allows Soldiers to obtain local situational awareness and understanding of their immediate surroundings while remaining in covered or concealed positions. The SBS program will be procured through multiple phases. The program will develop, integrate, and qualify additional capabilities for each phase. Funding in this project aligns with the Army's priorities in support of the Army Transformation Initiative (ATI). Realignment starting FY2026 to Soldier Borne Sensor (0609345A/A50) agile funding line.$$, NULL, NULL, NULL, NULL, NULL, 1596000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604808A_CS3$$, $$0604808A$$, $$CS3$$, $$Next Generation Advanced Bomb Suit$$, NULL, $$Funding in this project supports the Soldier Lethality Cross Functional Team (CFT). The NGABS program directly contributes to Soldier lethality and ground force commander freedom of maneuver by providing next generation sensor and optics in the cutting-edge Heads-Up-Display (HUD) while integrating the Government's latest investments in protective material for the modular, scalable NGABS bomb suit development. NGABS will increase the Warfighter survivability and mobility by optimizing Soldier protection for EOD personnel, while effectively managing all life cycle aspects of Personal Protective Equipment (PPE). Warfighter lethality is increased through bomb suit weight reduction utilizing extensive investments in protective material research and development. The result is material solutions that are lighter and are pieced together in a manner which increases Soldier mobility and longevity. EOD Soldier situational awareness and exposure to ballistic threats is enhanced through the NGABS HUD which allows the Soldier increased visibility under various obscurants and low/no-light situations.$$, NULL, NULL, NULL, NULL, NULL, 1361000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604818A_323$$, $$0604818A$$, $$323$$, $$Common Hardware Systems$$, 5030000, $$This funding supports the Army's Next Generation Command and Control (NGC2) initiative to modernize the Command and Control (C2) systems, Infrastructure Layer. Common Hardware Systems (CHS) is a mandated Army Strategic Source, as annotated in Army Regulation (AR) 25-1 Army Information Technology (IT) that acquires and sustains highly flexible, cost-effective, and simplified non-developmental solutions that integrate the latest and emerging commercial IT onto the Converged Mission Command Network. Efforts are aligned to support the Program Executive Office, Command, Control and Communications, Network (PEO C3N) network evaluation and experimentation goals. This funding line also supports network solution procurement and sustainment for U.S. Army Reserves, U.S. Army National Guard, U.S. Navy, U.S. Air Force, U.S. Marine Corps, and other Federal agencies. CHS provides technical support, warranty support, system engineering and design, and end-of-life and configuration management services to ensure interoperability and integration of hardware throughout the computing infrastructure. CHS continuously analyzes and tracks hardware from cradle to grave, from emerging technology until end of life. The program conducts hardware evaluations that facilitate and simplify the selection of common hardware solutions across numerous Army programs, agencies, Joint Services, and other Federal Agencies including: Mission Command; Tactical Network; Tactical Radios; Intelligence Systems and Analytics; Aviation Systems; Counter-Rocket, Artillery, Mortar (C-RAM); Communication Electronics Command; Combat Capabilities Development Command (DEVCOM); Army National Guard and Reserves; Navy; Air Force; Marines; the Federal Bureau of Investigation; among others. CHS rapidly procures common hardware configurations in support of Army 2030/2040, the sustainment community, and tactical programs that enable continuous modernization. CHS is an enabler of the initiative of continuous transformation, empowering end users to experiment, innovate, and integrate, the most modern Commercial of the Shelf (COTS) IT. CHS is utilized as a procurement contract for the Defense Innovation Unit (DIU) Blue list approved drones to inform this campaign of learning. CHS logistical services include the ability to add worldwide, 24-hour turn-around repair through strategically located support centers for tactical military units. These support centers provide tailorable supply chain and cybersecurity measures, customizable warranty management, maintenance and failure rate reporting, and technical support services to support specific Army program requirements. CHS is a model for modern acquisition strategy that strengthens the U.S. cybersecurity supply chain and manages risk by providing hardware solutions including servers, storage, clients, networking devices, tactical radios, ruggedized platforms, hand-held end devices, operational transit cases, installation kits, and peripheral devices procured from a mix of small and large businesses. CHS partners with the CECOM Integrated Logistics Support Center (ILSC) to develop a model for sustaining Commercial Off the Shelf (COTS) IT using the Standard Army Supply System.$$, 5030000, NULL, NULL, NULL, NULL, 4461000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604818A_C29$$, $$0604818A$$, $$C29$$, $$Centralized Technical Support Facility$$, 4443000, $$Project C29, The Centralized Technical Support Facility (CTSF): The CTSF is the Army's premier test and certification facility for System of Systems interoperability, functioning as CIO/G6's designated independent test agent and Land/WarNet/Mission Command (LWN/MC) configuration manager. The Central Technical Support Facility's (CTSF) directed mission is to perform Army Interoperability Certification (AIC) testing and configuration management for all 23 operational through tactical level Command, Computing, Control, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) systems, Mission and Space systems, Aviation systems and other individual, family, and system of systems, applications, and hardware prior to release to the field. The CTSF accomplishes this through the enforcement of a standards based architecture while supporting the development and implementation of an integrated computing infrastructure and a converged network. The CTSF provides validated test data to the Department of the Army and Joint agencies to accredit interoperability certifications. The distributed test environment of the CTSF is accomplished through the Federation of Net-centric Sites (FaNS) construct. This FaNS construct addresses distributed integration development and testing using the core infrastructure of the CTSF to harness Army and Joint expertise/resources. Through these federated resources, the CTSF executes or supports interoperability development, integration and certification testing of the systems and system of systems in the Warfighter Mission Area, to include Network Evaluation spinouts, as they become part of the Army's LandWarNet. The cited work is consistent with Strategic Planning Guidance and the Army Modernization and Strategy Plan.$$, 4443000, NULL, NULL, NULL, NULL, 4220000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604818A_C34$$, $$0604818A$$, $$C34$$, $$Army Tac C2 Sys Eng$$, 11159000, $$This funding supports the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems, Infrastructure Layer. Project C34, Army Tactical Command and Control Systems Engineering supports the Army's Network Modernization Strategy and coordinates technical efforts across and outside of PEO Command, Control, Communications, and Network (C3N) to ensure integration with the current and future Mission Command Network. Project C34 provides technical support to programs, informing design and solutions with specific emphasis on the ability for different program efforts to be integrated and interoperable with one another. Efforts support Army Modernization priorities including Army Unified Network Plan, Multi-Domain Operations, Joint All Domain Command and Control (JADC2), Data Modernization and emerging data-centric requirements. Project C34, Army Tactical Command and Control Systems Engineering: This project funds the PEO C3N System of Systems (SoS) engineering and integration, acquisition management, testing, fielding and sustainment support to ensure interoperability and affordability within the PEO C3N portfolio. The effort focuses on SoS Engineering and Integration for the Mission Command Network with increased emphasis on immediate Warfighter needs as well as leveraging emerging technologies. Fiscal Year 2026 will fund the continued development, implementation and integration of the Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) network architectures as the Army begins migration towards the adaptive, data centric environment of Next Generation Command and Control (NGC2). This includes maturing the technology enhancement roadmap for SoS capability evolution across the PEO C3N portfolio that incorporates network integration support and design products for system validation and integration testing, integration of tactical networked capabilities for all Mission Command Network systems including integration events, integration of tactical information assurance solutions and security measures for consistent cyber protection.$$, 11159000, NULL, NULL, NULL, NULL, 18630000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604818A_DD1$$, $$0604818A$$, $$DD1$$, $$Unified Network Technology Trans &$$, 14497000, $$Project DD1, Unified Network Technology Transition and Integration (UNTTI) supports the Army's Command Control (C2) Transport strategy. UNTTI is an RDT&E initiative enabling transport agnostic, high-capacity and resilient tactical communications for expeditionary operations. UNTTI efforts support system/subsystem development and demonstration, aimed at integration, maturation, evaluation, and testing to demonstrate systems against requirements. TEM Projects, Line of Sight Modernization, SATCOM Modernization, Transport Modernization, Secure Cellular, and System of Systems (SoS) Training. These technologies support new and improved communications capabilities with reduced Size, Weight, and Power (SWAP), while increasing throughput, providing network resiliency and Low Probability of Intercept/Low Probability of Detection (LPI/LPD) capabilities. The Program Executive Office Command, Control, Communications and Network (PEO C3N) is responsible for prioritizing, programming, managing and executing the projects detailed below and ensuring these funds are available to support the Army modernization priorities. The Command and Control Cross Functional Team (C2-CFT), Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center, Army Capability Network (ACM) Networks and Services (N&S) support the prioritization of technology demonstrations, focused evaluations, and expert analyses to inform future requirements, mature technologies, and deliver new capabilities. These projects inform technology integration, support user assessments, and transition to programs if appropriate. UNTTI procures, modifies, integrates, and tests system prototypes to demonstrate enhanced capabilities in accordance with Army modernization priorities. UNTTI supports developing technical, logistics, training, and other acquisition documentation to assist with the transition, insertion, and integration of efforts across PM Tactical Network and enables the transition of developing and new technologies to support NGC2. In addition, UNTTI resources validation and test efforts which improves the reliability, maintainability, and supportability of Tactical Network equipped units. These improvements avoid future costs by mitigating single point failures and thickening the network which ultimately improves network and cyber resiliency along with unit availability for contingency operations. In FY 2026, funding in the amount of $14.498M for UNTTI efforts includes Secure Cellular, Technical Exchange Meeting (TEM) Project - Gateway Automation, Transport Modernization, and Training Start Guides.$$, 14497000, NULL, NULL, NULL, NULL, 7610000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604818A_DK3$$, $$0604818A$$, $$DK3$$, $$Sensor Computing Environment$$, NULL, $$The Sensor Computing Environment (SCE) provides interoperability for sensors and systems across the Army. SCE operates across any modality of sensors and is designed for resilient operations in tactical conditions. Sensor CE provides the following capabilities to the Army and End Users: Provides software, standards, and a common sensor data model for all sensor information; Enables interoperability and understanding across all network security enclaves; Enables the sharing and control of sensor information; Provides a mature Software Development Kit (SDK) for rapid integration of sensors onto the Army's networks; and Implements the COE Cross Cutting Capability (CCC) for Sensor Alert Distribution providing common sensor awareness from tactical edge to all systems on the Enterprise network. The end state for SCE is to ensure the accessibility of multi-domain sensor data to those who need it through the network to enable information sharing among CEs while reducing acquisition and life-cycle costs through open standards and re-usable solutions across programs. This vision becomes achievable with the implementation of the COE CCC through the Army's MCN modernization. DK3 Sensor CE program will support the Army's Common Operating Environment (COE), and the further development of requirements to define the standards for interoperability used when connecting sensors to the Army networks. This will follow the Integrated Sensor Architecture (ISA), which is a Modular Open Systems Approach (MOSA) that provides a modular solution and extensible data model that can be used to meet requirements of operations with any modality of sensor, from Enterprise to tactical networks, across any security enclave, and capable of being used on embedded platforms. Funding in FY 2026 and beyond is realigned to Projects EJ6 and EK9, in support of the Army's Next Generation Command and Control (NGC2) initiative to modernize C2 systems, as detailed in the R2 B Program Change Summary (Change Summary Explanation) of this form. Capabilities Include: Common Sensor Data Model, Definition of Standard, Interface Specification, Architecture Definition, Mature Software Development Kit (SDK), Compliance Verifications & Validation Tools.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604818A_DL8$$, $$0604818A$$, $$DL8$$, $$Predictive Logistics$$, 3782000, $$Predictive Logistics (PL) supports the Army's Next Generation Command and Control (NGC2) initiative to modernize the Command and Control (C2) systems, Applications Layer. Predictive Logistics (PL) is a logistics optimization effort that will deliver hardware/software capabilities that improve unit readiness, support commanders' abilities to monitor, predict, and sustain combat power, and enhance existing maintenance and supply processes. Establishing automated data collection from self-reporting platform sensors, PL will process, store, and disseminate Logistics Status (LOGSTAT) data to the Common Operational Pictures (COP) at platform, command, and enterprise echelons via the Unified Network. This capability will also predict future logistics needs with a focus on Class III (petroleum, oil, lubricants) and Class V (ammunition/explosives) consumables and maintenance alerts, enhancing mission planning and execution. FY2026 funding in the amount of $3.782 million will provide for PL development engineering, modeling and simulation efforts and program management support to inform the development of fuel, ammunition, and critical maintenance requirements for PL Capability Needs Statements.$$, 3782000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604818A_EJ4$$, $$0604818A$$, $$EJ4$$, $$COMMAND POST COMPUTING$$, NULL, $$The Command Post Computing Environment (CPCE) funding line provides a modular environment with scalable capabilities from Battalion through Army Service Component Command (ASCC), and provides an available, reliable and resilient infrastructure which unifies data and services within the Command Post. The modular environment includes data visualization/management and the Army's primary command post Common Operational Picture (COP), which provides the Commander the ability to understand, visualize, and direct the operational environment facilitating mission planning and execution by leveraging common data and collaboration within and external to the unit through voice, video and chat. The modular environment provides access to all network domains and enables the Mission Partner Environment (MPE). The CPCE implements an integrated, interoperable, cyber-secure, data and software infrastructure that serves as the host for a unified set of multiple warfighting functional applications. This software infrastructure helps to eliminate "stove-piped" systems and duplicative or redundant implementations, while simplifying future application development efforts by providing key interoperability and data sharing improvements across multiple echelons. The data and software infrastructure and applications reside on Tactical Server Infrastructure (TSI) hardware, as well as previously fielded servers. The TSI provides the converged computing and data storage hardware/software required to host the warfighting mission area applications, MPE capabilities, Common Operating Environment (COE) Cross-Cutting Capabilities and enables a collaborative work environment. FY 2026 funding was realigned to PE 0604818A / Army Tactical Command & Control Hardware & Software, Projects EJ6 and EK9, in support of the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems, for the Data and Applications Layers. The capabilities being developed under this project remain critical and relevant to the Warfighter. The capabilities, along with the resources and requirements will transition under the overarching NGC2 capability to eliminate stove-piping, reduce duplication of effort, and provide capability within a single NGC2 core architecture.$$, NULL, NULL, NULL, NULL, NULL, 43829000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604818A_EJ6$$, $$0604818A$$, $$EJ6$$, $$TACTICAL ENHANCEMENT$$, 139993000, $$This funding line supports the NGC2 initiative to modernize C2 systems. NGC2 is one of the Army's highest modernization priorities and will enhance the ability to conduct multi-domain operations by integrating advanced technologies, improving interoperability, and increasing the speed and accuracy of decision-making processes. This funding line specifically supports the Data Layer efforts within NGC2. The Data Layer will deliver standardized and seamless data access across warfighting function applications (e.g. Command and Control, Information Advantage, Movement and Maneuver, Intelligence, Fires, Protection, Sustainment and Network Operations). Real-time access to common data is critical to maintaining a decisive advantage. The Data Layer will leverage industry best practices for iterative development and Development, Security, and Operations (DevSecOps) with an emphasis on artificial intelligence/machine learning (AI/ML) capabilities. FY 2026 Funding supports prototyping, continuous integration and continuous delivery (CI/CD) and continuous test, evaluation, verification, and validation (TEVV) of the C2 Data Layer. The Data Layer includes the operating system, platform, and common core services (including Applications, Analytics, AI/ML, and Training and Simulation). Funding also supports transition and integration of existing mission command system capabilities into a single NGC2 core architecture that eliminates stove-pipes and reduces duplication of effort. These efforts are essential for managing and sharing C2 data across applications, providing commanders with a common operating picture and the information required to make quick, accurate decisions in any environment.$$, 139993000, NULL, NULL, NULL, NULL, 8710000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604818A_EK9$$, $$0604818A$$, $$EK9$$, $$TACTICAL NETWORK OPERATIONS$$, 204958000, $$This funding line supports the NGC2 initiative to modernize C2 systems. NGC2 is one of the Army's highest modernization priorities and will enhance the ability to conduct multi-domain operations by integrating advanced technologies, improving interoperability, and increasing the speed and accuracy of decision-making processes. This funding line specifically supports the Applications Layer efforts within NGC2. The Applications Layer supports the delivery of warfighting function (WfF) applications and Unified Network Operations. WfF applications (e.g. Command and Control, Information Advantage, Movement and Maneuver, Intelligence, Fires, Protection, Sustainment and Network Operations) will be delivered to the specifications defined by the Data Layer (Project EJ6). Project EK9 also consolidates and further refines Network Operations (NetOps) tools that are key to enabling applications in a data-centric network with increased efficiency in overall network management. Warfighting function applications will operate in conjunction with the Data Layer to provide seamless mission command from the enterprise to the tactical edge, leveraging cutting edge available commercial technologies. This unified approach will dramatically improve the user experience for warfighters, enabling faster decision-making and ultimately increasing lethality. FY 2026 funding supports the development and seamless integration of critical WfF applications. This investment will focus on development/integration of WfF applications spanning Command and Control, Movement and Maneuver, Intelligence, Fires, Protection, Sustainment, and Network Operations and delivering those capabilities within a common user interface (NGC2). A key operational takeaway from this funding will be a demonstrably improved ability to rapidly plan, coordinate, and execute multi-domain operations, providing a decisive advantage on the battlefield.$$, 204958000, NULL, NULL, NULL, NULL, 47768000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604818A_EQ8$$, $$0604818A$$, $$EQ8$$, $$Mobile/Handheld Computing$$, 37040000, $$Project EQ8, Mobile/Handheld Computing Environment (M/HHCE) enables situational awareness (SA) and command and control (C2) for dismounted combat forces through the Nett Warrior (NW) system. M/HH CE utilizes Government-owned Tactical Assault Kit (TAK) as a foundation for integrating a wide array of functional software, such as UAV planning/control, casualty care and logistics. Future versions of NW and TAK will form the SA/C2 baseline for Next Gen C2 dismounted forces. The NW system provides leaders electronic real-time information on friendly positions; information about enemy activity and movement; navigational data and map imagery; a collaborative planning tool; and other mission related graphics which effectively puts the power of the entire Army tactical network in the hands of the dismounted leader. Nett Warrior (NW) and Soldier Borne Mission Command (SBMC) are the instantiation of the M/HHCE and comply with the technical standards documented by the M/ HHCE and provide the dismounted common computational platform for other products relevant to dismounted Soldiers. Through compliance with the M/HHCE, software applications from other programs are integrated with the NW and SBMC systems, reducing the need for duplicate hardware resulting in reduced Soldier Load. The M/ HHCE is directly aligned to the Army Network Modernization Strategy Line of Effort (LOE) 1 (Unified Network). M/HHCE also supports the Army Network Modernization Strategy LOE 2 (Common Operating Environment). These efforts are aligned to the Army's Tactical Network Capability Set development and fielding plans by utilizing (1) interoperable data, message, and waveforms, (2) sensors and applications that enable operations across domains and automated tools to aid decision-making and (3) integration with Joint C4ISR and strike capabilities. NW leverages commercial smart phone devices and secure Army tactical radios to provide the dismounted leader an integrated mission command and situational awareness capability for use during combat operations. NW applied feedback from conventional and Special Operations units to procure and implement Secret and Secure But Unclassified (SBU) networking equipment for Brigade Combat Teams (BCTs) and the Security Force Assistance Brigades to enable faster, more flexible Mission Command data exchanges with Joint and Coalition forces while maintaining the existing integrated mission command capability with Mounted CE (e.g., Joint Battle Command - Platform (JBC-P) or Mounted Mission Command (MMC)) system. NW uses Commercial-Off-The-Shelf (COTS) and Non-Developmental Item (NDI) computational & communication equipment to support Next Gen C2 and enable faster and more accurate decision making in fights at the tactical level. Requirements for the M/HHCE are established in the Army Requirements Oversight Council (AROC) approved COE Information Systems Initial Capability Document (IS ICD), the M/HHCE Requirements Definition Package (RDP), and the NW Capability Development Document in lieu of Capability Production Document. M/HHCE is a signature effort under the Network CFT (Common Operating Environment focused on dismounted Soldier). The Network CFT is one of the six Army modernization$$, 37040000, NULL, NULL, NULL, NULL, 7273000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604818A_ER9$$, $$0604818A$$, $$ER9$$, $$Expeditionary Army Command Post$$, 9993000, $$This funding supports the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems, Infrastructure layer. Command posts provide locations from which commanders, assisted by their staffs, command operations and integrate/synchronize combat power to accomplish missions across the range of military operations. Commanders organize mission command systems into command posts based on mission requirements and the situation that will best assist them in exercising command and control of assigned and attached forces. Command post survivability is vital to mission success. Depending on the threat, command posts need to remain small and highly mobile, especially at echelons below Division. Command posts are easily acquired and targeted by our adversaries when concentrated. Command post survivability is increased via dispersion, reduced size, redundancy, mobility, as well as camouflage and concealment. Command post survivability is further enhanced via dismounted operations that can take advantage of cover or shielding by terrain features or urban structures FY2026 funding supports modernization efforts of command post capabilities, with a focus on continuous improvements for on the move operations, modular command posts, and survivability. Funding also provides for safety testing, logistical support and program management.$$, 9993000, NULL, NULL, NULL, NULL, 11816000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_3233$$, $$0605502N$$, $$3233$$, $$SPAWAR STTR Program$$, 0, $$The Small Business Technology Transfer (STTR) program requires Federal agency that has an extramural budget for Research and Development (R&D) in excess of $100,000,000 to set aside 0.45% for STTR. This funds cooperative R&D between small businesses and research institutions. The goal of the STTR program is to facilitate the transfer of technology developed by a research institution through the entrepreneurship of a small business concern.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604820A_E10$$, $$0604820A$$, $$E10$$, $$Sentinel$$, 18853000, $$The FY 2026 request for Sentinel includes $18,853 thousand of discretionary and $14,000 thousand of mandatory (reconciliation) for a total of $32,853 thousand. The discretionary funds will be used to support enhancements, upgrades, and continued testing of the Army Modernization Priorities in support of the Sentinel Radar programs and will provide for an incrementally fielded Integrated Air and Missile Defense Fire Control System/capability for the composite Army Air and Missile Defense Brigades. The mandatory funds will develop and implement new signal processing techniques and waveforms to enhance Electronic Attack and Electronic Protect techniques based on the evolving threat, further enhancing radar survival and effectiveness in contested environments. Further information for this reconciliation request is provided in Section 20003 (Missile Defense) of the Reconciliation Exhibit. The Sentinel systems are a key component of the Army Integrated Air and Missile Defense (AIAMD) architecture, providing critical air surveillance of the forward areas. The Sentinel A4 utilizes Active Electronically Scanned Array (AESA) technology that is a ground-based sensor system designed to locate, identify and track Cruise Missiles, Fixed-Wing and Rotary-Wing Aircraft, Unmanned Aircraft Systems and Rocket, Artillery, and Mortar (RAM) projectiles. The multi-mission Sentinel A4 system will provide 360-degree surveillance and tracking with the ability to handle multiple simultaneous threats arriving from different azimuths. The Sentinel A3 consists of a trailer mounted radar with its prime mover, generator, identification Friend or Foe (IFF) system and Forward Area Air Defense Command, Control and Intelligence (FAAD C2I) systems interface. The Sentinel A3 provides persistent surveillance and fire control quality data on Army and Joint networks through external C2 platforms enabling protection of U.S. and coalition forces as well as critical geo-political assets against Cruise Missiles (CM), Fixed-Wing, Rotary- Wing Aircraft and Unmanned Aircraft System (UAS) threats.$$, 18853000, NULL, NULL, NULL, NULL, 78363000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604820A_PS1$$, $$0604820A$$, $$PS1$$, $$Army Long Range Persistent$$, 34373000, $$The FY2026 request for ALPS includes $34,373 thousand of discretionary and $4,000 thousand of mandatory (reconciliation) for a total of $38,373 thousand. The discretionary funds will support the Army Long-Range Persistent Surveillance (ALPS) sensor, which is a persistent, passive air surveillance sensor system. ALPS capabilities include long-range, 360-degree surveillance against conventional fixed wing and rotary wing aircraft, UAS, and cruise missiles. ALPS supports tactical to strategic operations via its capability to connect with multiple Army and Joint Command and Control systems including the Integrated Fire Control Network (IFCN). The mandatory funds will develop Fixed Site capability for defense of the homeland. Further information for this reconciliation request is provided in Section 20003 (Missile Defense) of the Reconciliation Exhibit. The ALPS program was started as an urgent capability in response to multiple Combatant Commands identified operational needs. The ALPS program tasks include all programmatic and engineering activities needed to modernize systems currently supporting multiple Combatant Commands and design/development effort to provide a passive mobile capability to Army Air and Missile Defense forces. In FY 2025, Project PS1 /Army Long Range Persistent Surveillance (ALPS) was a new effort realigned within PE 0604820A / Radar Development. Funding realigned from PE 0604741A / Air Defense Command Control and Intelligence - Eng Dev, Project 126 /PEO Electronic Protect for the design, development, integration, and test of ALPS.$$, 34373000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604822A_GF5$$, $$0604822A$$, $$GF5$$, $$General Fund Enterprise Business$$, NULL, $$GF5 - General Fund Enterprise Business System (GFEBS): GFEBS is the Army's core financial management system for administering its General Fund. Full Deployment was reached in 2012 and the system is currently in the Capability Support (sustainment) phase of the Business Capability Acquisition Cycle, focused on modernization, cyber security, and system enhancements while also conducting capability enhancements to meet policy and deliver a more accurate picture of Army financial awareness. GFEBS was implemented to fulfill the needs and enable the Army to comply with the Federal Financial Management Improvement Act, it is utilized by over 35,000 users across 200 locations worldwide. GFEBS was developed using a commercial off-the-shelf Enterprise Resource Planning system that is certified by the Chief, Financial Officer Council and provides six core financial functions (United States General Ledger (USGL), Cost Management, Funds Control, Payable Management, Real Property, Receivable Management and Reports). FY 2025 Base dollars in the amount of $1.995 million will continue to support increases in mission performance and improvement of automatized system processes, and additional audit-related enhancements. Continue efforts to support modernization efforts aligned with the Original Equipment Manufacturer's Systems Applications and Products (SAP) next generation capability, activities include code de-customization, data enablement, and improved automated data access to prevent end of support for the current database and platform. Funds will also support acquisition trades and market research on alternatives for SAP based finance/logistics consolidation to evaluate potential efficiencies by reducing platforms and licenses. GF5 has no FY2026 RDT&E funding request.$$, NULL, NULL, NULL, NULL, NULL, 16011000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604827A_EY2$$, $$0604827A$$, $$EY2$$, $$Integrated Soldier Power Data System$$, 3501000, $$Integrated Soldier Power Data System - Core (ISPDS-C) includes power and data managing/distribution devices, cutting-edge energy storage solutions, Soldier-worn power generation (fuel cell), and power scavenging devices. These capabilities fill the power and energy gaps created by the increase in mission essential, Soldier portable power consumers, such as heads up displays, situational awareness displays, global positioning systems, weapon sensors, radios, night vision systems, and other devices. This project line develops power sources and power management solutions for the individual Soldier and squad for use in all operating environments. This project develops and evaluates capabilities to fill the power and energy requirements for critical Network Baseline 4.0 Soldier worn systems to include tactical radios, assured position navigation and timing, Next Generation Squad Weapon, Nett Warrior, Enhanced Night Vision Goggle (all variants, including Binocular), and the Integrated Visual Augmentation System. ISPDS-C systems will enable dismounted Soldiers and squads to execute their missions more efficiently, independently, for longer durations and with fewer battery resupplies while reducing the logistical and physical burden associated with moving fuel and batteries. This project also develops and integrates vehicular on-the-move charging.$$, 3501000, NULL, NULL, NULL, NULL, 12430000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604827A_EY4$$, $$0604827A$$, $$EY4$$, $$Universal Battery Charger$$, 636000, $$Project EY4 - Universal Battery Charger: Universal Battery Charger (UBC) fills the power and energy gap created by the increase in mission essential, Soldier portable power consumers, by providing a variety of charging solutions capable of providing power to handheld communication devices and military batteries to support mounted and dismounted formations. The UBC is suited for mounted and dismounted operations at the company level and below in multi-domain and austere operating environments. The system can draw power from wall outlets, vehicle power, generators, and solar power sources. The UBC enables dismounted Soldiers to execute their missions with fewer battery resupplies, thus reducing the logistical burden associated with moving fuel and batteries. The UBC capability allows dismounted Soldiers to operate independently for longer missions. The UBC fills the power and energy gap associated with bulk charging.$$, 636000, NULL, NULL, NULL, NULL, 940000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604827A_LS2$$, $$0604827A$$, $$LS2$$, $$Lethal Semi-Autonomous Aerial$$, NULL, $$Project LS2 - Lethal Semi-Autonomous Aerial Unmanned System - Engineering Development: This project focuses on engineering and material development in support of the acquisition program for an enduring capability with Low Altitude Strike and Stalk Ordnance (LASSO) CDD which was approved in AUG24. Infantry Brigade Combat Teams (IBCTs) lack adequate organic capabilities at echelon to apply immediate, point, long range, and direct fire effects to destroy tanks, light armored vehicles, hardened targets, defilade, and personnel targets, while producing minimal collateral damage in complex terrain in all environmental conditions. Development will focus on the Fire Control Stations (FCS), All-Up Round (AUR), and System Architecture. Develop technology for incorporation into the CDD update, for the Program of Record, and conduct tech enhancements from current global conflicts. The funding contained within this budget line and project will be used to conduct evaluations of technologies and capabilities in the loitering munitions capability space, hardware and system architecture engineering and integration activities, and testing and evaluation activities. Realignment starting FY 2026 to Lethal Semi-Autonomous Aerial Unmanned Sys-Eng Dev (0609345A/A49) funding line.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604827A_S65$$, $$0604827A$$, $$S65$$, $$Platoon Power Generator$$, NULL, $$Platoon Power Generation - PM E2S2: This project supports the demonstration and development of Platoon Power Generation (PPG). PPG will provide small units with portable power to sustain Modified Table of Organizational Equipment (MTOE) unit power demand in support of 48 to 72 hour missions. It will be used for charging batteries and powering various types of Army communications and electronics devices. It will provide sufficient power to recharge and power all Platoon equipment and fulfill residual power gaps at the Squad and Soldier level. The generator will provide Platoon power for charging batteries when away from vehicles in all Brigade Combat Teams (Stryker, Armor and Infantry), Rangers and Special Forces in austere environments. Funding for this program was changed from FY 2026 and beyond due to reprioritization of resources across the Army portfolio.$$, NULL, NULL, NULL, NULL, NULL, 3926000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604840F_673501$$, $$0604840F$$, $$673501$$, $$Air Vehicle - Tech Refresh 3$$, 1212000, $$Technology Refresh 3 (TR-3) conducts post Critical Design Review (CDR) design activities. This effort will develop and deliver a TR-3 system through full flight- worthy certification and production readiness review for Lot 15. The design of TR-3 subsystems Integrated Core Processor (ICP), Aircraft Memory System (AMS), and Panoramic Cockpit Display Electronics Unit and Display Unit (PCD-EU, PCD-DU) configurations will contain new backplane technology, commercial operating systems, and modified middleware necessary to support Block 3F functionality and incorporation of all Block 4 capabilities. This work includes nonrecurring engineering for the development, test, and certification of the ICP, AMS, PCD-EU, and PCD-DU, and includes processing capacity to ensure long term viability for future capabilities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, $79.4M was expended for civilian pay expenses in this project element, and in FY 2025, $66.7M is forecasted for civilian pay expenses in this project element.$$, 1212000, NULL, NULL, NULL, NULL, 243761000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604840F_673502$$, $$0604840F$$, $$673502$$, $$Air Vehicle Block 4 Planning & Sys$$, 431867000, $$The F-35 Air Vehicle Program Management Office (AV PMO) development portfolio includes efforts to improve the F-35 air vehicle lethality, survivability, and interoperability in response to emerging threats outlined in the National Security Strategy and Operational Plans. The AV PMO delivers these capabilities utilizing a Continuous Capability Development and Delivery (C2D2) strategy combining traditional hardware upgrades and agile software integration processes. F-35 Block 4 Modernization is designed to counter the full spectrum of evolving near-peer enemy threats to ensure US and Allied forces have freedom of operation even in the face of advanced adversary Anti-Access/Area Denial (A2/AD) capabilities. As designed, Block 4 consists of three principle lines of effort: development of software-based capabilities, development and integration of new and modernized aircraft hardware which enable the development of new capabilities, and new weapons integration. Efforts under the Air Vehicle / Block 4 Planning and Systems Engineering project range from requirements decomposition and preliminary design of capabilities through completion of Developmental Flight Test. These activities are a continuation of the previous Block 4 developmental contracts, and include activities required to enable the successful completion of Flight Test, to include select facility upgrades required for research, development, test and evaluation. Block 4 upgraded capabilities and continuous improvements will maintain Air System viability against the evolving threats indicated in the Electronic Warfare Initial Capabilities Document (ICD), the Fifth Generation Fighter Modernization ICD, and the Block 4 Capability Development Document (CDD). Additionally, the Block 4 capabilities will reduce life cycle cost, improve Air System Integration, and improve operational suitability. Weapons integration efforts under this project deliver increased lethality, effectiveness, situational awareness and operational flexibility, and include M-code GPS compatibility, Advanced Integrated Fire Control implementation, network enabled weapons, increased Air-to-Air missile carriage, and employment envelope expansion. Beyond Line of Sight (BLOS) efforts under this project will deliver increased range and effectiveness of the F-35, by providing improved interoperability across joint platforms within a highly contested environment. Included in the Air Vehicle (AV)/Block 4 Planning and Systems Engineering effort is both Prime and Government Systems Engineering Support needed for Avionics/ Electronic Warfare and Weapons Integration efforts to include studies, analysis and risk reduction efforts. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, $79.4M was expended for civilian pay expenses in this project element, and in FY 2025, $66.7M is forecasted for civilian pay expenses in this project element.$$, 431867000, NULL, NULL, NULL, NULL, 635169000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604840F_673503$$, $$0604840F$$, $$673503$$, $$Test and Evaluation (T&E)$$, 289578000, $$Integrated Test activities in support of C2D2, to include Lockheed Martin support at all test sites. Non-recurring engineering required to plan for the service life extension of existing DT aircraft and modifications necessary to bring DT aircraft fleet to a more production-representative and sustainable configuration, and to develop flight test instrumentation and release test software to meet Block 4 requirements. Additional upgrades required to support development and evaluation of improvements driven by changes in the threat environment and as identified in the Electronic Warfare ICD, the Fifth Generation Fighter Modernization ICD, and the Block 4 Capability Development Document (CDD). Efforts include non-recurring engineering and procurement of a test article to evaluate service life of F-35B STOVL Aircraft. Integrated test also supports the evaluation of upgrades to ALIS, fielding of ODIN Base Kits, regression testing of fielded weapons upgrades, and various validation/verification efforts. Costs in the Accomplishments/Planned and Program R2A section have been broken out into the following R-2A categories: Development Foundation Contract, Development Test, Operational Test, Future Flight Test Capabilities/Investments, and Digital Infrastructure. Updated Major Thrust title of "Ground Test and Simulation Infrastructure (GTSI)" to "Digital Infrastructure (DI)" for PB2026. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, $79.4M was expended for civilian pay expenses in this project element, and in FY 2025, $66.7M is forecasted for civilian pay expenses in this project element.$$, 289578000, NULL, NULL, NULL, NULL, 474516000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604840F_673504$$, $$0604840F$$, $$673504$$, $$Propulsion (PP)$$, 120967000, $$Propulsion F135 projects within the Continuous Capability Development & Delivery (C2D2) are provided for developmental efforts for propulsion systems and test engine requirements such as Block 4 Integrated Flight Test Support, Engine Flight Test Mechanics, Flight Test Engineering, Engine Hardware, Test Engine Procurements, research, component, and capability development, prototypes, various studies, costs integral to support the developmental stages for F-35 engine modernization, affordability drivers for top engine availability degraders, and improvement to support the F135 Propulsion System for the F-35 Air Vehicle. Testing and development of the three F-35 aircraft variants require engine propulsion funding to enable continued flight hours. Flight hours are budgeted and planned to meet the Block 4 Flight Test timelines and required Flight Test support. Transition of Flight Test Support requirements to organic capability includes efforts performed by contractor and government installations, Autonomic Logistics Information System / Operational Data Integrated Network (ALIS/ODIN) transition, replacement of development-only hardware, and updating Joint Technical Data (JTD) packages as required. The F-35 engine is being modernized with the F135 Engine Core Upgrade (ECU), which is part of the Engine, Power, and Thermal Management Modernization (EPM) program. The F135 ECU is projected to recapture engine life for increased affordability while providing additional power and cooling capacity to support future mission systems enhancements for the global F-35 fleet. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, $79.4M was expended for civilian pay expenses in this project element, and in FY 2025, $66.7M is forecasted for civilian pay expenses in this project element.$$, 120967000, NULL, NULL, NULL, NULL, 196640000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604840F_673505$$, $$0604840F$$, $$673505$$, $$Maintenance Systems (MxS)$$, 39573000, $$Autonomic Logistics Information System (ALIS) is the current F-35 program solution for delivering core maintenance and logistics information solutions to F-35 warfighters. ALIS will continue to deliver the core logistics and maintenance infrastructure requirements for the F-35 enterprise as ALIS evolves into Operational Data Integrated Network (ODIN). ALIS includes features such as aircraft scheduling, training delivery, record keeping, technical data delivery, supply chain management, maintenance management, pilot and maintenance debriefing, and mission planning. Current ALIS development efforts are focused on low cost and high return investments that provide a high confidence return on investment in the short term, significant warfighter impact, and/or offer synergy with ODIN development efforts. ODIN will incrementally provide a modern, user-friendly integrated information system for the F-35 to deliver core maintenance and logistics information solutions. ODIN will be comprised of multiple elements to include modern hardware, architectures, software development methods, data environments, and platforms. Leveraging agile and modern software development practices, ODIN will serve as the primary logistics tool to support F-35 warfighter operations, health and diagnostics, mission planning, supply chain management, maintenance, and training. ODIN will substantially decrease F-35 administrator and maintainer workload, increase readiness rates for all F-35 variants, and allow software engineers to rapidly develop and deploy updates in response to changing warfighter requirements and improve data management, quality, and integrity. The ALIS to ODIN transition is intended to enable holistic fleet management, improve performance, enhance readiness, and reduce costs to the F-35 program. ODIN is comprised of both hardware and software which support the flow of Unclassified and Classified aircraft and maintenance-related data. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, $79.4M was expended for civilian pay expenses in this project element, and in FY 2025, $66.7M is forecasted for civilian pay expenses in this project element.$$, 39573000, NULL, NULL, NULL, NULL, 91711000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604840F_673506$$, $$0604840F$$, $$673506$$, $$Combat Data Systems (CDS)$$, 46716000, $$F-35 Combat Data Systems (CDS) Program Management Office mission include investment and modernization activities required for Block 4 development, integration, test and evaluation of Mission Data Hardware/Tools, Reprogramming Verification & Validation Systems (RVVS), and Mission Planning Software/Hardware, which includes the Next Generation Open Mission System (NOMS). Funding related to key deliveries to Electronic Warfare Squadrons and F-35 Operational Squadrons and enables government and contractor labor for mission planning and joint reprogramming enterprise. Other costs support Technology Investment for key Modernization / Innovation activities and Cloud based DevSecOps infrastructure. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, $79.4M was expended for civilian pay expenses in this project element, and in FY 2025, $66.7M is forecasted for civilian pay expenses in this project element.$$, 46716000, NULL, NULL, NULL, NULL, 90781000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604840F_673507$$, $$0604840F$$, $$673507$$, $$Training Systems & Simulation$$, 74332000, $$The F-35 Training Systems & Simulation Program Management Office (TSS PMO) development portfolio is aligned with the program's Continuous Capability Development & Delivery (C2D2) efforts and is organized in three primary lines of effort; Training System Capability Development (TSCD), Training Systems Investments (TSI) Roadmap, and Joint Simulation Environment (JSE) Development. Training System Capability Development (TSCD): Efforts will continue with a primary focus on alignment of Training System capabilities with other elements of the Air System. Specific efforts will include development of Block 4 capabilities to equivalent maturity of those in the Air Vehicle enabling release of one capability upgrade per year to the fleet, continued development of the Production Runtime Server (PRTS) - Pilot Training Device TR-3 equivalent - to enable Block 4 capabilities, continued development of Live-Virtual-Constructive (LVC) capabilities including Distributed Mission Training (DMT), and appropriate lab infrastructure to enable Training System development. Training Systems Investments (TSI) Roadmap: Development efforts will continue to focus on modernization of activities outlined in the TSS PMO roadmaps that will target the requirement of bringing higher fidelity training to the warfighter. Specific development and testing efforts focus on software architecture modernization, hardware architecture modernization, and Synthetic Threat Enhancement. Joint Simulation Environment (JSE): Development, integration and testing efforts will continue to focus on keeping F-35 In-A-Box (FIAB) software concurrent with aircraft capabilities and injecting complex threat/sensor models to establish an operationally representative simulation environment required for operational test trial validity, and the completion of Verification, Validation and Accreditation (VV&A) activities for F-35 Block 4 modernization. Efforts will include FIAB development, fidelity and capability upgrades to existing threats/sensors/weapons models, development of new threat/sensor/weapon models, and environment upgrades to enable effective verification of Block 4 capabilities. Efforts will continue toward expansion of JSE capability to F-35 Training Sites. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, $79.4M was expended for civilian pay expenses in this project element, and in FY 2025, $66.7M is forecasted for civilian pay expenses in this project element.$$, 74332000, NULL, NULL, NULL, NULL, 164462000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604840F_673508$$, $$0604840F$$, $$673508$$, $$Infrastructure & Support Costs$$, 130313000, $$The F-35 Joint Program Office equips U.S. and allied forces with operational F-35 weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The acquisition workforce funded in this program element will support development phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development. This funding does not include costs for base operating support civilian personnel. This program element supports both civilian pay and non-pay support requirements. Additional infrastructure and program management support costs include travel, supplies, contractor support including advisory and assistance support, off-base lease costs, program office IT, cybersecurity, model-based systems engineering, and risk reduction studies including audit readiness and affordability initiatives directly related to C2D2 development efforts. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, $79.4M was expended for civilian pay expenses in this project element, and in FY 2025, $66.7M is forecasted for civilian pay expenses in this project element.$$, 130313000, NULL, NULL, NULL, NULL, 130342000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604840F_673509$$, $$0604840F$$, $$673509$$, $$DevSecOps$$, 19870000, $$The F-35 Software Development, Security & Operations (DevSecOps) Cloud platform environment allows for US Government and contracted software development teams to produce, test and deploy capabilities for F-35 supported Project Management Offices (PMO) and Directorates. This includes providing support to the Combat Data Systems (CDS), Air Vehicle (AV), Maintenance Systems (MxSYS), Propulsion, Training Systems and Simulation (TSS) PMOs, and Directorate of Engineering. The mission of DevSecOps is to provide a centralized F-35 Data repository, a consolidated F-35 software development environment, and support for system development lifecycle (SDLC) of the F-35 platform, allowing for rapid release cycles to keep the F-35 ahead of its adversaries. Investment in, and modernization of, DevSecOps include efforts to support F-35 Software modernization efforts, develop organic government software capabilities, support SDLC and flight testing capabilities, enhance the security posture of the software development pipeline, and support goals of reducing long-term on-premise infrastructure environments cost, ultimately resulting in reducing fleet delivery timelines. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, $79.4M was expended for civilian pay expenses in this project element, and in FY 2025, $66.7M is forecasted for civilian pay expenses in this project element.$$, 19870000, NULL, NULL, NULL, NULL, 40768000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604840F_673510$$, $$0604840F$$, $$673510$$, $$Utility and Subsystem Support to$$, 27332000, $$The Power Thermal Management Upgrade (PTMU) program will provide the required power and cooling upgrade to the current F-35 thermal management system to meet the estimates for a 5th Generation F-35 fighter. During development, air vehicle cooling requirements grew to exceed planned bleed air extraction. To provide the necessary bleed air, the engine was required to run hotter, and early engineering assessments indicate that this increase in operating temperature decreases engine life, resulting in earlier depot inductions and an increase in life cycle cost. Future capabilities and mission systems will be limited by PTMS cooling capacity. With threats continuing to develop, the F-35 requires new mission systems to out pace the emerging threats to remain relevant and lethal. This upgrade will consist of modifications to the current Power Thermal Management System (PTMS), Fuel Thermal Management System (FTMS), and Electrical Power System (EPS). This work includes nonrecurring engineering for the development, test, and certification of the upgraded PTMS, FTMS, and EPS systems to ensure suitable cooling is available for future capacities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, $79.4M was expended for civilian pay expenses in this project element, and in FY 2025, $66.7M is forecasted for civilian pay expenses in this project element.$$, 27332000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604840F_674871$$, $$0604840F$$, $$674871$$, $$Information Operations Technology$$, 334000, $$Procure Microsoft 365 Enterprise Licensing Upgrades for Improved Zero Trust (ZT) Capabilities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, $79.4M was expended for civilian pay expenses in this project element, and in FY 2025, $66.7M is forecasted for civilian pay expenses in this project element.$$, 334000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604850N_2368$$, $$0604850N$$, $$2368$$, $$SSN(X) Class Submarine$$, 365987000, $$SSN(X) will be designed to increase to counter the growing threat posed by adversaries in strategic competition for undersea supremacy. It will provide greater speed, increased horizontal payload capacity, improved signatures, flexibility to adapt to future threats, and higher operational availability. SSN(X) will conduct full spectrum undersea warfare and be able to employ and coordinate with a larger contingent of remote autonomous systems (RAS) and sensors as a force multiplier. This project encompasses Navy RDT&E efforts required to design the next SSN.$$, 365987000, NULL, NULL, NULL, NULL, 162272000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604852A_FE8$$, $$0604852A$$, $$FE8$$, $$Vehicle Protection Suite$$, 76903000, $$Current ground combat vehicle platforms and tactical wheeled vehicles lack the ability to effectively detect, track, divert, disrupt, neutralize, or destroy incoming direct or indirect fired threat munitions. Current solutions to defeat these threats, Explosive Reactive Armor (ERA) and Slat armor, do not provide preemptive or active protection and impose secondary blast hazards to crew, dismounted soldiers, and adjacent vehicles and equipment. The Suite of Vehicle Protection Systems will develop, mature and integrate solutions onto multiple ground combat vehicles and tactical vehicles to increase the protection of the Army's ground systems from both current and next generation direct or indirect fired threat munitions. The Vehicle Protection Suite (VPS) Project (FE8) will design, mature, integrate, evaluate and field combinations of active, reactive, and passive protection capabilities and leverage both Horizontal Technology Integration (HTI) principles and the Modular Open System Architecture with the Army's Vehicle Protection System Base Kit (VBK) to develop tailored vehicle Survivability Sets specific to platforms that will mitigate existing protection gaps, allow for future technology insertion to mitigate and defeat evolving threats, and minimize the impact to the current capabilities hosted on Army ground combat and tactical vehicles. The protection capabilities will leverage technologies across a spectrum of survivability mechanisms including detection avoidance, threat detection, threat intercept and threat mitigation.$$, 76903000, NULL, NULL, NULL, NULL, 70384000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604854A_516$$, $$0604854A$$, $$516$$, $$Paladin/FAASV$$, 12484000, $$Project 516 is to modernize the field artillery to address obsolescence, improve performance and address emerging threats. The Self-Propelled Howitzer is an indirect fire weapon system with the ability of delivering accurate, long range, lethal and non-lethal cannon fires in support of both Combined Arms Maneuver (CAM) and Wide Area Security (WAS) operations. The Self-Propelled Howitzer and Ammunition Resupply Vehicle can be employed within any Brigade Combat Team formation to neutralize, suppress, or destroy enemy forces, while providing protected transport of a field artillery howitzer section on the modern battlefield. This effort will include system usage and optimization studies, simulations, development engineering, Line Replacement Unit (LRU) prototype development and procurement and validation for incremental upgrades of field artillery.$$, 12484000, NULL, NULL, NULL, NULL, 40939000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_3235$$, $$0605502N$$, $$3235$$, $$Marine Corps STTR Program$$, 0, $$The Small Business Technology Transfer (STTR) program requires Federal agency that has an extramural budget for Research and Development (R&D) in excess of $100,000,000 to set aside 0.45% for STTR. This funds cooperative R&D between small businesses and research institutions. The goal of the STTR program is to facilitate the transfer of technology developed by a research institution through the entrepreneurship of a small business concern.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604854A_DH7$$, $$0604854A$$, $$DH7$$, $$Next Generation Howitzer$$, 68378000, $$Project DH7 supports the Howitzer Modernization. The US Army modernized howitzer will provide highly mobile, survivable, versatile, transportable, long range, lethal fires in support of Army Transformation Initiative. This project supports the Mobile Tactical Cannon Directed Requirement (MTC-DR) to provide an enhanced capability reducing emplacement and displacement times, increasing crew survivability and protection, providing greater mobility, and affords improved fire support capability for Field Artillery formations well beyond the capability of the current howitzer systems. Fiscal Year (FY) 2026 funding supports the enhancements, integration, and testing of system of systems to include, but not limited to, artillery weapon system, ammunition, and fire control systems to achieve desired firing range and lethal fires effects on targets, as necessary for Artillery unit operations.$$, 68378000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604854A_HB6$$, $$0604854A$$, $$HB6$$, $$Mobile 155MM Howitzer$$, NULL, $$Project HB6 supports the mobile howitzer program. The Mobile Howitzer is a Self-Propelled, Wheeled Howitzer that provides lethal, proactive counter-fire essential for the survivability of the maneuver formations and other close support fires as required. The Mobile Howitzer improves the Field Artillery Battalion's ability to maintain pace with its supporting maneuver formations and survive against responsive, counter-fire from near-peer threats with rapid displacement and emplacement times. The mobile howitzer will improve tactical mobility and system survivability compared to existing towed howitzer systems. Development efforts, prototyping, system evaluations, and technology evaluations will focus on attributes such as improved emplacement and displacement times, driving speed, and crew protection capabilities, all without sacrificing lethality versus existing and future towed howitzer systems. Technology evaluations will leverage both 105mm and 155mm howitzers to understand benefits and limitations of potential enabling technologies.$$, NULL, NULL, NULL, NULL, NULL, 5000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604858F_640410$$, $$0604858F$$, $$640410$$, $$Tech Maturation and Risk Reduct/$$, 6481000, $$The DoD requires counter small, unmanned aircraft system (C-sUAS) defeat options with minimal collateral damage in situations where friendly forces and/or civilians are in close proximity to the threat, or where local regulation does not allow for electronic attack or kinetic effectors that have broad down range impact. Specifically existing solutions poorly equipped to be effective against higher speed and multiple targets (e.g salvos or swarms). The funding will directly support Defense Innovation Unit (DIU) Replicator 2 Commerical Solutions Opening (CSO) effort to onboard additional low collateral defeat (LCD) options into the Department of the Air Force (DAF) C-sUAS system. Potential options could fall under localized directed energy, kinetic with low-collateral risks, capture/entanglement, localized electronic attack, and/or other novel effectors.$$, 6481000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604858F_645350$$, $$0604858F$$, $$645350$$, $$Experimentation$$, 14342000, $$The Experimentation project funds experimentation campaigns to explore new concepts and their applications in operationally relevant environments and within a system-of-systems warfighting context. Operational Experimentation Campaigns are directly aligned and integrated with the OSD and DAF priorities. Concepts and enabling technologies explored in this activity inlcude but are not limited to target custody; counter-targeting; airborne targeting and tracking; autonomy; spectrum warfare; artificial intelligence; machine learning; expeditionary base defense; agile combat operations; position, navigation, and timing; and joint all-domain operations. These technologies hold great promise; yet their transition to acquisition programs and fielded capabilities is typically hampered due to uncertainties regarding their military utility and organizational adoption. Experimentation campaigns assess hypotheses that new capabilities will deliver decisive competitive advantage against our adversaries in a dynamic threat environment. These campaigns dramatically shorten and reduce the overall cost of the acquisition process by delivering robust information including operational utility assessments, training, tactics, and procedures (TTPs), total life cycle cost estimates, preliminary product support strategy, reliability and maintainability metrics, operational utility assessments and Doctrine, Organization, Training, Materiel, Leadership and Education, Personnel, Facilities and Policy implications. Campaigns reduce follow-on acquisition and implentation risk thru early accomplishment of key learning objectives. A key element of the experimentation campaigns is strong stakeholder partnerships and buy-in from senior DAF leadership including the Secretary of the Air Force, HAF/A5/7, HAF/A8, US Space Force Futures and Integration, Office of the Assistant Secretary of the Air Force for Acquisition, Technology and Logistics, warfighting Major Commands and Combatants Commands (capability recipients/end users), Space and Missile Systems Center, and Air Force Material Command (capability developers) that enables rapid transition of capabilities when operational utility, affordability, sustainability, and industrial capacity meet the Department of Air Force needs. Experimentation campaigns are centered on an operational level warfighting concept to provide context for assessment. They use wargaming, simulation, demonstrations, and field/flight experimentation to evolve, refine, and validate the warfighting concepts leading to solid, evidence-based materiel and non-materiel capability development approaches with associated recommendations. Experimentation campaigns improve the effectiveness of operations by refining concepts and generating new information to address challenging threats of the future which aids the fielding of advanced technologies by providing the credible evidence needed to make sound strategic decisions and investment choices. Warfighting concepts evolve based on the latest threat assessments and the Experimentation Campaigns are likewise modified to ensure the Department of the Air Force retains a competitive advantage. Much of the Operational Experimentation efforts are more thoroughly described at higher classification levels. Experimentation is focused on rapid learning and then pivoting existing or future capability development efforts based on that knowledge to ensure the most pressing operational gaps are addressed and our warfighting advantages are preserved. Further details can be provided in the appropriate forum. These funds may be used for program management support costs, but are not limited to, hardware, software, travel, contractor support services, civilian pay, supplies, facilities, infrastructure.$$, 14342000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604858F_645351$$, $$0604858F$$, $$645351$$, $$Prototyping$$, 15141000, $$The prototyping project enables demonstration of emerging technologies in an operational environment to determine and evaluate the competitive advantage against our adversaries, how the technology is integrated into the future fight, and acquisition pathways to deliver warfighter capabilities. Lifecycle prototyping investments focus on three major thrusts: (1) advancing capabilities of legacy weapon systems, (2) militarizing novel, mature commercial technologies, and (3) exploring partnerships with Department of the Air Force Program Executive Officers to rapidly transition technologies. Prototype project investments that advance capabilities of legacy weapon systems focus on kinetic energy effectors for base defense and expeditionary employment operations, and software-defined electronic warfare and communication capabilities. Prototype projects that seek to militarize novel, mature commercial technologies will focus on artificial intelligence, autonomy, cyber warfare capabilities, digital engineering, and novel weapon and aircraft technologies. Other areas may be pursued as the technology landscape evolves. This program element may include necessary civilian pay expenses required to manage, execute, and deliver emerging technologies. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2025 $0.997 million was expended for civilian pay expenses in this program element, and in FY 2026 $2.504 million is forecasted for civilian pay expenses in this program element.$$, 15141000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604858F_645352$$, $$0604858F$$, $$645352$$, $$Architecture Design and$$, 98869000, $$In September 2022, the Secretary of the Air Force (SecAF) directed the standup of the DAF Integrating Program Executive Office for Command, Control, Communication and Battle Management (DAF PEO C3BM). The construct emerged out of the Operational Imperatives (OI) analysis that identified a significant need for C3BM integration and a greater level of systems engineering and technical discipline across the enterprise to ensure the effectiveness of ABMS in supporting DAF operations. Notably, DAF PEO C3BM combines the previous efforts of the DAF Rapid Capabilities Office (RCO) ABMS program and the DAF Chief Architect Office (CAO). Furthermore, DAF PEO C3BM works in a federated manner with other PEOs across the DAF with C3BM equity to orchestrate end-to-end capability delivery. By bringing the ABMS and CAO portfolio of programs and authorities under a single PEO and then conferring unto that PEO the responsibility to integrate broader DAF battle management and C2 capabilities, one organization now has the architectural authorities to direct technical integration activities across the DAF while also having the acquisition authorities of a PEO to execute organic materiel solutions to field a survivable, distributable command and control capability into the integrated DAF BATTLE NETWORK. Architecture Design and Evaluation is directed by the DAF PEO C3BM with oversight by the Secretary of the Air Force along with the Chief of Staff of the Air Force, Chief of Space Operations, and Senior Acquisition Executive. This activity is supported by the Air Force Research Laboratory. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Department of the Air Force Tech Architecture. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F, 0605831F and/or 0604858F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 98869000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604860F_644860$$, $$0604860F$$, $$644860$$, $$Operational Energy and$$, 0, $$The Operational Energy and Installation Resilience program develops, matures, prototypes, demonstrates, and assesses technologies, software, and processes for decreasing operational energy risk and increasing installation resilience. The Air Force is the Department of Defense largest consumer of operational energy and requires resilient installations as power projection platforms to execute its missions. Technology transition, agile software development, and process integration efforts with a focus in these areas enable the Air Force to optimize operational energy use for maximum combat capability and mitigate multi-domain energy threats to installations. The objective of this program is to prioritize, validate performance in a relevant environment, and facilitate implementation of the validated solutions. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.688 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.790 million is forecasted for civilian pay expenses in this program element.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604860F_644861$$, $$0604860F$$, $$644861$$, $$Operational Energy$$, 31409000, $$The Operational Energy project develops, matures, prototypes, and demonstrates technologies, software, and processes focused on optimizing energy usage to maximize combat capability. Activities include mission planning and scheduling optimization, mobility fleet optimization, aircraft drag reduction technologies, and energy supply chain and logistics efforts. As DOD's largest consumer of operational energy, these energy-focused efforts facilitate implementation of validated solutions that increase weapon system and platform capabilities (range, endurance, number of sorties refueled, etc.) and mitigate supply chain risk for DoD's largest consumer of operational energy, the Department of the Air Force. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.688 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.790 million is forecasted for civilian pay expenses in this program element.$$, 31409000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604860F_644862$$, $$0604860F$$, $$644862$$, $$Installation Resiliency$$, 18051000, $$Installation Resiliency projects develop, mature, prototype, and demonstrate technologies, software, and processes focused on increasing installation energy resilience to ensure energy availability and reliability sufficient to provide for mission assurance and readiness. Supporting infrastructure is a critical and integral component of our weapon systems, and joint operations rely on connectivity across the Department of the Air Force enterprise. The Department of the Air Force requires resilient infrastructure and installations to execute its missions. Activity areas include Advanced Nuclear, Mission Resilience Digital Transformation, Resilient Energy technology, Flightline Modernization, and Energy for the Tactical Edge. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.688 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.790 million is forecasted for civilian pay expenses in this program element.$$, 18051000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604873C_MD40$$, $$0604873C$$, $$MD40$$, $$Program Wide Support$$, 2089000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System, as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs, therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 2089000, NULL, NULL, NULL, NULL, 37599000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604873C_MD96$$, $$0604873C$$, $$MD96$$, $$Long Range Discrim Radar (LRDR)$$, 58354000, $$The LRDR program is a crucial component of the Missile Defense Agency (MDA) mission, playing a significant role in the development and deployment of a layered Missile Defense System. This system is designed to defend the homeland from missile attacks of all ranges, in all phases of flight. The LRDR's contribution provides persistent long-range midcourse discrimination, precision tracking and hit assessment, thereby enhancing the Missile Defense System Homeland Defense Capability. Additionally, the LRDR program supports the United States Space Force's (USSF) Space Domain Awareness (SDA) and Space Object Identification (SOI) mission areas, further underlining its importance. The LRDR Program Element includes the requirements to design, develop, integrate, deliver, field, and sustain the LRDR. The LRDR operates in the S-band frequency with a scalable and open systems architecture to mitigate evolving threats and integrates into the Missile Defense System through the Command and Control, Battle Management, and Communications (C2BMC) system. The LRDR will incorporate discrimination improvements to enhance its effectiveness against advancing threats by discriminating and identifying re-entry vehicles with a higher degree of confidence to improve system performance and conserve ground-based interceptor inventory. The LRDR is comprised of an equipment shelter, two radar array faces, a mission control facility for radar operations, and supporting facilities and infrastructure. The Secretary of the Air Force approved Clear Space Force Station (CSFS), formerly known as Clear Air Force Station, AK as the LRDR site. The USSF Space Operations Command is the designated Lead Major Command. LRDR completed initial fielding on December 6, 2021. MDA pursued an incremental fielding approach in cooperation with the Northern Command, the Space Command, and the USSF. Early use fielding of the LRDR SDA capability occurred on March 27, 2024. LRDR was added to the Missile Defense System Operational Capability List (OCL) for SDA on December 20, 2024. LRDR Homeland Defense capability is planned to be added to the OCL in 3Q FY 2025. Operational Acceptance (OA) by the USSF is scheduled for 4Q FY 2025 following the completion of the LRDR Homeland Defense trial period and the operational Flight Test Other (FTX)-26a. The LRDR Program Element supports the fielding of the LRDR capabilities described below: - The LRDR capability that is added to the Missile Defense System OCL in 4Q FY 2025 includes increased Missile Defense System raid handling capability, conventional and advanced discrimination capabilities, implementation of mitigation techniques in denied environments, Missile Defense System integration and remote ops via C2BMC, including cyber protection/interoperability, autonomous and cued acquisition capabilities, initial sensor bias reporting, inherent SDA capability, and Electronic Protection (EP) capabilities.$$, 58354000, NULL, NULL, NULL, NULL, 1302728000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604874C_MD40$$, $$0604874C$$, $$MD40$$, $$Program Wide Support$$, 53146000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 53146000, NULL, NULL, NULL, NULL, 168472000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604874C_MD80$$, $$0604874C$$, $$MD80$$, $$Next Generation Interceptor$$, 1529268000, $$The Improved Homeland Defense Interceptors provides the development, integration, and testing of a Next Generation Interceptor AUR consisting of an integrated boost vehicle/multiple kill vehicle payload capable of surviving both natural and hostile environments while countering the allocated threat space. Meeting the United States Northern Command's (USNORTHCOM) Operational Needs for Homeland Defense. The Next Generation Interceptor will provide USNORTHCOM a solution that is lethal across the specified threat space; upgradeable to address future and advancing threats; and fully integrated into the Ground-Based Midcourse Defense (GMD) Weapon System (GWS). The Missile Defense Agency (MDA) issued a Request for Proposal in FY 2020 and competitively awarded two best value contracts on March 24, 2021, for a Next Generation Interceptor acquisition, which covers the development, integration, and testing of an AUR consisting of an integrated boost vehicle/multiple kill vehicle payload. The MDA maintained the competitive environment through Preliminary Design Reviews (PDR) and Knowledge Point (KP) 1 in FY 2024 to reduce technical risk, encourage schedule acceleration, and support the Department's ability to field a system capable of negating the expanding threat. With the PDR/KP #1 data, the MDA selected a single Prime contractor for continued development through a CDR; qualification; integration with the GWS; Peculiar Support Equipment (PSE) to support AUR emplacement and in-silo maintenance; ground cyber and flight testing; and AUR production.$$, 1529268000, NULL, NULL, NULL, NULL, 3500006000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604875D8Z_220$$, $$0604875D8Z$$, $$220$$, $$Electromagnetic Warfare$$, 2461000, $$The FY 2026 request for Electromagnetic Warfare (EW) includes $2.461 thousand of discretionary funds which supports EMSO capability recommendations for Departments priorities to include Golden Dome Homeland defense and Strategic Deterrence within the Indo Pacific region. The EW project funds capability advancements that focus on transitioning programs to the warfighter. The EW line also aligns Department efforts with key allies under the AUKUS Pillar II EW working group, to institutionalize cooperative acquisition and ultimately increase warfighter lethality.$$, 2461000, NULL, NULL, NULL, NULL, 17314000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604875D8Z_875$$, $$0604875D8Z$$, $$875$$, $$Portfolio Systems Acquisition (PSA)$$, 6166000, $$The FY 2026 request for Portfolio Systems Acquisition (PSA) includes $6.166 thousand of discretionary funds which supports air, land, sea, and undersea warfare programs and munitions with a focus on MDAPs and integrated acquisition portfolio management. These efforts entail integrated roadmaps to support acquisition investment decisions, and assessments of MDAPs and other linchpin acquisition efforts in a capability area context. PSA funds provide support in the areas of (1) integrated acquisition portfolio analysis; (2) acquisition roadmaps; and (3) acquisition decision support. These efforts guide the development and fielding of integrated acquisition systems in order to achieve Joint mission capabilities across the operational domain to defend against any global threats.$$, 6166000, NULL, NULL, NULL, NULL, 41369000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604876C_MD40$$, $$0604876C$$, $$MD40$$, $$Program Wide Support$$, 1305000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 1305000, NULL, NULL, NULL, NULL, 19562000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604876C_MT07$$, $$0604876C$$, $$MT07$$, $$THAAD Test$$, 36479000, $$Terminal High Altitude Area Defense (THAAD) Test conducts Missile Defense System Flight Tests and Ground Tests with other Missile Defense System elements (such as Army Navy / Transportable Radar Surveillance and Control (AN/TPY-2), Missile Defense System Command, Control, Battle Management, and Communication (C2BMC), Phased Array Tracking Intercept of Target (PATRIOT), and Aegis) in accordance with the IMTP. THAAD Test coordinates with Operational Test Agencies, conducts all pre and post flight test, ground test, testing of cyber security enhancements, and wargames and exercises requirements.$$, 36479000, NULL, NULL, NULL, NULL, 385335000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604878C_MD40$$, $$0604878C$$, $$MD40$$, $$Program Wide Support$$, 5774000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 5774000, NULL, NULL, NULL, NULL, 14269000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_3245$$, $$0605502N$$, $$3245$$, $$SBIR CRP-SSP$$, 0, $$Originally established in Section 252 of the 2006 NDAA Public Law No. 109-163, the Commercialization Readiness Program (CRP) may not use more than up to 1% of the SBIR to be used for payment of expenses incurred to administer CRP. 15 USC 638(y) authorizes the DoD to administer a Commercialization Readiness Program to accelerate the transition of SBIR/STTR-developed technologies, products, and services to Phase III, including the acquisition process.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604878C_MT09$$, $$0604878C$$, $$MT09$$, $$AEGIS BMD Test$$, 147844000, $$The Aegis Ballistic Missile Defense (BMD) Test program element is responsible for the planning, design, and execution of developmental and operational flight, ground, and cybersecurity testing of Aegis Based Defense hardware and software to characterize and validate joint deployable Missile Defense and Navy Integrated Air and Missile Defense capability to counter the allocated threats and ensure that these capabilities are operationally effective, suitable, and survivable upon transfer to the warfighter. Aegis Based Defense hardware and software are integrated into existing Aegis Weapon System baselines, Standard Missile (SM)-3 interceptor, and Navy's SM-6 interceptor. The Missile Defense Agency (MDA) works with the Director of Operational Test and Evaluation, the Navy's Operational Test and Evaluation Force, industry partners, and the Navy Warfare Centers in the designing, planning, safety, readiness, execution, data collection, pre-mission and post-mission analysis, and reporting. The system pre-flight predictions provide confidence in test execution by predicting element performance and exercising element interfaces. The system post-flight reconstruction replicates the Missile Defense System configuration, actual environmental conditions, and target dynamics observed in flight to anchor Modeling and Simulation (M&S) results. Aegis Ballistic Missile Defense participation in Hardware-in-the-Loop and integrated MDA level ground tests supports the operational capability fielding decisions.$$, 147844000, NULL, NULL, NULL, NULL, 990975000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604879C_MD40$$, $$0604879C$$, $$MD40$$, $$Program Wide Support$$, 2375000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 2375000, NULL, NULL, NULL, NULL, 27458000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604879C_MT11$$, $$0604879C$$, $$MT11$$, $$BMDS Radars Test$$, 66324000, $$This project provides activities for planning, analysis, and execution of Missile Defense System flight test events, including pre-and post-test ground testing (e.g. Digital and Hardware-in-the-Loop (HWIL) System Pre-Mission Tests and System Federation Validation Events). Sensor Test provides planning, analysis, and execution in accordance with the Ground Test Concept of Operations (CONOPS) supporting the Ground Test level of effort concept for Missile Defense System system-level ground tests identified in the IMTP. Test infrastructure funding provides for HWIL labs, Mission Operation Center/Mission Support Center (MOC/MSC), and program management required to operate and maintain a flight and ground test capability.$$, 66324000, NULL, NULL, NULL, NULL, 669231000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604880C_MC68$$, $$0604880C$$, $$MC68$$, $$Cyber Operations$$, 2293000, $$Sustain Missile Defense Agency (MDA) Department of Defense Information Assurance Certification and Accreditation Program (DIACAP) and Controls Validation Testing (CVT) activities, analysis of validation results, risk assessments and reviews of proposed Program Manager/Information Assurance Manager Plans of Action and Milestones for MDA Aegis Ballistic Missile Defense (BMD) mission systems. It maintains the Certification and Accreditation (C&A) data repository, capturing the DIACAP documentation (artifacts, validation results, and Information Assurance Risk Assessment results, and Designated Approving Authority (DAA) accreditation decisions) on all MDA Information Systems.$$, 2293000, NULL, NULL, NULL, NULL, 11947000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604880C_MD40$$, $$0604880C$$, $$MD40$$, $$Program-Wide Support$$, 848000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 848000, NULL, NULL, NULL, NULL, 18269000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604880C_MD68$$, $$0604880C$$, $$MD68$$, $$AEGIS Ashore$$, 21414000, $$Missile Defense Agency (MDA) is responsible for maintaining the Aegis Ashore Missile Defense Test Complex (AAMDTC) at the Pacific Missile Range Facility (PMRF). MDA uses AAMDTC in support of Ground Testing, Aegis Weapon System computer program development testing, fielding (with hardware upgrades), and proof of concept demonstrations. AAMDTC is capable of testing and developing both shore based and sea based Aegis capabilities. In support of European Phased Adaptive Approach Phase III, Aegis Ashore integrates the Aegis Ballistic Missile Defense (BMD) 5.1 and Standard Missile Block IIA capabilities into the Aegis Ashore sites. MDA will provide all upgrades to BMD capability, BMD specific mission equipment, and integration with existing Missile Defense System nodes for all Aegis Ashore sites.$$, 21414000, NULL, NULL, NULL, NULL, 1282948000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_3280$$, $$0605502N$$, $$3280$$, $$SBIR Due Diligence Program$$, 0, $$Each Federal agency required to establish an SBIR program may allocate not more than 2 percent of the funds allocated to the SBIR program of the Federal agency for the cost of establishing the due diligence program required under this subsection. (PL 117-183, Section 4 Foreign Risk Management (b)(3)(A), SBIR and STTR Extension Act of 2022).$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604887C_MD40$$, $$0604887C$$, $$MD40$$, $$Program Wide Support$$, 1580000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 1580000, NULL, NULL, NULL, NULL, 17694000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604887C_MT08$$, $$0604887C$$, $$MT08$$, $$Midcourse Test$$, 36745000, $$Missile Defense Midcourse Defense Segment Test provides flight, ground, and cyber testing of hardware and software to demonstrate an integrated capability to counter the allocated threats. The hardware and software is tested in an integrated environment with Missile Defense System Sensors; Command and Control, Battle Management, and Communications; United States Northern Command (USNORTHCOM) Warfighters; and national collection assets to assess and demonstrate the ability to defend the United States Homeland. Primary activities include planning, design, and execution of flight tests, ground tests, cyber tests; test resources; and program operations. Flight tests provide the opportunity to test actual hardware and software and to demonstrate Missile Defense System interoperability under operationally realistic conditions. Ground-Based Midcourse Defense Program participates in integrated Missile Defense System ground tests executed in both the Hardware-in-the-Loop (HWIL) lab environment and with deployed operational assets providing integrated performance data supporting hardware and software fielding decisions. The Ground-Based Midcourse Defense Program conducts cyber tests and participates in integrated Missile Defense System level cyber tests executed both in the HWIL lab environment and using operational assets providing performance data supporting cyber, operational resilience, and system survivability assessments. Test resources provide the infrastructure and laboratories to support the Ground Missile Defense (GMD) test program as well as day-to-day operations of the GMD test program to include support for test planning, execution, and post-event reconstruction. Program operations provides for technical and business management support of the test program.$$, 36745000, NULL, NULL, NULL, NULL, 637461000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604924D8Z_921$$, $$0604924D8Z$$, $$921$$, $$High Energy Tech Maturation$$, 5589000, $$This project is part of an overall Department of Defense strategy in Joint directed energy technology maturation and utility. Efforts within this project will focus on enabling next-generation directed energy weapons that engage threats at longer ranges with shorter engagement timelines in adverse environments with improved size, weight, and power requirements. These efforts complement, and will be closely coordinated with, other Department efforts directed at specific Service and Agency missions. This project builds upon other investments in directed energy technology maturation and utility by the Services and Agencies to harmonize Department efforts and eliminate duplication. As a result, efforts in this project will transition directed-energy technology to the Services and Agencies at a high enough technical readiness level for direct insertion into directed energy weapon systems. This project is executed via a rebranded technical program, a new technical program, and a new initiative within the JDETO. The rebranded technical program is the Directed Energy Tech Maturation Program, which enables (1) advanced prototypes in support of demonstrating mission-driven lethality and survivability and (2) test and evaluation in a relevant field environment with Joint-international participation. The new technical program is the Directed Energy Tech Utility Program, which enables (3) studies, analyses, and evaluations in mission-driven lethality and survivability that supports directed energy military utility assessments and (4) experimentation in an operationally relevant environment with Joint-international participation. Note that (1)-(4) are in alignment with the near-, mid-, and long-term goals of Department of Defense Directed Energy Roadmap and enable transition. The new initiative is the Joint Laser Weapon System Initiative. This initiative is also in alignment with the near-, mid-, and long-term goals of the Department of Defense Directed Energy Roadmap. Both the Directed Energy Tech Utility Program and the Joint Laser Weapon System Initiative are the result of mandatory funding in FY 2026.$$, 5589000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604932F_657011$$, $$0604932F$$, $$657011$$, $$LONG RANGE STAND-$$, 606955000, $$The Long Range Stand-Off (LRSO) Cruise Missile is a long-range survivable stand-off weapon capable of delivering lethal nuclear effects on strategic targets. LRSO will replace the currently fielded Air Launched Cruise Missile (ALCM) and will be integrated on both legacy and future bomber aircraft. The LRSO weapon system will be capable of penetrating and surviving advanced Integrated Air Defense Systems (IADS) from significant stand-off range to prosecute strategic targets in support of the Air Force's global attack capability and strategic deterrence core function. Funds may be used to address emerging or short-notice Diminishing Manufacturing Sources and Material Shortage (DMSMS) and supply chain issues. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 0.00M was expended for civilian pay expenses in this program element, and in FY25 0.00M is forecasted for civilian pay expenses in this program element. The program is conducting Engineering and Manufacturing Development (EMD) tasks to validate requirements to support Development and Operational Testing, and Production Readiness. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System      PE 0604932F / Long Range Standoff Weapon Development & Demonstration (SDD)$$, 606955000, NULL, NULL, NULL, NULL, 3774324000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604933F_655082$$, $$0604933F$$, $$655082$$, $$ICBM FUZE SUPPORT$$, 3252000, $$The Intercontinental Ballistic Missile (ICBM) Fuze Modernization Program has designed and currently producing a functionally equivalent replacement for the current Mk21 fuze that will provide a 20-year threshold, 30-year objective design life. Currently available Mk21/W87-0 fuze quantities do not meet United States Strategic Command's (USSTRATCOM) requirements and the current fuze is three times beyond its original ten year design life. The program will provide needed Minuteman III (MMIII) weapon system modifications, system testing, support/test equipment, data and training required to accommodate, field, and support the new Mk21 replacement fuze along with the W87-0 warhead as defined in the Air Force Global Strike Command's (AFGSC) Requirements Traceability Memo dated 2 December 2013. In addition, the Joint Requirements Oversight Council (JROC) signed the program's JROC Memorandum validating the operational requirement for the program on 6 December 2016. A replacement Mk21/W87-0 fuze is urgently required to meet warfighter requirements and to ensure operational capability. The Mk21 reentry vehicle and fuze is designed to be deployed on the current MMIII and LGM-35A Sentinel weapon systems. The US Air Force (USAF) developed the modernized Mk21 fuze using the Department of Energy National Nuclear Security Administration (DOE/NNSA) complex and a weapons system integration contractor. The DOE/NNSA complex consists of Sandia National Labs-California (SNL-CA), Sandia National Labs-New Mexico (SNL-NM) and Kansas City National Security Campus (KCNSC). The ICBM Fuze Modernization program leveraged technologies, parts, components, and development/production capabilities resulting from extensive fuze work performed by the US Navy (USN) and DOE/NNSA on the Mk5/W88 Alt 370 Fuze program. The Radar Module is the only common Major Component with Mk5/W88 Alt 370. The Pathlength Module, Thermal Battery Assembly, Missile Interface Controller Module, Launch Safety Device, Terminal Protection Device, and the Firing Set Interface Module share piece parts with the Mk5/W88 Alt 370 Firing Set, but are specific to the Mk21 Fuze. The ICBM Fuze Modernization Program replacement fuze is designed to integrate into the MMIII and the LGM-35A Sentinel weapon systems, to include support/ test equipment, data, flight test hardware, and training materials. The program conducted required system testing (including ground and flight tests). The program is coordinating Mk21 fuze replacement development efforts with the DOE/NNSA to synchronize USAF arming and fuze development activities with DOE/NNSA warhead requirements. When prudent, the program will conduct trade studies and initiate conceptual designs to address operational system issues and meet future requirements. The Fiscal Year 2026 budget request continues efforts to develop digital models and integrating the Fuze Mod into the MMIII and LGM-35A Sentinel weapon systems. As a cooperative USAF, USN, and DOE/NNSA acquisition, the USAF is executing the program using Department of Defense (DoD) Manual 5030.55 Joint Nuclear Weapons Life Cycle Activities (Phase 6.x process) while using the DOD 5000-Series instructions to meet Major Defense Acquisition Program (MDAP) statutory and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604933F / ICBM Fuze Modernization Development & Demonstration (SDD) regulatory requirements. The DOE/NNSA phase 6.x process is an iterative process that drives overlap and concurrency between activities and events that occur during the Engineering and Manufacturing Development (EMD) and Production and Deployment phases of the DoD 5000-Series Instruction. The program entered Phase 6.5 First Production on 6 March 2024. The first flight test was performed in FY 2019, the second flight test was performed in FY 2020, the third in FY 2022, and the final flight test was completed on 4 June 2024. The program was approved to enter Full Rate Production on 21 November 2024. The program is tailored to use the Joint Department of Defense - Department of Energy Phase 6.x processes for routine nuclear stockpile activities to align with USN and DOE/NNSA operations. The next phase will be 6.6 Full Scale Production. Program plans to enter Phase 6.6 during 3QFY2025. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024, 0.000M was expended for civilian pay expenses in this program element, and in FY 2025, 0.000M is forecasted for civilian pay expenses in this program element. FY 2025 RDT&E funding for PE 0604933F, ICBM Fuze Modernization, is in compliance with budgeted end items per the approved test strategy and FY 2024 Omnibus, Sec. 8059. The FY 2026 request was reduced by 0.583 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, 3252000, NULL, NULL, NULL, NULL, 1346043000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013A_FM9$$, $$0605013A$$, $$FM9$$, $$Information Technology for Criminal$$, 3095000, $$The project Criminal Investigation Management System (CIMS) is to develop, maintain, and operate a secure, unified comprehensive system of applications to support the Army's law enforcement (LE) mission and to transform the Department of the Army Criminal Investigative Division (DACID) Law Enforcement (LE) applications through continuous innovation and modernization to improve operational methodologies consistent with current LE community practices. FY 2026 Base dollars in the amount of $3.095 million will enable the continuous effort to increase and modernize the Criminal Investigation Management System (CIMS). Funds will allow the development and support of law enforcement data sharing in the Army Law Enforcement Community of Interest, as well as complying with mandated external sharing initiatives with DoD law enforcement agencies, select Army systems data sources which will be integrated into a single net-centric portal structure.$$, 3095000, NULL, NULL, NULL, NULL, 2599000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_3344$$, $$0605502N$$, $$3344$$, $$SBIR Trial Admin Program$$, 0, $$15 USC 638(mm)(1) authorized each Federal agency required to conduct an SBIR program to use not more than 3 percent of the funds allocated to the SBIR program of the Federal agency for administration of the program (while not explicitly stated in the law, the intent of this pilot program is to fund and maintain new initiatives).$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604940D8Z_940$$, $$0604940D8Z$$, $$940$$, $$Central Test and Evaluation$$, 542773000, $$The Central Test and Evaluation Investment Program (CTEIP) develops needed, high-priority Test and Evaluation (T&E) capabilities for joint/multi-Service requirements. CTEIP efforts include Hypersonics, Directed Energy, Cyber, Electronic Warfare, Nuclear Effects, Space, Autonomy and Multi-Domain Operations. Other Investments in test infrastructure align with objectives in the Strategic Plan for DoD T&E Resources for high priority test needs and common range Infrastructure. CTEIP uses a corporate investment approach to combine T&E needs from Service, Defense, and other Government agencies in order to maximize opportunities for joint efforts and avoid unwarranted duplication of test capabilities. CTEIP evaluates proposals and selects those that align to national strategic guidance, provide the greatest return on investment, make efficient use of limited test resources, leverage Service investment, and promote joint solutions to fill test capability gaps. CTEIP provides enterprise solutions that benefit the Department as a whole. These investments are needed so that test capabilities keep pace with U.S. and adversary technical advances as well as with quickly changing threats. The CTEIP includes special studies, analyses, project improvements, quick reaction efforts, and strategic planning related to test capabilities and infrastructure. CTEIP investments increase efficiency and reduce the cost of testing on DoD’s major ranges and test facilities. CTEIP provides efficiencies within the Department by sharing test resources that enable data collection and use between the test and training communities.$$, 542773000, NULL, NULL, NULL, NULL, 4675332000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604942D8Z_822$$, $$0604942D8Z$$, $$822$$, $$Director, Special Programs (DSP)$$, 1275000, $$Classified Program.$$, 1275000, NULL, NULL, NULL, NULL, 75050000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604944D8Z_548$$, $$0604944D8Z$$, $$548$$, $$DoD Special Programs$$, NULL, $$Classified Program$$, NULL, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605000BR_RD$$, $$0605000BR$$, $$RD$$, $$NUCLEAR$$, 14931000, $$The Counter Weapons of Mass Destruction (CWMD) Systems Development program element supports the development and demonstration of technologies and systems for the CWMD mission, including modeling and simulation capabilities, verification and monitoring technologies, and decision support systems.$$, 14931000, NULL, NULL, NULL, NULL, 52859000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605001E_MST-01$$, $$0605001E$$, $$MST-01$$, $$MISSION SUPPORT$$, 115673000, $$The Mission Support Program Element provides funding for the costs of mission support activities for the Defense Advanced Research Projects Agency. The funds provide personnel compensation for mission support civilians as well as costs for building rent, physical security, travel, supplies and equipment, communications, printing and reproduction.$$, 115673000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013A_099$$, $$0605013A$$, $$099$$, $$Army Human Resource System$$, 1374000, $$The Army Human Resource System Project (099) contains the following programs: ArmyIgnitED Modernization managed by the Program Executive Office Enterprise (PEO Enterprise) and Regional Level Applications Software (RLAS) managed by United States Army Reserves (USAR). 1. ArmyIgnitED: In support of recruiting and retention for a more educated workforce, ArmyIgnitED is an Army Credentialing and Continuing Education Services for Soldiers (ACCESS) program, 24/7 virtual financial management portal, and decision-support tool for 1) Active Duty, US Army Reserves and Army National Guard Soldiers to request Tuition Assistance (TA); 2) Cadets to request scholarship payments and 3) Department of the Army (DA) Civilians and Apprentices to request professional development funds. As an enterprise system, ArmyIgnitED streamlines eligibility verification for higher education funds and increases efficiencies through automated processes. The system supports Soldiers, Scholarship Cadets, DA civilians and apprentices pursuing post-secondary educational goals and professional development objectives. Army education counselors use it to provide educational guidance; Career Program Managers and Training Managers use it to manage civilian training; and Academic Institutions use it to deliver degree and course offerings and to report user progress and degree completions for approximately 1.4 million Soldiers, Cadets and civilians. ArmyIgnitED includes an automated registration tool that enforces policies and procedures, serves as a financial feeder for automated financial transactions, tracks academic / training progress within the system, and provides visibility of financial management and regulatory compliance of enrollment processes. ArmyIgnitED is hosted in the Air Force's Amazon Web Services (AWS) GovCloud (Cloud One) environment. FY 2026 Base Dollars in the amount of $1.374 million will continue to support enhancements during the CI/CD phase. FY 2026 planned capability enhancements include: Interfaces with Army Career Tracker (ACT), Academic Degree Training (ADT), Joint Service Transcript (JST), Interactive Media Instruction (IMI), Education Center Testing, and Institutional Delivered Credential (IDC). This is a decrease of $1.556 million from the FY 2025 requested level. 2. Regional Level Application Software (RLAS): RLAS is the United States Army Reserve Command (USARC) developed web-based application designed to assist Army Reserve Unit Commanders in accomplishment of critical day to day administrative tasks that support data information flow throughout all echelons Command levels within the Army Reserve. As the Army Reserve is geographically dispersed, RLAS efficiently leverages technology and remote execution of the following tasks: (1) Processes personnel actions to update USARC's official personnel database of record and maintain functionality of personnel actions not subsumed by IPPS-A; (2) Initiate, process, approve, publish and distribute Soldier Active Duty (AD) orders for Annual Training (AT), Active Duty Training (ADT), Active Duty Training School (ADTS), and Active Duty Orders Special Army Reserve (ADOS-RC); (3) Distribute, control, and execute Reserve Personnel Army (RPA) Appropriation for Request for Orders and Additional Drill Assembly processing; (4) Automated preparation and submission of Army Reserve Soldier AD Orders and Inactive Duty Training (IDT) payment requests; (5) Automated preparation and maintenance of Army Reserve Unit training schedules; and (6) Maintains reporting capabilities of critical personnel and resource management data for Army Reserve Commanders, USARC Staff, and Command echelons above and throughout USARC. RLAS is a Legacy Information System that operates as a Financial Feeder System to General Fund Enterprise Business Solution (GFEBS) official Accounting System of record.$$, 1374000, NULL, NULL, NULL, NULL, 536000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013A_184$$, $$0605013A$$, $$184$$, $$Installation Support Modules$$, 629000, $$This project supports the U.S. Army Coalition Interoperability Assurance and Validation (CIAV) Research Network. CIAV provides an enduring and agile capability to execute approved processes. The project provides a repeatable and persistent infrastructure within the assurance and validation Coalition partner environment designed to ensure the succinct exchange of critical mission data between Mission Partners throughout all phases of military operations. It also enables the Army's implementation of Mission Partner Environment (MPE) and Combined-Joint All Domain Command and Control. CIAV uses a mission-based interoperability approach to identify capabilities, limitations and associated operational impacts and provides recommendations to improve or resolve information exchange issues between the U.S. Army and its mission partners. Funding facilitates coalition interoperability information exchange issue in compliance with AR 34-1 Multinational Force Interoperability and DODI 8110.01, MPE Information Sharing Capability Implementation for the DOD. FY 2026 Base dollars in the amount of $0.629 million will fund comprehensive analysis of mission-based interoperability effectiveness, ensuring alignment with validated operational and technical requirements. Execute risk reduction events, mission network test cases, multinational interoperability assessments, and battle command system evaluations and support Coalition Interoperability Assessment and Validation (CIAV) testing with 22 nations connected to the CIAV test network.$$, 629000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013A_BY3$$, $$0605013A$$, $$BY3$$, $$Information Systems for Installations$$, 1625000, $$The Virtual Toolbox for Installation Mission Effectiveness (VTIME) is the Army's real-time planned installation common operating picture, analysis, visualization and planning tool. It serves as an integrating and processing hub for numerous Army Installation Modernization technologies supporting users across echelons. VTIME will support the Army installation enterprise with a near real-time common operating picture of data spanning functional areas and offer a modern analytic platform to support Army implementation of the Army Installations Strategy, Army Data Strategy, and Army Business Management Plan. VTIME has been prototyped as a hybrid cloud solution, being planned and prototyped to adapt commercially available technologies to integrate and understand diverse installation data sources and improve installation planning and operations. VTIME provides a novel capability able to apply artificial intelligence and machine learning to improve strategic, operational, and tactical installation decision-making, spanning functions such as facility investment planning, space and land assignment, master planning, and Garrison operations. VTIME is designed for hybrid-cloud implementations, to offer installations the ability to support operations under network-contested conditions. This integrated and comprehensive prototype can allow the senior commander to both maneuver in a complex battlespace by providing the ability to prevent, protect and recover from hazards and enable cost saving through improved decision-making and operational efficiencies, supporting future integrations of emerging installation operations modernizing technologies. Work is performed by the United States Army Engineer Research and Development Center. Work in this Project is related to, and fully coordinated with, PE 0605013A (Information Technology Development) and Project T05 (Army Business System Modernization Initiatives). Work in this Project supports the Army Installations Strategy as a critical enabler (data analytics) for modernization. Work in this Project complements the Office of the Assistant Secretary of the Army (Installations, Energy & Environment)'s Installation Modernization Pilot Program (AIMP2). FY 2026 Base dollars in the amount of $1.625 million will fund the migration of the cloud Virtual Toolbox for Installation for Mission Effectiveness (VTIME) components to cArmy, hardening and authorization of the Integrated Installation Planning (VIIP) initial operating capability and data interface agreements. Funds will complete design and partial integration of VTIME real-time decision-support solutions with production systems at Fort Benning. Funds will support acquisition planning activities for VTIME scaling to Army wide implementation.$$, 1625000, NULL, NULL, NULL, NULL, 987000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013N_2951$$, $$0605013N$$, $$2951$$, $$LIPHE/System Health$$, 2963000, $$Lifecycle Integrated Product Health Management (HM) Environment (LIPHE) will be an Integrated Lifecycle Failure Mode (FM) & HM Data application capturing the product system design associated with system functions, failure modes, and associated HM data requirements while enabling the linkage with platform collected operational HM and maintenance data. LIPHE will be a data application that associates Failure Mode definitions and signatures, system functions, and associated HM data requirements from stakeholder sources across a program's lifecycle. LIPHE will be an application that is both consumer and provider of agnostically administering FM & HM data definitions/data across NAE programs/platforms.$$, 2963000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502D8Z_502$$, $$0605502D8Z$$, $$502$$, $$Small Bus Innovation Research$$, 0, $$The goals of the Office of the Secretary of Defense (OSD) Small Business Innovation Research (SBIR) program is to stimulate technological innovation, increase private sector commercialization of federal research and development (R&D), increase small business participation in federally funded R&D, and foster participation by minority and disadvantaged firms in technological innovation. Leveraging the innovation of small business concerns is an important contributor to the development of the cuttingedge technologies that will generate decisive and sustained U.S. military advantages by increasing the readiness, modernization and lethality of the Joint Force. This program supports high priority projects within the DoD Components, their missions, and the Warfighter.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013A_DH1$$, $$0605013A$$, $$DH1$$, $$Operational Medicine Information$$, 5188000, $$The Operational Medicine Information Systems-Army (OMIS-A) Program Office provides modernized Operational Health Information Technology (OHIT) software applications to deployed Army medical personnel and units around the world. The OHIT software allows medical providers to electronically document patient care through the phases of care on the battlefield, from the moment of injury until the patient reaches a definitive care facility. With so many different roles and locations providing specific medical interventions at different stages of the patient transport process, electronic health record (EHR) documentation is critical for reasons such as patient safety, improved coordination of care, documentation accessibility across the battlefield, efficiency, accuracy and reliability of documentation, and better data analytics and reporting. The OMIS-A team collaborates with multiple stakeholders to ensure the battlefield EHR documentation data interfaces with other warfighting systems, such as the Army's Command and Control/Situational Awareness (C2/SA) systems so commanders at all echelons are informed in real-time on the patient movement status of injured Soldiers and the health status of their forces, allowing them to make informed decisions about troop readiness, resource allocation, and troop movement on the battlefield. The Soldier's battlefield EHR documentation data flows into the Military Health Systems EHR, MHS GENESIS, which will follow the Soldier through their military career and into the VA Healthcare system. The battlefield EHR data is critical for patient continuity of care and the availability of the battlefield EHR is pivotal in applying for and obtaining VA Disability compensation. Requirements in the operational environment are constantly evolving and to ensure the Warfighter's needs are being met, the OMIS-A program provides the following capabilities: -Develops and/or Integrates OHIT software applications onto numerous Army systems and networks, including the Army Integrated Tactical Network (ITN) -Tests and Evaluates software provided by the Joint Operational Medicine Information Systems (JOMIS) program to ensure effective operation and cyber compliance on Army network infrastructures -Develops OHIT software applications for Army specific requirements that JOMIS can/will not provide -Maintain Authority to Operate/Authority to Connect for all OHIT software applications on Army infrastructure -Field and train capabilities to all Army units FY 2026 Base funding in the amount of $5.188 million ensures continuous engineering solution and testing services of Army-adopted Joint OHIT applications, modernization of currently fielded Army-specific OHIT software, maintains system cybersecurity, develops system interfaces with other components of the Army and Joint systems, develops training materials for the Army, and ensures compliance with all Army networks, including the Integrated Tactical Network (ITN).$$, 5188000, NULL, NULL, NULL, NULL, 4086000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013A_FL9$$, $$0605013A$$, $$FL9$$, $$Army Accessioning IT Development$$, 2145000, $$Research related to the Army Suicide Prevention Program enhances the Army's ability to prevent suicidal behaviors by increasing understanding of risk and protective factors and by developing and testing interventions. Research in this area supports development and modification of policies, programs, and practices that address suicide prevention and related harmful behaviors that are devastating to the Total Army and its mission. This program also helps DoD ensure Service members start their military career with the skills and knowledge needed to be successful and to confront, overcome, and/or grow from challenges faced both in their military career and personal life. Research in this program will result in more precise determinations of potential for future successful service, and more targeted identification of individual or unit-level needs (e.g., requirements for intervention, training, and/or behavioral health services). Continued funding supports a comprehensive approach to the prevention of harmful outcomes for Soldier and ensures the Army's ability to meet mission requirements in the current and future operating environments. FY 2026 Base funding in the amount of $2.145 million will fund will expand efforts to assess and address risk and protective factors related to suicide, particularly in high-risk formations like combat units. The study will examine links between harmful behaviors and identify ways to strengthen Army leaders' ability to foster protective environments and improve access to services. Funding will also support the development and validation of tools, training, and organizational frameworks aimed at reducing harmful behaviors and improving outcomes throughout the Soldier Lifecycle, from selection and training to leadership development.$$, 2145000, NULL, NULL, NULL, NULL, 2204000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013A_FM7$$, $$0605013A$$, $$FM7$$, $$Human Resouces Information$$, 4527000, $$The efforts under this project support the Army's Human Resources Information Technology needs. 1. Human Resource Command (HRC) Core IT: This program supports efforts to plan, design, develop, and test Information Technology (IT) solutions to fulfill the Army's Warfighter Support Mission, accommodate emerging Army requirements, and fulfill Future Army needs. Ongoing development efforts support multiple functional areas including logistics, personnel, transportation, training, medical/health protection, and the sustaining base. The focus of the rationalization effort is to identify value-added applications capable of serving a broader Army enterprise audience and garnering efficiencies through the elimination of outdated, legacy, and duplicative applications. Applications are upgraded or enhanced to meet compliance with Army Common Operating Environment standards in accordance with Enterprise Cloud Management Agency (ECMA). Additionally, program supports enhancements and modifications to the Interactive Personnel Electronic Records Management System (iPERMS) and iPERMS-Secure (iPERMS-S), as well as development of interfaces based upon emerging requirements, Cybersecurity, functionality and compliance with Army standards. FY 2025 Plans: FY 2025 funding continues to support iPERMS enhancements and modifications, as well as development of interfaces based upon emerging requirements, cybersecurity, functionality, and compliance with Army standards, cArmy Cloud Migration efforts, and ASBS 2.0 development which also supports all and DA G1 Talent Management Task Force Battalion Command Assessment Program (BCAP) and is estimated for completion by Sep 2027. Additionally, USAHRC has utilized all FY 2024 and FY 2025 funding towards the completion of a viable ASBS 2.0 product while enhancing iPERMS auditing features to achieve the Army Data Strategy, modernizing applications to leverage authoritative data sources to reduce duplicate application capabilities, resulting in data and applications requiring fewer infrastructure services. This data and application rationalization allows USAHRC to operate a standard infrastructure, reducing hardware and software complexities in support of modernization. FY 2026 Base Plan: FY 2026 funding continues ASBS 2.0 development which also supports DA G1 Talent Management Task Force Battalion Command Assessment Program (BCAP) which is estimated for completion by Sep 2027. Additionally, USAHRC will utilize FY 2026 funding to complete rationalize data and databases to achieve the Army Data Strategy, modernizing applications to leverage authoritative data sources to reduce duplicate application capabilities, resulting in data and applications requiring fewer infrastructure services. This data and application rationalization allows USAHRC to operate a standard infrastructure, reducing hardware and software complexities and meets compliance with Army Common Operating Environment standards in accordance with Army Application Management Business Office (AAMBO).$$, 4527000, NULL, NULL, NULL, NULL, 13190000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013A_FM8$$, $$0605013A$$, $$FM8$$, $$Information Technology for Training$$, 12109000, $$This project funds information technology systems that support Army Training. The two systems under FM8 are described below. Of those, the Army Training Information System (ATIS) is an Army priority and the focus of the major investment in FM8. ATIS directly supports two of the four Army Unit Readiness Priorities - Training and Leader Development and serves as an enabler for Manning, Equipping, and Scheduling. 1. Army Training Information System (ATIS) Problem Statement: The Army's current collection of non-integrated training information systems provides limited utility with data that is unreliable, un-trusted, inaccessible, and not responsive to user needs. Sustaining these systems, with their various architectures, standards, and service providers results in higher operating and sustainment costs to the Army. Objective: Collapse 20 legacy systems into a single portal supporting 5 training capability areas. Solution: Utilizing Commercial Off the Shelf (COTS) software ATIS will deliver a single portal enterprise training environment capability encompassing scheduling, training development, learning content management, training management, and resource management for all individual, as well as collective training and education. As ATIS is fielded, the Army will reduce the overall cost of the training environment by retiring the duplicative, stove piped systems and improve performance with a data- centric, governed, and architecturally compliant system. ATIS will sunset 20 antiquated information training systems costing over $75M annually. - Training Development: provides ability to develop and coordinate information, including training packages, training events, courses, and exercises. - Training Management: provides centralized ability to access and manage information, including individual and collective/unit training that supports mission tasks and individual training records. - Enterprise Scheduling: provides a single integrated set of applications to schedule training resources, including transportation, classrooms, ranges, supplies, and mandated legal/social individual and unit training. - Content Management: provides centralized access to training information anytime, anywhere, including educational and professional instruction. - Resource Management: provides ability to manage availability/sustainability of training enablers and resources. Without ATIS, Army organizations will continue to maintain an abundance of legacy systems that have redundancies across functionality and capability, which contributes to redundancy and discrepancies in data, thus inhibiting efficient use of training resources (people, time, money, material) and inhibiting leaders' ability$$, 12109000, NULL, NULL, NULL, NULL, 5775000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605024A_FB1$$, $$0605024A$$, $$FB1$$, $$Anti-Tamper Technology Support$$, 6449000, $$Anti-Tamper (AT) Technology Support. The Protective Technologies (PT) organization is the Army's Lead Technical Agent for the DoD AT program, which is focused on preventing exploitation/reverse engineering (RE) of U.S. systems lost or captured on the battlefield or sold via Foreign Military Sales (FMS) or Direct Commercial Sales (DCS). In support of this mission, PT's classified efforts are focused on independent AT Validation and Verification (V&V) activities with Army programs, AT/RE Lab facilities and equipment and AT/RE Lab assessments. This project funds these efforts for the U.S. Army. Work in this Project is performed by the United States Army Futures Command (AFC), U.S. Army Combat Capabilities Development Command (DEVCOM), Aviation & Missile Center (AvMC), Redstone Arsenal, AL.$$, 6449000, NULL, NULL, NULL, NULL, 7274000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013A_T04$$, $$0605013A$$, $$T04$$, $$USMEPCOM TRANSFORMTION - IT$$, 10563000, $$The United States Military Entrance Processing Command (USMEPCOM) is an Office of the Secretary of Defense (OSD) Field Operating Activity with Army serving as its Executive Agent (EA). USMEPCOM reports to OSD Accession Policy (AP). USMEPCOM is the vital link between recruiting and training America's armed forces. The Command applies established DoD standards during military processing, thereby providing continual military enlistments to the Army, Navy, Air Force, Marines, Coast Guard, and Space Force. USMEPCOM processes applicants for military service through its 65 Military Entrance Processing Stations (MEPS) across the Continental United States (CONUS) as well as Non-Foreign Outside the Continental United States (OCONUS) locations. USMEPCOM began processing applicants for service in the 1970s using a by-hand paper intensive process. In 1995, USMEPCOM introduced the United States Military Entrance Processing Command Integrated Resource System (USMIRS) 1.0. USMIRS provides automated support for conducting aptitude tests and medical examinations and administratively processing, enlisting, and shipping applicants for the Armed Forces, Reserves, and Coast Guard. This includes the support for automated versions of the Armed Services Vocational Aptitude Battery (ASVAB) tests. The system also initiates Social Security Administration (SSA) checks for identity verification, interfaces with US Citizenship & Immigration Services (USCIS) to verify citizenship status, and interfaces with the Federal Bureau of Investigation (FBI) for background screening. The system utilizes digital fingerprints to identify/eliminate individuals with criminal records from entering military service. USMIRS supports recruiting capabilities through electronic interfaces and data sharing, using standard Department of Defense (DoD) data elements with Recruiting Service systems (such as ARISS, AIE, DMDC, and DCSA etc.) In the event a military draft is required, USMIRS supports mobilization through electronic links with the Selective Service System (SSS) as well as automated support for conducting aptitude tests and medical examinations and administratively processing, inducting, and shipping SSS registrants. In FY 2021, USMEPCOM launched the USMIRS 1.1 Minimal Viable Product (MVP). The MVP modernizes and expands the core functionality of USMIRS and migrates it to the cloud. The resulting system is automated, scalable, and secure. Further investment in the system is planned through FY 2035 to continue development of additional applications (to include a link to the Military Health System GENESIS (MHS GENESIS)), integrated analytics, predictive analytics (machine learning and power business intelligence), and data quality. FY 2026 Base dollars in the amount of $10.563 million will fund ongoing incremental modernization of the United States Military Entrance Processing Command Integrated Resource System (USMIRS), including legacy application upgrades, data transformation, and Artificial Intelligence (AI) integration.$$, 10563000, NULL, NULL, NULL, NULL, 5758000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013A_T05$$, $$0605013A$$, $$T05$$, $$Army Business System Modernization$$, 82987000, $$Army Business System Modernization Initiatives include: 1. Enterprise Business Systems-Convergence (EBS-C): SAP announced that the current application, Enterprise Central Component (ECC), would not be maintained after 2027 and customers will be required to upgrade to their new version SAP S/4 HANA. In response to this notification, the Army conducted studies in 2019/2020 by the Business Enterprise IT Leaders Group chaired by the Office of Business Transformation. Based on the results of these studies and direction from the Under Secretary of the Army, EBS-C is executing a strategic approach to modernize the Army business system landscape; align modern combat and combat support system capabilities with existing modernization efforts to enable Army force dominance during multi-domain large-scale combat operations in contested logistics environments; and improve overall Army financial operations resulting in improved financial management and successful audit outcomes. The Army is working EBS-C requirements to improve process agility and cross process integration; provide consistent user experiences with an intuitive user interface; and improve data integrity and security. At the enterprise level, EBS-C seeks to integrate financial and logistics processes and create opportunities to decrease overall Defense Business Systems (DBS) redundancies and duplications existing in the Army portfolio. The in-scope DBS for this effort includes General Funds Enterprise Business Systems (GFEBS) and GFEBS-Sensitive Activities (SA), Logistics Management Program (LMP), Global Combat Support System (GCSS)-Army, Army Enterprise System Integration Program (AESIP) Hub, and numerous non-ERP systems performing needed logistics and financial functions. FY 2026 base dollars in the amount of $64.905 million will enable the development of the EBS-C solution and the establishment of the Continuous Integration and Continuous Delivery (Cl/CD) pipeline. The development will continue based on the Minimum Viable Capability Release in FY 2025 deployed to the EBS-C solution in FedRAMP compliant government provided cloud environments utilizing proven agile methodology. 2. Global Force Information Management (GFIM) is an automated, integrated, and interoperable digital environment that enables the Army's Deploy to Redeploy/ Retrograde (D2RR) end-to-end business processes in support of Dynamic Force Employment (DFE). The GFIM system will provide the core Global Force Management- Data Initiative (GFM-DI) compliant data necessary for ERP systems, Business Mission Area (BMA) systems, and Warfighting Mission Area (WMA) systems to execute business processes efficiently and effectively in support of Army warfighting operations and Title 10 responsibilities. Today, over 85% of these core Army Business Processes are accomplished manually or with tools that are end-of-life, do not meet current Cybersecurity/Technology requirements, and are hosted on disparate technology platforms that are unable to be integrated. GFIM will provide an integrated planning, programming, and production capability to dynamically develop, design, and document an Army at rest and an Army in motion. GFIM will evolve both long-term and immediate bridging solutions that integrate and automate Army operational business processes. The GFIM components will provide the Army with a functional and integrated transactional platform that creates and develops the requisite force structure, deployment, redeployment, retrograde, and readiness data needed to man, equip, train, ready, and resource the force and feed the Army's ERPs and Non-$$, 82987000, NULL, NULL, NULL, NULL, 57804000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013A_VR3$$, $$0605013A$$, $$VR3$$, $$ASMIS-R (REPORTIT)$$, 1459000, $$The Army Safety Management Information System (ASMIS) 2.0 is the Army's designated system of record for Army Safety and Occupational Health (SOH) data collection, information management, decision support, and reporting. It is built to holistically support the information management needs of the Army SOH program in accordance with Public Law 91-596, Executive Order 12196, DoDI 6055.01, The Army Strategy LOE 1: Build Readiness, LOE 2: Modernize, AR 385-10, and Assistant Secretary of the Army - Installations, Energy and Environment strategic guidance. ASMIS 2.0 enables commanders and Army senior leaders to use data collected via these six key capabilities and other DoD data sources to prevent accidental losses, reduce associated costs, and enhance readiness. ASMIS 2.0 currently interfaces with 9 DoD systems and will interface with 22 upon completion. It directly supports the Warfighter through improved IT-enabled business processes and enterprise data analytics to enhance decision-making at all levels of the Army through greater use of leading indicators. In support of the Army Data Strategy, ASMIS 2.0 enables the Army to make SOH data visible, accessible, understandable, linked, trustworthy, interoperable, and secure (VAULTIS). Beyond the cost avoidance and reduction achieved by loss prevention, ASMIS 2.0 provides additional cost savings by eliminating 11 legacy systems. In FY 2026, we plan to develop and field two key capabilities: (1) the Occupational Health/Medical Surveillance module, and (2) the Safety & Occupational Health Expense and Budget Management capability.$$, 1459000, NULL, NULL, NULL, NULL, 3151000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013BL_01$$, $$0605013BL$$, $$01$$, $$Systems Modifications and$$, 1283000, $$The DCMA is engaged in several major Information Technology (IT) initiatives to improve and modernize the information technology environment. IT is the primary enabling capability the acquisition workforce relies upon to communicate with contractors, the DoD acquisition community and other customers. The National Defense Strategy IT modernization efforts drive these initiatives. The Defense Contract Management Agency (DCMA) continues to execute an IT modernization strategy established to improve visibility, insight, and collaboration between DCMA, the military services, other defense agencies, and contractors in the Defense Industrial Base (DIB). Core to this strategy is the Modernization and Analytics Initiative (MAI) program to modernize and integrate the entire DCMA portfolio of aging Contract Administration Services (CAS) capabilities and supporting infrastructure, leveraging Platform and Software as a Service (PaaS/SaaS) cloud environment, the Defense Logistics Agency (DLA) Procurement Integrated Enterprise Environment (PIEE), the Department of the Navy (DoN) Product Data Reporting and Evaluation Program (PDREP), and OUSD(C) ADVANA Business Intelligence and Data Analytics platform to enable department-wide CAS capabilities. These efforts support the Director’s strategic objective to modernize CAS tools to improve DCMA processes, enhance DOD Acquisition insights, and standardize contract administration actions and data accessibility across the Department enterprise. Development and research initiatives are core components of the DCMA ability to align efforts appropriately to the DoD IT strategy. In FY 2026, the DCMA continues to invest in the Procurement Integrated Enterprise Environment (PIEE) (hosts Wide Area WorkfFlow (WAWF) and Electronic Data Access (EDA)). This core initiative will empower mobile and fixed users' ability to utilize DoD enterprise capabilities at the same level with improved efficiency and effectiveness. The DCMA aligns with the DoD strategy for software modernization of enterprise capabilities. This involves migrating the DCMA application infrastructure to enterprise hosting environments and modern technology platforms, rationalizing existing applications to ensure capabilities align with mission requirements, and adopting new DoD strategies for modern software development methodologies. These solutions will improve process gaps to streamline/simplify automated contract administration, provide real-time data visibility, reduce manual intervention, and provide effective, regulatory-based tools for use across the Department. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Contract Management Agency                                                Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:           PE 0605013BL / Information Technology Development System Development & Demonstration (SDD)$$, 1283000, NULL, NULL, NULL, NULL, 202209000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013M_2906$$, $$0605013M$$, $$2906$$, $$Marine Corps IT$$, 16000000, $$Marine Corps Recruiting Information Support System (MCRISS) is an enterprise level system to automate administrative procedures for the recruiting station operations. This customized automated System, centered on procedures in the Guidebook for Recruiters, Volume I, dramatically improves efficiency and effectiveness in Marine Corps recruiting. Furthermore, Military Entrance Processing Command requires Marine Corps recruiting to provide information in electronic format only. MCRISS is the Marine Corps Recruiting Command's program to manage applicant processing from commitment to accession/commission into the Marine Corps and Marine Corps Reserve. This enterprise approach allows for efficient sharing of information about potential recruits and recruiter screening efforts, yielding a more cost-effective process. The current system requires modernization of the systematic recruiting components to provide efficiency for the Recruiting force from the Headquarters element down to the Recruiter and requires numerous updates in order to become fully compliant with Cyber Security and Center for Naval Analysis (CNA) policies and mandates to protect PII/PHI data captured and stored in the system. The Modernization effort will involve a competitive evaluation of several prototype systems, leading to a selection of a viable platform and the complete replacement of the current MCRISS system with modern and secure technology. Strategic Management Decision Support (SMDS): The SMDS program will provide a set of materiel and non-materiel solutions to facilitate data-driven and analytically sound decision support for Marine Corps strategic-level business processes, in order to optimize force development outcomes and improve institutional readiness. Supported business processes include global force management, readiness assessment, war gaming, planning, programming, budgeting, and capability solution development. SMDS will provide Marine Corps senior leaders, across all functional areas, adequate tools and data to make force development and readiness decisions with sufficient responsiveness to meet force management and planning, programming, budgeting, and execution (PPBE) process timelines. SMDS will enable Marine Corps data to be readily available, visible, accessible, and integrate multiple classification domains through a DISA Cross Domain Enterprise Solution. SMDS will provide enterprise data management with analytics and tools to provide enterprise-wide visualization, reporting, and data mining of Marine Corps data that is found on local and enterprise level Marine Corps systems. SMDS will provide the Marine Corps sufficient, consistent, relevant, and high-quality data to support strategic management processes and decisions through use of Joint DoD and Marine Corps systems. Command Individual Risk and Resiliency Assessment System (CIRRAS): operationally deployed in September 2020, enables the United States Marine Corps (USMC) commanding officers and senior enlisted advisors to make more informed and timely decisions on Force Preservation (FP) risk assessments, based on identifying and tracking individual Service Member (SM) behaviors associated with increased risk or resiliency as defined by the Marine Corps "Six Fs" (Fidelity, Fighter, Fitness, Family, Finances, and Future). CIRRAS is the Marine Corps Force Preservation Council (FPC) enterprise-wide system to manage individual SM FP risk by providing a consistent approach and a standardized methodology to support protective factors and mitigate adverse outcomes. Current efforts are to deploy additional FP functionality to increase the ability to perform, inform, and record behavioral Service Member risk assessment within the Marine Corps with the development of Version 1.1. The enhanced CIRRAS Version 1.1 capabilities being developed will automate resiliency scores, send automated alerts to leadership of "at risk" personnel, and implement additional system interfaces that will provide further key FP indicator data to assist in prevention of SM suicide. CIRRAS Version 1.1 is slated to deploy in Q4 FY 2023. Development of CIRRAS Version 2.0 will begin in FY 2024 and provide enhanced capabilities including automating e-forms, implementing a greater number$$, 16000000, NULL, NULL, NULL, NULL, 138741000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013N_2901$$, $$0605013N$$, $$2901$$, $$Navy Enterprise IT$$, 68359000, $$SECNAV PROJECTS IT SYSTEM MODERNIZATION The Department of the Navy Chief Information Officer, Technology Division (DONCIO IT) provides Information Technology (IT), Information Assurance (IA), Information Management (IM), Document Management (DM), Records Management (RM), Knowledge Management (KM) and other related support services to the Secretary of the Navy (SECNAV), Chief of Naval Operations (OPNAV), the DON Secretariat, including political appointees, flag officers and senior executives. This support spans across over 24 organizations, covers nearly 6,000 individual customers, and countless worldwide end users. These services include complete life-cycle software support, software application development, implementation, and post development software support. DONCIO IT is heavily involved in the research and analysis of emerging trends and technologies for use throughout the Secretariat. DONCIO IT is also a valued partner and stakeholder in the development, review, and implementation of all DON and DoD IT related policies that affect the Secretariat members. Additionally, DONCIO IT astutely manages the telecommunication needs of the Secretariat and OPNAV staffs to include providing state-of-the-art mobile devices, services and support, laptops, and a host of other peripherals as needed when these executives travel abroad and around the country. DONCIO IT acts as a trusted agent for the review and approval of all IT related acquisitions across the Secretariat and provides expert guidance on the utilization of DON service contracts that support the purchase of software, hardware and other IT-related functions. DONCIO IT also manages and supports all Cyber Security functions for its Secretariat customers. Furthermore, DONCIO IT manages and supports all administrative requirements and functions of the NMCI/NGEN contract for all Secretariat customers. Database and application development support is required to test, evaluate, and modify current and new systems/ capabilities for Secretariat customers. ELECTRONIC PROCUREMENT SYSTEM (ePS) The electronic Procurement System (ePS) is the Department of the Navy's (DON) End-to-End (E2E) Contract Writing System (CWS). It will provide the Navy and Marine Corps contracting community with a full contract writing management capability and integrates with federally mandated systems, DON financial systems, and industry. The ePS will utilize Department of Defense (DoD) standards and support auditability. The ePS will address existing CWS challenges including outdated architecture, limited capabilities, scalability concerns, and existing obsolete legacy systems. Full deployment of the ePS ensures compliance of the DON's contracting abilities with the following legislative mandates: the writing and management of all contracts must now occur in congressionally approved computer systems (Section 862 of the National Defense Authorization Act (NDAA) of 2013); the central management and oversight of all DoD business (10 U.S. Code (U.S.C.) Section 2222); and all contracting actions must be fully auditable and traceable (Section 1003 of the NDAA 2010 & Office of the Secretary of Defense (OSD) Financial Improvement and Audit Readiness (FIAR) Guidance). The ePS will use DoD data exchange capabilities (e.g., Procurement Data Standard (PDS) and Purchase Request Data Standard (PRDS)) in order to achieve standardized data interoperability with external systems. The Navy Enterprise Service Bus (NESB) serves as the hub to relay procurement data to various finance and other systems of record, such as Navy Enterprise Resource Planning (Navy ERP).$$, 68359000, NULL, NULL, NULL, NULL, 248214000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013N_2903$$, $$0605013N$$, $$2903$$, $$NAVAIR IT$$, 14070000, $$NAVY CYBERSECURITY Funding furthers the research and development of Cyber Warfare capabilities that cross all Naval Aviation systems within the Naval Aviation Enterprise improving cyber survivability and resiliency within naval aviation systems. Adheres to the tenants of the DON CIO's cyber ready call to action. Establishes IOC and further develops the NAVAIRSYSCOM Cyber Planning and Response Center (CPRC) as required by OPNAVINST 5239.1E U.S. Navy Cyber Security Program and OPORD NEPTUNE SHIELD issued by Fleet Cyber Command, the ECH II for the NAVY's CSSP. Efforts align with CJCSM 6510.01B Cyber Incident Handling Program and SECNAVINST 5239.19A DON Computer Network Incident Response and Reporting Requirement. The CPRC provides ability to conduct incident response, reporting and C2 of cyber events impacting NAE platforms and weapons systems both ashore and afloat as well as the analysis and assessment critical in determining cause for event, likelihood of additional similar events and the development of solutions to prevent future incidents. Funding provides the further development of critical assessment capabilities such as a new world class Naval Aviation Cyber Red Team allowing for capability to research, identify and validate nation-state exploitable cyber susceptibilities and vulnerabilities in both deployed and next-generation warfighting platforms. Additionally, funding allows for further research and development of cross platform solutions utilizing leading edge technologies such as Artificial Intelligence and machine learning that enable cyber situational awareness, cyber supply chain risk analysis, automate and convert data collection for metrics, Cyber Test and Evaluation methods, cyber protection conditions, Cyber Safe certification process, Cyber Workforce analysis, cyber ready metrics, model based systems engineering capabilities, and supports Cooperative Research and Development Agreements between government and aviation manufacturing companies to improve information sharing supporting the above efforts. These cyber warfare research and development efforts will strengthen our cyber posture by developing solutions to deter, detect, and mitigate cyber threats and safeguard classified naval aviation systems and platforms from "cradle to grave." DIGITAL THREAD (DT) Funding provides a Naval Enterprise Solution to manage technical data required for weapons systems to promote workforce automation, resource optimization, and process standardization for program lifecycle management and to integrate acquisition with the warfighter. This will support future state for Logistics IT and enhancing Readiness in providing an enterprise solution with Naval Product Lifecycle Management (N-PLM). N-PLM is integral to Digital Log IT, supporting the Naval Maintenance, Repair, and Overhaul (N-MRO), Naval Supply Chain Management (N-SCM). Digital Thread (DT) is the capability providing digital process integration with complete, secure and authoritative data, coordinated as part of approved Navy LOG-IT. DT integrates the product life cycle to provide universal access to authoritative data and workflow automation, enabling configuration management of data, implementation of closed loop quality, and consolidation of engineering products including digital$$, 14070000, NULL, NULL, NULL, NULL, 86598000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013N_2904$$, $$0605013N$$, $$2904$$, $$NAVSEA IT$$, 19521000, $$Navy Maritime Maintenance Enterprise Solution (NMMES) is the Information Technology (IT) toolset currently utilized to execute ship and submarine maintenance in the Naval Shipyards (NSY), Regional Maintenance Centers (RMC), Ship Repair Facility (SRF) Japan, Intermediate Maintenance Facilities (IMF), Forward Deployed Regional Maintenance Center, Pearl Detachment - Guam, and commercial industrial sites worldwide. These maintenance activities support Fleet operations 24 hours per day, 7 days per week. The NMMES IT solution is used by over 40,000 civilians and military who conduct over $10.2B of ship, aircraft carrier, and submarine maintenance and modernization on an annual basis. The NMMES program includes sustainment as well as multiple modernization efforts to ensure the continued effectiveness of the Fleet maintenance IT toolset. These efforts consist of adding mandatory enhancements, such as Financial Improvement and Audit Readiness (FIAR) changes and aligning with the Standard Accounting Budget Reporting System (SABRS) and Navy Enterprise Resource Planning (ERP) system requirements as the general ledger. The NMMES program provides for software changes, retiring and/or replacing of costly legacy applications, transition planning, and systems engineering for integration with existing and future solutions. These efforts align with direction to ensure that proposed interim solutions support and facilitate the transition to the planned maintenance solution end state. This program will provide modernization, migration, testing, and consolidation of obsolete IT tools and code base to the next generation of centrally hosted tools supporting Fleet Maintenance systems for the Navy. Funding for NMMES PU 2904 addresses critical deficiencies and minimizes the inherent risks that a catastrophic failure would be to fleet readiness. The funds are required to support the modernization of products that are on outdated software, align maintenance applications and processes with evolving shipbuilding techniques, and enhance the existing applications to make them cloud capable. It also provides for software enhancements required to make applications Financial Improvement and Audit Readiness (FIAR) compliant and to enable system modifications of financial feeder applications to interface with a FIAR compliant system of record. The requirement to handle 3-D integrated product models being delivered with CVN-78, Virginia Class and Columbia Class are also driving the requirement. NAVSEA plans to execute these funds primarily through a current sustainment contract and several separate contracts through existing delivery orders to gain the specialized resources and material necessary to sustain these vital functions.$$, 19521000, NULL, NULL, NULL, NULL, 338310000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013N_2905$$, $$0605013N$$, $$2905$$, $$BUPERS IT$$, 0, $$The MyNavy HR Transformation Portfolio will conduct a thorough review of business processes and requirements to ensure optimal alignment with the Navy's top priorities. Following the efforts related to the Strategic Alignment, the MyNavy HR Enterprise will evaluate the appropriate resourcing required for continued Research, Development, Test and Evaluation efforts required to successfully develop, integrate and field a modernized Human Resource System for the Warfighter. MyNavy HR Transformation is not just a technology refresh of existing systems, but a holistic change to how MyNavy HR Services are provided. This effort is the linchpin of the Navy's s Manpower, Personnel, Training & Education (MPT&E) Business IT Transformation strategy that stems from investing in programs that directly align with the Sailor 2025 vision. The current 70-year-old business processes and 40-year-old obsolete IT systems will not sustain anticipated Fleet growth and is neither cost efficient nor effective. MyNavy HR involves revolutionary change by using agile delivery model to the greatest extent possible to implement business IT products using the Industry Best Practices Model (e.g., early investment for largest ROI, rapid prototyping, and vanilla g Commercial Off The Shelf (COTS) products usage). MyNavy HR is a fully integrated portfolio of IT Systems organized into five distinct pillars: Navy Personnel and Pay (NP2), Learning Stack (LS), Enterprise Customer Relationship Management (eCRM), Single Point of Entry (SPOE), and Authoritative Data Environment (ADE). This portfolio of systems serves as the cornerstone of the OPNAV N1 MyNavy HR strategy. The impetus for building an adaptive family of systems is gearing MyNavy HR Transformation towards customer needs. The traditional waterfall delivery methodology of IT goods and services cannot meet the emergent requirements evolving from shortened technical obsolescence. Thus, MyNavy HR Transformation will employ an agile delivery method that is highly structured, with a repeatable software development approach designed to quickly deliver usable capability to the end user. These capabilities are packaged as Minimum Viable Products (MVPs) which are routinely delivered to the customer for their use and evaluation. Favorably received MVPs are subsequently refined and integrated into a production baseline. Rapidly integrating a family of systems using an agile methodology necessitates an overarching system integrator and coordinator to ingest pilots and prototypes into a technical baseline. MyNavy HR ITS will provide the Global Design & Strategic Planning to baseline the "55 to 1" technical execution plan and will articulate the "system of systems" baseline release. Additionally, pilots and prototypes that have reached sufficient maturity will be integrated and deployed into the production baseline. AUTHORITATIVE DATA ENVIRONMENT (ADE) The Authoritative Data Environment (ADE) is an enterprise information management system that will migrate the existing MyNavy HR legacy data warehouses into a central data repository that is composed of a data warehouse, data lake, data management tools and an Application Program Interface (API) Layer. ADE will provide an authoritative data-sharing framework, leveraging scalable and interoperable technologies as well as business intelligence and data analytic capabilities. ADE will need to interface and integrate with SPOE and all MyNavy HR transactional and business systems, including enabling 'plug & play' of new services, technologies, and system capabilities. Some of the key principles of ADE include:$$, 0, NULL, NULL, NULL, NULL, 623079000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013N_2953$$, $$0605013N$$, $$2953$$, $$Model Based Product Support$$, 11337000, $$MODEL BASED PRODUCT SUPPORT (MBPS) is the maritime component of Navy Product Lifecycle Management (PLM): As supported by PEO MLB, Logistics Information Technology (LOG-IT) modernization will provide the capability of performing integrated, real-time, data driven operational and shore logistics thru an integrated infrastructure comprised of three basic and interdependent product lines, Navy PLM, Navy Supply Chain Management (SCM) and Navy Maintenance, Repair and Overhaul (MRO) lines of effort which enable warfighter readiness. LOG-IT systems must be able to operate in disconnected environments with modern, cyber-secure and auditable systems that compress the Kill Chain. The MBPS program is major authoritative data source for LOG-IT. The MBPS program modernizes ship / submarine readiness modeling, technical data management, and configuration management IT systems to enable advanced digital twin and readiness analytics capabilities. MBPS provides capability to migrate legacy LOG IT applications into an integrated Navy Product Life-Cycle Management (N- PLM) environment to include both maritime and aviation support. It will be hosted in a government-approved commercial cloud environment and used on a 24/7 basis by over 200,000 personnel assigned to 286 ships/submarines, all aircraft and over 700 shore-based activities, impacting a yearly $6.5B investment in product sustainment.$$, 11337000, NULL, NULL, NULL, NULL, 10391000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013N_3026$$, $$0605013N$$, $$3026$$, $$ERP Convergence$$, 32015000, $$Project 3026 ERP Convergence is a FY 2026 new start. Navy Enterprise Resource Planning (Navy ERP) is an integrated business management system that modernizes and standardizes Navy's business processes. Navy ERP utilizes best commercial practices to provide real-time information exchange, unprecedented financial and asset visibility, and improved reporting and decision- making capabilities across key acquisition, financial, workforce management, and supply chain operations. The Department of Navy (DON) has designated Navy ERP as the Navy's financial system of record for all the major acquisition System Commands including General Fund (GF) and Navy Working Capital Fund (WCF) activities. Navy ERP is essential to the DON in meeting the 2024 National Defense Authorization Act's requirement for the Department of Defense to receive an unqualified opinion on the financial statements of the Department by 2028 Further, Navy ERP is core to recording transactions across financial, acquisition and logistics operations within the Navy General Ledger (GL). Activities will implement mandatory treasury and federal mandates for interoperability and cyber-security to include decommissioning of legacy systems. The DON remains committed to the strategy of reducing redundancy by migrating to two General Ledger systems: Navy ERP and Defense Agencies Initiative (DAI) ERP. The final migration effort will be to bring Commander, Naval Installations Command (CNIC), Naval Facilities Engineering Systems Command (NAVFAC), and the three Fleet commands into Navy ERP: Pacific Fleet (PACFLT), United States Fleet Forces Command (USFFC), and Reserve Forces (RESFOR). The current funding profile supports the ERP+ software upgrade of the Navy Enterprise Resource Planning (Navy ERP) system following the projected FY 2026 completion of the Navy's on-going migration of financial management (FM) data and operations to ERP Central Component (ECC). The ERP+ software upgrade consists of moving financial management data and operations, which had been previously consolidated into the ERP ECC, into ERP+ as the ECC system reaches obsolescence/end of service life in 2030. Periodic software upgrades are a fact-of-life/fact-of-technology that occurs approximately every ten years for business systems. Any delay in executing this needed tech refresh will result in an 8-30% increase in relative support/security costs starting in 2027. The development of the ERP+ tech refresh is being shaped by four guiding tenets: Maximize out-of-the-box technology, adopt standard business processes, optimize technology, and follow and Agile value-led approach. The software upgrade improves User Experience & Business Agility. An improved user experience is simple, intuitive, responsive, and an effective solution delivery that enables and enhances mission performance. Embracing modern software development and delivery practices maintains relevance with accelerating pace of technology change and expanding impact of the information environment (include changing/updating processes, embracing new technology such as Artificial Intelligence or advanced analytics).$$, 32015000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013N_3167$$, $$0605013N$$, $$3167$$, $$Joint Technical Data Integration$$, 7869000, $$JOINT TECHNICAL DATA INTEGRATION (JTDI) Funding provides an enterprise common data transport solution to support the future state for Logistics IT and Readiness: Naval Product Lifecycle Management (N-PLM), Naval Maintenance, Repair, and Overhaul (N-MRO), Naval Supply Chain Management (N-SCM), and Integrated Data Environment (IDE). In addition to transporting authoritative technical data to maintainers in the ashore, afloat, and expeditionary environments, JTDI also automates the movement of CBM+ data generated by smart weapon systems deployed around the globe, consolidates and makes platform sensor data available for automated ingest into the Standard Data Repository, which provides modern, highly integrated analytic capabilities to enable condition-based maintenance processes. JTDI is a digital technical data access, delivery and local Organizational & Intermediate level library management toolset that improves accuracy and timeliness of weapon system repair manuals and other technical data delivery, minimizes the Fleet's library management burden, and reduces maintenance work hours with a Return on Investment of 2.5:1. Funding supports the evaluation, testing and integration to develop a JTDI Government Off-The-Shelf (GOTS) solution for installation on Carrier and Amphibious Assault class ships, the Consolidated Afloat Networks and Enterprise Services Network (CANES), and at other globally deployed Navy/Marine Corps activities. JTDI is aligned with NAVAIR LOG IT digital transformation objectives and Navy Digital Roadmap. MARINE AVIATION LOGISTICS ENTERPRISE INFORMATION TECHNOLOGY (MAL-EIT) MAL-EIT funding supports the evaluation, development, testing and integration of software and hardware solutions across all US Marine Corps Aviation activities to be used in the planning and execution of geographically distributed, expeditionary Aviation Logistics (AVLOG) chains in support of deployed USMC Air Combat Element operations. The MAL-EIT Program is one of four programs contained within the Marine Aviation Logistics Support Program (MALSP) modernization program known as MALSP II. Legacy MALSP is nearly 25 years old and grossly inadequate in IT capability to meet the informational, planning, and C2 needs of a dynamic, geographically distributed nodal AVLOG system. MAL-EIT is a Defense Business System Abbreviated Acquisition Program that will develop and deliver the required IT capability necessary to eliminate the IT related gaps existing in the legacy MALSP. MAL-EIT is a family of IT solutions to be developed and delivered in three increments. These increments are depicted below: Expeditionary Pack Up Kit (EPUK): Provides Expeditionary Supply Operations to include business administration, inventory, and customer service operations. Next Generation Buffer Management System: Provides buffer management in a time domain, and buffer sizing analysis. Logistics Planning Tool and Optimizer Tool: Provides capability to develop tailored Remote Expeditionary Support Packages, consumption forecasts, and Nodal Logistics Lay down designs.$$, 7869000, NULL, NULL, NULL, NULL, 65820000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013N_9406$$, $$0605013N$$, $$9406$$, $$Maintenance Data Warehouse$$, 36650000, $$Maintenance Data Warehouse funds the Naval Aviation Enterprise (NAE) components, in coordination with Navy LOG-IT, of digital transformation, which is a critical component of improving readiness, giving Navy users access to authoritative truth data and automating inefficient manual processes. It will be executed in a fully agile manner providing continuous fleet readiness improvements. The initial configuration will be supported with an agile Minimal Viable Product (MVP) as the foundation for continuous capability introduction. AVIATION LOGISTICS ENVIRONMENT (ALE) The Aviation Logistics Environment (ALE) will provide the seamless environment to support the integration of the other capabilities developed in Maintenance Data Warehouse. Aviation Logistics Environment (ALE) provides a global logistics enterprise solution, delivering capabilities via a net-centric, shared data environment that supports shore-based, afloat, and expeditionary operations. ALE consists of three components: Ground Station, Aviation PLM, and Enterprise Service Bus (ESB). The Maintenance Engineering Ground Station for Aviation (MEGA) is the Naval Aviation Type/Model/Series (T/M/S)-agnostic ground station. MEGA is currently under development using Government off-the-Shelf (GOTS) software and PLM/ESB is configuring Commercial off-the-Shelf (COTS). The Aviation Product Lifecycle Management (Aviation PLM) capability will provide the digital thread of aviation logistics data for allowable and as-configured Repair Bill of Materials (R BOM) sustainment, technical bulletins, technical directives and engineering change proposals, and reliability centered maintenance and maintenance planning. The Enterprise Service Bus (ESB) capability will provide the digital backbone for data connections to and from authoritative data sources. ALE consolidates aging, near-end-of-life systems, and applications and aligns Information Assurance (IA) and cybersecurity requirements. AVIATION DATA WAREHOUSE/DECISION KNOWLEDGE PROGRAMMING FOR LOGISTICS ANALYSIS AND TECHNICAL EVALUATION (DECKPLATE) The next generation data warehouse containing over 30 years of aircraft maintenance, flight, components, and usage data. Through the use of web-based, commercial off the shelf software for data load, analysis, query, and reporting tools, the user has the capabilities to effectively obtain readiness data in a near real-time environment, as well as providing historical data for long range planning, trend and records analysis, records reconstruction, and compliance with technical directives. DECKPLATE supports the mission of the warfighter who requires a single source of near real-time aviation data in which to base critical readiness decisions. DECKPLATE collects data from authoritative sources, such as the fleet maintenance systems, into a data warehouse. To provide the warfighter with a common view of Logistics IT data, the time consuming tasks of collecting, extracting, transforming, and loading source data will enable a federated data view that will reduce and ultimately eliminate duplicative and manual processes, while providing visibility and access to trusted data for decision support. This also accomplishes a reduction in legacy systems mandated by Office of the Chief of Naval Operations. DECKPLATE manages total inventory for two major categories of assets, Aircraft (General Equipment) and Engine/Propulsion Systems/Modules (EPSMs) (Operating Materials & Supply). DECKPLATE is comprised of the transactional Aircraft Inventory and Readiness Reporting (DECK-AIRRS) and the Engine Transaction Reporting (DECK-ETR) subsystems, which provide the complete lifecycle for aircraft and Engine/ Propulsion$$, 36650000, NULL, NULL, NULL, NULL, 210211000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605013N_9999$$, $$0605013N$$, $$9999$$, $$Congressional Adds$$, 0, $$C778-Actionable Analytics for reliable maintenance provides the required Logistics Information Technology, data enablement, and Logistics/Engineering/Analytics domain expertise to realize predictive Condition Based Maintenance Plus (CBM+) use cases and business process within an Enterprise common CBM analytics environment to optimize aircraft availability and materiel readiness by incorporating health and usage leading indicators into the failure mode mitigation process, enabling the Warfighter to more efficiently meet mission requirements. The CBM+ analytics environment automates required maintenance, aircraft Health Monitoring System (HMS) sensor, and supporting data collection, storage, integration, and analysis capabilities across the Naval Aviation Enterprise, leveraging the integration of large scale on-premises, in cloud, and at edge Log IT solutions for proactive CBM+ data-driven decision support. C896-Cyber Supply Chain Risk Management Funding will support the development of a prototype Cyber Supply Chain Risk Management (C-SCRM) cloud system to illuminate cyber risk within the supply chain down to the individual component level. This will be accomplished through the development of system models utilizing techniques such as Model Based Systems Engineering (MBSE) instead of relying on classic document based approach. Analysis will leverage machine learning algorithms and artificial intelligence. Dashboards will be developed for those weapons systems that are aligned as well as a global dashboard for the Cyber Planning and Response Center. Some systems will require the creation of Software or Hardware Bill of Materials, in this case a standard data item description will be used. This effort utilizes current logistics business IT systems and their associated data lakes within an enterprise C-SCRM solution that will allow for sharing of C-SCRM data across platforms as well as syscoms resulting in reductions in cost for each program office and schedule to meet the acquisition timeline. It will also reduce risk across the enterprise by illuminating and preventing cyber vulnerabilities from propagating by sharing vulnerabilities to common critical systems and vendors before they find a way into the Fleet. C375-Cyber Digital Twin Development Funding will support the research and development of digital twins to help evaluate the complex interactions during cyber- attacks and defensive actions within cyber physical aviation systems. This funding will also support the development, procurement, and installation of the infrastructure necessary to enable this effort that the digital twins are being created to support. This program will focus resources on the critical tasks as well as measure how much risk has been introduced and which technologies are most effective in reducing and managing the cyber risk to weapons systems.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605018A_ED9$$, $$0605018A$$, $$ED9$$, $$Integrated Personnel and Pay System$$, 164600000, $$The Integrated Personnel and Pay System-Army Increment II (IPPS-A Inc II) provides an integrated, multi-Component, personnel and pay system that streamlines existing Human Resources (HR) systems and processes by enhancing efficiency and accuracy of personnel and pay procedures in support of 1.1 million Soldiers. This program is an essential building block to reform the Department of the Army towards achieving greater performance and affordability in support of the National Defense Strategy and the Congressional audit mandate. The IPPS-A program to date has completed a phased deployment of Military Human Resource and talent management capabilities across all Army components (Active, Guard and Reserve). This includes all Army National Guard units in the 54 states and territories into one single solution. The program has subsumed 120 systems/ instances and six partial capabilities bringing the Army's total military force into a single HR authoritative system. In accordance with the Acquisition Strategy approved by the Army Acquisition Executive on 21 June 2022, the program office will incrementally release Army Military Payroll, additional Human Resource (HR) Capabilities (e.g., Archiving, Talent and Strength Management, and Audit), and HR Enhancements to the deployed baseline. In 4QFY24, IPPS-A began migration from the legacy infrastructure hosting solution with Defense Information Systems Agency (DISA) to a Cloud Hosting solution. As part of our transition from Waterfall Development to an Agile Development Framework, the program is transitioning to the Software Acquisition Pathway. In 1QFY25, the program awarded the Solution Provider bridge contract to enable competition for the new Product Support and Delivery contract to be awarded in 1QFY26 that provides maintenance and system enhancements enabling subsumption of legacy systems. FY 2026 Base dollars in the amount of $164.600 million supports Agile software development and incremental delivery of additional capabilities for Army Military Payroll as well as additional HR capabilities to enable subsumption of 18 full and four partial additional legacy systems. These funds will continue cloud migration prior to the legacy DISA infrastructure end of life in FY28. These critical investments support the Army to be audit ready and achieve cost savings through cloud migration, legacy system subsumption and delivery of the Army Military Payroll capability. Funds also support other enabling infrastructure and software upgrades to include support for Identity, Credential, Access Management (ICAM) implementation achieving zero-trust compliance. In 1QFY26, the program will award the new Product Support and Delivery contract that provides maintenance and system enhancements enabling subsumption of legacy systems.$$, 164600000, NULL, NULL, NULL, NULL, 86914000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605018F_676003$$, $$0605018F$$, $$676003$$, $$HRM Structural$$, 64050000, $$The Air Force Integrated Personnel and Pay System (AFIPPS) is a web-enabled, Enterprise Resource Planning (ERP) solution that integrates existing personnel and pay processes into one self-service system. AFIPPS supports how the Department of the Air Force (DAF) owns and operates the Human Resource Management domain and is a component of the AF/A1 digital transformation journey, currently underway. AFIPPS continues the transformation by providing an accurate and single authoritative source of personnel data to ensure timely delivery of pay, entitlements, allowances, and benefits to all Active Duty Air and Space Forces, Air National Guard (ANG), and Reserve (USAFR) components. AFIPPS represents the DAF's commitment to modernize business practices and provide enhanced support to service members and their families by integrating personnel and pay systems. AFIPPS will eliminate DAF reliance on the unsustainable Defense Finance and Accounting System (DFAS) and the Defense Joint Military Pay System (DJMS) for payroll processing and ensures improved auditability of service member pay. The AFIPPS program directly increases readiness for total force service members, human resources and financial management specialists, and DAF Commanders. AFIPPS will improve the DAF community's experience by allowing members to self-initiate pay/personnel actions, decreasing pay errors, and providing accurate personnel/pay data for leadership decision-making. AFIPPS modernizes the existing Military Personnel Data System (MilPDS) and adds pay and leave capability. In Jan 2021, the DAF leveraged a MilPDS self-service capability deployment to verify the baseline system had the infrastructure for the new pay and leave capability in place. The self-service capability allowed DAF Airmen and Guardians to initiate self-registration, validate member data and verify operational performance. AFIPPS revised the original deployment strategy from a single Go-Live deployment in January 2025 to a HR Deployment in second quarter fiscal year 2025 that will subsume MilPDS, a Limited Deployment to a low-risk population with no prior service in the fourth quarter fiscal year 2025 to continue HR activities with the inclusion of payroll capabilities with an additional Limited Deployment prior to Full Deployment (FD), and a FD to all DAF military personnel in second quarter fiscal year 2027 for continued HR activities with payroll capabilities. This requirement supports performance of a full financial audit as required by title 10 U.S.C Chapter 9A, Sec 240-D. Reduces civilian personnel full-time equivalents and funding in the amount of 0.196M to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0605018F / AF Integrated Personnel and Pay System (AF-IPPS) Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability; The use of such programs funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, 0605898F. In FY 2024 0.000M was expended for civilian pay expenses in this program element, and in FY 2025 0.388M is forecasted for civilian pay expenses in this program element. The FY 2026 request for AFIPPS includes 64,050 thousand of discretionary and 0 thousand of mandatory (reconciliation) for a total of 64,050 thousand. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 64050000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605022D8Z_013$$, $$0605022D8Z$$, $$013$$, $$Defense Exportability Features (DEF)$$, 6780000, $$The DEF Program funds activities to support identification of major defense acquisition programs for possible export and the planning for design and incorporation of exportability features during the research and development phases of these programs. Features include, but are not limited to, technology and engineering design activities such as capability differentials, anti-tamper, system assurance, and software assurance. Activities include the development of program protection strategies for the program; the design and incorporation of exportability features into the system; implementation of exportability requirements into contracts; and other research, development, test, and evaluation activities. Defense exportability features play a critically important role in DoD efforts to build partnership capacity. Funds support building joint and coalition environments by enabling the export of DoD systems to a wide range of partner nations, resulting in improved security and interoperability. In addition to the operational benefits, by providing these resources up front, the United States and partner nations will save significant resources by more efficiently designing and producing exportable U.S. systems. Experience has shown that failure to identify the full range of CPI early in a DoD program's design phase can drive major affordability and schedule problems later when programs have to "retrofit" program protection measures prior to export. Early development of export variants, including systems design approaches to integrate exportable anti-tamper protection and differential capability requirements to lower production costs, makes it possible to improve quality and timely deliveries to allies and friends and may enhance U.S. industry share of the global marketplace.$$, 6780000, NULL, NULL, NULL, NULL, 127745000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605024F_675066$$, $$0605024F$$, $$675066$$, $$Anti-Tamper Technology$$, 62965000, $$The Anti-Tamper (AT) Technology Executive Agency budget funds activities related to the DoD Executive Agent for AT (ATEA) responsibilities required by DoD Directive 5200.47E, "Anti-Tamper (AT).” These responsibilities are unique to the DoD ATEA and the Air Force Component Office of Primary Responsibility (OPR) for AT. The DoD ATEA is responsible for developing and enforcing AT policy and guidance, assessing AT technologies (hardware and software), maintaining and developing new AT technology products and assessment capabilities, maintaining and maturing AT laboratory equipment and infrastructure, establishing and maintaining a library of AT technologies, providing security guidance and support mechanisms, providing outreach and education to the DoD AT community, providing intelligence support, and evaluating AT implementations across all DoD acquisition programs, foreign military sales (FMS), and direct commercial sales (DCS). The AF OPR for AT evaluates AT on applicable AF acquisition programs, FMS, and DCS as well as manages AF AT technology development. AT directly enables CPI resilience. AT protects critical program information (CPI), in U.S. weapon systems that are no longer under U.S. control (e.g., lost/left on the battlefield or sold to a foreign government) from hands-on, reverse engineering (RE) attacks. AT protections enable the U.S. to preserve its technological advantage and the combat capabilities of critical weapons systems while supporting the warfighters' mission requirements. Furthermore, AT adds longevity to DoD weapon systems by deterring or delaying RE attacks, and thus reducing an adversaries' ability to obtain the CPI and/or develop weapon countermeasures against the system. All DoD acquisition programs, FMS, and DCS with CPI require a validated AT Plan. The AT program includes resources required for subject matter experts (SMEs) to evaluate AT Plans and conduct AT validation on all DoD Weapon Systems. Additionally, the AT program provides resources for SMEs to perform AT assessments of both commercial off the shelf (COTS), contractor funded government only use (CFGO) and government off the shelf (GOTS) products. As the COTS, CFGO and GOTS technologies advance, the AT program includes the resources required to mature AT hardware/software assessment capabilities. These capabilities include the acquisition of specialized equipment, maintenance and/or renovations to support the integration of this equipment, and modifications to new and/or existing laboratory facilities to meet equipment and security requirements. The DoD ATEA coordinates technology development among the DoD Services/Agencies, National Laboratories, and Industry. These technology development efforts fund development of new AT technology, as well as enhance existing AT technology efforts to increase the technology readiness level (TRL) and facilitate transition for programs to implement. The AT technology development and enhancement efforts include: advanced AT sensor hardware, secure processing, crypto-analysis, tamper penalties, modifying and developing technology to address vulnerability and susceptibility of fielded parts, and other AT enablers. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0605024F / Anti-Tamper Technology Executive Agency Operational Systems Development The Air Force AT OPR conducts AT technology and product development to meet Air Force service needs to mature promising AT technologies to transition to Air Force weapons systems. Technology and product development priorities are given to those technologies/products that most benefit AF acquisition programs while aligning to the overall DoD ATEA technology and product development strategy. These activities are coordinated through the ATEA as a part of the ATEA technology and product development roadmap and to coordinate with Navy and Army AT technology development efforts. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, 0605898F. In FY24 $2.906M was expended for civilian pay expenses in this program element, and in FY25 $4.544M is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 62965000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605024N_3414$$, $$0605024N$$, $$3414$$, $$Anti-Tamper Technology Support$$, 1791000, $$This project enables development of new and novel Anti-Tamper technologies and solutions toward Department of Navy technical needs and requirements through DoN AT Technical Authority engagement in government, defense industrial base, and commercial technology endeavors. The technologies and solutions to be developed address and mitigate exploitation and reverse engineering threats associated with sensing, weapon, combat, and Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) systems and platforms when they are outside of U.S. control. The technologies include secure microelectronics and processing, sensors, software, architecture components, and enabling technologies. The technology and solutions will be assessed and tested for technology and manufacturing maturity, as well as suitability for DoN-relevant environments and use cases. Government laboratory expertise will mature in Anti Tamper technologies and techniques. Factors related to integration and composition of discrete technologies and solutions will be understood and, where applicable, demonstrated to enhance their value to the overall protection scheme and effectively deter, impede, detect, and respond to credible reverse engineering and exploitation threats.$$, 1791000, NULL, NULL, NULL, NULL, 31521000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605027D8Z_927$$, $$0605027D8Z$$, $$927$$, $$Next Generation Resource$$, 9765000, $$The Office of the Under Secretary of Defense (Comptroller) (OUSD(C)) is responsible for advising the Secretary of Defense on all Defense budgetary and fiscal matters, for Defense budget development and execution, and for overseeing financial management across the Department. The OUSD(C) has a broad set of responsibilities in supporting the Planning, Programming, Budget and Execution (PPBE) process. The Office of the Director, Cost Assessment and Program Evaluation (CAPE), provides independent analytic advice to the Secretary of Defense on all aspects of the Defense program, including alternative weapon systems and force structures, the development and evaluation of programs and defense program alternatives, and the cost-effectiveness of defense systems. OUSD(C) and CAPE use multiple systems to formulate, justify, distribute, and execute DoD budgets. The information managed by the budget formulation and programming systems is redundant, and reconciliation of information is difficult and inefficient. These systems require extensive manpower investments to provide executives the information needed to make timely key financial decisions. The OUSD(C) and CAPE require a more efficient and effective Defense budget environment that optimizes the budget cycle to ensure users are processing and reporting efficiently and DoD Senior Leadership has the information to make informed, critical decisions. The OUSD(C) requires capabilities to provide for the effective formulation, and justification of the Defense budget to be adaptable and modern. This includes the following: • Automated exchange and reconciliation of budget data • Improved efficiency through the utilization of a unified budgetary model • Instantaneous ability to generate data for management reviews and decisions • Capability to accommodate emerging business practices • Agile methods to launch and terminate new development efforts more quickly • Seamlessly combine the outputs of multiple efforts at various levels of maturity for organizational responsiveness and alternative resource allocation for innovation adoption As of the 3rd Quarter FY 2022, NGRMS has been developed and has deployed Initial Operating Capability (IOC) to all Department of Defense Services and agencies. The system has been designed as a single system with a unified data source for OUSD(C) and CAPE, which supports the reforming and modernizing of the PPBE$$, 9765000, NULL, NULL, NULL, NULL, 59127000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605030A_EA8$$, $$0605030A$$, $$EA8$$, $$Joint Tactical Networking Center$$, 20954000, $$The Joint Tactical Networking Center (JTNC) is chartered to enable the Department of Defense (DoD)'s rapid identification, characterization, procurement, fielding, and sustainment of modular, innovative tactical communications products that ensure secure, interoperable, and resilient Command, Control, Communications, Computers, Intelligence, Surveillance, and Reconnaissance (C4ISR) capabilities. The JTNC provides technical expertise to facilitate tactical communications management, innovation, and standardization. The JTNC: (1) maintains a cyber-hardened DoD Information Repository (IR), (2) provides Technical Analyses/Capability Characterizations on tactical communications products, (3) provides Open Systems Architecture Standards, (4) provides exportability analysis and licensing reviews, and (5) serves as Technical Advisor to the Communications, Command, and Control Leadership Board (C3LB) and Tactical Communications Senior Steering Group (TCSSG). JTNC mission is executed in coordination with key government stakeholders to include: C3LB, TCSSG, Communications Technologies and Waveforms Working Group (CTWWG), Resiliency Sub-Working Group (RSWG), the Department of Defense (DoD) Chief Information Officer (CIO), Under Secretary of Defense for Acquisition and Sustainment (USD(A&S)), Joint Staff J6 (JS J6), the Under Secretary of Defense for Research and Engineering, USD(R&E), and the Services. Particular attention is paid to ensuring that interagency work is collaborative and eliminates duplicative capability. The JTNC enables a common software baseline that is hardware agnostic leading to increased competition for Software Defined Radios (SDR). Current JTNC directed requirements, outlined by the C3LB, consist of the CTWWG, Joint All-Domain Command and Control (JADC2) support, development/maturation of the DoD IR framework & Cloud migration, and development of the Joint Communications Marketplace (JCM) to meet DoD and Industry requirements in conjunction with DoD Instruction 4630.09. Through collaboration with USD R&E (INSS) and industry partners, JTNC is in the process of capturing information on resilient waveform technologies and portfolio products. The ultimate goal is to expedite market research activities by collecting, analyzing, and making data available in support of emerging Government waveform acquisitions. The JTNC and Joint Interoperability Test Command (JITC) co-chair the High-Frequency Interoperability and Architecture Sub- Working Group (HF I&A SWG) to resolve HF 3G and 4G interoperability issues, thus facilitating next-generation HF systems. The JTNC HF team is also pathfinding for a new tactical MIL-STD to provide more resilient communications. Additionally, the JTNC is engaged in the analysis of software artifacts involving high assurance devices,$$, 20954000, NULL, NULL, NULL, NULL, 17981000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605030F_3600$$, $$0605030F$$, $$3600$$, $$Research, Development, Test & Evaluation, Air Force / BA 5: System$$, NULL, $$No FY 2026 funding requested in the Program Element. No FY 2025 funding was requested in the Program Element. All JTNC funding has been shifted to Army PE 0605030A. The Joint Tactical Networking Center (JTNC) is chartered to enable the Department of Defense (DoD)'s rapid identification, characterization, procurement, fielding, and sustainment of modular, innovative tactical communications products that ensure secure, interoperable, and resilient Command, Control, Communications, Computers, Intelligence, Surveillance, and Reconnaissance (C4ISR) capabilities. The JTNC provides technical expertise to facilitate tactical communications management, innovation, and standardization. The JTNC: (1) maintains a cyber-hardened DoD Information Repository (IR), (2) provides Technical Analyses/Capability Characterizations on tactical communications products, (3) provides Open Systems Architecture Standards, (4) provides exportability analysis and licensing reviews, and (5) serves as Technical Advisor to the Communications, Command, and Control Leadership Board (C3LB) and Tactical Communications Senior Steering Group (TCSSG). JTNC mission is executed in coordination with key government stakeholders to include: C3LB, TCSSG, Communications Technologies and Waveforms Working Group (CTWWG), Resiliency Sub-Working Group (RSWG), the Department of Defense (DoD) Chief Information Officer (CIO), Under Secretary of Defense for Acquisition and Sustainment (USD(A&S)), Joint Staff J6 (JS J6), The Under Secretary of Defense for Research and Engineering, abbreviated USD(R&E), and the Services. Particular attention is paid to ensuring that interagency work is collaborative and eliminates duplicative capability. The JTNC enables a common software baseline that is hardware agnostic leading to increased competition for Software Defined Radios (SDR). Current JTNC directed requirements, outlined by the C3LB, consist of the CTWWG, Joint All-Domain Command and Control (JADC2) support, development/maturation of the DoD IR framework & Cloud migration, and development of the Joint Communications Marketplace (JCM) to meet DoD and Industry requirements in conjunction with DoD Instruction 4630.09. Through collaboration with USD R&E (INSS) and industry partners, JTNC is in the process of capturing information on resilient waveform technologies and portfolio products. The ultimate goal is to expedite market research activities by collecting, analyzing, and making data available in support of emerging Government waveform acquisitions. The JTNC and Joint Interoperability Test Command (JITC) co-chair the High-Frequency Interoperability and Architecture Sub- Working Group (HF I&A SWG) to resolve HF 3G and 4G interoperability issues, thus facilitating next-generation HF systems. The JTNC HF team is also pathfinding for a Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0605030F / Joint Tactical Network Center (JTNC) Development & Demonstration (SDD) new tactical MIL-STD to provide more resilient communications. Additionally, the JTNC is engaged in the analysis of software artifacts involving high assurance devices, such as software defined radios ported with specific waveforms to support National Security Agency (NSA) efforts. The JTNC participates in Standards-related activities such as the Interface Control Working Group (ICWG) and has been collaborating with the Army on the development of C4ISR/Electronic Warfare Modular Open Suite of Standards (CMOSS) specifications. Finally, the JTNC continues evolving its Waveform Assessment and Milestone Review (WASMR) and Capability Characterization processes. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
