INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605864N_2922$$, $$0605864N$$, $$2922$$, $$MRTFB Maint & Repair$$, 40615000, $$This project provides funding for the maintenance and repair of the Major Range and Test Facility Base (MRTFB) Real Property Maintenance Activities at the Naval Air Warfare Center Weapons Division, the Naval Air Warfare Center Aircraft Division, and the Atlantic Undersea Test and Evaluation Center. Funds mission critical emergency services, recurring maintenance and repair, and major repair projects. In addition, it addresses priority items on the Backlog of Maintenance and Repair list.$$, 40615000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605829F_665830$$, $$0605829F$$, $$665830$$, $$Acq Workforce-Global Battle Mgmt$$, 0, $$This Project funds the Air Force Life Cycle Management Center (AFLCMC) civilian workforce in the Command, Control, Communications & Battle Management and Electronic Systems Directorates. AFLCMC equips U.S. and allied forces with operational weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this program element will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. These program elements support both civilian pay and non-pay support requirements.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605830A_EE5$$, $$0605830A$$, $$EE5$$, $$Aviation Ground Support Equipment$$, 930000, $$Aviation Ground Support Equipment (AGSE) Product Office tests and evaluates critical ground support equipment to enhance the functionality and maintenance of both the Army's enduring fleet of rotary wing aircraft and the Future Long Range Assault Aircraft (FLRAA). This is accomplished by providing aircraft diagnostic, repair and servicing capabilities essential to support aircraft maintenance and operational readiness. Priority efforts include modification of the Aviation Ground Power Unit (AGPU 1.1) to support FLRAA, the development of new products and a comprehensive study/analysis of AGSE's 24 enduring products to identify future capability gaps required to fully support the enduring fleet and FLRAA. Continued investments in AGSE's ability to develop, test and evaluate aircraft support equipment ensure Army Aviation can rapidly deploy, operate and sustain operations across the globe in a multi-domain environment, supporting the National Defense Strategy and National Military Strategy.$$, 930000, NULL, NULL, NULL, NULL, 1124000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605831F_665826$$, $$0605831F$$, $$665826$$, $$acq workforce-global power$$, 304623000, $$This Project funds the Air Force Life Cycle Management Center (AFLCMC) civilian workforce in the Fighters and Advanced Aircraft, Bombers, and Armament Directorates. AFLCMC equips U.S. and allied forces with operational weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this project will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. This project supports both civilian pay and non-pay support requirements.$$, 304623000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605831F_665827$$, $$0605831F$$, $$665827$$, $$Acq Workforce-Global Vig &$$, 318999000, $$This Project funds the Air Force Life Cycle Management Center (AFLCMC) civilian workforce in the Intelligence, Surveillance, and Reconnaissance and Special Operations Forces, Combat Readiness, Training, and Propulsion Directorates. AFLCMC equips U.S. and allied forces with operational weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this project will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. This project supports both civilian pay and non-pay support requirements.$$, 318999000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605831F_665828$$, $$0605831F$$, $$665828$$, $$Acq Workforce-Global Reach$$, 179071000, $$This Project funds the Air Force Life Cycle Management Center (AFLCMC) civilian workforce in the Mobility, Training, and Presidential and Executive Airpower Directorates. AFLCMC equips U.S. and allied forces with operational weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this project will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. This project supports both civilian pay and non-pay support requirements.$$, 179071000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605831F_665831$$, $$0605831F$$, $$665831$$, $$Acq Workforce - Capability$$, 280687000, $$This Project funds the AFLCMC civilian workforce in cross-cutting and mission support organizations such as Plans & Programs, Engineering, Contracting, Financial Management, Logistics, Program Management, Intelligence, Information Protection, Safety, Personnel, Small Business, Inspector General, and Staff Judge Advocate. The Air Force Life Cycle Management Center (AFLCMC) equips U.S. and allied forces with operational weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this program element will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. These program elements support both civilian pay and non-pay support requirements.$$, 280687000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605831F_665832$$, $$0605831F$$, $$665832$$, $$Acq Workfoce-Advanced Prgm$$, 69785000, $$This Project funds the AFLCMC civilian workforce supporting Special Access Programs across the Center. AFLCMC equips U.S. and allied forces with operational weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this project will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. This project supports both civilian pay and non-pay support requirements.$$, 69785000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605832F_665832$$, $$0605832F$$, $$665832$$, $$Acq Workfoce-Advanced Prgm$$, 0, $$The Air Force Life Cycle Management Center (AFLCMC) equips U.S. and allied forces with operational weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this program element will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. These program elements support both civilian pay and non-pay support requirements.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605833F_665833$$, $$0605833F$$, $$665833$$, $$Acq Workforce - Nuclear Systems$$, 368881000, $$This program element directly funds the Air Force Nuclear Weapons Center (AFNWC) and Air Force Life Cycle Management Center (AFLCMC) nuclear acquisition workforce. AFNWC and AFLCMC equip U.S. forces with operational nuclear weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, technical and business capabilities needed to oversee Nuclear Systems acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this program element will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. These program elements support both civilian pay and non-pay support requirements.$$, 368881000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605853N_0149$$, $$0605853N$$, $$0149$$, $$International Coop RDT&E$$, 3699000, $$Provides funding for program management, execution, and support activities to implement a broad range of cooperative naval Research and Development, Test and Evaluation (RDT&E) initiatives to improve coalition interoperability, harmonize U.S. Navy requirements with allied and friendly nations and identify cooperative international opportunities. The funding is used to develop approaches to international cooperation consistent with combatant commanders (COCOMs), Chief of Naval Operations (CNO), and Secretary of the Navy (SECNAV) priorities in the maritime domain. Various cooperative RDT&E programs, projects and exchanges are pursued to identify cooperative acquisition programs, enhance Overseas Contingency Operations (OCO) efforts, fill capability gaps, improve US/coalition interoperability, and standardize defense capabilities with international partners. Such efforts have resulted in: 1. Negotiating and developing approximately 57 international RDT&E Agreements annually with allied and friendly nations; 2. Executing Information Exchange Annexes (IEAs) with foreign partners; 3. Improving IEA information dissemination with allied and friendly countries and within Department of the Navy (DON); 4. Coordinating Navy inputs to the Office of the Under Secretary of Defense (OUSD) Acquisition and Sustainment (A&S) Foreign Comparative Test (FCT) Program, and Coalition Warfare Program (CWP) as well as the DON Technology Transfer Security Assistance Review Boards (TTSARB). 5. Representing the U.S. Navy in Office of the Secretary of Defense (OSD) directed Armaments Cooperation Forums, including the Conference of North Atlantic Treaty Organization (NATO) Armaments Directors' groups (NATO Naval Armaments Group (NNAG)), and Senior National Representative (SNR); 6. Funding of various international RDT&E support databases including Technical Project Officer (TPO), International Agreement Generators, Information/Data Exchange Agreements, and Project Agreements/Memorandums of Understanding; 7. Funding for Engineering and Scientist Exchange Program (ESEP).$$, 3699000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605853N_1767$$, $$0605853N$$, $$1767$$, $$Naval War Col Strategic Studies Supt$$, 10294000, $$Naval War College (NWC) research, analysis and gaming activities serve as a focal point, stimulus, and major source of strategic and operational thought within the Navy, Joint and Interagency communities. These efforts generate strategic and operational alternatives, tactical imperatives, quantitative analysis, war gaming, political- military assessments, and provide recommendations to the Chief of Naval Operations (CNO), Fleet Commanders and numbered Fleet Commanders regarding the formulation and execution of maritime options for the President of the United States.$$, 10294000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605853N_2098$$, $$0605853N$$, $$2098$$, $$Navy Postgraduate School (NPS)$$, 12920000, $$Navy Postgraduate School (NPS) research and analysis activities serve as a focal point, stimulus, and major source of strategic, tactical and operational thought within the Navy communities. These efforts generate strategic and operational alternatives, tactical imperatives, quantitative analyses, technical developments and assessments, and political-military assessments. Also, provide recommendations to the Chief of Naval Operations (CNO), Fleet Commanders and numbered Fleet Commanders regarding the formulation and execution of maritime options for the President of the United States. Research will be conducted that will enhance graduate education for Naval Officers and potentially provide students with areas of studies for theses and faculty projects. These research activities also serve as a means for OPNAV Resource Sponsors and Major Commands to have analysis and decision support research conducted in the uses of the applied, soft, and hard sciences in solving diverse and complex resource allocation and strategic issues facing the Navy today and envisioned in the future.$$, 12920000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605853N_2221$$, $$0605853N$$, $$2221$$, $$JT Mission Assessment Studies$$, 25368000, $$This exhibit has been updated to reflect the establishment of the Navy Analytic Office (NAO), which is responsible for the executive oversight of Navy studies and analysis. The NAO was stood up to better align the annual Analytic Agenda to Chief Naval Operation's (CNO) strategic priorities while also providing for study of the more tactical requirements of the Fleet and Navy writ large. The outcome will be synchronized modeling, simulation, assessments, wargames, experiments and exercises providing rich, shared data to support and refine warfighting concepts and to inform budget decisions. The Navy Annual Studies Program supports the Analytic Agenda by providing both the development and use of modeling, simulation and analytically-based warfare, business analyses and analytic tools that provide the basis for decision making with respect to concepts of operations (CONOPS), Command, Control, Communications, Computers, Intelligence, Surveillance and Reconnaissance (C4ISR) Systems; warfare systems, and analytical underpinnings/basis for programmatic decisions of the Navy's top leadership regarding their architectures, force structure, and the Navy's core "organize, train, and equip mission" (the warfare and provider Enterprises). The program provides capability-based planning assessment for Joint Capabilities Integration and Development System (JCIDS), conducts analysis to affect warfighting capability trades and enterprise resources, identifies needs, gaps and overlaps, and assesses alternative solutions to Joint needs. The program provides overarching Planning, Programming, Budgeting and Execution System (PPBES) analyses and guidance for PPBES which provides gap analysis and investment strategy and total obligation authority allocation. It provides independent capability analysis and assists in structuring follow-on Navy analyses. The program coordinates Navy's position for the enhanced planning process and conducts net assessments. It serves as the lead campaign analysis to approve Navy warfare and support requirements. The program supports the Maritime Strategy which charts a course for the Navy, Coast Guard and Marine Corps to work collectively with each other and international partners to prevent crises from occurring, or reacting quickly should one occur to avoid negative impact to the United States. The Studies Program provides a broad- view perspective across the Fleet and Navy staff, with an integrated look at both warfighting and warfighting-support programs. It provides Navy alternatives in assessing the implications embedded within resource decisions in a quantified context of costs versus capability versus risk. The program provides independent analytic support to Navy leadership in conjunction with various executive level decision forums. This project funds concept development engineering, mission effectiveness analysis, and other analyses for formulation of future surface ship and associated platform force structure along with development of the tools to accomplish these efforts. Advanced platform concept studies and systems technology assessments will be conducted as will the development and upgrade of concept design and engineering tools, methods, and criteria. Concept Formulation (CONFORM)/Concept Development and Experimentation (CDE) for ships, boats and unmanned maritime vehicles must be continuously exercised to remain viable. It takes years to train competent practitioners, and knowledge currency is quickly lost without practice. Evolving threats and technologies drive concepts (and the tools, processes, and skills needed to produce them) towards obsolescence without constant attention. Capability Based Assessments and Analysis of Alternatives (AoA) timelines are insufficient for establishing potential material solution cost versus capability relationships without significant concept formulation work beforehand. Active collaboration between the Office of the Chief of Naval Operations requirement sponsors, Program Offices, and the various System Commands (Naval Sea Systems Command, Naval Air$$, 25368000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605853N_3017$$, $$0605853N$$, $$3017$$, $$Enterprise Information Systems$$, 1152000, $$This project funds the Office of Naval Research (ONR) Next Generation Enterprise Network (NGEN) Information Technology corporate costs.$$, 1152000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605853N_3270$$, $$0605853N$$, $$3270$$, $$Sec. 2912 Operational Energy$$, 0, $$PU 3270 Naval Postgraduate School (NPS) Operational Energy EREACTS Program: The Operational Energy EREACTS program is a key initiative within the DoD that develops, implements, and sustains innovative energy-saving operational initiatives. This program aligns with the operational energy objectives set by the SECNAV by improving resiliency, efficiency, and warfighter readiness. The Navy Postgraduate School (NPS) is instrumental in this effort, conducting innovative research and offering operational energy education to the Fleet through various funded projects.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605864N_2958$$, $$0605864N$$, $$2958$$, $$Cyberspace Activities$$, 465000, $$This project provides funding for cyber requirements for the Major Range and Test Facility Base (MRTFB) Real Property at the Atlantic Undersea Test and Evaluation Center (AUTEC). Funds critical cybersecurity upgrades to instrumentation and networks to ensure capabilities are secure and available to support customer test requirements.$$, 465000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605864N_3386$$, $$0605864N$$, $$3386$$, $$MRTFB Marine Vessels$$, 14462000, $$This project funds the overhauls and preventative maintenance of the 23 Major Range and Test Facility Base (MRTFB) marine vessels located at Naval Air Warfare Center Weapons Division, Point Mugu, CA, Pacific Missile Range Facility, Honolulu, HI, Naval Undersea Warfare Center Keyport, WA, Naval Air Warfare Center Aircraft Division, Patuxent River, MD, and Atlantic Undersea Test and Evaluation Center. These vessels are used to launch and recover torpedoes, acoustic systems, and other weapons, provide range surveillance and clearance, and can be configured for target services. Overhauls are required to operate ships over 300 tons in compliance with American Bureau of Shipping "Load Line" certification requirements. Major preventative maintenance requiring shipyard support is also performed during these periods to mitigate risks of failures and sustain critical, Hull, Mechanical and Electrical systems to support operations at sea.$$, 14462000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605853N_3312$$, $$0605853N$$, $$3312$$, $$MTMD-Maritime Theater Missile$$, 25328000, $$This project funds participation in Maritime Integrated Air and Missile Defense projects with other nations through the Maritime Missile Defense Projects Framework Memorandum of Understanding of 2004 (as amended 2009, 2015, 2016 and 2020). Known as the Maritime Theater Missile Defense (MTMD) Forum, it promotes interoperability with the Navies of twelve participating nations (Australia, Belgium, Canada, Denmark, France, Germany, Italy, Netherlands, Norway, Spain, United Kingdom and the United States). This project provides interoperability assessment and opportunities to Allies that directly contributes to increasing the number of countries capable of supporting NATO Ballistic Missile Defense (BMD). Engineering analysis and data analytics from MTMD activities are provided to European and Pacific Combatant Commands in direct support of theater Integrated Air and Missile Defense (IAMD) priorities. The MTMD Forum addresses challenges associated with integrating maritime Allied Air Defense in Support of Ballistic Missile Defense Operations into joint IAMD command and control. MTMD Forum nations leverage At- Sea Demonstration (ASD) test events, coupled with operational Fleet Exercises (Formidable Shield and Pacific Dragon), to integrate technology and validate national capabilities in operational constructs, supportive of operational force employment. The MTMD Forum encourages national development of systems and practices that enhance protection and defense against the proliferation of short, medium and long- range Ballistic Missile (BM) and Advanced Anti-Ship Cruise Missile (ASCM) threats through the development of interoperable sea-based Integrated Air and Missile Defense (IAMD) capability among MTMD Forum nations. The MTMD Forum enhances utilization of existing sea-based IAMD systems to protect against current threats, while measuring progressive improvement and development of compatible systems to better counter evolving threats. This project supports USN participation in a Maritime IAMD Project Arrangement focused on: (1) Battle Management Command, Control, Communications, Computers, and Intelligence (BMC4I) to define and develop architectures and perform engineering to address coalition capability gaps. (2) Modeling & Simulation (M&S) to establish and maintain a maritime coalition M&S testbed and to perform legacy and future systems simulation testing. (3) Hardware-in-the-Loop Testing of Coalition combat systems to assess interoperability within the Coalition Distributed Engineering Plant (CDEP). (4) Open Architecture (OA) work to develop Interface Standards and Data Models. (5) Test Planning and Execution (TPEX) to develop Test Plans, oversee exercise participation and conduct post event data analysis and reporting. (6) Operational Requirements (OR) to identify operational constraints and tactical constructs surrounding coalition maritime integrated air and missile defense activities, and their integration into joint operations. (7) Reciprocal Use of Test Facilities agreements with other nations to support Maritime IAMD and MTMD Forum-related demonstrations.$$, 25328000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605853N_3330$$, $$0605853N$$, $$3330$$, $$Naval Research Laboratory (NRL)$$, 23103000, $$This program provides a systematic and planned approach to improve vital in-house science and technology (S&T) laboratory facilities which are reaching or have reached critical stages of deterioration at the Naval Research Laboratory (NRL), where the average building age is 70 years old, as of 2025. Critical S&T research cannot be sustained or succeed in deteriorated facilities. World class research can only be accomplished in facilities that are at a minimum "adequate", but preferably "state-of-the-art." Due to their advanced age and deterioration, funds will be used for restoration and modernization efforts in support of NRL's research mission of meeting future technological threats and providing support to the warfighter.$$, 23103000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605853N_3363$$, $$0605853N$$, $$3363$$, $$PACOM Initiative$$, 31674000, $$China Strategic Initiative (CSI) became a DoD RDTE program in FY 2014. The CSI program is U.S. Indo-Pacific Command's(INDOPACOM) first Asia Rebalance initiative and provides critical support to planning efforts across the Command addressing Secretary of Defense's # 1 priority. CSI is a command-directed program that provides the Commander, INDOPACOM, and his staff vital support at all levels of planning and decision-making within the INDOPACOM Area Of Responsibility. The CSI program provides: cutting-edge research on adversary approaches to warfare, monitoring and analysis of adversary social media and censorship, unique understanding of effects of U.S. actions at the strategic and operational levels, sponsorship of Track 1.5/2 Strategic Nuclear Dialogue with China, etc. This funding is for a classified effort and details can be provided at a higher classification level. Pacific Multi-Domain Training and Experimentation Capability (PMTEC) is foundational to meeting Commander, USINDOPACOM's high-end warfighting capability, theater force posture, and Ally & Partner (A&P) objectives through the execution of joint experimentation in the Indo-Pacific. The innovative combinations of new technology, capability, and CONOPS in Joint Exercises will enable integration, warfighting assessment, and rapid capability development. PMTEC is the joint synchronizer and integrator by bringing together OSD, Service RDT&E, other government agencies, industry, and academia with Combatant Commands, Service Components, warfighting units, and A&Ps to expedite experimentations of R&D projects/prototypes and to facilitate more rapid modernization and interoperability. The Joint Experimentation Program (JExP) is a theater-wide campaign of joint experiments to inform and strengthen the ability of joint and combined forces to execute all-domain operations in contested environments. JExP is focused on both what the U.S. and allies can do to protect partners subjected to military aggression, and also what those partners can do to defend themselves against said aggression. To determine the readiness of developmental systems to operate within the contested environment, JExP consists of three experimentation categories/pillars: a. Joint Experimentation within Exercises b. Stand-alone Experimentation c. Joint International Experimentation The Research, Development, Test & Evaluation funds materiel, both commercial and government off the shelf systems, required to execute international experiments to include support equipment and/or developmental software and systems for potential leave-behind capabilities. Lastly, it funds the logistics required to deploy, install, and remove any specific developmental equipment required for JIE.$$, 31674000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605853N_9999$$, $$0605853N$$, $$9999$$, $$Congressional Add$$, 0, $$This program provides a systematic and planned approach to improve vital in-house science and technology (S&T) laboratory facilities which are reaching or have reached critical stages of deterioration. The program includes restoration and modernization (R&M) initiatives for NRL facilities, where the average age of the buildings is over 69 years, as of 2024.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605856N_0128$$, $$0605856N$$, $$0128$$, $$Mgmt/Tech Supt Strategic$$, 1355000, $$The project provides analytical support to the Director, Undersea Warfare Division as a basis for major policy, planning, and acquisition program decisions. It supports the development of the Submarine Force strategic vision to guide research and development investment strategy and future planning. Additionally, this line supports studies in the area of submarine and undersea surveillance missions, force structure, payloads and sensors, and force employment.$$, 1355000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605856N_1038$$, $$0605856N$$, $$1038$$, $$Acoustic & Non-Acoustic Analysis$$, 2354000, $$This project provides analytical support to the Director, Undersea Warfare as a basis for major policy, planning, and acquisition program decisions. It supports studies in the area of undersea surveillance missions, sensor system communications, and acoustic performance prediction systems, environmental and medical effects of acoustic systems, operational security, and future threat analysis. Supports synthetic mission lay down simulations for Integrated Undersea Surveillance System (IUSS) strategic planning and resource allocation. Supports continued development and documentation of architecture for future undersea surveillance capabilities and systems. Supports studies to determine long-term impact of IUSS active sensors on marine animals and development of Surveillance Towed Array Sensor System (SURTASS) Low Frequency Active (LFA), and Compact LFA (CLFA).$$, 2354000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605864N_3154$$, $$0605864N$$, $$3154$$, $$Nanoose and Dabob Bay Ranges$$, 15464000, $$This project provides maintenance and operations support for the Nanoose and Dabob Bay Ranges along with associated support systems to provide Test and Evaluation and readiness assessment services for acquisition programs and the Fleet. Operates ocean-based environment, measurement and support systems. Maintains and repairs systems that measure warfare system performance. Oversees test, training, and measurement facilities, equipment, operations and maintenance processes. Satisfies customer exercise and measurement requirements through the operation of ocean-based test and measurement systems. Assures the readiness of systems through the implementation of calibration, maintenance, repair and life cycle processes. Performs exercise planning, exercise interpretation and development of surrogate environments, for system performance measurement. Assists in the design, fabrication and testing of systems for Undersea Warfare applications. Oversees the manning and maintenance of Naval Undersea Warfare Center Division Keyport range craft and range craft systems. This project funds costs not chargeable to customers.$$, 15464000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605857A_031$$, $$0605857A$$, $$031$$, $$Environmentally Sustainable$$, 2857000, $$The Environmentally Sustainable Acquisition/Logistics (ESAL) Project provides support to the system acquisition community to integrate environmental quality issues and concerns into the life cycle system acquisition process, including human health risks, life safety, material obsolescence due to regulatory pressures, occupational exposures and energy efficiency. This includes helping the acquisition community address high priority issues associated with hexavalent chromium, cadmium and airborne lead. The focus of ESAL is on improving readiness, enabling mission capabilities, improving acquisition processes, reducing supportability burden, and minimizing total ownership cost. The Assistant Secretary of the Army for Installations, Energy and Environment has defined the functions of the ESAL project in coordination with the Army Acquisition Executive and the Assistant Secretary of the Army (Acquisition, Logistics, and Technology). This Project provides direct support to the Army Installations (maintenance community, Soldier and family health, and surrounding community health and safety) and Army acquisition community to pursue environmental sustainability and comply with legal statutes, policies and regulations during the life cycle of Army materiel. ESAL helps address Army Modernization Priorities, while sustaining readiness and achieving compliance with its installations, weapon systems, industrial base, field and deployed activities directed by international treaties, Federal statutes, Executive Orders, Department of Defense (DoD) and Army policies and regulations. ESAL also reduces exposure to toxic materials to Soldiers, civilians, family members to reduce the possibility of substitution regret. Beginning in FY26 The Environmentally Sustainable Acquisition/Logistics Project will assume Department of Defense Executive Agent Responsibilities for the Unexploded Ordnance Center of Excellence (UXOCOE), in direct support of Assistant Secretary of the Army, Acquisition, Logistics, and Technology ASA(ALT). The UXOCOE Project provides central coordination of the DoD's Counter Explosive Hazards (C-EH) research and engineering (R&E) investment efforts by maintaining and openly sharing awareness in order for the DoD to efficiently, effectively, and economically acquire C-EH technology capabilities. The collection and management of this information is critical to achieving the DoD mandate and goals established by OSD and Army Senior Leadership. This UXOCOE is DoD's only federated requirement to acquire accurate and timely technical information that is essential to successfully meeting Warfighter C-EH technology development milestones required by future forces, and allow both DoD Component and Army Science and Technology (S&T) leadership to refine investment strategy and quickly react to emerging opportunities and issues. Work in this Project is performed by the United States Army Futures Command (AFC), U.S. Army Combat Capabilities Development Command (DEVCOM).$$, 2857000, NULL, NULL, NULL, NULL, 1274000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605857A_06I$$, $$0605857A$$, $$06I$$, $$Environmental Quality Technology$$, NULL, $$This Project provides Research, Development, Test, & Evaluation (RDTE) Management Support for the demonstration and validation of innovative environmental quality technologies to modernize materials and processes required for current and future operational sustainment and warfighter training capabilities. The Project supports technologies that increase life safety, reduce Soldier and worker human health risks, enhance readiness, and enable mission capabilities of the current and future force, while simultaneously increasing performance and standardization across the Army. This Project provides for management of RDTE activities conducted under Program Element 0603779A (Environmental Quality Technology Dem/Val) / Project E21 (Environmental Quality Technology Dem/ Val), which supports the Cross Functional Teams and the Army's top modernization priorities by addressing potential obsolescence of legacy materials and current and emerging impacts on human health and the environment. The Project expedites technology transition from the laboratory to operational use by establishing toxicology assessments to support the demonstration of modern materials and processes fulfilling or surpassing the performance requirements outlined in Material Specifications, Depot Maintenance Work Requirements, Technical Manuals, Drawings, and other technical data. Work in this Project is performed by the United States Army Futures Command (AFC), U.S. Army Combat Capabilities Development Command (DEVCOM).$$, NULL, NULL, NULL, NULL, NULL, 296000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605863N_0568$$, $$0605863N$$, $$0568$$, $$RDT&E Acft Flt Hours$$, 43389000, $$Research, Development, Test and Evaluation (RDT&E) Aircraft Flight Hours: This non-acquisition project supports direct flight hour costs, which include aviation fuel and a portion of the costs of Aviation Depot Level Repairables (AVDLR) associated with NAVAIR test pilot proficiency flights, including organizational and intermediate maintenance, associated consumables, including petroleum, oil, lubricants, and spare and replacement parts for components that fail. Annual test pilot flight hours, as delineated in OPNAVINST 3710.7, are satisfied through a combination of program funded test flights, which vary year to year based on program schedules; flights funded through this project unit ensure a baseline level of pilot readiness. These flight hours ensure test pilots remain proficient in assigned type / model / series aircraft in which they are qualified (approximately 3 hours per month) during lulls in program test schedules to ensure proficient test pilots are available to safely support aviation program testing. Readiness hours are designed to provide aircrew with a minimum of 11 flight hours per month, for a total of 133 hours annually. Flight hours support ferry flights to Fleet Readiness Centers for planned depot maintenance, post maintenance, acceptance test flights, aircrew training and test pilot proficiency when test program demand is low, in direct support of Research and Development Programs at Naval Air Systems Command, and Office of Naval Research flight activities. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward maintaining test pilot readiness in direct support of general research, development, test and evaluation.$$, 43389000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605863N_0569$$, $$0605863N$$, $$0569$$, $$RDT&E Acft Supt$$, 53196000, $$Research, Development, Test and Evaluation (RDT&E) Aircraft Support: This continuing project funds costs associated with the preventive and corrective maintenance of fixed and rotary wing aircraft which directly support test and evaluation of aircraft and associated weapon systems and sensors. Testing aboard dedicated RDT&E aircraft reduces the number of fleet units required to support test and evaluation of aviation programs. This project unit funds airframe Standard Depot Level Maintenance (SDLM), the Integrated Maintenance Concept and Planned Depot Maintenance, major in-service repairs, emergent repairs and aircraft engine periodic maintenance and overhauls and aircraft material condition and field inspections. Also included in this project unit, are the costs of Aviation Depot Level Repairables (AVDLR), which are spare and replacement parts for components that fail during the conduct of readiness flight operations, aircrew training and proficiency flight hours, and must be replaced to support follow-on flight operations. This project unit also funds Aircraft Structure Periodic Assessments (ASPA), Individual Material Readiness List (IMRL) tools and support equipment, Aviation Climate Assessment Survey System (ACASS) and other projects and peripheral equipment associated with the maintenance of flight readiness for RDT&E aircraft. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing equipment required for general research, development, test and evaluation.$$, 53196000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605863N_2924$$, $$0605863N$$, $$2924$$, $$SDTS$$, 14313000, $$This project provides for the preventive and corrective maintenance of mission critical Hull Mechanical and Electrical (HM&E) and remote control system maintenance aboard the Self Defense Test Ship (SDTS) in support of the Navy RDT&E of ship self-defense systems. Testing aboard this ship provides the capability to safely test self-defense weapon systems within their minimum range and reduces the number of fleet units required to support RDT&E efforts. Funds are used to purchase consumable supplies and repair parts, conduct routine preventive and emergent corrective maintenance and engineering support services.$$, 14313000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605864N_9999$$, $$0605864N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional Adds: C378: Tactical edge networking payloads C784: Future workforce innovation$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605863N_3206$$, $$0605863N$$, $$3206$$, $$T&E Enterprise$$, 20639000, $$The Testing & Evaluation Enterprise merges common ship, element, and system requirements into the fewest number of test events while leveraging planned Combat System Ship Qualification Trials (CSSQT) to accomplish Developmental Testing (DT) and Operational Testing (OT) requirements. All tests on the SDTS require the sharing of infrastructure, missile range allocations, execution time, and underway time to eliminate duplicative testing. T&E Enterprise provides end-to-end mission Operational Testing in a realistic operational environment, capitalizing on Probability of Raid Annihilation Modeling and Simulation (M&S) data validated with results of Operational and Live Fire Testing, and ensuring a consistent approach across ship classes. Applicability of all test events is beneficial across multiple ship classes with the same variation under test. Currently finishing Air Warfare Ship Self Defense (AW SSD) testing on legacy SSDS Baseline 10 class ship, CVN 78 (TEMP 1714), and starting testing on follow on SSDS Baseline 12 ship classes, CVN 79, LHA 8, and LPD Flt II (TEMP 1910). This approach merges common ship, element, and system requirements into common infrastructure for combined Developmental and Operational Testing (DT/OT) of the Surface Navy antiship cruise missile (ASCM) defense requirement, expressed as a Probability of Raid Annihilation (PRA). Enterprise Testing characterizes system performance with live fire events and through Modeling & Simulation (M&S) assessments informed by live-fire demonstrations. Enterprise Cost elements: a) Enterprise Testing and Planning. SDTS and Lead Ship tracking and firing exercises are conducted against single- and dual-, subsonic and supersonic ASCM threat surrogates. Includes the contractor and government costs to administer the Enterprise, collect and distribute data from live events, maintain Cybersecurity certifications, and financial management. b) Self-Defense Test Ship (SDTS) Combat Systems. Includes procurement, installation, check-out, stage testing, routine preventive maintenance, and repairs of major combat system elements. c) Enterprise Testbed (ETB). Includes all M&S costs required to create OT-quality digital representations of shipboard combat system performance including infrastructure, distributed secure network, and common environmental services for DT/OT. SDTS testing requirements outlined in AW SSD Enterprise TEMP 1714 and lead/operational ship testing requirements for Evolved Sea Sparrow Missile (ESSM) TEMP 1471, Rolling Airframe Missile (RAM) Blk 2 TEMP 286-2, DDG 1000 TEMP 1560, CVN 78 TEMP 1610, Cooperative Engagement Capability (CEC) TEMP 1415, SSDS TEMP 1400, LHA 6 TEMP 1697, AN/SPQ-9B TEMP 1463, Surface Electronic Warfare Improvement Program (SEWIP) TEMP 1658 (Block 1A), and LCS TEMP 1695.$$, 20639000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605863N_3238$$, $$0605863N$$, $$3238$$, $$Threat Engineering$$, 19942000, $$The Threat Engineering program assesses the current and future threat environment and works in coordination with the Office of Naval Intelligence (ONI) to develop, produce, and evolve digital threat engineering models in support of test and evaluation (T&E) requirements. NAVSEA requires comprehensive, validated threat modeling and simulation (M&S) products to dynamically and responsively interact with surface ship air defense systems and subsystems to allow for a performance evaluation in an operationally realistic environment. These threat M&S products, called Acquisition Threat Engineering Products (ATEP), must contain the details, features, and components necessary to react with the Blue air defense systems as the actual threats will with, deployed air defense systems to provide a comprehensive, high- confidence evaluation of Blue system capabilities. The successful and rigorous end-to-end evaluation of surface ship combat systems, to include the component systems, are required before capability and ship baselines can be delivered to the warfighter. ATEPs are valid T&E assets that satisfy Director of Operational Test and Evaluation (DOT&E) and Operational Test & Evaluation Force (OPTEVFOR) requirements in both Modeling and Simulation (M&S) testbed and at-sea configurations. ATEPs satisfy OPTEVFOR's threat model requirement for fidelity commensurate with the Blue-force system representations and contain intel-derived lethality/vulnerability data, physics-based six degrees-of-freedom models, reactive seekers and guidance, and other engineering data. ATEPs are necessary to evaluate mandatory ship Key Performance Parameters (KPP), including operational effectiveness and suitability. ATEPs are also used to evaluate a system's lethality and survivability, and its ability to achieve its performance requirements within operation and sustainment costs. In many cases, ATEP models are the only way in which the Navy can accurately emulate threat ASCM performance. ATEPs reduce Navy operational testing (OT) costs by enabling portions of OT to be conducted via M&S, increasing requirements coverage and avoiding the costs of targets and weapons that would ordinarily be required to conduct OT solely via live fire events. Threat Engineering products inform investment strategies, validate the effectiveness of capabilities provided to the Fleet, and augment live-fire T&E to obtain affordable, statistical confidence in measured performance. Threat Engineering work is prioritized to avoid technical surprise, avoid point solutions, and ensure Fleet capability against specific threats (most stressing, unique, or widely deployed and exported). Each threat system poses unique challenges to the various combat system elements and each threat system affects Blue system effectiveness in different ways, therefore each combat system configuration must undergo rigorous testing against multiple threats. T&E using M&S is essential to fill gaps and to offer realistic operational scenarios that cannot be tested via live-fire events (due to safety, numbers of targets, limitations on the characteristics of the targets, cost to develop a realistic threat, etc.). OPTEVFOR has listed a number of threat representations in ATEPs as their number one and number two priorities for the past five years because they are appropriately built to represent the salient features of the threat as an Intelligence Community-Validated and sufficient product qualified to be used in Operational T&E (OT&E).$$, 19942000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605864N_0541$$, $$0605864N$$, $$0541$$, $$AUTEC$$, 104428000, $$As a detachment of Naval Undersea Warfare Center, Division Newport, the mission of the Atlantic Undersea Test and Evaluation Center (AUTEC) is to provide the U.S. Navy an underwater range facility for full-spectrum test and evaluation of Undersea Warfare systems and for Fleet training and readiness assessment. The Atlantic Undersea Test and Evaluation Center Program Office is headquartered at Newport, RI. Atlantic Undersea Test and Evaluation Center's administrative offices are located at West Palm Beach, Florida. Test facilities are located at Andros Island, Sites 1 through 4, and the Berry Islands in the Bahamas. Atlantic Undersea Test and Evaluation Center aircraft make scheduled daily flights between West Palm Beach and Andros Town Airport. Atlantic Undersea Test and Evaluation Center manages and, under service contract, maintains and operates a 500 square nautical mile deep-water and a 100 square nautical mile shallow-water range; air-target tracking capabilities; sonobuoy simulation systems; electronic warfare threat simulation systems; rotary wing aircraft; aircraft ground support facilities; acoustic targets; torpedo retrieval and flushing capabilities; open-ocean range craft; marine support facilities; and data processing and analysis capabilities. Major test facilities on Andros Island are located at Site 1. The Command Control Building houses the range tracking displays and replay centers, the computer center, operations support functions, communications center, and the central timing system. The Range Support Facility houses a torpedo post-run workshop, Mark 46 /Mark 50 and Mark 54 lightweight torpedo Intermediate Maintenance Activity, a Mark 30 undersea target Intermediate Maintenance Activity, a Mark 48 heavyweight torpedo Research and Development Turnaround facility and related technical facilities. The complex includes electrical and physical calibration labs, a complete electronics maintenance shop, a dive locker, a precision machine shop, and logistics support areas. Atlantic Undersea Test and Evaluation Center has a 285-foot concrete pier with a controlling depth of 17 feet (5.2 meters) at mean low tide. An adjacent wharf is approximately 240 feet in length (72 meters) with a controlling depth of 15 feet at mean low tide. Power is available at both locations. Facilities at the pier/marine area include fully equipped machine /fabrication and marine overhaul shops. Also at Site 1, six Range User Buildings are maintained for assembling test equipment and equipment check-out during test mobilization or dockside periods. These staging areas are equipped with a variety of power sources, gantry cranes, compressed air and security features. A fully equipped range user hanger for ground maintenance and storage of helicopters is located at the Atlantic Undersea Test and Evaluation Center helicopter airstrip. Sites 2, 3, and 4 are small, instrumented areas located south of Site 1 used to extend tracking of sonobuoys, communications, and air target track. This project funds costs that are not chargeable to customers.$$, 104428000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605864N_0566$$, $$0605864N$$, $$0566$$, $$NAVAIR Environmental Compliance$$, 5477000, $$This continuing project supports environmental compliance, conservation and pollution prevention related efforts at the Navy Major Range and Test Facility Base (MRTRB) located at Patuxent River, MD, China Lake, CA, Point Mugu, CA, and Atlantic Undersea Test and Evaluation Center, Bahamas. The Navy Major Range and Test Facility Base environmental projects include ongoing efforts to comply with Federal, State, and local environmental requirements. The Major Range and Test Facility Base are test and evaluation facilities that provide for Department of Defense test and evaluation support missions. These missions include: Weapons system testing, military operational squadron training on new weapon systems, and validation of performance or operational characteristics.$$, 5477000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605864N_0653$$, $$0605864N$$, $$0653$$, $$NAWC Weapons Division$$, 163851000, $$Project provides continuing maintenance and operational support for the Naval Air Warfare Center (NAWC) Weapons Division Test and Evaluation capabilities. These capabilities include the Pacific Ranges and Facilities, consisting of China Lake Ranges, Ordnance T&E facilities and the Point Mugu Sea Range, aerial and surface target launch and recovery, target test instrumentation and Test and Evaluation aircraft. The Pacific Ranges use China Lake's 1.1 million acres of land and 17,000 square miles of military restricted (R-2508) airspace together with Point Mugu's 125,000 square miles of instrumented sea range and 36,000 square miles of controlled overlying airspace, and airfield and test instrumentation at San Nicolas Island to perform its Test and Evaluation mission. Included in the China Lake ranges is the Electronic Combat Range, which provides outdoor free space developmental and operational testing of airborne electronic warfare systems and tactics against shipboard and land based air defense systems. These ranges perform metric radar, multilateration and optical tracking of test objects; command, control, and destruct for range safety purposes; communications; frequency interference control and analysis; collection processing and display of telemetered data; real-time data processing and display; and the operation of a sub scale aerial target launch capability. Other test capabilities include sled tracks, measurement facilities; propulsion, warhead, environmental, rocket motor, and other missile component test facilities; and gun ranges. This project funds costs that are not chargeable to customers.$$, 163851000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605864N_0654$$, $$0605864N$$, $$0654$$, $$NAWC Acft Division$$, 112815000, $$This project provides funds for the maintenance and operations of the Naval Air Warfare Center (NAWC) Aircraft Division's Major Range and Test Facility Base (MRTFB) capabilities used to conduct test and evaluation of air platforms and associated systems. Naval Air Warfare Center Aircraft Division has extensive airfield, flight test ranges, aircraft systems test facilities and simulation laboratories to support aircraft Research Development Test and Evaluation. This includes 50,000 square miles of airspace, 39,375 square miles of sea space, and 7,950 acres of land space. Product areas include aircraft systems flight test and evaluation, carrier suitability certification, test article preparation, installed system test and evaluation, and modeling and simulation support of the acquisition program test requirements. The Test and Evaluation Group, Patuxent River, performs development and operational test and evaluation of manned and unmanned air vehicle systems, including mission systems, equipment, subsystems, components, and support systems. This project also provides test and evaluation facilities for air-breathing propulsion systems and extensive facilities for conducting both installed and uninstalled aircraft engine development and test and evaluation. This project funds costs that are not chargeable to customers.$$, 112815000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605865N_0831$$, $$0605865N$$, $$0831$$, $$OPTEVFOR Support$$, 28577000, $$This program element (PE) provides OPTEVFOR general support funding for headquarters annual operating expenses and ensures OPTEVFOR compliance with Secretary of Defense (SECDEF) and Secretary of the Navy (SECNAV) directives during the conduct of independent operational testing and evaluation (OT&E). This funding supports planning, testing, and reporting on the operational effectiveness, suitability, and cyber survivability of new and improved systems and recommending Fleet usage to the Chief of Naval Operations (CNO). Funding also supports initiatives (including the manpower to execute) that improve OPTEVFOR's ability to develop "minimum, adequate" test strategies maximizing efficiencies and minimizing assets/time required to conduct planned operational testing, thereby driving down overall T&E costs for the Navy. The CNO, as well as acquisition executives and managers at all levels, have a continuing need for expeditious and efficient OT&E to make decisions on providing new/upgraded warfighting capabilities to the Fleet. To this end, this funding supports OPTEVFOR's continued pursuit of a variety of initiatives aimed at increasing efficiencies in T&E. These initiatives include the development of organizational level metrics that align with and inform North Star performance; develop IT infrastructure to enable/support planning/testing/analyzing/reporting to address data needs and venues for multiple stakeholders; maximize leverage of operational test data collection opportunities while ensuring OT insight is provided with agility to Fleet and Acquisition decision makers across the DON Enterprise; reduce data collection burden through streamlined development of measures and data requirements during Mission Based Test Design (MBTD). All of these initiatives improve the quality of OT&E, thus ensuring adequate test of combat systems prior to delivery to Fleet units. Issues discovered by OT&E have direct, long-term, Navy- wide implications on the Fleet's readiness and warfighting capability. Rapid advances in technology, changes in fleet tactics, and increased complexity of weapons systems and platforms have increased the need for technical and operational analyses that are sophisticated and timely in order to ensure an optimal return on investment of Navy resources.$$, 28577000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605865N_2958$$, $$0605865N$$, $$2958$$, $$Cyberspace Activities$$, 2303000, $$This project funds the civilian salaries and supports associated maintenance and sustainment of cyber hygiene and resiliency of network infrastructure, as well as enterprise IT services for OPTEVFOR operational support networks. Additionally, these funds ensure the hardware and software required to maintain is in compliance with cybersecurity directives that support command operations as required. The Cyber Pure funding under this project directly supports the Assessment & Authorization (A&A) of OPTEVFOR IT systems and the monthly patching and scanning, and reauthorization required for continuous monitoring.$$, 2303000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605866N_0706$$, $$0605866N$$, $$0706$$, $$EMC & RF Mgmt$$, 2318000, $$Electromagnetic Compatibility (EMC) and Radio Frequency (RF) Management Program: This project develops tools, processes, and algorithms to identify and mitigate Electromagnetic Interference (EMI) sources for Navy systems and platforms. (a) It will support the research, development, testing, and evaluation of electromagnetic compatibility criteria and frequency management to support afloat electromagnetic spectrum operations. The RF EMC criteria will be enhanced to include new RF systems and to comply with fleet operational requirements and streamline Strike Force frequency management processes. It will provide automated Spectrum Management (SM) compatibility criteria for development of operational task communication and radar/weapon plans to support fleet deployments, exercises, and contingency operations. It will provide identification and mitigation of EMI in Navy, North Atlantic Treaty Organization (NATO), Allied, Ashore and Joint Combat Operations. It will provide analysis related to spectrum reallocation proposals to assess impacts on Navy operations and systems, as well as for the Spectrum Supportability Risk Assessments. It will assist numbered fleet commands and DoD commands with determination of EMC criteria and processes to maximize ships' ability to operate in contested and congested environments. (b) It will support the Shipboard Electromagnetic Compatibility Improvement Program (SEMCIP) to identify, engineer, and evaluate effectiveness of potential EMI corrections. The program also characterizes and quantifies the operational impact of EMI problems on system's mission performance. (c) It will support the Nuclear Electromagnetic Pulse (EMP) Survivability Program. The program assesses the EMP survivability of all mission critical systems and funds development of a hardness assurance and maintenance program. It will develop improved modeling capability to reduce hardness validation costs at delivery and over the lifetime of the system/platform. The program develops new and updated design criteria, test methodology, test limits, and survivability validation procedures for all Navy systems, ships, submarines and shore facilities.$$, 2318000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605866N_3239$$, $$0605866N$$, $$3239$$, $$Real-Time Spectrum Operations$$, 20245000, $$The Real-Time Spectrum Operations (RTSO) program develops tools, processes, and algorithms to conduct spectrum planning, spectrum sensing and monitoring of the electromagnetic (EM) environment; to characterize and predict electromagnetic (EM) environmental effects (E3); and to manage and maneuver to avoid and mitigate electromagnetic interference (EMI) and EM vulnerability of Navy platforms. RTSO supports Navy and Marine Corps EM Spectrum Operations for global spectrum usage and allocation planning. RTSO researches the effects between shipboard transmitters and receivers and EM system interactions with the other systems installed on units within a strike group. The program developed a capability to sense and monitor shipboard EM spectrum usage and provides information to validate spectrum plans in support of Emissions Control (EMCON) within the strike group. RTSO software validates and displays spectrum plan compliance with a spectrum common operational picture. This EM spectrum management aid, combined with an Own Force Monitoring (OFM) sensor input, supports Battlespace Awareness and Information Operations. These self-awareness and validation capabilities greatly enhance the Navy's ability to perform command and control of the EM spectrum warfighting domain. FY 2026 RTSO will continue research, development, enhancement and refinement of RTSO software cloud architecture, spectrum common operational picture (COP), live data ingest, detection and counter-detection (1-to-1), time slide, and network nodes. Continue research and development of proof-of-concept capabilities for spectrum mission planning decision aids and intelligent sectoring/cut-outs for radiating systems. Continue research and development efforts for models to estimate effective RF performance ranges of spectrum dependent systems in the complex electromagnetic environment (one-on-one and multi-on-one effects). RTSO will continue to participate in Limited Objective Experiments (LOEs) to demonstrate incremental capability to Fleet users and continue development of a software architecture supporting mission module delivery of RTSO capability on all platforms. Finalize RTSO v2.3 release to afloat Fleet users in a cloud environment, including integration testing, cybersecurity authorization, and completing deployment configurations for all deployment environments. Begin engineering work to develop an improved RTSO OFM and spectrum management design for at least seven different ship classes. RTSO will continue engineering research and development integrating RTSO software and outputs with other software applications and hold fleet user engagements to gain sailor feedback on latest software capabilities to improve usability, functionality, and applicability to user requirements.$$, 20245000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605867N_1034$$, $$0605867N$$, $$1034$$, $$TAC SAT Recon Office$$, 7325000, $$The details of this program element are classified CUI and are submitted annually to Congress in the classified budget justification books.$$, 7325000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605873M_0030$$, $$0605873M$$, $$0030$$, $$Studies & Analysis/MC$$, 3191000, $$Marine Corps Requirements Oversight Council (MROC) established Operations Analysis Directorate (OAD), as the sole operations research, analytic support, and studies management program for the Marine Corps Study System (MCSS). MCSS analysis is achieving greater efficiency, productivity, and innovation through operations research methodologies such as: operational analysis, statistical analysis, multi-objective decision methods, optimization, cost analysis, and a wide range of computer-based models and combat simulations ensuring the optimization of resources now and in the future. Analyses span the spectrum of conflict in a Joint, Interagency, Intergovernmental, and Multinational (JIIM) context to inform critical senior level decision makers of current and future national security issues and provides unique and distinct analytic capabilities that enable the collaboration and sharing of analyses that reduces the duplication of topics that are of broad interest. MCSS is an integral part of the Marine Corps and Joint Chiefs decision-making processes to organize, man, train, equip, sustain, and transform resources from the current to the future force.$$, 3191000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606225D8Z_106$$, $$0606225D8Z$$, $$106$$, $$Technology and Resource Analysis$$, 3461000, $$The Office of Net Assessment develops and coordinates analyses that examine the standing trends and future prospects of U.S. and other military capabilities and military potential. The net assessments address near and long-term problems and opportunities for the U.S. military forces to help counter technological advantages of potential U.S. adversaries. These efforts will pursue research to analyze the future security environment.$$, 3461000, NULL, NULL, NULL, NULL, 20074000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605873M_0033$$, $$0605873M$$, $$0033$$, $$OT&E Support$$, 14998000, $$The Marine Corps Operational Test and Evaluation Activity (MCOTEA) supports the material acquisition process by managing the Marine Corps Operational Test (OT) programs for Acquisition Categories (ACAT) I through ACAT IV (less OT of manned aircraft) and performs other functions that may be directed by the Commandant of the Marine Corps. The primary purpose of Operational Test and Evaluation (OT&E) is to provide information to the Milestone Decision Authority (MDA) regarding the Operational Effectiveness (OE) and Operational Suitability (OS) of the system addressed at a decision point. MCOTEA must ensure that the Marines in the Operating Forces receive the very best possible equipment and support. MCOTEA must also ensure each system proposed for acquisition is tested adequately, evaluated objectively, and reported independently. Marine Corps Operational Test and Evaluation Activity (MCOTEA) is the only unit that provides the Marine Corps with required operational test and evaluation (OT&E) capability, ensuring the Marine Corps is compliant with laws and regulations, and ensuring that training and equipment are operationally effective, relevant, and suitable. Additionally, MCOTEA's early involvement, coordination, and oversight in developmental testing and evaluation of new combat and combat support systems ensures that our Marines are the best trained, and have the best equipment, with the lowest test costs for taxpayers. Finally, MCOTEA's support of rapid acquisitions ensures that Marines in the fight are supported with the newest and most advanced equipment and that the Marine Corps is compliant with regulations.$$, 14998000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605873M_1403$$, $$0605873M$$, $$1403$$, $$Office of Net Assessment$$, 0, $$The Commandant of the Marine Corps' (CMC) Office of Net Assessment (ONA) was established in July 2022 as a result of a CMC tasking in the April 2021 Annual Force Design Update. ONA provides long-term comparative assessments of trends, key competitions, risks, opportunities, and future prospects of USMC roles and missions in order to support strategic decision making for the CMC and Assistant Commandant of the Marine Corps (ACMC). Previously executed in Center for Naval Analysis PE: 0605154N RDTE PRJ: 0031$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605873M_3009$$, $$0605873M$$, $$3009$$, $$Marine Corps Wargaming Capability$$, 6190000, $$The enhanced Wargaming Capability (WGC) facilitates Force Design by utilizing advanced modeling and simulation systems and analytic assessments of current Operation Plans, Concepts of Operations, future operational and functional concepts, and operational and technology-based approaches. These results will refine our Force Design through our campaign of learning and increase research capacity to maintain the USMC as a "force-in-readiness." The USMC WGC consists of Wargaming software, modeling, and simulation tools and systems, a Wargaming and Analysis Center (MILCON Project P-719), and the necessary personnel supporting the new capability. The WGC solution will provide an enhanced basis for analytically informed decision support to capability development prioritization and resourcing. The WGC program acquisition strategy utilizes 10 U.S.C 2302 Middle Tier of Acquisition (MTA). During 1st quarter of FY 2023 the program learned of delays with the facility construction impacting entry into the building for infrastructure installation and system accreditation. This delay shifted the program's planned transition to an MTA Rapid Fielding to no later than the 3rd quarter of FY 2024. The program gained entry into the facility in the 1st quarter of FY 2024 and began the Information Technology (IT) and Audio-Visual (AV) infrastructure installation to support the accreditation process for certifying the complex technologies. The overarching strategy consists of four phases: Phase I: Risk Reduction Prototyping (FY 2019 - FY 2020); Phase II: Integrated Prototyping (FY 2020 - FY 2022); Phase III: Baselining (FY 2023 - FY 2024) and Production; Phase IV: Sustainment/Operations.$$, 6190000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605873M_3783$$, $$0605873M$$, $$3783$$, $$Information Environment Strategy,$$, 4437000, $$The Information Environment (IE) is a global, interconnected, complex, continuously changing eco-system that is increasingly connected across our war fighting functions. Given the complexity and the speed of changes in the IE and to address the significant role information now plays in current and future conflicts, a unifying operational and technical strategy must be developed to outpace our adversaries. Analysis will inform the development and integration of Marine Corps Information Environment Enterprise (MCIEE) that are guided by the Commandant's Planning Guidance (CPG) and Marine Corps Force Design. Research and analysis efforts support: design and coordinated implementation of an Objective Network to fight on and through a contested environment; design structure to engage and collaborate with Joint and Coalition partners; and conduct analysis to inform the development and fielding of an integrated information capability. These efforts will be accomplished leveraging analytic support from government Labs and Industry to dynamically exploit our National Defense Strategy (NDS) priority operational problems related to the Information Environment through demonstration, limited user evaluations, and functional capability assessments with the Fleet Marine Forces.$$, 4437000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605898A_FJ2$$, $$0605898A$$, $$FJ2$$, $$Army SHARP RDTE$$, 1176000, $$Research related to the SHARP program provides a better understanding of sexual assault, sexual harassment, and gender discrimination in the Army, including an improved understanding of vulnerable populations, high-risk locations, and Soldier experiences of SA/SH. Results from this program of research indicate where to target prevention efforts and provide science-informed strategies to reduce/prevent SA/SH/GD. This research challenges stereotypes and ensures the Army can provide tailored prevention and response activities directed at the most prevalent sexual assault, sexual harassment, and gender discrimination behaviors and scenarios. Research funding is required to ensure that Army SHARP is best positioned to address DoD and Service requirements, including recommendations from OSD's Independent Review Commission on Sexual Assault in the Military aimed at reducing sexual assault and sexual harassment in the military. Conducting research to meet these requirements is a necessary step in developing targeted training, prevention, and response activities and ensuring these activities are having the desired effect and impact on the Total Force.$$, 1176000, NULL, NULL, NULL, NULL, 1208000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606295M_3753$$, $$0606295M$$, $$3753$$, $$Capability Development Support$$, 4732000, $$Capability Development Support will provide Marine Aviation with the capability to conduct fully informed mission and operational analysis, driven by threat data and guided by Force Design. As USMC tactics evolve in support of the Stand-in Force (SiF), this PU informs investment decisions for future Marine Aviation capabilities and drives innovation through the validation of Science and Technology (S&T) transitions into both legacy and future Fleet assets.$$, 4732000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605898A_M65$$, $$0605898A$$, $$M65$$, $$Army Test and Evaluation Command$$, 52260000, $$This Project provides funding for the salaries and related personnel benefits for the authorized civilian personnel positions that provide for the management functions and the technical direction of the United States (U.S.) Army Test and Evaluation Command (ATEC) Headquarters mission located at Aberdeen Proving Ground (APG), Maryland. ATEC plans, conducts and integrates developmental testing, independent operational testing, independent evaluations, and assessments to provide essential information to Soldiers and acquisition decision makers supporting the American Warfighter. Additionally, ATEC provides Direct Support to the Army Futures Command (AFC). ATEC provides testing and independent evaluation support to AFC Cross Functional Team (CFT) efforts including risk reduction support to experiments, demonstrations, requirements, research, development, and acquisition. As such, ATEC priorities are aligned to the Army's Transformation priorities. This Project resources the workforce to execute the following functions: human resources, safety, security, environmental, strategic planning, operations, engineering and logistics, resource management, test capabilities management, policy and standardization, public affairs, legal, Inspector General, Equal Opportunity, and information/ technology support for command-wide databases in support of the developmental, evaluation and operational test mission with technical direction to the Army Evaluation Center (AEC), APG, Maryland; to the Operational Test Command (OTC), Fort Cavazos, Texas which consists of three forward Test Directorates (Airborne and Special Operations Test Directorate, Fort Liberty, North Carolina; Air Defense Artillery Test Directorate, Fort Bliss, Texas; and the Fires Test Directorate, Fort Sill, Oklahoma) together with four other Test Directorates (Aviation; Maneuver; Mission Command; Maneuver Support and Sustainment) at Ft Cavazos, Texas; and to the seven Major Range and Test Facility Base (MRTFBs) and one non-MRTFB test range: Aberdeen Test Center (ATC) at APG, Maryland; West Desert Test Center (WDTC) at Dugway Proving Ground (DPG), Utah; Electronic Proving Ground (EPG) at Fort Huachuca, Arizona; White Sands Test Center (WSTC) at White Sands Missile Range (WSMR), New Mexico; Yuma Test Center (YTC) at Yuma Proving Ground (YPG), Arizona; Arctic Regions Test Center (ARTC) at Fort Greely, Alaska; and Tropic Regions Test Center (TRTC) at various locations, as well as for Redstone Test Center (RTC) at Redstone Arsenal, Alabama. This is the operating budget for ATEC Headquarters, which provides technical direction for the annual execution of over 2,500 developmental tests; over 755 operational events; and over 700 Evaluation and Safety documents supporting Army transformation and other acquisition programs. It also provides funding to address enterprise level operating requirements that support the entire command and its three missions. ATEC's total program averages around $2 billion in direct and reimbursable funding.$$, 52260000, NULL, NULL, NULL, NULL, 54289000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605898E_MH-01$$, $$0605898E$$, $$MH-01$$, $$MANAGEMENT HQ -$$, 13623000, $$The Management HQ - R&D Program Element provides funding for the administrative support costs of the Defense Advanced Research Projects Agency. This project provides funding for DARPA Management Headquarters Activities (MHA). The funds provide personnel compensation for management headquarters civilians as well as associated travel and support contract costs.$$, 13623000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605898F_665898$$, $$0605898F$$, $$665898$$, $$Management HQ-R&D$$, 5960000, $$The Management Headquarters program element 0605898F includes management headquarters personnel for Air Force Life Cycle management Center. The Air Force Life Cycle Management Center (AFLCMC) equips U.S. and allied forces with operational weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this program element will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. This program element supports both civilian pay and non-pay support requirements.$$, 5960000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605898N_0223$$, $$0605898N$$, $$0223$$, $$Sub Combat System Improvement$$, 113000, $$This project provides management headquarters contractor support to the Integrated Warfare Systems (IWS) Program Executive Office (PEO). This work supports Navy Acoustic Superiority and Technology Insertion Initiatives through the application of advanced development and testing of sensors and sensor processing systems supporting tactical control systems improvements. This addresses technology challenges to improve tactical control in littoral and open ocean environments for a variety of operational missions.$$, 113000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605898N_0824$$, $$0605898N$$, $$0824$$, $$Science & Technology Managment$$, 25023000, $$This project funds all basic costs of Office of Naval Research Management Headquarters Activity (MHA) non-labor in support of the entire Navy Science & Technology (S&T) program. Through this support, the S&T enterprise pursues the technological advances that enable the Fleet's ability to operate from a position of technological superiority. Specifically, funding facilitates the execution of the Navy's basic research, applied research, and advanced technology development programs at the nation's universities/colleges, Navy laboratories, Warfare Centers, and private industry.$$, 25023000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605898N_1447$$, $$0605898N$$, $$1447$$, $$Surf Combatant Combat System Imp$$, 212000, $$This project provides management headquarters contractor support to the Integrated Warfare System (IWS) Program Executive Office (PEO). This work supports Cruiser and Destroyer AEGIS Combat System (ACS) upgrades and integrates new equipment and systems to pace the threat and capture advances in technology.$$, 212000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605898N_3159$$, $$0605898N$$, $$3159$$, $$Naval Integrated Fire Control-$$, 208000, $$This project provides management headquarters contractor support to the Integrated Warfare System (IWS) Program Executive Office (PEO). This work supports Naval Integrated Fire Control - Counter Air (NIFC-CA) project. Through this support technological advances are being developed enabling PEO IWS to extend the Naval Theater Air and Missile Defense battlespace out to the maximum kinematic range of our weapons.$$, 208000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605898N_3186$$, $$0605898N$$, $$3186$$, $$Air and Missile Defense Radar$$, 585000, $$This project provides management headquarters contractor support to the Integrated Warfare System (IWS) Program Executive Office (PEO). Through this support, technological advances are being developed, enabling PEO IWS to deliver "Enterprise" solutions for Naval Warfare Systems that operate seamlessly and effectively within the Fleet and Joint Forces.$$, 585000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605898N_3345$$, $$0605898N$$, $$3345$$, $$ONR Management Headquarters$$, 16610000, $$This project funds all basic costs of Office of Naval Research Management Headquarters Activity (MHA) salaries in support of the entire Navy Science & Technology (S&T) program. Through this support, the S&T enterprise pursues the technological advances that enable the Fleet's ability to operate from a position of technological superiority. Specifically, funding facilitates the execution of the Navy's basic research, applied research, and advanced technology development programs at the nation's universities/colleges, Navy laboratories, Warfare Centers, and private industry.$$, 16610000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606774D8Z_852$$, $$0606774D8Z$$, $$852$$, $$Defense Civilian Training Corps$$, 8752000, $$The Defense Civilian Training Corps (DCTC) program is directed by 10 U.S.C. Ch 113 with the purpose to prepare selected students for public service and meet critical skill gaps in acquisition, digital and critical technologies, science, engineering, finance, and other civilian occupations determined by the Secretary of Defense. With the requested FY 2026 funding, DoD will continue the two-year DCTC acquisition and sustainment-focused education and development program, piloting with the four universities and testing model improvements.$$, 8752000, NULL, NULL, NULL, NULL, 55000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605976F_3600$$, $$0605976F$$, $$3600$$, $$Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E$$, NULL, $$Restoration includes repair or replacement work to restore facilities damaged by inadequate sustainment, excessive age, natural disaster, fire, accident, or other causes. Modernization includes alteration or replacement of facilities to implement new or higher standards, to accommodate new functions, or to replace aging building components that typically last more than 50 years (such as framework or foundation). Environmental compliance costs, facility leases, and other tasks associated with facilities operations (such as custodial services, grounds services, waste disposal and the provision of central utilities) are not included. Restoration/modernization funds support the following Air Force test organizations and their associated test and evaluation facilities: the 96th Test Wing (TW) at Eglin AFB, FL; the 412TW at Edwards AFB, CA; and the Arnold Engineering and Development Complex (AEDC), to include assets at Arnold AFB, TN, the 704th Test Group (TG) at Holloman AFB, NM, the 704TG Landing Gear Test Facility (LGTF) at Wright-Patterson AFB, OH, the Hypersonic Wind Tunnel 9 at White Oak, MD, and the National Full-Scale Aerodynamics Complex (NFAC) at Moffett Field, CA. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605978F_3600$$, $$0605978F$$, $$3600$$, $$Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E$$, NULL, $$Sustainment is defined as the maintenance and repair activities necessary to keep facilities in good working order and includes regularly scheduled adjustments and inspections, preventative maintenance tasks, and emergency response and service calls for minor repairs. It also includes major repairs or replacement of facility components (usually accomplished by contract) that are expected to occur periodically throughout the lifecycle of facilities. This work includes regular roof replacement, refinishing of wall and floor surfaces, repairing and replacing of heating and cooling systems, replacing tile and carpeting, and similar types of work. This work also includes inspection and repair of heavy plant machinery, high-power electrical switching gear, hydraulic, lubrication, forced-air and fluid cooling systems, high pressure vessel health monitoring, facility control and remote monitoring systems, liquid oxygen systems, steam systems, test instrumentation, and fire detection and suppression systems. Environmental compliance costs, facility leases, or other tasks associated with facilities operations (such as custodial services, grounds services, waste disposal, and the provision of central utilities) are not included. Sustainment funds support the following Air Force organizations and their associated test and evaluation facilities: the 96th Test Wing (TW) at Eglin AFB, FL; the 412 TW at Edwards AFB, CA; the Arnold Engineering and Development Complex (AEDC), to include assets at Arnold AFB, TN, the 704th Test Group (704TG) at Holloman AFB, NM, the 704TG Landing Gear Test Facility (LGTF) at Wright-Patterson AFB, OH, the Hypersonic Wind Tunnel 9 at White Oak, MD, and the National Full-Scale Aerodynamics Complex (NFAC) at Moffett Field, CA. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606002A_XW9$$, $$0606002A$$, $$XW9$$, $$Reagan Test Site$$, 72302000, $$This Project funds management and contracting personnel support (salaries and travel) to enable the management of the test and evaluation of major Army and DoD missile systems for the RTS. Funds also provide contracting support for end item procurement, life cycle acquisition planning, and solicitation, negotiation, award, execution and management for weapon systems contracts. This PE provides contractors to accomplish key operations and maintenance functions for RTS instrumentation suites and also provides mission essential bandwidth via a fiber optic cable system. Funds provide the expertise required for operating and maintaining a number of one-of-a-kind radar, optical, telemetry, command/control/communications, safety, and data reduction systems. These systems include the four unique radars of the Kiernan Reentry Measurement Site; Super Recording Automatic Digital Optical Tracker long range video-metric tracking systems; high density data recorders for high data-rate telemetry collected by ten antennas; an underwater acoustic impact location system; and data analysis/reduction hardware/software and Continental United States (CONUS) based mission control center. The Advanced Research Project Agency Long-Range Tracking and Instrumentation Radar and the Target Resolution Discrimination Experiment radars located at RTS are the only radars in this area of operation that have deep-space tracking capability. The Millimeter Wave Radar is one of the highest resolution imaging radars in the world, providing critical intelligence data. Funding also enables weapon system assessment of operational effectiveness and suitability for the Army, Air Force, Navy and MDA, which all have programs planned that have significant test and data gathering requirements at RTS. This test data cannot be obtained except through the use of technical facilities available on and in the vicinity of RTS. Program supports Army's PATRIOT air defense system; Air Force's Minuteman III ICBM and the Space and Missile Center's associated programs; MDA's Ballistic Missile Defense System, ICBM Targets, and Layered Ballistic Missile Defense operational tests (including: PATRIOT, Terminal High-Altitude Area Defense, and Aegis Weapon System), and NASA's space experiments.$$, 72302000, NULL, NULL, NULL, NULL, 89911000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606003A_FI9$$, $$0606003A$$, $$FI9$$, $$Counterl Intel and Human Intel$$, 5660000, $$The Counterintelligence (CI) and Human Intelligence (HUMINT) Modernization Project supports ongoing rejuvenation and development of new critical CI and HUMINT systems, applications, tools, equipment, and capabilities necessary to defeat foreign intelligence, international terrorist, and insider threats while enhancing our HUMINT collection capability, management processes, and responsiveness. CI Support to Force Protection (CIFP) provides for development and testing of software code of Atlas, the planned successor of Army Counterintelligence Operations Portal and further development of the CHS system for forces echelon Corps and below to be integrated into the CI and HUMINT Equipping Program Army, replacing CI and HUMINT Automated Reporting Computer System. The Castle Keep Portal is the Army's enterprise capability to automate workflow services, SCI program reporting, metrics, analysis, and information sharing to protect classified information within and across the defense elements of the Intelligence Community. The Multi-Source Data Fusion Platform curates and integrates Army Counterintelligence (CI) and Human Intelligence (HUMINT) data with Army Identity Intelligence architecture, establishes application programming interfaces, leverages and trains Artificial Intelligence/Machine Learning (AI/ML) tools and models, and develops new workflows and user interfaces with the Military Threat Actor knowledge base and Defense Watchlisting activities that supports sharing of information across the Army CI, HUMINT, and I2 capabilities for timely decisions on persons of interest.$$, 5660000, NULL, NULL, NULL, NULL, 6348000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606775D8Z_780$$, $$0606775D8Z$$, $$780$$, $$Joint Production Accelerator Cell$$, 5493000, $$The Department of Defense (DoD) needs a reliable supply of diverse weapons systems and supplies to ensure operational readiness amidst unpredictable volatile global events. These national security challenges place variable stresses on the DoD’s munitions inventory and generate a range of production needs, limiting the utility of addressing capability requirements strictly on a program-by-program basis. This Program Element (PE) advances promising manufacturing technologies and processes with the intention of improving operational readiness across the Joint Force. This PE furthers the Department’s efforts to rebuild the military and reestablish deterrence by accelerating the delivery of critical weapon systems through advanced manufacturing. It identifies and prototypes ways to build and maintain surge production capacity and resilience for critical weapons. It identifies areas for advanced manufacturing, works with piloting entities to analyze approaches, and collaborates with critical weapons programs. The outcomes will include scalable demonstrations and guidance on advanced manufacturing and acquisition reforms.$$, 5493000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606004F_646020$$, $$0606004F$$, $$646020$$, $$Commercial Capabilities$$, 1097000, $$Commercial Capabilities Integration & Transition uses the Small Business Innovation Research process to discover, prototype, and rapidly field commercial solutions to solve combatant commander and warfighter requirements. Commercial Capabilities Integration & Transition partners with OSD in rapid prototyping and experimentation activities. Additionally, Commercial Capabilities Integration & Transition partners with various agencies to include AFRL, DIU, OSD R&E, Rapid Defense Experimentation Reserve, and Defense Innovation Accelerator, FFRDCs, NNSA and others to identify critical science and technology capabilities. Furthermore, Commercial Capabilities Integration & Transition leverages the U.S.'s small business community, accelerating the Department's acquisition process, to rapidly prototype and demonstrate these critical science and technology capabilities for integration into AF systems. This energizes the Nation's small business community and increases the industrial base to meet the emerging challenges of incorporating revolutionary technologies like AI/ML, quantum, cyber, advanced communications/networks, advanced propulsion, directed energy, training systems, etc. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 1097000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606005D8Z_399$$, $$0606005D8Z$$, $$399$$, $$Special Activities$$, 18594000, $$This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress. For further information, please contact the Assistant Secretary of Defense for Mission Capabilities in the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)).$$, 18594000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606005F_643316$$, $$0606005F$$, $$643316$$, $$Digital Transformation$$, 15997000, $$This program encompasses the acquisition and development of common digital tools, software, and training to expedite the delivery of pertinent technologies, capabilities, and weapons throughout the enterprise. This program ensures the swift and cost-effective deployment of software tools to acquisition programs by developing common, enterprise-level, cloud-hosted software tool environments; this will equip the acquisition enterprise with Model-Based Systems Engineering, analytics, requirements management, and product life cycle management tools that will accelerate the delivery of war fighting capabilities. The program's objective is to develop and deploy enterprise-wide approaches for standardizing and scaling digital tool capabilities, resulting in reduced program delivery times. This holistic approach enables unprecedented collaboration with industry, lowers contract deliverable costs through government-approved data architectures and model delivery, and enhances foundational capability across the DAF by providing access to cloud-hosted tools to empower the acquisition workforce. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 15997000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606017F_666157$$, $$0606017F$$, $$666157$$, $$Development Planning$$, 11098000, $$Development Planning (DP) funds activities to analyze the Force Design in support of the Capability Development Enterprise. DP conducts coordinated Mission Engineering and Analysis to identify and refine key capability trades, technology needs, and cost and schedule implications. Emphasis is placed on developing options that address force design gaps by analyzing multi-domain capabilities and evaluating Doctrine, Organization, Training, Materiel, Leadership and Education, Personnel, and Facilities-Planning (DOTMLPF-P) concepts. This analysis informs trade space of candidate concepts, ensuring required attributes are met. The outcome of this effort will be tradespace attributes and mission engineering artifacts which will underpin Capability Development decisions. These funds may be used for program management support costs, but not limited to hardware, software, travel, contractor support, civilian pay, supplies, facilities, and infrastructure. This program element may include necessary civilian pay expenses required to manage, execute, and deliver RAM capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, 0605898F, 0606398F. Projected civilian pay expenses are anticipated to be 5.833 million in FY2025 and 6.416 million in FY2026 for this program element.$$, 11098000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606017F_666158$$, $$0606017F$$, $$666158$$, $$INTEGRATED SIMULATION AND$$, 17059000, $$The Integrated Simulation and Analysis project funds activities that develop and support integrated analysis and digital engineering tools for the Capability Development Enterprise. In addition, the project develops tools and methodologies to support required analysis and studies; this produces system performance representations/ models, environments, architectures, digital artifacts, data, and tools that underpin variable fidelity, stand-alone, interactive, and distributed simulations. The project incorporates Mission Engineering and Digital Engineering enterprise tools and methods (i.e. Model-Based Systems Engineering [MBSE], Modeling Simulation and Analysis [MS&A] ecosystem) as the technical and digital underpinning for the simulation models/ behaviors; it develops and maintains digital records for future analytical needs and serves as a template to identify, road map, and enable the Modeling and Simulation- centric portions of the acquisition life cycle and of operational missions. The project may fund IT and licenses to execute modern Mission Engineering and Digital Engineering. The project initiates and leverages studies performed by industry, academia, FFRDCs and UARCs that may be required to develop and create technology representative models and data.$$, 17059000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606018F_674877$$, $$0606018F$$, $$674877$$, $$NC3 Integration,$$, 40066000, $$Nuclear Command, Control, and Communications (NC3) is critical to our Nation's nuclear deterrence. Nuclear Deterrence Operations (NDO) is an Air Force Core Function. Within this core function, Nuclear Command and Control (NC2) is the exercise of authority and direction by the President, as Commander in Chief, through established command lines, over nuclear weapon operations of military forces. The President's authority and direction are exercised through the Nuclear Command and Control System (NCCS). The NCCS is the designated combination of flexible and enduring elements including facilities, equipment, communications, procedures, personnel, and the structure in which these elements are integrated, all of which are essential for planning, directing, and controlling nuclear weapon operations. These functions are accomplished through the NC3 system of systems. The NC3 system of systems provides connectivity from the President or Secretary of Defense through the National Military Command System (NMCS) to nuclear execution forces worldwide. To enhance NC3 mission success, the Air Force (AF) formalized AF NC3 elements as a specified AF Weapon System (WS), AN/USQ-225. Activities funded in this Program integrate legacy systems, ongoing NC3 programs, and future capabilities for the overall AF NC3 WS. The AF Nuclear Weapon Center NC3 Integration Directorate (AFNWC/NC) ensures current, new, and future NC3 capabilities are fully integrated as part of the Air Force's overall effort to sustain, modernize, and recapitalize the nuclear enterprise. AFNWC/NC is responsible for integrating NC3 materiel management across Air Force Materiel Command (AFMC) to include authority and responsibility for weapon system architecture, weapon system configuration management, weapon system state-of-health reporting, risk management, supply chain management, overall integration, system test, verification, and certification. AFNWC/NC is responsible for analyzing, defining, building, and sustaining current and future AF NC3 WS system of systems configuration baselines, and marshaling necessary Supporting Centers in AFMC and other units/agencies in the Air Force and the Department of Defense (DoD) to support and/or accomplish these tasks. AFNWC/NC collaborates with AFMC Supporting Centers to champion the full spectrum of doctrine, organization, training, materiel, leadership and education, personnel, facilities, and policy (DOTMLPF-P) efforts, in support of U.S. Strategic Command as the Enterprise Lead for NC3, the Under Secretary of Defense for Acquisition and Sustainment as the NC3 Enterprise Capability Portfolio Manager, and Air Force Global Strike Command (AFGSC) as the Lead Command championing NDO requirements for all Combatant Commands. This program funds activities for integrating AF NC3 WS materiel, authority and responsibility for model-based systems engineering (modeling, simulation and visualization) of the NC3 WS, digital engineering, configuration management, change management, risk management, weapon system state-of-health and mission worthiness assessments and reporting, supply chain supportability and risk management, and overall AF NC3 WS integration, development, system test, experimentation, modeling and simulation of capability gaps with potential solution alternative trade space assessments, verification, fielding, and certification. This program also supports capability gap analyses, predictive analysis of impacts to the weapon system, modernization and integration activities in support of AFGSC's Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0606018F / NC3 Integration Operational Systems Development Capability Development Process (ACDP), Joint All Domain Command and Control (JADC2) and Advanced Battle Management System (ABMS) initiatives. Starting in FY25, this PE will also be supporting NC3 baseline integration into the Sentinel Weapon System Program, to include new equipment purchases and the transfer of Minuteman III (MMIII) NC3 equipment to the Sentinel Weapon System. The FY 2026 request was reduced by [1.586] million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” The FY 2026 total adjustment was an increase of 15.022M. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.000M was expended for civilian pay expenses in this program element, and in FY 2025 0.000M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 40066000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607131A_ER5$$, $$0607131A$$, $$ER5$$, $$Indirect Fire and Fuze Technology$$, 2302000, $$The Indirect Fire and Fuze Technology Project includes product improvement, and development efforts to upgrade indirect fire weapon systems and munitions that are fielded and/or are in production. Initiatives include improved target engagement, increased reliability, availability, maintainability, and safety, standardization and interoperability with weapons and munitions of Allied Nations, defense exportability features, reduction of failure mechanisms, and supply chain risk through introduction of new and alternative technology and materiel solutions, improvement of manufacturing methods and their associated production and life cycle support processes, new capabilities in response to the evolving and emerging threats and countermeasures, and reduction/elimination of potential environmental and health risks associated with these products. The Indirect Fire and Fuze Technology Project will enhance the Department of Defense's (DoD) portfolio.$$, 2302000, NULL, NULL, NULL, NULL, 14144000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606100D8Z_101$$, $$0606100D8Z$$, $$101$$, $$Budget and Program Assessments$$, 7619000, $$This program supports the Office of the Director, Cost Assessment & Program Evaluation (CAPE). It funds assessments that help to resolve budget and programmatic issues across the full range of the Department’s activities. Projects that support this effort help to inform the leadership on program alternatives, capability concept development, design and cost, the appropriate balance of capabilities across the force, and also to identify how well the Department’s expenditures are meeting its goals, and how well the force can implement the Defense strategy. This program provides for analytical research across the entire spectrum of defense issues and concerns. The research agenda focuses on near to long-term problems identified by the Secretary of Defense, and addresses difficult and complex questions linked to program alternatives for current and future capabilities and forces in order to enhance DoD senior leadership's deliberations and decision-making. This program provides the scientific and technical engineering services needed for research studies in the development of models and simulations and the evaluation of current analytical tools and scientific methods used to evaluate and assess weapons systems and warfighting capabilities for warfighting environments and scenarios, and related force structure. Deliverables from this program will include reports, briefings, and analyses designed to illuminate critical issues facing the Department. Outcomes include recommendations for new modeling techniques, programmatic alternatives, and scenario development.$$, 7619000, NULL, NULL, NULL, NULL, 8320000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606100D8Z_118$$, $$0606100D8Z$$, $$118$$, $$Enterprise VAMOSC$$, 5465000, $$Enterprise Visibility and Management of Operating and Support Cost (EVAMOSC) addresses CAPE's responsibility to develop and maintain a database of actual operating and support (O&S) costs for major weapons systems, as required in 10 USC Section 4325. Additionally, the EVAMOSC data capability will directly support development and reporting of readiness metrics associated with implementation of the interim National Defense Strategy.$$, 5465000, NULL, NULL, NULL, NULL, 5543000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606114D8Z_109$$, $$0606114D8Z$$, $$109$$, $$Analysis Working Group Support$$, 5229000, $$This program supports the Office of the Director, Cost Assessment & Program Evaluation (CAPE). It funds assessments that help the Analysis Working Group (AWG) to assist the Secretary and Deputy Secretary in guiding the analytic community and ensuring strategic analysis products are robust and of the highest quality. The end goal is an analytic enterprise that is agile, responsive, and provides sound decision support for the Secretary and Deputy Secretary. This program provides for analytic research across the Department to guide reform of the Departments analytic enterprise. Projects that support this effort help to develop a high performing and innovative analytic enterprise with the right policies, structures, people, and tools to support timely strategic decisions that create an advantage for the U.S Military now and into the future.$$, 5229000, NULL, NULL, NULL, NULL, 4046000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606118A_DM2$$, $$0606118A$$, $$DM2$$, $$AIAMD Software Development &$$, 358854000, $$Agile software development is the key pacing activity for introducing enhanced Army Integrated Air and Missile Defense (AIAMD) system capabilities, integrating with emerging AMD effectors and sensors, and interoperating with joint and higher echelon mission command systems. The Defense Acquisition Executive (DAE) approved AIAMD entry into the Software Acquisition Pathway (SWP) Execution Phase on September 21, 2021. This pathway facilitates rapid and iterative delivery of software capability to the user and enables multiple 1-N capability items to be worked concurrently as defined by emerging joint Warfighter priorities. The IAMD Battle Command System (IBCS) based AIAMD architecture is a software intensive capability that enables net-centric, system of systems (SoS) command and control of AIAMD. The AMD Mission Command Product Office executes the IBCS program in accordance with the SWP utilizing the Scaled Agile Framework (SAFe) development methodology. This approach delivers Program Increments (PI) in the form of quarterly software-based improvements and annual capability releases that address Warfighter priorities (1-N), emerging threats, and weapon and sensor integration requirements. Software testing occurs at the end of each PI cycle with functional testing at the Contractor System Integration Lab (C-SIL), followed by validation of performance requirements at the Government System Integration Lab (G-SIL). The software is then delivered to White Sands Missile Range (WSMR) for testing with tactical sensors and weapons. Funding of $358.854 million in FY 2026 supports Integrated Fires System of Systems agile software development, updates and integration, developmental testing, requirements verification of the software build, operational testing, modeling and simulation and integration activities for integrated fires capabilities to include Patriot, IFPC, LTAMDS, and Forward Area Air Defense Command and Control (FAAD C2) Convergence into IBCS. The program also expands development capacity to meet increasing integration demands to support 1-N capability. Development and testing in FY26 contributes to the Guam Defense System (GDS) architecture including countering advanced threats and capability integration with LTAMDS, IFPC, Sentinel A4, RIG-360, and ALPS. The FY 2026 request for AIAMD Software Development & Integration includes $358,854 thousand of discretionary and $103,000 thousand of mandatory (reconciliation) for a total of $461,854 thousand. The mandatory funds support full THAAD integration into the AIAMD architecture and foundational requirements for Golden Dome for America (GDA) to include remotely operated autonomous system and AI enabled fire control. Software development activities for GDA support significantly reducing human-in-the-loop interactions across sensor and effector platforms, leverage AI technologies and techniques reducing human cognitive load, augmenting required tasks, and increasing system performance and enabling consolidated remote operations of sensors and shooters. Further information for this reconciliation request is provided in section 20003 (Missile Defense) of the Reconciliation Exhibit.$$, 358854000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606135D8Z_069$$, $$0606135D8Z$$, $$069$$, $$Artificial Intelligence & Machine$$, 0, $$The RAI Division fulfills the functions of both RAI Capability Development and the building of an RAI Customer Ecosystem. The RAI Division provides critical tools and infrastructure and best practices to all DoD Partners. This includes the building and release of the RAI Toolkit and RAI Toolkit Web Application, the DoD’s AI Assurance Portal, DoD Data and Model Card Templates and supporting software, the DoD’s Frontier AI Red Teaming Program (for the AI RCC), technical guardrails and benchmarks for Frontier AI, enterprise-wide AI Assurance Tools, RAI & AI Assurance support to the Services, the development and validation of the Department’s AI Assurance policies, and various technical resources for topics including Red Teaming, Human Machine Teaming, Stakeholder Engagement, Risk Management, etc. Additionally, the CDAO RAI Division has built and continues to grow the DoD RAI Ecosystem, through chairing the Department’s RAI Working Council, leading the DoD’s RAI Community of Interest, co-chairing NATO’s AI Assurance body, leading the DoD’s RAI Academic Council, and chairing (by appointment of the White House) the working group responsible for assembling the process and resources for the inter-agency to comply with White House AI Risk Requirements.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606135D8Z_086$$, $$0606135D8Z$$, $$086$$, $$Responsible AI$$, 0, $$The RAI Division fulfills the functions of both RAI Capability Development and the building of an RAI Customer Ecosystem. The RAI Division provides critical tools and infrastructure and best practices to all DoD Partners. This includes the building and release of the RAI Toolkit and RAI Toolkit Web Application, the DoD’s AI Assurance Portal, DoD Data and Model Card Templates and supporting software, the DoD’s Frontier AI Red Teaming Program (for the AI RCC), technical guardrails and benchmarks for Frontier AI, enterprise-wide AI Assurance Tools, RAI & AI Assurance support to the Services, the development and validation of the Department’s AI Assurance policies, and various technical resources for topics including Red Teaming, Human Machine Teaming, Stakeholder Engagement, Risk Management, etc. Additionally, the CDAO RAI Division has built and continues to grow the DoD RAI Ecosystem, through chairing the Department’s RAI Working Council, leading the DoD’s RAI Community of Interest, co-chairing NATO’s AI Assurance body, leading the DoD’s RAI Academic Council, and chairing (by appointment of the White House) the working group responsible for assembling the process and resources for the inter-agency to comply with White House AI Risk Requirements.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606300D8Z_807$$, $$0606300D8Z$$, $$807$$, $$Defense Science Board$$, 6563000, $$This program supports the Department's initiatives to Build Long-Term Advantage, and Build a Resilient Joint Force and Defense Ecosystem. The Secretary of Defense established the Defense Science Board (DSB) as a discretionary advisory committee, in accordance with chapter 10 of title 5, U.S. Code (commonly known as “the Federal Advisory Committee Act” or “FACA" and 41 C.F.R. § 102- 3.50(d). The DSB provides independent advice and recommendations on matters supporting the Department of Defense’s (DoD) scientific and technical enterprise to the Secretary of Defense, the Deputy Secretary of Defense, the Under Secretary of Defense for Research & Engineering, the Chairman of the Joint Chiefs of Staff, and other Department officials. The DSB focuses on matters concerning science, technology, manufacturing, acquisition processes, and other topics of special interest to the DoD in response to specific tasks, and is not established to advise on individual DoD procurements. The DSB is concerned with the pressing and complex technological problems facing the DoD in such areas as research, engineering, organizational structure and process, business and functional concepts, and manufacturing, and ensures identification of new technologies and new applications of technology in those areas to strengthen national security. The funds provided allow for the procurement of professional, analytical, and administrative services, to include the tasks of planning, preparation, execution, administrative support, logistics, documentation, and travel for DSB, Subcommittee and Task Force meetings and conferences. The vendors contracted provide essential services in support of the DSB and the DSB staff in the following areas: technical, business, and administrative planning; organizing, managing, coordinating, and tracking (e.g., cost, schedule, and deliverables); and performance management, data management, and subcontract management along with refining initial and final reports of the various study groups. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                   Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:              PE 0606300D8Z / Defense Science Board RDT&E Management Support$$, 6563000, NULL, NULL, NULL, NULL, 2409000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606301D8Z_057$$, $$0606301D8Z$$, $$057$$, $$Force Safety & Occupational Health$$, 1702000, $$This effort supports the Department's priority of Taking Care of Our People. The requirements are aligned to Department of Defense (DoD)/Federal strategic direction including the DoD Digital Modernization Strategy, DoD and Federal Data Strategies, Personnel and Readiness Strategy for 2030, and the DoD Safety and Occupational Health (SOH) Strategic Plan. To protect the lives, safety, health, and welfare of the DoD workforce, and the significant investments we make in our weapons systems, platforms, and infrastructure, we must acknowledge and provide adequate resources for SOH. Ensuring the safety of our workforce requires an enduring culture of safety, where consistent and standardized mishap, near-miss, and hazard reporting is the norm – at least on-par with industry and the private sector aviation and industrial communities. According to the 2020 National Commission on Military Aviation Safety (NCMAS) report, this begins with a centralized system and processes with which to gather, synthesize, and report Safety information at all levels. In addition to the NCMAS report, 10 United States Code Service (USCS) 184 directs the Department to establish uniform data collection standards and a centralized collection system and repository for mishap information. Currently, the DoD collects SOH information from disparate, incomplete, and often overlapping sources - a process that hinders opportunities for timely and in-depth trending and analysis to support Department-wide risk mitigation and mishap prevention efforts. Many of the DoD Components, including some of the Combatant Commands, do not have a safety information management system to enter, track, or manage mishaps, near-misses, or hazards. Without such a system and process, the Department is unable to adequately identify and analyze trends across the DoD Components, efficiently share lessons learned, and track corrective actions in response to recommendations. This effort addresses the Congressional requirements and fulfills capability gaps through modernization of the Force Risk Reduction tool to a safety information case management system. The system will be based on the Department’s safety business processes and data standards, which are being incorporated into Department of Defense Instruction (DoDI) 6055.07 “Mishap Notification, Investigation, Reporting, and Record Keeping.” A central SOH information management system based on the safety business processes and data standards will be available for all DoD Components, providing the capability to those DoD Components without an existing automated tool. It will continue to consolidate all SOH information and serve as the Department’s authoritative repository for all standardized SOH data, providing the capability to those DoD Components without an existing automated tool. It will continue to consolidate all SOH information and provide leaders, serving as the Department’s authoritative repository for all standardized SOH data, and ensuring leaders have current, accurate, and actionable safety information and insights to forecast, mitigate, and prevent future mishaps, injuries, and occupational illnesses, and to drive safety innovation and modernization. Failure to receive this funding will result in non-compliance with Title 10 U.S.C. §184 requirements. Expanding FR2 functionality is the most efficient and effective approach to providing a compliant centralized safety collection and information management capability and repository. Without this funding, the Department will continue to lack a complete understanding of safety impacts to our personnel and operational readiness. Mishap reporting will continue to be inconsistent, and the Department will struggle to manage and share recommendations and lessons learned$$, 1702000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606355N_0798$$, $$0606355N$$, $$0798$$, $$Allied/Coalition Maritime Environment$$, 0, $$The ACME program advances Information Warfare (IW) to include Command, Control, Communications, Computers, Intelligence, Surveillance and Reconnaissance (C4ISR); Electronic Warfare (EW); and Cyber Warfare, interoperability with Australia, Canada, New Zealand, United Kingdom, United States (AUSCANNZUKUS), North Atlantic Treaty Organization (NATO), and other Allied and Coalition partners. The program determines maritime operational gaps with our allies, identifies Doctrine, Organization, Training, Material, Leadership, Personnel, and Facilities (DOTMLPF) solutions with the potential to fill those gaps, and assesses these solutions and associated concepts of operation in laboratory and at-sea environments. The ACME program includes integration and testing in support of Allied and Coalition warfighting capabilities, including interoperability testing of IW equipment. Allied and Coalition interoperability is critical for future maritime operations, especially as the United States Navy cooperatively works towards a federated environment leveraging initiatives such as Federated Mission Networking (FMN), Secret and Below Releasable Environment (SABRE), and Combatant Command solutions such as Indo-Pacific Command Mission Network and Cooperative Partner Environment. Currently, connectivity with AUSCANNZUKUS and other Allied/Coalition forces is focused on traditional paths, requiring extensive backhaul through ashore infrastructure. Higher bandwidth solutions suitable for use over tactical networks require development and assessment for emerging coalition and joint interoperability requirements, such as Network Operations Without Shore (NOWS), Denied, Degraded, Intermittent and Low-bandwidth (DDIL) operations, and to counter Anti-Access Area Denial (A2/AD) threats. Increases in data throughput are required for the effective exchange of rich IW data sets and services via Service Oriented Architectures (SOA) within the limitations of High Frequency (HF), Ultra-High Frequency (UHF), and other portions of the radio frequency spectrum, coupled with appropriate Information Assurance and Computer Network Defense (IA/CND) mechanisms. Development and assessment of potential solutions will integrate improved IP capabilities with the Advanced Digital Network Systems (ADNS) and existing international standards (e.g. Allied Communications Publication 200, NATO Standardization Agreements 5066 and 4691). The continued development and refinement of advanced tactical networking technologies and protocols, to include Low Probability of Intercept (LPI), Low Probability of Detection (LPD), and Anti-Jam (AJ) capabilities as well as Automatic Link Establishment (ALE) standards, will provide for a significant improvement in secure data sharing within, and between, coalition maritime elements. Coalition Warrior Interoperability eXperiment (CWIX) has been integrated within the ACME program. CWIX efforts are focused on assessing federated Coalition capabilities within the NATO command construct via connected Live, Virtual, Constructive (LVC) capabilities resident in the Combined Federated Battle Laboratories Network (CFBLNet). CWIX also resources engineering activities in cooperation with PEO C4I to integrate USN Expeditionary Mission Partner Environment with US Air Force (USAF) Mission Partner Capabilities Office (MPCO) Enterprise Mission Partner Environment efforts. Additionally, CWIX resourcing enables assessment of NATO Federated Mission Networking Spiral Specifications as they relate to USN Programs of Record via the Coalition Interoperability Assurance and Validation (CIAV) construct in conjunction with Joint Staff J6.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606355N_2144$$, $$0606355N$$, $$2144$$, $$Space & Elec Warfare Engineering$$, 24966000, $$To support Navy objectives in advancing Information Warfare (IW) capabilities, the Space and Electronic Warfare (SEW) Engineering project primary functions are: Develop the architectures, specifications and standards, tools, and processes to support a single integrated Navy Cybersecurity plan. Develop cybersecurity engineering criteria within Navy specific guidance to drive common and consistent implementation of security controls within a threat informed mission impact approach across current and future Navy Programs of Record/projects. This eliminates redundancies and inefficiencies characteristic of previous stove-pipe development efforts in which each system addressed security individually. These efforts enable a standardized approach to improve the Navy's cyber resiliency to Cyber Adversary's weaponization of IT/OT susceptibility to attack. Provide the cybersecurity vulnerability and functional test standards, which supports cybersecurity test requirements and the Command, Control, Communications, Computers, Intelligence (C4I) components of Naval Information Warfare Systems Command (NAVWARSYSCOM) Information Warfare (IW) Kill Chain Testing for SYSCOM Red Team. NAVWAR develops and deploys innovative Naval approach for rapid delivery of software applications with emphasis on security & automation via Certified Continuous Integration (CI) / Continuous Delivery (CD) pipeline tools based upon NAVWAR designed SECDEVOPS services under SECNAV Rapid Assess & Incorporate Software Engineering (RAISE). This combination of Systems Commands functions, services and tools ensures Navy platforms in operational maritime environments can effectively defend and "fight through" cyber adversary attacks under a framework of mission thread analysis and assessment. NAVWAR establishes an integrated Enterprise Architecture to support design, development and delivery of integrated Navy Command, Control, Communications, Computers, Intelligence, Surveillance, and Reconnaissance (C4ISR), Business Information Technology (IT), and Space System capabilities. This architecture reflects current (as-is) and future (target) end states to support technical analyses, program planning, and enterprise-level investment decisions across IW capabilities on both ashore and afloat platforms. Provides engineering tools and processes to drive rigorous systems engineering discipline across the acquisition lifecycle to support rapid development and delivery of secure and interoperable C4ISR, Business IT, and Space Systems capabilities that meet Fleet requirements. Conduct Systems Engineering Technical Reviews (SETRs) to provide independent, objective assessments and certifications of technical maturity and compliance with applicable architectures, specifications and standards across IW capabilities.$$, 24966000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606355N_3319$$, $$0606355N$$, $$3319$$, $$Fleet Experimentation$$, 12585000, $$Mission: The Fleet Experimentation (FLEX) program seeks out and examines potential materiel and non-materiel solutions (initiatives) to the Fleet's highest priority warfighting gaps and generates data-driven findings and actionable recommendations to resolve or mitigate those gaps. As part of a multi-year campaign, 10 to 15 major analytic experimentation activities take place annually that include workshops, war-games, and with a focus on live force, operationally oriented at-sea events. The FLEX Program is owned by Commander U.S. Fleet Forces Command (CUSFFC), Commander U.S. Pacific Fleet (CPF), and Commander U.S. Naval Forces Europe - Africa (CNE-AF). The three four-star Fleet Commanders identify the Fleet priorities and warfighting gaps for FLEX to address, and Navy Warfare Development Center (NWDC), as the Executive Agent (EA), designs, plans, executes, analyzes, and reports on the FLEX initiatives. Commanders' FLEX guidance is linked to the January 2024 Chief of Naval Operations (CNO) Navigation Plan (NAVPLAN) direction to continue refinement of concepts and capabilities through experimentation. FLEX priorities are also aligned to the Warfighting Integration NAVPLAN Implementation Framework (WIN NIF) Operating Review for the CNO that identifies the North Star, supporting pillars, and approach. FLEX initiatives are tied to CNO-approved Distributed Maritime Operations (DMO) and Joint Warfighting Concept (JWC) concept capability requirements, Fleet warfighting gaps, and Key Operational Problems (KOP). FLEX aligns with National Defense Strategy priorities, lines of effort 1 (lethality) and 3 (reform), and numerous other strategic guidance documents highlighting the need to increase organizational learning and capability development in experimentation, wargames, and exercises. USFFC N8/N9-manages the FLEX investment -- $12.585M (FY26) to support planning, execution, analysis, and reporting for analytically rigorous experiments leveraging Limited Objective Experiments (LOE) and scheduled fleet exercises.$$, 12585000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606355N_3320$$, $$0606355N$$, $$3320$$, $$TRIDENT Warrior$$, 0, $$U.S. Navy's Trident Warrior (TW) experiment campaign enables early delivery of Information Warfare (IW) capabilities to the warfighter via Fleet-directed TW operational events. It integrates stand-alone systems and efforts to achieve enhanced capabilities and demonstrates these capabilities in operational environments. This places innovative technologies into the hands of the warfighter to evaluate their effectiveness. Additionally, it develops supporting doctrine and Concepts of Operation to improve warfighting effectiveness. Coordinates IW efforts with other Service/Joint/Department of Defense/National efforts to ensure Joint/Interagency/ Allied/Coalition applicability and interoperability.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606771D8Z_145$$, $$0606771D8Z$$, $$145$$, $$Cyber Resiliency & Cybersecurity$$, 14220000, $$The Cyber Resiliency & Cybersecurity Policy program supports the efforts of the Office of the Under Secretary of Defense, Acquisition and Sustainment (OUSD A&S), focusing on the defense of the Department’s critical mission weapon systems and supporting DoD Installation Critical Infrastructure (ICI)and supporting Commercial Critical Infrastructure (CCI)from cyber attack, protecting the Department’s sensitive unclassified information residing within the Defense Industrial Base (DIB) sector and supply chain , and capability portfolio management for Joint Cyber Capabilities used by the Cyber Mission Force. This program funds the following critical efforts: 1) Cybersecurity for Weapon Systems and Critical Infrastructure: Conduct Capability Portfolio Management and lead the Department’s Strategic Cybersecurity Program (SCP) to continue critical weapon systems and ICI cybersecurity assessments and mitigations and cyber harden priority Department of Defense (DoD) missions. Office of Assistant Secretary of Defense for Acquisition (ASD(A))/Cyber Warfare Directorate (CWD) Cyber Resiliency efforts are aligned with the following initiatives: Assess: - Conduct mission level cyber risk assessments for priority Defense Missions in support of Combatant Commands (CCMDs). Conduct enhanced mission level cyber risk assessments/wargames for the Missile Defense Mission in support of Golden Dome for America. Conduct supporting table top exercises (TTXs). - Conduct Cyber Risk Assessments for ICI and CCI in support of CCMDs and asset owners. - Conduct Integrated Sensing Monitoring Experiments (ISMX)and Sensing and Monitoring Pilots to assess the performance of Cybersecurity Sensing and Monitoring capabilities for WS and ICI. Inventory / Prioritize: - Develop, sustain, and employ the Cyber Risk Mitigation Tool (CRMT), an Enterprise-wide decision support tool for tracking and prioritizing cyber vulnerability assessments and mitigations. Develop CCMD specific cyber risk scorecards/risk matrices. - Prioritize and advocate for Cyber Risk Mitigations based upon mission analysis conducted by program offices, the National Security Agency (NSA), Deep Cyber Resiliency Assessment teams, USCYBERCOM (USCC), and other cybersecurity professionals. Mitigate: - Advocate and oversee funding for priority ICI and commercial critical infrastructure (CCI) supporting Golden Dome for America based on a prioritized list of assets. - Conduct SCP POAM periodic updates with Services and Agencies for prioritized DoD weapon systems. Enhance Governance: Conduct 4-Star Level Integrated Acquisition Portfolio Reviews (IAPRs) that address cybersecurity / cyber hardening / cyber defense for priority DoD missions.$$, 14220000, NULL, NULL, NULL, NULL, 84527000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606829D8Z_934$$, $$0606829D8Z$$, $$934$$, $$Sustainment Transition Capabilities$$, 30000000, $$Mission Description: FY 2022 NDAA Section 142 requires the Department to transition Sustainment functions from the F-35 Joint Program Office to the Military Departments (MILDEPs) of the Air Force and Navy no later than end of 2027. The Under Secretary of Defense (USD) Acquisition & Sustainment (A&S) Report to Congress dated 30 January 2023, states that the MILDEPs will achieve Initial Operating Capability (IOC) by end of 2027 to act as the Inventory Control Point (ICP) and reach Full Operating Capability (FOC) by end of 2029. Additionally, for NDAA Section 142 to effectively occur, FY 2024 NDAA Section 1005 mandates that the Department achieve an unmodified audit opinion by the end of 2028. To achieve both statutory requirements and allow the MIPDEPS to assume ICP control by the end of 2027, the Department requires a Logistics Information Technology (LogIT) network that will facilitate necessary data exchange via Department standard Defense Logistics Management Standard (DLMS) transactions and the F-35 prime vendor systems. Once the network is established the Departments’ financial and business systems will have enabled capability for full asset visibility, financial transactions, and Inventory Control Points (ICPs) accountability operations. This investment will deliver that data architecture design, implementation, and capability which will provide the MILDEPs with the necessary asset visibility and controls to assume full ICP responsibilities from the prime vendors. F-35 spares are currently maintained within the current Prime vendor databases. The vendor did not use established standardized Department of Defense supply and inventory control processes when the F-35 program originated. As a result, this prevents the Department from easily capitalizing the parts and assuming full ICP responsibilities from the prime vendors. The establishment of the data exchange will allow the Department to begin the transition of the spares inventory into the ICPs for lifecycle management. This transition will be accomplished through establishing provisioning and cataloging actions of the F-35 spares, estimated in value around $15 billion. Provisioning and cataloging the spares will convert the spares to National Stock Numbers (NSNs) facilitating their integration into the Defense Logistics Agency’s (DLAs) Warehouse Management System (WMS) for worldwide inventory management and asset visibility. The outcome will provide the MILDEPs with necessary data elements to accomplish demand planning, procuring and repairing spares. Justification: The RDT&E funds will be used to ensure the necessary data architecture is designed and implemented to automate data between the prime vendors and the Department’s business systems. The Deputy Chief Finance Officer (DCFO) requires a mandated milestone of October 2026 for Services to financially report on the$$, 30000000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606853BR_MN$$, $$0606853BR$$, $$MN$$, $$DEFENSE CRITICAL$$, 14841000, $$The Defense Threat Reduction Agency (DTRA), as the DoD Center of Excellence for Mission Assurance Assessments, has been tasked by Deputy Assistant Secretary of Defense for Defense Continuity and Mission Assurance with leading change within the MA community on behalf of Office of the Under Secretary of Defense to ensure best practices are documented during the Joint Mission Assurance Assessments (JMAA), Balanced Survivability Assessments (BSA), and Red Team Assessments. Including but not limited to dependency analysis, asymmetric threats, cyber operations, general engineering, security operations, and emergency management. In partnership with the Critical Infrastructure Defense Analysis Center (CIDAC) and the U.S. Department of the Navy's Defense Critical Infrastructure - Mission Assurance program, DTRA’s Mission Assurance program will perform mission analysis; engineering and commercial infrastructure network interdependency analysis; MA assessments; information enterprise design, implementation, and support; and defense industrial base supply chain network and related analysis. Efforts provide broad leadership, best practices, research, development, coordination, support to DoD Components around specific focus areas to drive solution-oriented efficiencies, collaboration, and results that benefit the entire DoD MA enterprise.$$, 14841000, NULL, NULL, NULL, NULL, 10039000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0606942A_FL2$$, $$0606942A$$, $$FL2$$, $$Cyber Vulnerabilities Assessments$$, 6354000, $$This funding line reduces the Army's risk to adversarial cyber intrusions or attacks that could compromise critical weapon systems and kill chains. Cyberspace Operational-Resilience Assessment - Platform (CORA-P) is the Army program to improve survivability across Army modernization efforts and maintain readiness of operational capabilities. CORA-P addresses the requirements of Section 1502 of the FY24 NDAA, which directed the Services to harmonize the identification and mitigation cyberspace vulnerabilities in critical weapon systems. Headquarters, Department of the Army initially established CORA-P to continue Section 1647 assessments, while expanding to include supply chain risk analysis and electromagnetic spectrum vulnerabilities. CORA-P has since shifted from executing new assessments to harmonizing defensive efforts across existing Army and DoD assessment programs (including the Strategic Cybersecurity Program). CORA-P now focuses on developing and delivering vulnerability remediations that result from these assessments as well as from sensitive threat intelligence and other potential indicators of compromise. Activities include improving the structure and visibility of vulnerability data to improve portfolio risk management, initiating remediation efforts for high-priority, crosscutting issues, and avoiding future risks by driving improvements earlier in materiel development for modernization programs. As part of CORA-P, the Army identifies and prioritizes capabilities most-relevant to National Defense Strategy priorities based on input from mission planning, JROC guidance, and sensitive threat intelligence. This also includes coordinating Army Cyber Command lead Crisis Action Teams, where specific vulnerabilities affect the Army weapon/business systems. A key aspect is integrating efforts across both HQDA and Army Commands to understand total risk exposure while avoiding duplication. The Army then reviews the security posture of these critical components, develops remediation strategies, and facilitates delivery of fixes at mission- relevant speed. This includes working with program offices, capability managers, and resource managers to develop realistic plans of action for manage risk across outyears, and then gaining Army Senior Leader approval as needed. CORA-P ensures Army cyberspace remediation investments address areas of highest operational risk. When applicable, this PE also provides for Red Team enhancement to support Combatant Command mission-level cyber vulnerability assessments.$$, 6354000, NULL, NULL, NULL, NULL, 6025000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607101A_DJ7$$, $$0607101A$$, $$DJ7$$, $$Radiological Detection System$$, 115000, $$The Combating Weapons of Mass Destruction Product Improvement (CWMD) line supports obsolescence management efforts for overall chemical, radiological, and biological detection and protection for the warfighter for multiple programs of record. Radiological Detection System (RDS) will replace the current radiation detection, indication, and computation (RADIAC) systems used by the Joint Services and will consolidate the capabilities into one joint solution. RDS consists of a handheld base unit with beta/gamma detection capability and six probes. RDS incorporates geolocation data- Global Positioning System interface capability, Network Ready data and lessons learned from Operation TOMODACHI which includes common measurements, common equipment, and adequate sensitivity. RDS benefits the warfighter by providing a common Joint capability to detect, identify, and compute total exposure to multiple radiation types, and reduces the acquisition as well as sustainment costs across the Joint Services by taking advantage of economies of scale. FY26 funding will resource mandatory testing to validate the interoperability of the RDS with Army Radios - achieving KPP 3 of Net Ready.$$, 115000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607131A_CP2$$, $$0607131A$$, $$CP2$$, $$Precision Fire Technology$$, 3630000, $$This Project supports required Precision Guided Munitions (PGMs), and Precision Fuze and Fuze Setter assessment and improvement initiatives to support increased rates of fire for items that have been fielded or in full rate production, such as the M1155 Enhanced Portable Inductive Artillery Fuze Setter (EPIAFS), Excalibur and Precision Guidance Kit (PGK). Efforts will identify, characterize, study, analyze, test, and develop PGM and Fuze technologies to increase range, lethality, effectiveness, survivability, and accuracy in support of the Army's Cannon Transformation Strategy.$$, 3630000, NULL, NULL, NULL, NULL, 3325000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607131A_ER2$$, $$0607131A$$, $$ER2$$, $$Close Combat Technology$$, 4707000, $$Project ER2 Close Combat Technology includes development efforts to upgrade Close Combat technologies, energetics, and munitions, such as counter explosives, grenades, demolitions, shoulder launched munitions, pyrotechnic simulators, countermeasure flares, non-lethal ammunition/systems, and networked munitions and mines, that have been fielded or have received approval for full rate production. Funding will allow the project to identify, characterize, study, analyze, test and develop technologies to resolve close combat munition reliability, safety, environmental, storage, standardization, obsolescence and manufacturing/producibility issues.$$, 4707000, NULL, NULL, NULL, NULL, 2780000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607131A_ER6$$, $$0607131A$$, $$ER6$$, $$Direct Fire Technology$$, 3048000, $$The Direct Fire Technology funding will be used to support direct fire ammunition from small caliber ammunition, medium caliber ammunition and large caliber ammunition enhancements to lethality, effectiveness, survivability, accuracy and general product improvements. Fiscal Year (FY) 2026 funding supports a number of small caliber ammunition projects including improvements to training ammunition; improvements to make small caliber primers more environmentally friendly; optimization of handgun ammunition; exploring precision sniper improvements and continuing the effort to reduce Soldier load by developing lightweight ammunition. Improvements to medium caliber ammunition include lethality and safety enhancements including Counter Unmanned Aircraft System (C-UAS) technology. Improvements to 105mm and 120mm tank ammunition include examination and implementation of performance enhancement and improvements to tracer, combustible cartridge case and 105mm Advanced Multipurpose (AMP).$$, 3048000, NULL, NULL, NULL, NULL, 41486000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607136A_ES3$$, $$0607136A$$, $$ES3$$, $$Blackhawk Product Improvement$$, 23998000, $$This funding line is a key enabler of the Army's development and modernization priorities in support of the H-60 Black Hawk helicopter. The program develops, tests, qualifies, and integrates the next generation capability for integration and implementation to the H-60 fleet to increase combat capability and reduce cognitive workload. The two overarching efforts are digital backbone and airframe enhancements. The digital backbone design supports rapid integration of future capabilities that align with Future Vertical Lift (FVL) Family of Systems (FoS), as well as airframe enhancements aligned with Launched Effects (LE). Fiscal Year 2026 Base funding will be utilized for the digital backbone design and airframe enhancements in support of launched effects.$$, 23998000, NULL, NULL, NULL, NULL, 40923000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607137A_ES4$$, $$0607137A$$, $$ES4$$, $$Chinook Product Improvement$$, 10859000, $$NOTE: The increase in funding from FY2025 to FY2026 is required to complete production configuration flight testing to qualify the CH-47F Block II as described in paragraph three (3) below. Program Element (PE) 0607137A Chinook Product Improvement Helicopter Program is critical to achieving heavy lift capability in support of Transformation in Contact (TiC) and Continuous Transformation objectives. The CH-47F Block II helicopter, with an increased payload and operational reach, is the only platform that can lift the Joint Light Tactical Vehicle (JLTV), M777 and medium girder bridge to enable the TiC Forces to Compete, Penetrate, Disintegrate, and Exploit at operationally relevant distances. CH-47 Modernization Product Management Office includes the Block II acquisition program that upgrades existing CH-47F aircraft and procures common hardware between the CH-47F and MH-47G aircraft. The CH-47F Block II program reduces Operating and Support (O&S) costs, increases maximum gross weight to 54,000 pounds, provides additional capability to the field with greater reach, and increases payload capability. CH-47F Block II upgrades improve the aircraft's safety and reliability with a strengthened airframe, and improvements to the rotor, fuel and electrical systems. The CH-47F Block II program includes updates to software packages, Common Avionics Architecture System (CAAS), Digital Advanced Flight Control System (DAFCS), and incorporates other avionics changes introduced into the final CH-47F Block I production lots. In addition to providing significant increased capability to the field, the program includes provisions for anticipated future upgrades, and weight and cost savings initiatives. The increased capabilities ensure the TiC has a platform with the flexibility and performance necessary to meet the needs of current and future operations. The Cargo Project Management Office awarded the CH-47F Block II Engineering and Manufacturing Development (EMD) contract in July 2017. The EMD phase produced three production representative test articles to support a Production Decision. This phase includes contractor and government led ground and flight system level qualification testing, which requires Electromagnetic Environmental Effects (E3), operation assessments, and aircraft subsystem Live-Fire Test and Evaluation (LFTE). System Level testing is required to complete an Operational Assessment and Material Release (MR).$$, 10859000, NULL, NULL, NULL, NULL, 20386000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607139A_ES6$$, $$0607139A$$, $$ES6$$, $$Improved Turbine Engine Program$$, NULL, $$This funding line is a key enabler of the Army Modernization Priorities in support of the Improved Turbine Engine Program (ITEP). ITEP develops, tests, qualifies, and integrates the next generation turboshaft engine on Black Hawk and Apache aircraft. The Improved Turbine Engine (ITE) replaces the existing T700 engine design originated in the 1970s and meets the operational requirement of 6,000 feet pressure altitude and 95 degrees (6K/95). The ITE will fit inside the existing engine bays of the Black Hawk and Apache Helicopters and provides a significant power enhancement of up to fifty percent (total of 3,000 class shaft horsepower) with increased fuel efficiency. Additional benefits include improved design life, enhanced reliability, lower maintenance cost and restored capability lost due to aircraft weight growth without an increase to the logistics footprint. The program consists of systems engineering and program management, detailed design engineering, design assurance, hardware manufacturing and testing, component and module level development and testing, system level testing and qualification, and platform integration and qualification.$$, NULL, NULL, NULL, NULL, NULL, 182204000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607142A_EW9$$, $$0607142A$$, $$EW9$$, $$Aviation Rocket System Product$$, NULL, $$The Aviation Rockets and Small Guided Munitions Product Improvement and Development line funds the development, integration and test of current and future munitions and launchers, and their interface to platforms. Additionally, it will fund a range of improvement initiatives to modernize the Hydra-70 2.75 inch rocket and launcher system. The current Hydra-70 2.75 inch rocket system requires performance improvements to comply with 1) US Code - Title 10, Chapter 141, Section 2389 "Ensuring Safety regarding Insensitive Munitions", 2) Department of Defense (DoD) Directive 5000.1, Chairman of the Joint Chiefs of Staff (CJCS) Instruction 3170.01C, Under Secretary of Defense for Acquisition, Technology, and Logistics (OUSD (AT&L)) Memorandum of January 26, 1999, "Exemption for Existing Inventory Items to Insensitive Munitions (IM) Requirements", 3) signed Initial Capability Document (ICD) for Army Aviation Weapons, Sub-Systems and Munitions (AAWSSM), 4) Air Launched Effects (ALE) Initial Capability Refinement Document (ICRD) dated 21 October 2019, and 5) existing/emerging Headquarters, Department of the Army (HQDA) G-3/5/7 and U.S. Army Training and Doctrine Command (TRADOC) aviation weapon requirements for guided and unguided rocket and munition systems. Improvements to existing rocket systems and munitions will include design, qualification and integration of precision guidance capability, increased lethality, improved target suppression, increased standoff range, reduced minimum engagement range, improved pre-launch constraints and munitions communications/programmability, increased stowed kills, increased product reliability, improved hardness against unplanned stimuli, reduced Warfighter workload, and reduced environmental impact for both manned and unmanned applications. PE 0607142A EW9 has no FY 2026 funding request.$$, NULL, NULL, NULL, NULL, NULL, 2904000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0608140D8Z_676$$, $$0608140D8Z$$, $$676$$, $$Business Mission Analytics$$, 100972000, $$The Business & Mission Analytics project enables DoD organizations to leverage data, analytics, and artificial intelligence to improve decision making in multiple functional and cross-functional areas. Through the delivery of enterprise capabilities, services, and best practices, we empower business and warfighting operators to leverage data to achieve decision advantage. Funding resources the development and delivery of new analytics that support Joint customers, including Combatant Commands, the Joint Staff, OSD Principal Staff Assistants, and cross-Service efforts.$$, 100972000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607143A_EX1$$, $$0607143A$$, $$EX1$$, $$Unmanned Aircraft Systems Universal$$, NULL, $$Scalable Control Interface (SCI) is a permissions-based software control suite used by Soldiers to simultaneously control multiple, disparate types of uncrewed or optionally-manned aircraft and payloads through a universal interface with scalable levels of authority. SCI distributes UAS capabilities by greatly increasing the number of UAS control devices available to Soldiers, Commanders, and Battle Staff. SCI provides simultaneous employment of multiple aircraft/payloads from a single control node. SCI leverages a Modular Open System Approach (MOSA) to software in order to reduce time and cost to integrate new hardware and software in response to the dynamic future operating environment. Deployment of SCI includes devices in the Mobile/Handheld Computing Environment (such as Nett Warrior), Mounted Computing Environment such as Mounted Family of Computer Systems (MFoCS), Command Post Computing Environment such as Tactical Services Infrastructure (TSI), fixed wing aircraft, and rotary wing aircraft. SCI will integrate decision aiding, autonomy, and artificial intelligence improvements as they technically mature, in order to support Multi-Domain Operations and reduce cognitive workload.$$, NULL, NULL, NULL, NULL, NULL, 24466000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607145A_FD5$$, $$0607145A$$, $$FD5$$, $$Apache Product Improvement$$, 44371000, $$The Apache Product Improvement program prioritizes, informs, influences, matures, tracks, statuses, and packages technologies and/or material solutions to address known capability gaps identified during real-world combat missions and associated with current/emerging threats for the transition to Apache development for integration and implementation to the AH-64E fleet to increase combat capability.$$, 44371000, NULL, NULL, NULL, NULL, 44762000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607148A_BY8$$, $$0607148A$$, $$BY8$$, $$AN/TPQ-53 Counterfire Target$$, 43054000, $$This funding line supports the AN/TPQ-53 Counterfire target Acquisition Radar program, a key enabler of the Army Long Range Precision Fires (LRPF) Modernization Priority. The AN/TPQ-53 Counterfire Target Acquisition Radar System is a highly mobile radar set that automatically detects, classifies, tracks, and locates the point of origin of projectiles fired from mortar, artillery, and rocket systems. It mitigates close combat radar coverage gaps by providing a 90 degree search sector (stare mode) as well as 360 degree coverage (rotating). The AN/TPQ-53 system incorporates Multi-Mission Radar (MMR) software into the system baseline, enabling air surveillance for Commander's situational awareness of UAS. The AN/TPQ-53 system interoperates with mission command systems to provide the maneuver commander increased counterfire radar flexibility, providing data to the Forward Area Air Defense Command and Control (FAAD C2) node for the sense and warn force protection capability. The AN/TPQ-53 is provided to Brigade Combat Teams (BCTs), Field Artillery Brigades (FABs) and Division Artilleries (DIVARTYs) and serves as an enabler for systems requiring target in-flight updates. Fiscal Year (FY) 2026 RDTE funds support tests for Distributed Digital Receiver Exciter (DDREX) Capability Sets #1 and #2 to enhance system survivability, electronic protection (EP), and bandwidth agility to improve system capability in a peer/near-peer threat environment. FY 2026 funds also continue DDREX Capability Sets #3 and #4 to counter indirect fire with improved hostile weapon location accuracy and survivability against the latest electronic warfare threats identified in the Counterfire Radar Systems (CFRS) Validated Online Lifecycle Threat (VOLT) report dated 15 February 2022.$$, 43054000, NULL, NULL, NULL, NULL, 52190000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607150A_BS5$$, $$0607150A$$, $$BS5$$, $$Intel Cyber Development$$, 13129000, $$INSCOM's SIGINT/EW/Cyberspace Capability Development Program is continuous and iterative; generally, when presented with a demand signal for development of a capability, the target delivery window is between 30 days up to 12 months. If INSCOM cannot deliver within the target window, INSCOM coordinates with Geographic and Functional Combatant Commands, ARCYBER and PdM-IW to develop an effective capability solution. INSCOM's tools portfolio provides mission applications that serve as the "ammunition" needed to conduct operations and impose costs while enabling the organic software developers to build tools at the speed required for persistent engagement. In addition, INSCOM maintains a robust development level of cutting-edge multi-domain electronic warfare, signals intelligence and cyberspace operations tools and weapons.$$, 13129000, NULL, NULL, NULL, NULL, 4345000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607162D8Z_548$$, $$0607162D8Z$$, $$548$$, $$ChemBio Weapons Elim Tech Impr$$, 2360000, $$Chemical and biological weapons (CBW)-based threats continue to evolve in response to changing geopolitics and emerging technologies. Each of the nations that are deemed as threats to United States (U.S.) national security are believed to have and/or be developing chemical and/or biological weapons. The Department of Defense (DoD) must be prepared to eliminate these threats during and/or after the execution of a contingency operation or in support of a diplomatic breakthrough, enabling the U.S. to achieve peace through strength and strengthening deterrence. Chemical Weapons Convention (CWC) and Biological Weapons Convention (BWC) obligations and DoD strategic guidance demand the Department maintain a complete and enduring capability to assess and destroy CBW, regardless of location or environment. In accordance with the CWC and BWC, the U.S. must be prepared to “destroy [chemical/biological] weapons…in its possession or…under its jurisdiction or control.” It is critical for the DoD to possess the capabilities to directly disable or defeat WMD threats prior to use. This capability must provide operational flexibility that enables early action and expedient destruction, from small-scale disablement and defeat in a non-permissive or austere environment to large-scale destruction of a foreign CBW stockpile in a post-contingency or permissive environment. Our current capabilities are inadequate to support these requirements, and we are currently unable to invest in the development and/or improvement of capabilities to eliminate CBW on the scale required. The Department must be proactive in ensuring we are prepared to eliminate known and expected CBW threats before adversary use against U.S. military or civilian personnel at home or abroad or our allies. The Chemical and Biological Weapons Elimination (CBWE) Research and Development Activities (RDAs)support the Department’s initiatives to rebuild our military and reestablish deterrence by ensuring a complete and enduring capability to assess and destroy chemical and biological weapons (CBW), regardless of location or operational environment. This program addresses Joint Force priorities, tasks, and requirements. Fiscal Year (FY) 2026 funding is for the advanced development of chemical weapons destruction capabilities in support of Joint Warfighter and U.S. Recovered Chemical Warfare Material requirements. The CBWE portfolio provides material solutions that enable DoD to prevent adversary acquisition, transfer, deployment, and use of CBW as well as meet U.S. Chemical Warfare Convention (CWC) treaty obligations. The CBWE portfolio will execute along several Lines of Effort (LOEs) to help prepare the Joint Force for a future operating environment in which adversary possession of Weapons of Mass Destruction (WMDs) pose threats ranging from tactical to existential, and limit U.S. strategic choices. These LOEs will create options for assessment$$, 2360000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0608140D8Z_677$$, $$0608140D8Z$$, $$677$$, $$SUNet$$, 58970000, $$SUNet (Secure Unclassified Network) is an off-DODIN Government owned (GOTS) network and compute platform that provides critical mission support for Combatant Commands, Interagency Task Force groups, fast-moving AI missions, and emerging DoD missions that cannot be met by other existing agency-specific capabilities. SUNet adheres to DoD RMF standards and can support data and missions at the CUI level and below. The platform provides DoD with maximum flexibility to leverage best in industry software, tools, and developers in a secure environment to achieve and maintain operational advantage.$$, 58970000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0608140D8Z_679$$, $$0608140D8Z$$, $$679$$, $$ADVANA Infrastructure$$, 238341000, $$This PE funds capabilities and activities to make disparate DoD datasets more widely accessible, understandable, interoperable, and actionable across the DoD enterprise by providing the government-owned, contractor operated enterprise data stack, analytic and AI tools, and data and AI engineering expertise to improve DoD decision making across multiple functional areas and organization levels. It includes the ability to develop, train, and support the DoD workforce to effectively leverage the data, analytics, and AI capabilities provided through Advana.$$, 238341000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607210D8Z_819$$, $$0607210D8Z$$, $$819$$, $$Industrial Base Analysis and$$, 273379000, $$Global supply chain disruptions have become more common, with recent world events highlighting risks and vulnerabilities that undermine our national security. The 2022 Industrial Capabilities Report (ICR) report outlined strategic focus areas and enabling capabilities, associated vulnerabilities, and recommendations to strengthen the DIB. The FY 2026 IBAS budget reflects the DoD’s commitment to ensuring our supply chains can provide our warfighters with decisive advantage. This budget includes investments to respond to Executive Orders, emerging and modernization priorities and technologies, and other defense requirements. The IBAS budget is the result of significant coordination for each strategic focus area via the Program Review Teams (PRTs), which developed an integrated and prioritized investment strategy to address the most pressing needs for each focus area, to include mapping to investment authorities. The FY 2026 IBAS budget reflects the outcome of the PRT recommendations and has been coordinated to complement adjacent investments by related programs including the Defense Production Act Title III and Manufacturing Technology (ManTech) programs, and within the Military Services. Accordingly, investments in the following strategic focus areas will establish, sustain, and expand domestic capabilities and capacities to build more sustainable and resilient supply chains. Workforce – The DoD relies on a skilled workforce to innovate, produce, and sustain our weapon systems. Decades of erosion across workforce development pipelines jeopardize and threaten our industrial base’s ability to remain competitive. Workforce is a critical enabler for all DIB technology, mission, and market sectors. Analytically informed IBAS industrial workforce investments catalyze the development of sustained, regionally focused public-private partnerships (between companies, state/ local governments, academia, non-profits, industry associations, and other entities) to strategically close shortfalls in recruitment, training capacity/quality, and hiring/ retention. Efforts will continue to focus on recruitment, training, placing and retaining skilled workers in support of defense priority states / regions coordinating with other interagency programs, and leveraging authorities from other departments to support priority defense programs. FY 2026's primary effort will be the continuation and sustainment of a major, multi-year, joint OSD-Navy endeavor begun in FY 2023 focused on ensuring the health and capacity of the DoD’s Maritime and Submarine industrial workforces.$$, 273379000, NULL, NULL, NULL, NULL, 1531838000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607212A_DM4$$, $$0607212A$$, $$DM4$$, $$TENCAP OPERATIONAL$$, 0, $$B. Program Change Summary ($ in Millions)                                            FY 2024             FY 2025             FY 2026 Base            FY 2026 OOC             FY 2026 Total Previous President's Budget                                                      0.000               0.000                   0.000                       -                    0.000 Current President's Budget                                                       0.000               0.000                   0.000                       -                    0.000 Total Adjustments                                                                0.000               0.000                   0.000                       -                    0.000 • Congressional General Reductions                                          -                   - • Congressional Directed Reductions                                         -                   - • Congressional Rescissions                                                 -                   - • Congressional Adds                                                        -                   - • Congressional Directed Transfers                                          -                   - • Reprogrammings                                                            -                   - • SBIR/STTR Transfer                                                        -                   -$$, 0, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607310D8Z_242$$, $$0607310D8Z$$, $$242$$, $$Counterproliferation Modernization$$, 12704000, $$Counterproliferation (CP) Modernization supports the 2025 Interim National Defense Strategic Guidance objective of peace through strength with modernized capabilities that reestablish deterrence and rebuild our military. Program investments in CP capabilities, including pathway defeat and WMD device defeat activities, enable the Department to maintain credible options to defend the homeland against WMD use. Investments result in capabilities that take action against actors of concern and reduce access to WMD development pathways and delay further development, degrade capabilities where possible, and prevent WMD use. (2023 DoD Strategy to Counter Weapons of Mass Destruction (CWMD)). This Program Element (PE) modernizes currently fielded capabilities for operating units with assigned CP/CWMD missions to disrupt, degrade, delay, deny, and defeat adversary nuclear, chemical, and biological weapons, delivery platforms, command and control systems, and hardened and deeply buried targets. Program investments enable modernized WMD deterrence and CP capabilities that provide flexible options across all domains, including tactical situational awareness, low visibility methods of maneuver, and the ability to employ immediate effects without diminishing future capabilities, enabling active campaigning that supports the Administration’s CP priorities, mitigating risk to mission and risk to force. Funding is prioritized for projects that close Joint Force warfighter capability gaps, including the defense of Taiwan and the homeland. An annual investment strategy is used to meet emergent operational needs validated by the Joint Force, yielding new fielded capabilities within one to two years. This program funds labor, materials, and travel in support of its requirements, performed by a government agency or by private individuals or organizations under a contract with the government, for activities and acquisitions including Research, Development, Test & Evaluation (RDT&E), assessments and analyses, , education, and other activities related to capability development and fielding of nuclear modernization, homeland missile defense, one-way attack autonomous systems, critical cybersecurity and counter-small UAS initiatives.$$, 12704000, NULL, NULL, NULL, NULL, 84640000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607312A_BR5$$, $$0607312A$$, $$BR5$$, $$Army Operational Systems$$, NULL, $$The Army Operational System Development budget line includes development efforts across all Army Battlefield Operating Systems to upgrade systems that have been fielded or have received approval for full rate production. Systems in this budget line are characterized as having, or supporting programs that have received, Milestone C or Low Rate Initial Production (LRIP) approval. Selected programs within this budget line will exhibit a logical progression of program phases, development and production funding within the FYDP, consistent with the Department's full funding policy.$$, NULL, NULL, NULL, NULL, NULL, 19000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607313A_CE2$$, $$0607313A$$, $$CE2$$, $$Prophet$$, NULL, $$Project CE2 supports the Prophet Enhanced Program, the Army's current fielded terrestrial Signals Intelligence (SIGINT)/Electronic Warfare (EW) support system. Funds provide for development and integration of Signals of Interest (SOI); Technical Insertion (TI) engineering for Next Generation Signals; state-of-the-art SIGINT exploitation techniques to increase the capabilities of Prophet Enhanced; enabling the system to pace near peer; and emerging enemy threat signals. Additionally, funds provide for efforts to include engineering, development and testing to mitigate component obsolescence. The Prophet Enhanced is the tactical commander's organic ground-based SIGINT/EW support system. Its primary mission is to provide 24-hour situation development and information superiority to the supported maneuver brigade to enable the most effective engagement of enemy forces. Prophet Enhanced provides a modular, scalable, open architecture-based system solution optimized for ease of use in a variety of configurations. It also incorporates product modification, integration, evaluation and demonstration events of equipment for rapid integration of TIs and product development to ensure operational relevance.$$, NULL, NULL, NULL, NULL, NULL, 6389000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0708047S_ABC$$, $$0708047S$$, $$ABC$$, $$DPAS$$, 3020000, $$The DPAS system provides accountability and management functionality of General Equipment, Real Property and Internal Use Software, to the Department. The budgeted projects will provide enhancements to the existing capability, ensure efficient operation, and provide solutions for process gaps as they are discovered. The greater enhancements to DPAS allow the DOD to sunset legacy systems as DPAS assimilates the legacy functionality into the overall operations.$$, 3020000, NULL, NULL, NULL, NULL, 26512000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607665A_DU2$$, $$0607665A$$, $$DU2$$, $$Management Agency$$, 1594000, $$The Defense Forensics and Biometrics Agency (DFBA), under the Provost Marshal General, fulfills the Secretary of the Army's Executive Agent (EA) responsibilities for all DoD forensics and biometrics activities. As the proponent, DFBA supports and provides oversight for Research, Development, Test & Evaluation (RDT&E) activities and information management throughout the Armed Services and DoD. DFBA leads and facilitates in the development of improvement and implementation of efficiencies to developed and deployed biometric technologies for Combatant Commands (CCMDs), Services, DoD, and Agencies; facilitates transition of capabilities that contribute to the enhancement of the biometric community; increases Joint Service interoperability; and empowers the warfighter by improving operational effectiveness on the battlefield. The DFBA strategy pursues technology opportunities through scientific discovery and makes investments responsive to specific requirements identified by combat developers. Justification: FY 2026 funding in the amount of $1.594million for Project DU2 will provide DFBA the ability to actively manage research efforts to address DoD biometrics objectives and requirements. DFBA supports the conduct of biometric and forensics activities (e.g. standards conformance and interoperability assessments), provides guidance to the research and development community, assists DoD acquisition organizations, and coordinates efforts with DoD and interagency stakeholders. This level of engagement promotes information sharing across the biometrics community to maximize utility of RDT&E efforts.$$, 1594000, NULL, NULL, NULL, NULL, 768000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607757D8Z_779$$, $$0607757D8Z$$, $$779$$, $$Radiological and Nuclear Defense$$, 2945000, $$This Program Element (PE) supports the Department's Defense Priorities to Rebuild our Military and Reestablish Deterrence. This PE supports the modernization of radiological and nuclear (R/N) defense capabilities that enable the Department to prevent R/N attacks on the homeland and Joint Force abroad through deterrence, as well as survive and operate in and through a R/N environment. This aligns with the Interim National Defense Strategy and addresses the challenges of keeping pace with our increasingly nuclear-capable adversaries by developing modern R/N detection and identification capabilities that are networked into secure and hardened communications, command, and control (C3) systems. This PE supports the Office of the Under Secretary of Defense for Acquisition and Sustainment (OUSD(A&S)) Radiological and Nuclear Defense Capability Development (RNDCD) Program. The RNDCD Program is addressing the strategic objective of ‘fielding modernized R/N detection capabilities to enable the Joint Force to operate more effectively in a R/N contaminated environment’ (Department of Defense (DoD) Strategic Management Plan for FY2022-2026). The RNDCD Program enhances DoD’s capabilities to campaign across the domains of threats and spectrums of conflict by improving the Department’s capability to campaign, fight, and win in a R/N environment. By building a R/N resilient Joint Force and National Guard Bureau, this program contributes to reestablishing deterrence by denying any strategic advantage our adversaries may perceive in using nuclear weapons on the homeland or Joint Force stationed abroad. This program is specifically geared to provide modern, networked R/N detection, indication, and identification capabilities to the warfighter and to upgrade obsolescing equipment, increasing capability to operate in a R/N environment (2023 CWMD Strategy). The RNDCD Program enables DoD to: prepare for and respond to any emergency involving nuclear and/or radiological events in the United States; provide a capability for the Joint Force to withstand, operate through, and recover from an R/N event; improve resilience; and promote integrated layered deterrence of WMD with state, local, and other federal agencies. This funding line is the only Budget Authority (BA)-7 funding in the Department dedicated to modernizing R/N capabilities for the warfighter. The Office of the Secretary of Defense uses the RNDCD Program to invest strategically in projects across the Military Services, Combatant Commands, and Defense Agencies. Funding is prioritized for projects that close Joint Force warfighter capability gaps. An annual investment strategy is used to meet emergent operational and capability needs which are validated by the Joint Force and the National Guard Bureau, yielding new fielded capabilities within one to three years.$$, 2945000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607865A_DJ6$$, $$0607865A$$, $$DJ6$$, $$Effector Product Improvement$$, 125541000, $$The Effector Product Improvement (DJ6) upgrades lower tier effectors (interceptors, fire control and M903 launching stations) to address operational lessons learned, enhancements to joint force interoperability and communications, and other system performance improvements to provide overmatch capability against the emerging threat. The FY 2026 request for Effector Product Improvement includes $125,541 thousand of discretionary and $15,000 thousand of mandatory (reconciliation) for a total of $140,541 thousand. The mandatory funds provide support for Aviation and Missile Command support for all-digital and Hardware in the Loop (HWIL), Modeling and Simulation (M&S) efforts: Millimeter-wave Simulation System - 1 (MSS-1), Millimeter-wave Simulation System - 2 (MSS-2), PATRIOT Simulation (PATSIM), threats and targets. Further information for this reconciliation request is provided in Section 20003 of the Reconciliation Exhibit. DJ6 PIP activities support enduring components of the system as legacy PATRIOT Ground Equipment is sunset with fielding of Integrated Battle Command System (IBCS). As components, software, and hardware improvements are developed, there is a continuing need for system level modeling, simulation, integration and testing. Modeling and Simulation (M&S) allow for performance assessment against specific threats in a manner that is not practical to demonstrate with live fire flight tests alone due to cost, target availability, and range constraints. Flight testing is periodically required for M&S validation as well as satisfying ATEC/DOTE requirements of segment improvements. In FY2026, DJ6 funding in the amount of $125.541 million will support test and development of improvements to currently fielded PATRIOT Family of Missiles (PFoM) and M903 launching stations to keep pace with current and emerging threats, support Guam Defense Systems specific efforts, and support Integrated Fires Control development and testing for the Army's Integrated Air and Missile Defense. -U.S. Government Program Management of DJ6 PIP efforts supporting system interceptors, launching stations, and associated materiel. -AMD Effectors Survivability efforts enhance electronic protection across lower tier effectors (MSE interceptors, fire control and M903 launching stations). -PAC-3 Software Development Against Threat supports improved missile capability to counter current and emerging electronic attack threats. -Integrated PAC-3 Fire Control Development provides funding to support PAC-3 Fire Control and Link on ELES (LoE) development for integration with IBCS to enable Army Integrated Air and Missile Defense Modernization. -DEVCOM and Other Agencies provides funding for government labor to support product development to keep pace with current threats.$$, 125541000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0607865A_DV8$$, $$0607865A$$, $$DV8$$, $$Patriot Product Improvement$$, 58222000, $$The PATRIOT system includes a family of hardware, software, interceptors (PAC-2, Guidance Enhanced Missiles, PAC-3 and PAC-3 Missile Segment Enhancement) and Ground Support Equipment. PATRIOT system components (interceptors, launcher, and radar) are integrated with current force PATRIOT and Army Integrated Air and Missile Defense (IAMD) components, including IBCS. As PATRIOT system components software and hardware improvements are developed, there is a continuing need for system level modeling, simulation, integration and testing. Modeling and Simulation (M&S) allow for performance assessment against specific threats in a manner that is not practical to demonstrate with live fire flight tests alone due to cost, target availability, and range constraints. Flight testing is periodically required for M&S validation as well as satisfying ATEC/DOTE requirements of segment improvements. The FY 2026 funding in the amount of $58.222 Million supports the following: -PATRIOT system components software and hardware improvements for threat evolution: Performs necessary analysis and development efforts to maintain PATRIOT system (interceptors, ground support equipment, and current radar) effectiveness against evolving threat technologies and capabilities, support convergence with the IBCS, and complete PATRIOT Component Software Builds (PCSB). This effort identifies evolving threats and threat characteristics that present a challenge to PATRIOT's current capabilities and develops initial concepts to maintain system effectiveness including detection, tracking, discrimination, and engagement relative to these threats. Additionally, evolving threat information is used to develop, integrate, and assess evolving lethality models in high-fidelity interceptor simulations supporting system level assessment of hit-to-kill and warhead interceptor performance. -Advanced Electronic Counter Measures (AECM): This task investigates the implications of advanced technology Digital Radio Frequency Memory available on airborne platforms that enables new ECM techniques which could adversely degrade Air and Missile Defense System effectiveness. AECM efforts support PATRIOT system interceptors, ground support equipment, and current radar. -Task 2: Implements improved ground system and interceptor capabilities (PATRIOT Advanced Capability-2/Guidance Enhanced Missiles, PATRIOT Advanced Capability-3, and Missile Segment Enhancement) to counter emerging Tactical Ballistic Missile threats. -Task 6: Software improvements enhance ground support equipment and current radar discrimination of higher altitude Tactical Ballistic Missile Re-entry Vehicles (RVs) from associated objects to support the full engagement capabilities of the interceptor. Longer-range detection, track, and improved high-altitude discrimination are required to achieve the required lethality performance against the RV and to mitigate and reduce missile wastage against separation debris. This task leverages the signal processing capabilities of the Radar Digital Processor, and supports the high altitude engagements required by the PATRIOT Advanced Capability-3 (PAC-3) and PAC-3 Missile Segment Enhancement (MSE) missiles. -Task 7: Performs analysis on existing and evolving Tactical Ballistic Missile (TBM) countermeasures to determine the effects on PATRIOT system effectiveness. Develops hardware and software concepts to address countermeasure effects to ensure the PATRIOT system maintains its effectiveness. Develops detailed system requirements to implement concepts; design/code/test software implementation leveraging Radar Digital Processor, Modernized Adjunct Processor, Enhanced Weapons Control Computer - Emulator and Flight Solution Computer-Redesign processing capabilities. Implements simulation-based concepts to define trade space and establish$$, 58222000, NULL, NULL, NULL, NULL, 170729000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0608041A_CD1$$, $$0608041A$$, $$CD1$$, $$Defensive Cyber - Software Prototype$$, 89238000, $$- Defensive Cyber Operations (DCO) programs are key elements of the DCO Maneuver Baseline infrastructure, platform, and tools. The employment of defensive capabilities achieves the following objectives: deter, destroy and defeat cyberspace threats; gain time; economy of force; control key terrain; protect tasked critical assets and infrastructure; and develop intelligence. DCO consists of platform and software programs which are key elements of the DCO Maneuver Baseline infrastructure, platform, and tools. DCO supports the Army Cyber Command (ARCYBER), Information Warfare Operations Center (IWOC), Army Forces Command (FORSCOM), five (5) Regional Cyber Centers (RCCs), Cyber Warfare Battalion (CWB), Multi-Domain Task Force (MDTF), Cyber Protection Brigade (CPB), and twenty-one (21) Cyber Protection Teams (CPTs) in COMPO 1/2/3. Fiscal Year (FY) 2026 funding in the amount of $88.393 million supports Cyber Analytics (CA), Tools Suite, User Activity Monitoring (UAM), Forensics and Malware Analysis (F&MA), DCO Development Environment (DCODE), Garrison DCO Platform (GDP), and Deployable DCO System (DDS) capabilities. Funding will be executed by Program Executive Office - Intelligence, Electronic Warfare and Sensors (PEO IEW&S). - Army Cyber Command (ARCYBER) Rapid Cyber Prototyping (RCP) provides software-based capabilities that can quickly respond to emerging cyber threats and keep up with threat technology, while supporting multi-Domain operations. ARCYBER identifies potential development and prototyping efforts via Cyber Needs Forms (CNFs) based on operational feedback, changes in the operational information environment and/or trends of adversarial activity, which drive concept of operation (CONOP) and Tactics Techniques and Procedures (TTPs) modifications. These are separate and distinct from DCO programmed efforts already funded or budgeted for by Project Manager (PM) DCO and are used to rapidly address a network threat/vulnerability. FY 2026 funding in the amount of $0.845 million will be executed by ARCYBER.$$, 89238000, NULL, NULL, NULL, NULL, 104048000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0608140D8Z_517$$, $$0608140D8Z$$, $$517$$, $$Data Reform Initiative (AWG)$$, 4500000, $$The Analysis Working Group (AWG) assists the Secretary and Deputy Secretary of Defense in guiding the analytic community to ensure analysis products are robust and of the highest quality. The end goal is an analytic enterprise that is agile, responsive, and provides sound decision support for the Secretary and Deputy Secretary. Funding for this project supports analytic research across the Department to guide reform of the Department’s analytic enterprise. Projects that support this effort help develop a high performing and innovative analytic enterprise with the right policies, structures, people, and tools to support timely strategic decisions that create an advantage for the U.S Military now and into the future.$$, 4500000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0608648D8Z_059$$, $$0608648D8Z$$, $$059$$, $$DAVE and Data Visibility$$, 17549000, $$Data Visibility delivers data standards via the Acquisition Visibility Data Framework (AVDF). Data Visibility supports the acquisition data strategy requirements of Section 836 of the NDAA for FY 2021 and data collection and sharing for additional Acquisition Pathways, Defense Business Systems, and Software Acquisition. AV enables the integration and interoperability of defense acquisition, building an enduring strategic mission advantage by aligning the Department's processes to design, develop, and deliver the acquisition data to enable the Office of the Under Secretary of Defense for Acquisition and Sustainment (OUSD(A&S)) to meet the Digital Acquisition & Sustainment and Transparency objectives of the Department and the requirements of Congress. Comprehensive digital acquisition, data science and analytics, and increased data transparency and access will improve acquisition decisions, enable sophisticated analysis, and inform innovative ways of doing business so that the OUSD(A&S), OSD staff, and the Services and Components can quickly inform policy and budget decisions with accurate, authoritative data.$$, 17549000, NULL, NULL, NULL, NULL, 48812000, 2026) ON CONFLICT DO NOTHING;
