INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0708012K_LSA$$, $$0708012K$$, $$LSA$$, $$Logistics Support Activities$$, 2876000, $$The Distributed Continuity Integrated Network – Top Secret Enterprise Services (DCIN-TS ES) (0708012K/0701113K) is a Department of Defense (DoD) continuity of operations and continuity of government decision-support collaboration environment that facilitates decision making among principals and staff. Available in Fixed, Transportable, and Mobile configurations; functions on air, ground, rail, and sea platforms.$$, 2876000, NULL, NULL, NULL, NULL, 7642000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0708012S_03$$, $$0708012S$$, $$03$$, $$Pacific Disaster Center$$, 2000000, $$The Pacific Disaster Center (PDC) is a public/private partnership managed by the University of Hawaii under a cooperative agreement with the Department of Defense. It is functionally within the organization of the Office of the Under Secretary of Defense (Policy) (OUSD(P)) as Principal Staff Assistant (PSA) and Defense Logistics Agency (DLA) for program management. The PDC is a world-recognized authority and leader in science and information technology applications relating to humanitarian assistance and disaster relief (HA/DR), including real-time assessments, predictive analysis, and disaster risk reduction. PDC develops new and innovative technologies and services, operating an (unclassified) integrated multi-hazard monitoring, early warning, and decision support system, called DoD RAPIDS, for the Department. PDC also provides advanced analytics leveraged by the Department for strategic planning, risk intelligence, impact modeling, strategic competition, and critical asset protection.$$, 2000000, 0, 0, 0, 0, 31503000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0708045A_E25$$, $$0708045A$$, $$E25$$, $$Mfg Science & Tech$$, 67002000, $$This Project develops and demonstrates manufacturing technologies and processes that enable improvements in producibility and affordability of emerging and enabling components and subsystems of Army ground and air platforms, Soldier systems, weapons systems, air and missile defense systems, and sensors and electronics. Work is performed to advance the state-of-the-art, leveraging automation in manufacturing processing and fabrication techniques for coatings, multifunctional materials, and structural elements for Army-specific applications.$$, 67002000, NULL, NULL, NULL, NULL, 72797000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0708045A_EA2$$, $$0708045A$$, $$EA2$$, $$MANTECH INITIATIVES (CA)$$, NULL, $$Congressional Interest Item funding provided for ManTech Initiatives. This effort will develop the ability to manufacture ballistic protective inserts to defeat armor-piercing rifle projectiles in shapes optimized for coverage of torso and extremities to include female geometry; enhance industrial preparedness to manufacture and process high-tenacity ballistic insert backers; identify various operations at Letterkenny Army Depot (LEAD) and technologies that may reduce acquisition and sustainability costs as well as repair-cycle times of defense weapons systems; project continues development of an advanced manufacturing cell for missile fins and components to improve performance, quality, and throughput; demonstrate production volume of a prototype manufacturing process the critical energetic ingredients in Picatinny Arsenal Explosive (PAX) 3; develop new refractory metal alloys that are highly resistant to heat and wear and tailored casting/molding processes that incorporate optimal mold material, alloying techniques, heat treatment, and machining; and develop and mature robotics and automation systems to increase productivity of parts and increase safety of forges.$$, NULL, NULL, NULL, NULL, NULL, 46000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0708051F_648051$$, $$0708051F$$, $$648051$$, $$Rapid Sustainment$$, 32666000, $$The Rapid Sustainment Modernization program provides funding to accelerate the delivery of critical technologies to improve readiness and reduce sustainment costs. The Rapid Sustainment Office (RSO) will develop, test, and deploy new technologies for implementation across the Department of the Department of the Air Force (DAF) enterprise. The RSO will achieve this by reaching across the enterprise to include the warfighter, depot maintenance, field maintenance, supply chain, and program offices to identify enterprise needs. The RSO will then identify, assess, develop, validate, and verify new technology projects that support these areas. The Technology Focus Areas are Advanced Manufacturing (Additive Manufacturing/Coldspray), Artificial Intelligence/ Machine Learning (AI/ML), to include but not limited to Condition Based Maintenance Plus (CBM+), RSM Technologies, to include Data and Digital Engineering, Automation/Robotics, Augmented and Virtual Reality, and Rapid and Austere Environments. New technologies in these areas are evaluated in support of the DAF enterprise. Funding in this PE will be used in agile processes to support development activities to rapidly respond to emergent requirements from the DAF enterprise in the year of execution to include but not limited to addressing Diminishing Manufacturing Sources and Material Shortages, reducing unscheduled weapons system maintenance, and enabling maintenance capabilities in austere environments. This PE may fund studies of new technologies to determine applicability to DAF requirements. This program element may include necessary civilian pay expenses and emergent or unanticipated civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2025 up to $5.086 million is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. This requirement supports performance of full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0708051F / Rapid Sustainment Modernization (RSM) Component Development & Prototypes (ACD&P)$$, 32666000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0708610F_675207$$, $$0708610F$$, $$675207$$, $$Logistics IT System$$, 18581000, $$The AF requires an integrated logistics capability that provides timely, accurate and reliable information to decision makers at all levels of command and across the full range of military operations. Log IT is a portfolio of programs that currently addresses Transformation, Remediation, and Modernization of Operational Systems. Transformation focuses on transforming the Logistics IT enterprise to a more efficient, cost-effective integrated IT infrastructure. Remediation entails modifying operational Logistics software systems to address congressionally-mandated Financial Improvement & Audit Readiness requirements and remediating critical IT risks. Modernization concentrates on software upgrades for operational systems to increase functional capabilities, reduce sustainment costs, meet statutory IT compliance requirements and improve user performance. Transformation: - The AF must transform its logistics business processes and transition away from using numerous custom stovepipe systems and processes that perform similar tasks. Eliminating process redundancies across the logistics enterprise will enable the AF to execute more secure, resilient, efficient, cost-effective and integrated logistics. The objective of transformation is to conduct Business Process Re-engineering (BPR) to identify and eliminate overlaps in business processes across core logistics systems and, where appropriate, implement new IT systems that employ best commercial practices and modern cloud-based architectures. - The AF will take full advantage of the flexibilities provided by DoDI 5000.75, Business Systems Requirements and Acquisition guidance, as well as Agile development methodologies to identify requirements across the spectrum of Doctrine, Organization, Training, Materiel, Leadership and Education, Personnel, Facilities and Policy (DOTMLPF-P); and to acquire and deploy approved material solutions in the most efficient and effective manner possible utilizing the 5-phased Business Capability Acquisition Cycle (BCAC). The BCAC phases are structured to optimize a joint responsibility of functional and acquisition activities, leading to the successful delivery of the business capability. There will be an emphasis placed on acquisition of business systems aligned to commercial best practices utilizing commercial off-the shelf (COTS), government off-the-shelf (GOTS) solutions, and modern platforms that support continuous integration and continuous deployment (CI/CD) following a development, security, and operations (DevSecOps) methodology. - The AF logistics enterprise is comprised of multiple overarching functional areas, to include base and depot-level maintenance, end-to-end supply chain management, and predictive analysis and forecasting. The AF will standardize its business processes within each major logistics functional area through Transformational Capability Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                             Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                   PE 0708610F / Logistics Information Technology (LOGIT) Operational Systems Development Initiatives (TCIs). These TCIs include, but are not limited to: Maintenance, Repair and Overhaul Initiative (MROi PE 0708055F), Foundational Logistics Information Technology Enterprise System (FLITES), Supply Capability Initiative, Air Force Product Lifecycle Management Capability Initiative (AF-PLM), and Field Maintenance Capability Initiative. There may be one or more specific initiatives aligned to each of the major CI areas referenced above. Transformation Capability Initiatives (TCI): - TCI Foundational Logistics Information Technology Enterprise System (FLITES) provides the capability to manage comprehensive, accurate, reliable item master data (e.g., accurate identification and authorization of owners and users of items). FLITES is a key component of the Air Force (AF) Logistics Capability Transformation Plan. It will provide Item standardization and configuration management from a single authoritative source, ensuring foundational logistics processes are executed in concert to support the A4 logistics baseline. It will enable key integration and transformation capabilities, including Item Unique Identification (IUID) association to business transactions; streamlined management of part item attributes across supply, finance, engineering, technology, transportation, maintenance, and vendor communities; and provide translation capabilities between functional and technical business communities and systems. - TCI Supply Capability Initiative is focused on enabling simplified, standardized processes to fundamentally enhance the business operations and provide total asset visibility across the supply chain. These improvements have been identified in the USAF Logistics Capabilities Transformation Plan. • Procurement: Encompasses all business functions necessary to obtain goods (both inventory and expense) and services, sourced internally and externally through strategic partnerships with Trading Partners. • Order Management: Encompasses all business functions necessary to accept and process customer orders (internal/external) for services and/or inventory held for sale or internal consumption. • Inventory Management: Encompasses all business functions necessary to establish and manage inventory for all types of items (repairable, consumable, expense items and other low cost items) including Air Force owned inventory and other items that are sent to the Air Force for repair (Foreign Military Sales and other Services). • Asset Management: Encompasses all business functions necessary to establish in-use accountability and life-cycle management of capital, centrally managed, and local purchased assets. • Financial Management: Encompasses all accounting functions necessary to record and produce auditable financial statements (for GF and WCF) - TCI Field Maintenance Logistics Capability Initiative (LCI) will improve the AF field maintenance capabilities across the Mission Generation Network (MGN) and Repair Network (RN) functionalities supports USAF Strategic Master Plan, Vector 1: Provide Effective 21st-Century Deterrence and Vector 3: Ensure a Full-Spectrum Capable, High-End Focused Force. It also directly supports the future vision of Air Force maintenance being divided between Mission Generation, which takes place on the flight line, and repair networks that provides support to Mission Generation as outlined in the 2015-2025 Enterprise Logistics Flight Plan (ELFP). MGN will address the cumulative effort required to launch, recover, configure, inspect and repair aircraft. It includes activities covering the planning, scheduling and execution of aircraft preparation and maintenance to support sortie production and is predominantly accomplished in an on-equipment environment. MGN and RN will standardize processes where appropriate, allowing for optimization of resources, enhanced visibility of assets, reduced rework, reduced variability, improved documentation and configuration management, all allowing for more rapid and informed decision-making at the base and enterprise level. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0708610F / Logistics Information Technology (LOGIT) Operational Systems Development - Funds will be used to perform studies, analysis, assessments, and innovative integration efforts for common technology capabilities such as cloud migration, technology develop… [truncated]$$, 18581000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0801380F_674567$$, $$0801380F$$, $$674567$$, $$Modeling and Simulation$$, 17711000, $$Project 674567, Modeling & Simulation Foundations, develops and supports a software tool named Air, Space and Cyberspace Collaborative Environment - Information Operations Suite (ACE-IOS). ACE-IOS is used during major theater exercises to provide realistic intelligence, surveillance, and reconnaissance (ISR), electronic warfare (EW), information operations (IO), and cyber effects simulation. ACE-IOS is part of the cyber live-virtual-constructive (LVC) environments for use during Joint training of offensive and defensive ISR/cyber capabilities for the USAF, DoD, select coalition, and national agencies. ACE-IOS is also used at Air Force and and Joint ISR operational training, conducted by the AF simulation centers worldwide. Warfighters train using ACE-IOS models and simulations with specific extensions in support of the USAF Cyber Simulation Center (CSC) and the USAF ISR schoolhouse. Robust ACE-IOS modernization is imperative to ensure that air, space, and cyberspace training and mission rehearsal activities can provide warfighters with realistic, interoperable, and readily available tools, data, and services. Planned ACE-IOS enhancements support of the users at mod-sim centers for multi domain capability and the USAFISR schoolhouse. Specific cyber effects software extensions are required for warfighter training and exercising of tactical cyber mission forces (CMF), cyber service providers (CSP), and operational-level command and control, intelligence, and cyber planners and operators supporting global operations.$$, 17711000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0801380F_675135$$, $$0801380F$$, $$675135$$, $$Warfighter Readiness$$, 16187000, $$Project 675135, Warfighter Readiness, develops and supports a software tool named Command & Control Simulation Environment for Training (C2SET). C2SET will be the authoritative representation of USAF and Joint theater-level air and space power training to Air and Space Operations Center (AOC) warfighters and Combatant Commanders' battle staffs. C2SET delivers realistic models and tools representing the tactical and operational capabilities the USAF brings to the joint fight. The goal is delivering a fully scalable and more scientific based modeling, simulation, and training stimulation to the users. C2SET will replace legacy model called Air Force Modeling & Simulation Training Toolkit (AFMSTT) with the proven Advanced Framework for Simulation, Integration, and Modeling (AFSIM) and/or similar models. AFMSTT entered sustainment in FY 2021 and continues to receive operational updates to maintain operational currency until fully replaced by C2SET and depreciated. C2SET includes several complimentary initiatives: Warfighter and Joint Training Integration supports the Chief of Staff of the Air Force (CSAF) directed Live, Virtual, and Constructive (LVC) integration efforts and is a critical piece to the USAF's implementation of the Strategic Plan for Transforming DoD Training. The goal of LVC training and mission rehearsal is to prepare our warfighters for the full range of military operations and maintain the combat readiness levels required by the Combatant Commands. This can only be accomplished by training and rehearsing in realistic operational environments. These environments include live training ranges and virtual simulators enhanced with constructive entities. Specific training and mission rehearsal events can include some or all of these simultaneously; making the ability to integrate LVC capabilities a necessity. The Air, Space, and Cyberspace Constructive Environment (ASCCE) is the USAF's authoritative federation of constructive to the Combined Forces Air Component Commander (CFACC).$$, 16187000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0804743F_675304$$, $$0804743F$$, $$675304$$, $$Aviation Resource Management$$, 0, $$The Aviation Resource Management System (ARMS) program will sunset in FY 2025. ARMS will be replaced by the new, cloud-based solution, Aviation Resource Tool Enterprise Mission Information System (ARTEMIS) and will ensure indefinite, secure integration with existing operations systems. ARMS is a web-based on-line management information system designed to support the base level Director of Operations (DO), aircrew supervisors, and managers. ARMS provides management policies and ensures the status of the Air Force flying programs are available to flying/jump supervisors to make resource allocation decisions. ARMS ensures accurate tracking of flying and ground training programs for each weapon system at each base and provides accurate and timely aircrew/ parachutist information which assists in monitoring, tracking, and scheduling military training required to meet Air Force mission requirements. Additionally, the ARMS manages flying hours for aircrew parachutists world-wide to include USAF, Air Force Reserve Command (AFRC) and the Air National Guard (ANG).The current ARMS functionality resides at a Defense Information System Agency (DISA) DECC and consists of "5” logical modules to include: Flight, Individual Training, Jumper Aircrew, Resource Tracking, Reports, and System. The sustainment of these capabilities and the introduction of new capabilities follows an agile development process, but the effectiveness of that process is severely limited by the existing production environment. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024 $0.000 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.000 million is forecast for civilian pay expenses in this program element.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1105219BB_S851$$, $$1105219BB$$, $$S851$$, $$MQ-9 Unmanned Aerial Vehicle$$, NULL, $$As the supported Combatant Command in global operations, the United States Special Operations Command (USSOCOM) requires the capability to find, fix, finish, exploit, and analyze time-sensitive high-value targets. These targets can often only be identified with patient collection of information and require rapid, decisive action during the short periods in which they present themselves. This project addresses the primary areas of Intelligence, Surveillance, Reconnaissance, and Target Acquisition and Strike. The majority of the developmental funds provides for the Operational Flight Program (OFP) Software for the aircraft, Ground Control Station (GCS), and turret. Special Operations-peculiar (SO-p) modifications to the OFP allow for a rapid integration of emerging capabilities in order to maintain relevance and dominance of the MQ-9.$$, NULL, NULL, NULL, NULL, NULL, 275563000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0804772F_652400$$, $$0804772F$$, $$652400$$, $$Training Developments$$, 5067000, $$Training Developments provide a more cost effective and timely approach to pilot training with technological and instructional innovations designed to improve upon Specialized Undergraduate Pilot Training (SUPT). New innovative training technologies are studied and validated for implementation by the Air Education and Training Command (AETC) pilot training program to ensure delivery of rapidly developed prototypes and operationally tested learning methods and technology to realize flying training efficiencies. Training Developments' focus is the SUPT program which includes but not limited to T-6, T-1, and T-38. Funding for Training Developments has resulted in The Air Mobility Fundamentals - Simulator Only program which reduces the pilot training timeline from 7 months to 3 months and directly aids AETC's flying training enterprise and USAF pilot shortage. Training Developments will continue to conduct future flying training innovation and field testing as AETC looks to transition to the Airmen Development Command. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.000 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.000 million is forecast for civilian pay expenses in this program element.$$, 5067000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0804776F_665297$$, $$0804776F$$, $$665297$$, $$Technical Training$$, 1698000, $$TECHNICAL TRAINING MANAGEMENT SYSTEM [TTMS]: TTMS provides AETC organizations with a world class commercial-off-the-shelf [COTS] / government- off-the-shelf [GOTS] learning management system which supports six functions: course design and development; student evaluation; instructor management; student management; data analysis; and resource administration. TTMS is a centralized web-based system which provides productivity enhancements and higher degree of efficiency to AETC. The primary requirement objectives currently under development are: 1] Integration of Basic Training Management System [BTMS] capabilities and student records into the TTMS. Prior to FY25 these efforts were funded by to PE 0804731F, General Skill Training This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, 1698000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0808736F_648737$$, $$0808736F$$, $$648737$$, $$Studies in Sexual$$, 1997000, $$This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 0 was expended for civilian pay expenses in this program element, and in FY2025 0 is forecasted for civilian pay expenses in this program element. Funds moved from PE 808737F to this PE (808736F) beginning in FY25. This is not a new start. Following completion of a Presidentially-directed Independent Review Committee (IRC) on Sexual Assaults for the Department of Defense, the Secretary of Defense (SECDEF) directed the implementation of multiple IRC recommendations. The Integrated Prevention PE contains two programs in support of those recommendations: The Air Force Office of Special Investigations (OSI), Records, Investigations and Operations Network (ORION) program and the Interpersonal Self-Directed Violence (ISDV) Prevention program. Air Force Office of Special Investigations (OSI), Records, Investigations and Operations Network (ORION): The Department of the Air Force (DAF) Office of Special Investigations (OSI) is DAF's sole felony-level criminal investigative agency mandated to investigate criminal offenses, to include sexual offenses and interpersonal violence. IRC recommendations C2, C3, C4, 1.8, 2.6a, 3.1, and 3.3a, directed the DAF to increase its ability to collect, analyze, and integrate data related to sexual offenses and interpersonal violence to inform and guide prevention and response. The DAF will develop and deploy the OSI Investigations, Operations, and Records Network (ORION) information system as to satisfy SECDEF requirements. In tandem with the context above, another key driver for development of ORION is the DAF's requirement to identify a central case management system solution to allow for more effective oversight of and more efficient execution of the DAF's criminal indexing process. ORION will be a cloud-based, next-generation case management system used to document, manage, store, and report criminal investigative and counterintelligence information involving violations of the Uniform Code of Military Justice and the United States Code. ORION will serve as OSI's central mission application capable of Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0808736F / Special Victim Accountability and Investigation Component Development & Prototypes (ACD&P) ensuring sexual assaults, intimate partner violence, violent extremism, service-member deaths, and dozens of other crimes are properly investigated and recorded. ORION will be used by over 3,000 OSI personnel including nearly 2,000 federally-credentialed Special Agents at OSI's 300+ global operating locations. ORION will enable the DAF to modernize criminal indexing processes both operationally and technologically. Operationally, ORION will reduce redundancy, streamline processes, encourage standardization, and decrease administrative burden. The DAF is exploring options to use ORION to replace other systems and enable data transfer to other stakeholders with the goal to increase integration and productivity and avoid duplicative data entry. ORION could also be leveraged to be placed on one or more Special Access Programs (SAP) networks to become a system of record for OSI investigative and security support to DAF SAP programs. Technologically, ORION leverages the affordability, scalability, security, and services provided by cloud computing. Additionally, ORION will be mobile-ready, enabling agents to securely access and document investigative data from mobile devices whenever and wherever needed, thereby increasing efficiency and reducing delays. Lastly, ORION will be built on a low-code/no-code enterprise platform which enables the rapid development, deployment, and sustainment of capability. The DAF is considering options to leverage ORION and its enterprise low-code/no-code platform for other DAF case management and/or business process management requirements. Such a platform, operated and sustained at the enterprise level, has potential to yield cost savings, operational enhancements, and technical efficiencies as well as reduce DAF overheard. With ORION serving as the initial application, the case management platform could promote the expedited development, deployment, and sustainment of future case management systems at economies of scale. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 1997000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0808737F_648737$$, $$0808737F$$, $$648737$$, $$Sexual Assault Prvntion$$, 5167000, $$This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 $0 was expended for civilian pay expenses in this program element, and in FY2025 $0 is forecasted for civilian pay expenses in this program element. ORION funds moved from this PE (808737F) to PE 808736F beginning in FY25. Following completion of a Presidentially-directed Independent Review Committee (IRC) on Sexual Assaults for the Department of Defense, the Secretary of Defense (SECDEF) directed the implementation of multiple IRC recommendations. The Integrated Prevention PE contains two programs in support of those recommendations: The Air Force Office of Special Investigations (OSI), Records, Investigations and Operations Network (ORION) program and the Interpersonal Self-Directed Violence (ISDV) Prevention program. Air Force Office of Special Investigations (OSI), Records, Investigations and Operations Network (ORION): The Department of the Air Force (DAF) Office of Special Investigations (OSI) is DAF's sole felony-level criminal investigative agency mandated to investigate criminal offenses, to include sexual offenses and interpersonal violence. IRC recommendations C2, C3, C4, 1.8, 2.6a, 3.1, and 3.3a, directed the DAF to increase its ability to collect, analyze, and integrate data related to sexual offenses and interpersonal violence to inform and guide prevention and response. The DAF will develop and deploy the OSI Investigations, Operations, and Records Network (ORION) information system as to satisfy SECDEF requirements. In tandem with the context above, another key driver for development of ORION is the DAF's requirement to identify a central case management system solution to allow for more effective oversight of and more efficient execution of the DAF's criminal indexing process. ORION will be a cloud-based, next-generation case management system used to document, manage, store, and report criminal investigative and counterintelligence information involving violations of the Uniform Code of Military Justice and the United States Code. ORION will serve as OSI's central mission application capable of Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0808737F / Integrated Primary Prevention Component Development & Prototypes (ACD&P) ensuring sexual assaults, intimate partner violence, violent extremism, service-member deaths, and dozens of other crimes are properly investigated and recorded. ORION will be used by over 3,000 OSI personnel including nearly 2,000 federally-credentialed Special Agents at OSI's 300+ global operating locations. ORION will enable the DAF to modernize criminal indexing processes both operationally and technologically. Operationally, ORION will reduce redundancy, streamline processes, encourage standardization, and decrease administrative burden. The DAF is exploring options to use ORION to replace other systems and enable data transfer to other stakeholders with the goal to increase integration and productivity and avoid duplicative data entry. ORION could also be leveraged to be placed on one or more Special Access Programs (SAP) networks to become a system of record for OSI investigative and security support to DAF SAP programs. Technologically, ORION leverages the affordability, scalability, security, and services provided by cloud computing. Additionally, ORION will be mobile-ready, enabling agents to securely access and document investigative data from mobile devices whenever and wherever needed, thereby increasing efficiency and reducing delays. Lastly, ORION will be built on a low-code/no-code enterprise platform which enables the rapid development, deployment, and sustainment of capability. The DAF is considering options to leverage ORION and its enterprise low-code/no-code platform for other DAF case management and/or business process management requirements. Such a platform, operated and sustained at the enterprise level, has potential to yield cost savings, operational enhancements, and technical efficiencies as well as reduce DAF overheard. With ORION serving as the initial application, the case management platform could promote the expedited development, deployment, and sustainment of future case management systems at economies of scale. Air Force Integrated Resilience Office (A1Z), Interpersonal Self-Directed Violence Prevention: The Department of the Air Force (DAF) Integrated Resilience Directorate (A1Z) is the Air Force's lead agency for the research, development, and analysis of ISDV prevention and resilience programming across The Force. The IRC recommended multiple initiatives to help the Services research, develop, and assess interpersonal and self-directed violence (ISDV) prevention strategies. ISDV encompasses sexual assault, domestic violence, suicide, and resilience. IRC recommendations 2.3, 2.4, 2.6, and 3.5 directed the DAF to implement prevention strategies at organizational and community levels through the modernization of prevention education, training, program evaluation, and improved processes for data collection and analysis. The DAF will execute the IRC's recommendations in support of initiatives to include, but not limited to: - The Tech-based Machine Learning Initiative - A state-of-the-art DoD prevention research capability that utilizes machine learning algorithms to analyze qualitative data to identify trends that lead to ISDV. - The Community Prevention Platform [CPP] - A web-based software system that will maintain Installation and Major Command community action plans and facilitate DAF Headquarters ability to track and assess plans. - The Peer-Network Resilience Training Program (PRTP) - An initiative to analyze and modernize current resilience training processes to more effectively reflect today's generation of Service members. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                             Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0808737F / Integrated Primary Prevention Component Development & Prototypes (ACD&P) - The Project Proficiency-based Sexual Assault Training (PSAT) - This initiative will similarly update and expand the current Air Force sexual assault training by implementing tailored-training based on subject knowledge as well as long-term training-competency tracking for Airmen/Guardians over their career cycle. - The Sexual Assault Prevention Response Virtual Reality (SAPR V) - This initiative will further enhance training initiatives by implementing cutting-edge Virtual Reality capability to more effectively enable Airmen and Guardians to recognize and prevent sexual assault. The DAF is committed to implementing the Commission's recommendations to more effectively identify behavioral and cultural contributors to ISDV, educate/train Airmen and Guardians to facilitate ISDV prevention, and transparently document and track Installation-level strategies to facilitate evaluation. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 5167000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0901202F_675196$$, $$0901202F$$, $$675196$$, $$Joint Technology$$, 2080000, $$Funding supports development of innovative capabilities to address Personnel Recovery in Large Scale Combat Operations, Multi-Domain Operations and anti-access/ area denial environments for Combatant Commanders and the Services. Joint personnel Recovery Agency [JPRA] developmental efforts address Personnel Recovery capability gaps and shortfalls identified in the Personnel Recovery Initial Capabilities Document approved by the Joint Requirements Oversight Council memorandum 120-12 on 8 Aug 2012, and subsequent supporting documents approved in the Joint Capabilities Integration Development System. Activities include funding for research and development, support equipment, contract services and all associated costs specifically identified to support the JPRA headquarters Ft. Belvoir, VA and other agency operating locations. Development and transition to sustainment of an enterprise level information data system [Personnel Recovery Information Data System [PRIDS] to enable DoD data management, analysis and collaboration. Funds also provide USAF Platform One/Cloud One housing for PRIDS. DODI 3002.1 directed JPRA capability. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 $0.0M was expended for civilian pay expenses in this program element and in FY25 $0.0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0901202F / Joint Personnel Recovery Agency Operational Systems Development$$, 2080000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0901218F_674139$$, $$0901218F$$, $$674139$$, $$Civilian Compensation$$, 4355000, $$This program element provides for payment of civilian compensation benefits for disability due to personal injury sustained while in the performance of duty or due to employment-related disease according to the Federal Employees Compensation Act [FECA] under Title 5 U.S.C., Chapter 81. The Department of Labor [DOL] administers this program and charges the Department of the Air Force for its employee costs; therefore, this is a MUST PAY bill for Air Force. The Program Element[PE] excludes manpower authorizations and costs. This PE is in Budget Activity 7 in support of payment of civilian compensation benefits for disability due to personal injury sustained while in the performance of duty or due to employment-related disease according to FECA under Title 5 U.S.C., Chapter 81. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2023 $0 was expended for civilian pay expenses in this program element, and in FY2024 $0 is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 4355000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0901220F_675194$$, $$0901220F$$, $$675194$$, $$Force Development$$, 2766000, $$The Force Development Transformation program contains two independent DAF initiatives addressing vital personnel issues: Personnel Services Delivery and the Total Integration Mobilization Execution System. Personnel Services Delivery: Personnel Services Delivery (PSD), under the Personnel Administration program, funds operational developments necessary to acquire, field, and modify business processes to transform the delivery of Human Resources (HR) capabilities through the structured redesign of the Total Force Personnel Community's people (Active Duty, Reserve, Guard, and Civilians), processes, and technologies. PSD Transformation fundamentally shifts the way personnel services are provided, transitioning from primarily face-to-face interactions with a personalist to a tiered model with services delivered through online self-service, contact centers, and reduced in-person interactions. PSD supports the migration of legacy applications and other information technologies from on premises data centers to a more sustainable cloud-based hosting solution and flexible services-based architecture as defined by the Defense Enterprise Service Management Framework (DESMF). In addition, funds will be used to perform studies and innovative integration efforts for common technology capabilities such as cloud migration, technology development, and mobile application. The FY 2026 request for PSD includes 1,735 thousand of discretionary and 0 thousand of mandatory (reconciliation) for a total of 1,735 thousand. The mandatory funds procure an additional 0 PSD systems in FY 2026. Further information for this reconciliation request is provided in Chapter 5 of the Reconciliation Exhibit. Total Integration Mobilization Execution System: The Total Integrated Mobilization Execution System is the Department of the Air Force's cloud-based system of record to mobilize Air Reserve Component (ARC) forces to perform operational and institutional missions in support of the active component. TIMES collects and prioritizes global ARC utilization requirements, generates mobilization authorizations, and automates and synchronizes the ARC utilization process to rapidly generate capability, increase lethality, and enable predictive analytics and data-driven decision making. The Air Force cannot execute the Secretary of Defense's national security priorities without mobilizing the forces and capabilities in the ARC. Approximately 35-40% of the Combatant Command requirements that are tasked to the Air Force are filled by ARC forces. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability; The use of such programs funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, 0605898F. In FY 2024 and FY 2025, 0.000M Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0901220F / Personnel Administration Operational Systems Development was expended for civilian pay expenses in this program element, and in FY 2026 0.000M is forecasted for civilian pay expenses in this program element. AF/A3OD did POM for two GS-14 positions in recent data calls. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 2766000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0901226F_3600$$, $$0901226F$$, $$3600$$, $$Research, Development, Test & Evaluation, Air Force / BA 7:$$, NULL, $$The Office of Studies and Analysis (SAF/SA) leads strategic assessments of USAF and USSF contributions to Joint-all domain warfighting capabilities regarding current/ future force structure, operational lethality, risk/issues and combat agility in military scenarios. The Secretary of the Air Force, Chief of Staff of the Air Force and Chief of Space Operations utilize these analytical assessments to inform Strategy, Planning, Programming, Budgeting, and Execution decisions regarding modernization, development, and procurement quantities of DAF weapon platforms to ultimately provide effective and affordable warfighting capabilities aligned with the National Defense Strategy. From nuclear modernization, autonomous collaborative combat aircraft, integrated missile/homeland/base defense, long range Joint kill-chains, SAF/ SA provides a wide breadth of analytical insights enabling US decision overmatch through effective and affordable enterprise modeling, simulation and analysis (MS&A) capabilities. SAF/SA utilizes RDT&E funding to modernize and develop MS&A capabilities not just for SAF/SA use, but also as enterprise products used by the DoD, Joint Force, Intelligence Community, industry, academia, and Coalition Partners. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0901226F_676009$$, $$0901226F$$, $$676009$$, $$M & S DEVELOPMENT$$, 14761000, $$The Office of Studies and Analysis (SAF/SA) leads strategic assessments of USAF and USSF contributions to Joint-all domain warfighting capabilities regarding current/ future force structure, operational lethality, risk/issues and combat agility in military scenarios. The Secretary of the Air Force, Chief of Staff of the Air Force and Chief of Space Operations utilize these analytical assessments to inform Strategy, Planning, Programming, Budgeting, and Execution decisions regarding modernization, development, and procurement quantities of DAF weapon platforms to ultimately provide effective and affordable warfighting capabilities aligned with the National Defense Strategy. From nuclear modernization, autonomous collaborative combat aircraft, integrated missile/homeland/base defense, long range Joint kill-chains, SAF/ SA provides a wide breadth of analytical insights enabling US decision overmatch through effective and affordable enterprise modeling, simulation and analysis (MS&A) capabilities. SAF/SA utilizes RDT&E funding to modernize and develop MS&A capabilities not just for SAF/SA use, but also as enterprise products used by the DoD, Joint Force, Intelligence Community, industry, academia, and Coalition Partners. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 14761000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0901410F_643483$$, $$0901410F$$, $$643483$$, $$CON-IT$$, 29277000, $$The Contracting Information Technology (CON-IT) system enables the Department of the Air Force (DAF) to accomplish its mission effectively and securely in today's rapidly changing and increasingly contested cyber domain. The Air and Space Forces require a single, 21st century contract management solution to enable DAF mission execution, from acquiring and sustaining weapon system platforms, to supporting contingency operations overseas. CON-IT supplies this single solution by consolidating and replacing numerous aging and increasingly unsupportable, legacy contract writing and management systems, while enabling the Air and Space Forces to procure vital capability faster and with increased data accuracy through built-in automation. Specifically, CON-IT's functionality provides contract data sharing interoperability across all DAF contracting communities and external business partners such as Defense Contract Management Agency, Defense Finance and Accounting Service, and industry partners. In addition, CON-IT facilitates the execution of the DAF's 200+ billion annual budget, ensuring global procurement operations are timely, auditable, and secure. CON-IT enables the DAF to anticipate and respond to the changing pace and dynamic nature of processes, regulations, compliance and technologies across the contracting domain. It empowers the contracting community to comply with Financial Improvement Audit Readiness (FIAR). CON-IT supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. CON-IT was the Department of Defense's (DoD) first contract writing system meeting Section 862 of FY13 NDAA requirements implementing DoD Procurement Data Standards (PDS). In addition, CON-IT implements Section 508 of the Rehabilitation Act of 1973 (as amended) to make Electronic and Information Technology (EIT) accessible to people with disabilities. To modernize the DAF contracting infrastructure, requirements are divided into 2 objectives. Objective 1: Develop the following 8 capabilities: • Capability 1: Modernize contract writing for 3,800 operational/installation contracting users, sunsetting the Standard Procurement System (SPS) system. (Completed in FY19; first and only service to comply with the original Office of the Secretary of Defense (OSD) SPS sunset mandate) • Capability 2: Modernize contract writing capability for the contingency contracting community, sunsetting O'Contrax system. (Completed in FY20) • Capability 3: Modernize contract writing capability for 2,500 Weapon Systems contracting users, sunsetting ConWrite, a 20+ year-old system containing contracts worth more than 2 trillion for major weapon system programs such as B-21, KC-46, and more. (Fielded in FY24) • Capability 4: Deliver Business Intelligence (BI) capability to provide timely and reliable data for decision makers across the entire DAF. (Completed in FY23) • Capability 5: Modernize capability to meet the unique classified needs within all contracting communities. This capability is on the critical path to sunset ConWrite and is planned to be completed FY25. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0901410F / Contracting Information Technology System Component Development & Prototypes (ACD&P) • Capability 6: Modernize capability to meet the unique needs of the R&D contracting community to execute grants and cooperative agreements. This capability is on the critical path to sunset ConWrite and is planned to be completed FY26. • Capability 7: Add E-Filing capability to provide a single, authoritative source for electronic contract file storage with capability to search and review individual documents. This capability is planned to be complete in FY26. • Capability 8: Modernize contract writing capability for 1,500 Logistics contracting community users to award weapon system sustainment product support/logistics requirements. Enables the DAF to sunset the Automated Contract Preparation System (ACPS), a 30+ years old legacy system. This capability is on the critical path to sunset ACPS and is planned to be completed in FY28. Thus far, CON-IT has successfully fielded four (Capabilities 1-4), Minimum Viable Products (MVP) of the eight established capabilities modernizing contract writing and management for both the operational and contingency contracting communities as well as improving Business Intelligence. Fielding these capabilities resulted in the replacement of two of four contract writing systems. Objective 2: Maintain Compliance. CON-IT has deployed to 6,672 active users across 329 procurement organizations worldwide as of 4QFY24. In FY24, CON-IT awarded 75,181 contract actions totaling 42.5B, compared to 73,334 contract actions totaling 28.4B in FY23. The DAF continuously addresses numerous technical debt backlog requirements to maintain system functionality and meet modern data standards. These initiatives also develop capability to maintain compliance with Federal and OSD mandates, coordinate DevSecOps, and improve infrastructure and system performance. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 0.000M was expended for civilian pay expenses in this program element, and in FY25 0.000M is forecasted for civilian pay expenses in this program element. The FY 2026 request for CON-IT includes 29,277 thousand of discretionary and 0 thousand of mandatory (reconciliation) for a total of 29,277 thousands. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0901410F / Contracting Information Technology System Component Development & Prototypes (ACD&P)$$, 29277000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0901538F_675177$$, $$0901538F$$, $$675177$$, $$Cost Estimating Modeling (CEM)$$, 3982000, $$Cost Estimating Modeling (CEM) enhances Air Force and Space Force-wide cost estimating capabilities by developing current cost estimating datasets and methods and tools, data architectures/structures, and other cost estimating method/tool gap-filling initiatives. In collaboration with the OSD Cost Assessment and Program Evaluation (CAPE) Cost Assessment Data Enterprise (CADE) project, the Department of Defense's (DoD) unified information system and initiative to collect, organize, store, and use contractor and acquisition data more efficiently, CEM products improve the quality, timeliness, and effectiveness of acquisition program cost estimates in support of Department of Air Force (DAF) and DoD acquisition decisions, programming and execution decisions, and Congressional mandates. The partnership between CEM and CADE is a leading example of a data initiative designed as a response to a Congressionally expressed desire for better outcomes in acquisition. CEM research places DAF datasets, analysis, estimating tools, and institutional knowledge availability at analyst's fingertips rather than relying on an inefficient, ad hoc, and decentralized approach. CEM ensures the DAF continuously improves cost estimating capabilities for broad cross-cutting areas, as well as specific weapon system types like aircraft, space and launch systems, missiles, and others. This project performs knowledge-based studies to include organizing complete datasets, analyzing historical data, and studying changing technologies/programmatic information to develop new estimating methods (e.g., statistical tools, cost estimating relationships) across hundreds of product work breakdown structure elements and functional cost elements. CEM delivers valuable datasets, methods, and analytical tools in support of higher quality/credible estimates required by statute and regulation allowing for more realistic cost-conscious decisions on over $200 billion of critical war-fighter capability. Changing technologies, acquisition laws, policy directives, and initiatives drive the continuous requirement for revised cost estimating processes, methods, and tools. Critical policy requirements for which CEM research facilitates implementation and compliance are: - Statute (e.g., Title 10, section 167; USC 3221, 3227, 4251, 4252, 4253, and 4328) - Policy directives (DoDI 5000.73, DoDI 5000.74, DoDI 5000.75, DoDI 5000.80, DoDI 5000.85, DoDI 5000.87) - FY 2016/17/18/21 NDAA reports (PL 114-92/114-328/115-91/116-283) including provisions relating to Major Defense Acquisition Programs (Section 804 of the FY16 NDAA authorized rapid prototyping and rapid fielding of defense systems) - Annual life-cycle cost estimation requirements - Weapon System Acquisition Reform Act (WSARA) (provisions related to improving cost estimating quality and affordability analysis) - Secretary of the Air Force acquisition excellence plans (priorities to improve cost estimating capability and affordability analysis) - Office of the Secretary of Defense policy (initiatives on enhanced trade-off analysis, affordability analysis, and cost reduction initiatives) This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and$$, 3982000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0901554F_675178$$, $$0901554F$$, $$675178$$, $$Def Enter Acct Mgt Sys (Deams)$$, 38942000, $$DEAMS, an Enterprise Resource Planning (ERP) program built upon the commercial-off-the-shelf (COTS) solution Oracle e-Business Suite (EBS), provides a modern accounting and finance management capability with robust auditability at its core. As the Department of the Air Force's (DAF) existing core accounting and financial management solution, DEAMS represents a key component of the DAF's long-term business process improvements, addressing the Secretary of Defense's (SECDEF) priority for auditability and is the essential tool for ensuring the DAF's alignment with the SECDEF's vision for a more efficient and effective military. By providing accurate financial data, strengthening internal controls, and facilitating auditability, DEAMS empowers the DAF to meet its financial reporting obligations, maintain public trust, and ultimately contribute to a stronger national defense. Additionally, this program element uses critical financial data to enhance future program planning and execution and will provide greater transparency to defense spending, making it easier to track how funds are being used and identify potential areas for savings. This increased accountability aligns with the SECDEF's call for a clean Pentagon audit and ensures the responsible use of taxpayer dollars. FY2026 funding will support continued capability development and functionalities within the system. This includes ongoing efforts to achieve an unqualified System and Organization Controls (SOC) audit opinion, ensuring compliance with audit and transparency requirements. Funding will also enhance data integrity and automation by evolving the Treasury Direct Disburse (TDD) capability to streamline interfund transactions. System integration and interoperability will be improved by integrating Acquisition Management System (AMS) and Foreign Military Sales (FMS) accounting systems with DEAMS for improved financial visibility and reconciliation. Funding will also be used to modernize technology by upgrading the Oracle e-Business Suite (EBS) and the Oracle Analytic Server (OAS). These upgrades will enhance system performance, security, and scalability, enabling DEAMS to remain a relevant and auditable accounting system. The FY2026 funding also supports the development of the system by continuing to enhance the functionality of the logistics, payroll, asset accounting, budget distribution and personnel travel management systems creating an enterprise-wide system for seamless data flow and better tracking of resources and more accurate financial reporting. This program element replaces numerous inefficient and/or obsolete legacy systems with a single, integrated platform that standardizes financial data across the DAF. The streamlined approach ensures data consistency and accuracy, critical for reliable financial reporting and informed decision-making. This program element supports the current 17,000 users across all United States Air Force (USAF) and United States Space Force (USSF) bases worldwide, serving all Air Force and Space Force Major Commands, and Unified Commands where the DAF acts as the executive agent. The DAF will deploy DEAMS to the acquisition$$, 38942000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0901579D8Z_732$$, $$0901579D8Z$$, $$732$$, $$Office of Strategic Capital$$, 0, $$In support of the Department of Defense, Office of Strategic Capital’s (OSC) mission is to attract and scale private capital to technologies critical to the national and economic security of the United States. The National Defense Authorization Act for Fiscal Year 2024 (FY2024 NDAA) states OSC shall: • Develop, integrate, and implement capital investment strategies proven in the commercial sector to shape and scale investment in critical technologies and assets; • Identify and prioritize promising critical technologies and assets that require funding and have the potential to benefit DoD; and • Make eligible investments in such technologies and assets, such as supply chain technologies, not always supported through direct investment. To accomplish its mission, OSC uses loans, loan guarantees, and technical assistance – an efficient use of taxpayer dollars – to crowd in investment by aligning government and private sector incentives. The office’s tools take advantage of the power of markets and competition to support DoD needs. OSC’s investments are guided by its FY2025 Investment Strategy, which describes that competition between the United States and its adversaries occurs over the: (i) control of economic chokepoints; (ii) scaling of key industries, and (iii) commercialization of critical technologies. OSC investments will provide the Department of Defense advantages in all these competitive arenas, especially by securing critical supply chains and rebuilding the industrial base. These activities directly align with the administration’s priorities communicated through the Interim National Defense Strategic Guidance (INDSG), and other forthcoming authoritative documents such as the National Security Strategy of the United States (NSS), interim National Defense Strategy (NDS) and Defense Planning Guidance (DPG). Specifically, the program will: • Develop new financial products, such as direct equipment finance loans for manufacturers, project finance loans to support capital intensive projects, working capital loans for businesses in need of short-term financing, and loan guarantees through private banks. • Provide loans, loan guarantees and technical assistance to businesses, funds, and other entities within the 33 Covered Technology Categories prescribed by Congress in line with the objectives described by the FY25 Investment Strategy, INDSG, NSS, NDS, and DPG. • Identify and prioritize areas for investment through engagements with the Services, Combatant Commands, National Security Council, and other interagency partners. • Create new data tools to map economic networks to determine chokepoints that impact U.S. national and economic security. • Increase private capital investment to enhance the commercialization of DoD and United States Government (USG) science & technology investments.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0901598C_MD38$$, $$0901598C$$, $$MD38$$, $$Management Headquarters$$, 28719000, $$The Missile Defense Agency (MDA) Headquarters provides oversight, direction and control over MDA's acquisition programs and fielded systems. The MDA Headquarters staff functions (government salaries, government travel, and contract support services) support the mission and operations of the world-wide MDA mission.$$, 28719000, NULL, NULL, NULL, NULL, 360366000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0902498N_0831$$, $$0902498N$$, $$0831$$, $$OPTEVFOR Support$$, 2041000, $$This program element (PE) provides Operational Test and Evaluation Force (OPTEVFOR) general support funding and operating costs for Management Headquarter Activity (MHA) functions that support OPTEVFOR compliance with Secretary of Defense (SECDEF) and Secretary of the Navy (SECNAV) directives during the conduct of independent operational testing and evaluation as described in PE 0605865N Operational Test & Evaluation Capability.$$, 2041000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0903235K_JSP$$, $$0903235K$$, $$JSP$$, $$Joint Service Provider$$, 1283000, $$Joint Service Provider (JSP) provides mobile classified computing and communications platforms technology test and development for the immediate Office of the Secretary of Defense, enabling secured computing at residence, temporary and mobile locations around the world. JSP also encompasses the Secretary of Defense Communications Office (SECDEFCOMS). SECFEFCOMS provides the Secretary of Defense resilient communication and situational awareness capabilities, which enable the Secretary of Defense and Immediate Office to coordinate national defense, in every circumstance.$$, 1283000, NULL, NULL, NULL, NULL, 18562000, 2026) ON CONFLICT DO NOTHING;
