INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1001004F_664645$$, $$1001004F$$, $$664645$$, $$International$$, 4430000, $$The mission of this program is to establish, sustain, expand, and enhance mutually beneficial international partnerships through the implementation of air, space, and cyber international armament cooperation (IAC) agreements thereby supporting Department of the Air Force (DAF) and Department of Defense (DoD) goals and objectives. These International Agreements (IAs) will: significantly improve U.S. and allied conventional defense capabilities and capacity; accelerate the availability of defense systems; solve capability gaps; develop, acquire, upgrade, sustain, and/or support interoperable equipment with our allies; create cooperative acquisition, production, or logistic partnerships; promote mutual and equitable sharing of effort, cost, information, and risk; provide access to remote or operational test sites; leverage economies of scale; and promote interoperability with our allies. The DAF is party to more than 680 current air, space, and cyber bilateral and multilateral IAs to solve U.S. and allied military capability gaps, develop materiel solutions, harmonize requirements, and build interoperability with our international partners. This program element funds the DAF to identify, develop, process, negotiate, conclude, implement, and manage IAs in compliance with statutory provisions, legal authorities, fiscal constraints, technology transfer controls, intellectual property rights, third party transfer provisions, equitability criteria, industrial base factors, political-military interests, and the National Defense Strategy (NDS). Included in this budget are: air, space, and cyber IAC and IA activities; specialized working groups; Air Senior National Representative (ASNR) activities; technology assessments; requirements development; Engineering and Scientist Exchange Program (ESEP); and Administrative and Professional Exchange Program (APEP). This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E         PE 1001004F / International Activities Management Support$$, 4430000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160408BB_S500A$$, $$1160408BB$$, $$S500A$$, $$Operational$$, 234653000, $$Details are provided under separate cover.$$, 234653000, NULL, NULL, NULL, NULL, 2198964000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160279BB_S050$$, $$1160279BB$$, $$S050$$, $$Small Business Innovation Research$$, NULL, $$The goals of the Small Business Innovation Research (SBIR) program are to stimulate technological innovation, increase private sector commercialization of federal research and development (R&D), increase small business participation in federally funded R&D, and foster participation by minority and disadvantaged firms in technological innovation. Leveraging the innovation of small business concerns is an important contributor to the development of the cutting-edge technologies that will generate decisive and sustained U.S. military advantages by increasing the readiness, modernization, and lethality of the United States Special Operations Command (USSOCOM). This program supports high priority projects within the USSOCOM Components, their missions, and the Warfighter.$$, NULL, NULL, NULL, NULL, NULL, 351014000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160279BB_S051$$, $$1160279BB$$, $$S051$$, $$Small Business Technology Transfer$$, NULL, $$The goals of the Small Business Technology Transfer (STTR) program is to stimulate a partnership of ideas between small business concerns (SBCs) and research institutions through the United States Special Operations Command (USSOCOM) funded research or research and development (R/R&D). By providing awards to SBCs or cooperative R/R&D efforts with research institutions, USSOCOM supports innovation and economic growth to generate decisive and sustained U.S. military advantages. This program supports high priority projects within the USSOCOM Components, their missions, and the Warfighter.$$, NULL, NULL, NULL, NULL, NULL, 26621000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160401BB_S100$$, $$1160401BB$$, $$S100$$, $$SOF Technology Development$$, 50026000, $$This project conducts studies and develops laboratory prototypes for applied research and advanced technology developments and leverages other organizations' technology projects. Small incremental co-investments with the Department of Defense (DoD), other government agencies, and commercial organizations allow the United States Special Operations Command (USSOCOM) to influence the schedule and direction of technology developments, emerging technologies, and capabilities for Special Operations Forces (SOF), with significant economies of investment. This USSOCOM investment strategy is used to link technology opportunities with capability deficiencies, capability objectives, technology thrust areas, and technology objectives through key stakeholder relationships with the DoD and government technology developers. Technology development needs in these areas may be advertised to industry and government research and development agencies via agency announcements and calls for white papers.$$, 50026000, NULL, NULL, NULL, NULL, 783040000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160402BB_S200$$, $$1160402BB$$, $$S200$$, $$Advanced Technology Development$$, 134182000, $$This project provides for rapid prototyping, Advanced Technology Demonstrations (ATDs) and Joint Capability Technology Demonstrations. It is a means for demonstrating and evaluating the utility of emerging/advanced technologies in operationally relevant environments with Special Operations Forces (SOF) users. This project integrates disruptive solutions and emerging technologies and then presents them in technology demonstrations, in conjunction with joint experiments and other assessment events. Evaluation results often facilitate the initiation of new programs and the insertion of appropriate technologies to acquisition programs. This project leverages key stakeholder relationships with the Department of Defense and government technology developers to address unique, joint special mission or area-specific needs for which a few rapid prototypes must be developed on a responsive basis, or of sufficient time sensitivity to accelerate prototyping efforts of a normal acquisition program in any phase.$$, 134182000, NULL, NULL, NULL, NULL, 1733583000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160402BB_S201$$, $$1160402BB$$, $$S201$$, $$Rapid Defense Experimentation$$, 0, $$USSOCOM's component of the Rapid Defense Experimentation Reserve (RDER) is executed within this program element (PE) Element of Cost (EOC). To facilitate rapid modernization of the force, the Rapid Defense Experimentation Reserve (RDER) initiative was established in the Defense Planning Guidance for Fiscal Years 2023-2027, to encourage multi-component experimentation through a campaign of learning. Services, Agencies, and other participating organizations are to identify "best of breed” capabilities developed among the DoD prototyping programs, and execute approved projects through large-scale, cross- service experiments in order to refine and/or validate the Joint Warfighting Concept (JWC). Organizations nominate proposals to the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) that are multi-component — involving Joint Services, International partners and/or other government agencies and link to one or more of the four key supporting concepts ("functional battles”) of the Joint Warfighting Concept: Joint Concept for Fires, Joint Concept for Command and Control, Joint Concept for Contested Logistics, and Joint Concept for Information Advantage.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160402BB_SF101$$, $$1160402BB$$, $$SF101$$, $$Engineering Analysis$$, 18100000, $$This project provides a rapid response capability to support Special Operations Forces (SOF) programs and capabilities across the enterprise. The purpose is to correct system deficiencies, improve asset life, and enhance mission capability through the means of feasibility studies, analysis of alternatives, pre-developmental risk reduction studies, and engineering analyses. This project provides the engineering required to improve the design and performance integrity of the SOF equipment and software and to integrate disruptive “off-the-shelf” technologies to meet current and emergent capability gaps. This project also conducts risk reduction studies, analyses, and demonstrations to support emerging, time-critical equipment, weapons, and sensor enhancements.$$, 18100000, NULL, NULL, NULL, NULL, 135360000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160403BB_D615$$, $$1160403BB$$, $$D615$$, $$Rotary Wing Aviation$$, 60743000, $$This project provides for the development, rapid prototyping, demonstration, and integration of current and maturing technologies for Special Operations Forces - peculiar (SOF-p) rotary wing aviation and training requirements. This project provides next generation mobility to allow SOF-p helicopters to operate in denied environments. Rotary wing aircraft supported by this project include currently fielded: MH-60M; MH-47G; A/MH-6; and Future Long-Range Assault Aircraft (FLRAA). The currently fielded aircraft provide aviation support to SOF in worldwide contingency operations and low-intensity conflicts. These aircraft must be capable of rapidly deploying, penetrating hostile areas undetected, and operations at extended ranges under adverse weather conditions to infiltrate, provide logistics for, reinforce, and extract SOF. The anti-access/area denial (A2/AD) threat is characterized by an extensive and sophisticated ground based air defense system and an upgraded air- to-air capability targeted against helicopters. The Mission Processor Upgrades (MPU) provides for non-recurring engineering, systems engineering/testing, and future aircraft architecture studies that support replacement and upgrade of the current mission and video processors for all Army Special Operations Aviation (ARSOA) rotary wing aircraft. Tactical Mission Networking (TMN) focuses on technology development of platform software and hardware systems with capabilities to enable aircraft to effectively adapt and overcome the challenges of a highly contested and congested Radio Frequency (RF) environment.$$, 60743000, NULL, NULL, NULL, NULL, 437129000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160403BB_S750$$, $$1160403BB$$, $$S750$$, $$Mission Training and Preparation$$, 8176000, $$This project funds the definition, design, development, prototyping, integration, and testing of Mission Training and Preparation Systems (MTPS) to support training, avoid obsolescence, and maintain simulator concurrency with weapon system configurations; support mission planning and rehearsal systems enhancements required to meet Special Operations-peculiar (SO-p) mission requirements and correct deficiencies identified in previous testing; and support mission planning and rehearsal capabilities in current MTPS. The MTPS project also includes program management, systems engineering, configuration management, architecture development, risk reduction, and trade study initiatives, as well as initiatives to assure interoperability and commonality between diverse SOF training systems. Additionally, this project funds the Extended Reality (XR) Training Transformation Simulator Block Upgrade Fixed Wing (SBUDF) program that develops and integrates training innovation and transformation solutions across the United States Special Operations Command (USSOCOM) fixed wing and special tactics augmented and virtual reality (AR/VR) mission training device portfolio, to include AC-130J, MC-130J, CV-22, Armed Overwatch/OA-1K and C-146.$$, 8176000, NULL, NULL, NULL, NULL, 2801000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160403BB_S875$$, $$1160403BB$$, $$S875$$, $$AC/MC-130J$$, 15184000, $$This project supports the development, rapid prototyping, integration, automation, and testing of the AC-130J and MC-130J aircraft. The AC-130J Ghostrider provides close air support (CAS), air interdiction, and armed reconnaissance in support of special operations and conventional forces in contested and degraded environments. The MC-130J Commando II provides clandestine, or low visibility, single or multiship, low-level infiltration (infil), exfiltration (exfil), and resupply of Special Operations Forces (SOF), by airdrop or airland and air refueling missions for special operations helicopters and tiltrotor aircraft, intruding politically sensitive or hostile territories. Incremental upgrade and agile software delivery approaches will be used to rapidly prototype, integrate and mature SOF capabilities onto the AC-130J and MC-130J aircraft. Capability Release Two (CR2) includes the following SOF modifications: Special Mission Systems (SMS), Auxiliary Flight Deck Station (AFDS), Defensive System Upgrade (DSU), Terrain Following (TF)/Terrain Avoidance (TA) radar, Airborne Mission Networking (AbMN), and Electronic Warfare (EW)/Radio Frequency Countermeasures (RFCM) programs. Additionally, Capability Release Three (CR3) builds upon the CR2 configuration through integration of an enhanced Tactical Flight Management System (TFMS), Auto-Route Replanner (ARR), integrated Defensive Countermeasure (DCM) Suite implemented in alignment to the Open Mission Systems (OMS) standard reference architecture and hosted on an upgraded Next Generation SMS. Efforts like Integrated Tactical Mission Systems (ITMS) in CR3 provide critical automation and integration of SOF Tactical Mission Systems (TMS), including navigation, communication, precision fire control and defensive systems required for safe flight in AC-130J and MC-130J aircraft. Requirements include upgrades to integrate and automate SOF TMS such as AbMN interoperability, data fusion and improved situational awareness, improved threat detection and avoidance, integrated TF / TA and Silent Knight Radar (SKR) improvements, DCM suite, Precision Strike Package (PSP) interoperability, integrated EW, and embedded training. Integrating and automating SOF mission systems that deliver these capabilities is critical to fielding SOF-capable AC-130J and MC-130J aircraft to be more lethal, resilient, survivable, agile, and responsive.$$, 15184000, NULL, NULL, NULL, NULL, 226858000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160403BB_SF100$$, $$1160403BB$$, $$SF100$$, $$Aviation Systems Advanced$$, 29099000, $$This project provides for the development, rapid prototyping, demonstration, and integration of current and maturing technologies for Special Operations - peculiar (SO-p) aviation and training requirements to transform the foundation of future SOF aviation for the Joint Force. Timely application of SO-p technology is critical and necessary to meet requirements in areas such as: Aviation Engineering Analysis (AEA), Electronic Warfare (EW)-Radio Frequency Countermeasures (RFCM), High Speed Vertical Takeoff and Landing (HSVTOL), High Energy Laser (HEL), MC-130J Amphibious Capability (MAC), Adaptive Airborne Enterprise (A2E), MH-47G and MH-60M SOF Common Terrain Following (TF)/Terrain Avoidance (TA) Silent Knight Radar (SKR), and Precision Strike Package (PSP). The AEA provides engineering analysis, market research, and designs to address aircraft survivability needs such as signature management, situational awareness (SA), and versatile mission platform/equipment (payloads, communication, and weapons) to achieve SOF objectives. The EW-RFCM supports development, integration, and test activities to provide EW capability against Radio Frequency (RF) threats for SO-p AC/MC-130J aircraft. The HSVTOL supports development and demonstration of agile and responsive air mobility capabilities to support runway independent operations, increased speed of maneuverability, and provide the ability to penetrate anti-access (A2)/anti-denial (AD) environments. The HEL supports development of an AC-130J laser weapons system for Low Probability of Detection (LPD) use in complex environments to enable joint/coalition SOF operations against targets such as communication nodes, light-to-medium duty vehicles, and power infrastructures. The MAC supports development and demonstration of amphibious capabilities on a C-130J to support runway independent operations and provide the ability to operate in logistically constrained environments. MH-47G and MH-60M SOF Common TF/TA SKR supports development, integration, and testing of SOF Common TF/TA Multi- Mode Radar (MMR) that provides Low Probability of Intercept (LPI) and LPD capabilities for MH-47G and MH-60M aircraft. The PSP supports systems engineering, analysis, development, and enhancement of the baseline PSP for integration, installation, and test on SOF AC-130J aircraft and other SOF aviation platforms.$$, 29099000, NULL, NULL, NULL, NULL, 1658162000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160403BB_SF200$$, $$1160403BB$$, $$SF200$$, $$CV-22$$, 4497000, $$This project supports integration, design, development, rapid prototyping, and test to provide improved capabilities to include, but not limited to: more robust performance in situational awareness (SA); intelligence, surveillance, and reconnaissance (ISR), weapons, avionics; Special Operations Forces (SOF) communications; defensive/ survivability systems; interoperability; speed and maneuverability; mission deployment and improved reliability and maintainability of the CV-22 platform. The CV-22 Osprey is a SOF variant of the V-22 vertical medium lift, multi-mission aircraft. The CV-22 provides long-range, high speed, all weather, infiltration (infil), exfiltration (exfil), and resupply of SOF teams in hostile, denied, and politically sensitive areas that allows the Joint Force to be more agile and responsive. These capabilities are not currently provided by other existing SOF vertical lift aircraft. Funding supports the following CV-22 requirements: CV-22 SOF Common Terrain Following (TF)/Terrain Avoidance (TA) Silent Knight Radar (SKR), Development, Reliability Improvements, and Test Aircraft Flying Hours and Maintenance.$$, 4497000, NULL, NULL, NULL, NULL, 94984000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160403BB_SF300$$, $$1160403BB$$, $$SF300$$, $$Armed Overwatch/Targeting$$, 2000000, $$This project supports integration and testing of SO-peculiar (So-p) capabilities and aircraft certification efforts for the Armed Overwatch program. Armed Overwatch provides Special Operations Forces (SOF) with crewed deployable, affordable, and sustainable crewed aircraft systems capable of executing close air support (CAS), precision strike, and armed intelligence, surveillance, and reconnaissance (ISR) requirements in austere and permissive environments for use in Irregular Warfare operations.$$, 2000000, NULL, NULL, NULL, NULL, 46544000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160405BB_S400$$, $$1160405BB$$, $$S400$$, $$SO Intelligence Systems$$, 102732000, $$This project is part of the Military Intelligence Program (MIP). Provides for the identification, development, testing, and rapid prototyping of Special Operations Forces (SOF) intelligence equipment to identify and eliminate deficiencies in providing timely intelligence to deployed forces. Programs address the primary areas of intelligence dissemination, sensor systems, tagging, tracking, and locating devices, integrated threat warning to SOF mission platforms, SO-peculiar (SO-p) support from space systems including Tactical Exploitation of National Capabilities (TENCAP) system under National Systems Support to SOF (NSSS), space-based payload development, and tactical uncrewed systems. The systems developed and tested in this project are NSSS; Special Operations Tactical Video System/Reconnaissance, Surveillance, and Target Acquisition (TVS/RSTA); Integrated Survey Program (ISP); Sensitive Site Exploitation (SSE); SOF Signals Intelligence (SIGINT) Processing, Exploitation, Dissemination (PED) Silent Dagger (SD); small Uncrewed Multidomain Systems (sUMS) and Multi-Mission Tactical Unmanned Aerial Systems (MTUAS). The intelligence programs funded in this project will meet annual emergent requirements. The United States Special Operations Command (USSOCOM) has developed an overall strategy to ensure that Command, Control, Communications, Computers, and Intelligence (C4I) systems and tactical uncrewed systems continue to provide SOF with the required capabilities throughout the 21st century. The USSOCOM's tactical uncrewed and C4I systems comprise an integrated network of systems providing positive command and control and timely exchange of intelligence and threat warning to all organizational echelons. The C4I systems that support this new architecture employ the latest standards and technology by transitioning from separate systems to full integration with the Global Information Grid (GIG). The GIG allows SOF elements to operate with any force combination in multiple environments.$$, 102732000, NULL, NULL, NULL, NULL, 765093000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160431BB_S375$$, $$1160431BB$$, $$S375$$, $$Weapons Systems$$, 2027000, $$This project provides for the next generation systems Pre-Planned Product Improvements (P3I), testing, and integration of specialized weapon systems and weapon accessories to meet the unique requirements of Special Operations Forces (SOF). The efforts include product improvements and testing of the Suppressed Upper Receiver Group (SURG), Advanced Sniper Rifle (ASR), Machine Gun (MG) Barrel, Mid-Range Gas Gun (MRGG), Reduced Signature Assault Rifle (RSAR), Hand Gun (HG) Suppressor, Lightweight Machine Gun-Medium (LMG-M), and Lightweight Machine Gun-Assault (LMG-A). The product improvements will leverage the latest technological advances to achieve over match capability for integrated deterrence by posturing to fight and win against current and emerging threats.$$, 2027000, NULL, NULL, NULL, NULL, 12116000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160431BB_S385$$, $$1160431BB$$, $$S385$$, $$Soldier Protection and Survival$$, 32058000, $$This project funds the development, testing, integration, rapid prototyping and evaluation of specialized equipment to meet the unique soldier protection and survival requirements of Special Operations Forces (SOF), including, but not limited to: individual survival equipment; Multi-Mission Electronic Countermeasures (MM-ECM); and Counter Uncrewed Systems (aerial, ground and maritime); and personnel safety equipment to improve the mobility of SOF, while conducting varied missions. These missions are generally conducted in harsh and hostile environments, for unspecified periods and in locations requiring small unit autonomy.$$, 32058000, NULL, NULL, NULL, NULL, 125687000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160431BB_S385A$$, $$1160431BB$$, $$S385A$$, $$Body Armor and Associated$$, 1697000, $$This project funds the development, testing, integration, rapid prototyping and evaluation of specialized equipment to meet the unique soldier protection and survival requirements of Special Operations Forces (SOF), including, but not limited to: individual survival equipment; Multi-Mission Electronic Countermeasures (MM-ECM); and Counter Uncrewed Systems (aerial, ground and maritime); and personnel safety equipment to improve the mobility of SOF, while conducting varied missions. These missions are generally conducted in harsh and hostile environments, for unspecified periods and in locations requiring small unit autonomy$$, 1697000, NULL, NULL, NULL, NULL, 14518000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160431BB_S395$$, $$1160431BB$$, $$S395$$, $$Visual Augmentation, Lasers and$$, 4514000, $$This project supports the development, testing and integration of SO-peculiar visual augmentation devices to include: binocular and monocular night vision devices; laser markers and designators; geo-location and targeting systems; weapon mounted optics and aiming lasers; sensors and detection systems; weapon mounted visible lights and clandestine pointers; infrared imaging devices; and simulators and training devices that provide the individual SOF operator with superior battle space awareness and decision making information.$$, 4514000, NULL, NULL, NULL, NULL, 28576000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160431BB_S700$$, $$1160431BB$$, $$S700$$, $$Communications Equipment and$$, 118097000, $$This project provides for communication systems to meet emergent requirements to support SOF. Communications Equipment and Electronics Systems is a continuing effort to develop smaller, lighter, more efficient and more robust SOF command, control, communications, and computer (C4) capabilities. The USSOCOM C4 systems comprise an integrated network of systems providing positive command and control and the timely exchange of information to all organizational echelons. The C4 systems that support this new architecture employ the latest standards and technology by transitioning from separate systems to full integration within the Global Information Grid (GIG). The GIG is a multitude of existing and projected national assets that allows SOF elements to operate with any force combination in multiple environments.$$, 118097000, NULL, NULL, NULL, NULL, 153097000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160431BB_S710$$, $$1160431BB$$, $$S710$$, $$Tactical Systems Development$$, 50521000, $$This project provides for development, testing, and integration of specialized automation equipment to meet the unique requirements of Special Operations Forces (SOF). Specialized automation equipment will permit small, highly trained forces to conduct required operations across the entire spectrum of conflict. These operations are generally conducted in harsh environments, for unspecified periods and in locations requiring small unit autonomy. SOF must infiltrate by land, sea, and air to conduct unconventional warfare, direct action, or deep reconnaissance operations in denied areas against insurgent units, terrorists, or highly sophisticated threat forces. The requirement to operate in denied areas controlled by a sophisticated threat mandates that SOF systems remain technologically superior to threat forces to ensure mission success. The project also supports SOF mission planning and execution capabilities as well as initiatives to assure the interoperability and commonality of these capabilities across diverse air, ground and maritime systems.$$, 50521000, NULL, NULL, NULL, NULL, 48476000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160431BB_S725$$, $$1160431BB$$, $$S725$$, $$Tactical Radio Systems$$, 39687000, $$This project is for the development of all Special Operations Forces (SOF) tactical radio programs. Tactical Radios provide the critical command, control, and communications (C3) link between SOF Commanders and SOF Teams conducting operational missions and training exercises. They also provide interoperability with all Services, various agencies of the U.S. Government, Air Traffic Control, commercial agencies, and allied foreign forces. Tactical Radios rapidly and seamlessly establish and maintain mobile and fixed command and control (C2) communications between operational elements and higher echelon headquarters, allowing SOF to operate with any force combination in multiple environments.$$, 39687000, NULL, NULL, NULL, NULL, 73364000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160431BB_S800$$, $$1160431BB$$, $$S800$$, $$Munitions Advanced Development$$, 26724000, $$This project funds advanced engineering, operational system development, and qualification efforts related to specialized kinetic and non-kinetic munitions and equipment to meet the unique requirements of Special Operations Forces (SOF).$$, 26724000, NULL, NULL, NULL, NULL, 188153000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160432BB_S500E$$, $$1160432BB$$, $$S500E$$, $$Special Programs$$, 550000, $$This project is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress.$$, 550000, NULL, NULL, NULL, NULL, 70601000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160434BB_S855$$, $$1160434BB$$, $$S855$$, $$Unmanned ISR$$, 2281000, $$This project is part of the Military Intelligence Program (MIP). Unmanned Intelligence, Surveillance, and Reconnaissance (ISR) rapidly develops and deploys special capabilities to perform ISR for deployed Special Operations Forces (SOF) using non-traditional means. Group 1, 2, 3 and 4, Unmanned Aerial Systems (UAS) developmental efforts are to identify, develop, integrate, and test Special Operations-peculiar (SO-p) mission kits, mission payloads, air vehicle enhancements, and modifications to ground control stations. Based on stakeholder input and requirements, United States Special Operations Command develops and integrates UAS payloads to advance ISR capabilities that address dynamic and emergent operational needs of the SOF user. Efforts include improving imagery intelligence and electronic warfare payloads, capitalizing on developing technologies to reduce size, weight and power while addressing processing and data management challenges. This program also provides a mechanism for SOF user combat evaluation of emerging sensor technologies.$$, 2281000, NULL, NULL, NULL, NULL, 196764000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160480BB_S910$$, $$1160480BB$$, $$S910$$, $$SOF Tactical Vehicles$$, 9213000, $$This project provides for the development and testing of a variety of capability upgrades to Special Operations Forces (SOF) Vehicles and mission enabling equipment. Current SOF tactical vehicles are categorized into Light, Medium, Heavy, and Commercial, which include the Lightweight Tactical All-Terrain Vehicle (LTATV); Ground Mobility Vehicle (GMV 1.0 / 1.1); Joint Light Tactical Vehicle (JLTV); Mine Resistant Ambush Protected (MRAP) Vehicle; Armored Ground Mobility System (AGMS); Non-Standard Commercial Vehicle (NSCV); and Special Operations-peculiar (SO-p) modifications for commercially available and service common platforms. The SOF mission mandates that SOF vehicles remain technologically superior, operate in multiple environments, and able to meet any threat to provide a maximum degree of survivability.$$, 9213000, NULL, NULL, NULL, NULL, 77706000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160483BB_S0417$$, $$1160483BB$$, $$S0417$$, $$Underwater Systems$$, 120475000, $$This project provides for the Engineering and Manufacturing Development (EMD) of combat underwater submersibles, Special Operations Forces (SOF) combat diving systems, underwater support systems, and underwater equipment. This project also provides for pre-acquisition activities (materiel solutions analysis, advanced component development and prototypes) to respond to emerging requirements. These submersibles, equipment, and diving systems are used by SOF in the conduct of infiltration/extraction, personnel/material recovery, hydrographic/inland reconnaissance, beach obstacle clearance, underwater ship attack, and other missions. The capabilities of the submersible systems, diving systems, and unique equipment provides small, highly trained forces the ability to successfully engage with increased lethality while maximizing survivability of the SOF personnel and equipment.$$, 120475000, NULL, NULL, NULL, NULL, 679864000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160483BB_S1684$$, $$1160483BB$$, $$S1684$$, $$Surface Craft$$, NULL, $$This project provides for the Engineering and Manufacturing Development (EMD) of combatant craft, combatant craft mission equipment, Pre-Planned Product Improvement (P3I), and technology insertion to meet the unique requirements of Special Operations Forces (SOF). This project also provides for pre-acquisition activities (materiel solutions analysis, advanced component development and prototypes) to quickly respond to new requirements for maritime craft and subsystems, leading to increased lethality and survivability of personnel and equipment. The craft capabilities and unique equipment provide small, highly trained forces the ability to successfully conduct operations associated with SOF maritime missions. The FY 2026 request for Maritime Systems includes $120.745 million of discretionary and $180.813 million of mandatory (reconciliation) funding for a total of $301.288 million. Further information for this reconciliation request is provided in Section 20009 (INDOPACOM Capabilities) of the Reconciliation Exhibit. The following justifications reflect the sum totals of mandatory (reconciliation) and discretionary categories of funding. Combatant Craft Forward Looking Infrared (CCFLIR) has $2.031 million of mandatory funding. Due to system limitations in the R2A/R3 CCFLIR is only captured in the R4/R4A.$$, NULL, NULL, NULL, NULL, NULL, 135148000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1160490BB_S500D$$, $$1160490BB$$, $$S500D$$, $$Operational$$, 21752000, $$This project is part of the Military Intelligence Program. This project is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress.$$, 21752000, NULL, NULL, NULL, NULL, 171968000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1201212SF_670220$$, $$1201212SF$$, $$670220$$, $$Datalake & UI/UX$$, 18451000, $$"This is a new start and critical initiative activity to implement Personnel Management Act (PMA) Human Resource (HR) Information Technology (IT) Automation and develop a data layer within the existing Air Force Human Resources structure that can be utilized to meet current and future Space Force needs. In December 2023 the 2024 National Defense Authorization Act established the Space Force Personnel Management Act, a five-year term for USSF to define and implement policy, process, and system actions for a single component USSF that defines all Guardians in one of two statuses: fulltime or parttime. The CSO has directed SF/S1, with the support of SAF/SQ, to undertake the task of researching various pathways and start early development and testing of an optimized platform for use by Guardians across the service. To meet the constrained timeline, SF/S1 has developed a novel solution utilizing existing AF/A1 structures to establish a flexible data layer using an agile approach to limit development cost and allow for a customizable modular solution. In the near term the CSO has expressed concern over the loss of critical human capital as members depart military service in favor of the private sector, with no ability to retain talent within a reserve component. As a solution, the CSO has directed the required mechanisms (policy, procedures, technology) be developed and put in place by 2026 to demonstrate ability to retain guardians in a part time posture with the option to return to full time status at a later date. To meet the intent of this directive, the SF/S1 has built a pilot program to be able to demonstrate a viable solution by overhauling the current Air Force HR data infrastructure to better automate and streamline the critical pathways and deliver the functionality needed to process Reservist into a component less part-time status by Jan 2026. In the out years, additional functionality will be delivered to the system in incremental sprints to solve the problem in an efficient solution space. Agile sprints allow for better accounting for cost schedule and performance metric tracking delivering a critical HR too to the force as quickly as possible. " This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:           PE 1201212SF / Service-Wide Support (Not Otherwise Accounted For) Operational Systems Development$$, 18451000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1202140F_672486$$, $$1202140F$$, $$672486$$, $$JOINT NAVWAR CENTER$$, 0, $$Navigation Warfare [NAVWAR] is deliberate defensive and offensive action to assure and prevent positioning, navigation, and timing [PNT] information through coordinated employment of space, cyberspace, and electronic warfare [EW] operations. Funds are used to create and maintain NAVWAR knowledge and ensure NAVWAR superiority across the DoD. IAW the most recent Unified Command Plan, USSPACECOM is responsible for [a] [U] Advocating for requirements and capabilities supporting NAVWAR operations and joint resilient PNT for the DoD, and [b] [U] Providing contingency and operations support to CCMDs for NAVWAR and joint resilient PNT planning. USSPACECOM will research, develop, test, assess and evaluate NAVWAR options IOT advocate across Services and the other CCMDs to achieve PNT overmatch. Funds are used to create and maintain NAVWAR knowledge. NAVWAR expertise is developed in part by execution of PNT Operational Field Assessments [POFAs] that assess Red and Blue PNT-related capabilities, limitations, and vulnerabilities. GYPSY POFA's are linked to Commander USSPACECOM's Joint Exercise Program [JEP] and nested within the Chairman's Exercise Program [CEP]and Combatant Commander's [CCMD] Tier 1 exercises [PACIFIC SENTRY AND AUSTERE CHALLENGE are examples] and provide operationally realistic threat-representative, PNT-contested environments for analytical assessment of air, ground, maritime, space & cyberspace mission capability. FORTUNE POFAs are PNT capability and vulnerability assessments associate with a Service exercise or mission event. PRISM POFAs encompass all other Operations, Actions, and Activities [OAAs] and other assessments to include evaluation of rapid innovative NAVWAR Capabilities and/or solutions. Assessments inform materiel and non-materiel solutions, service acquisition decisions, capability gaps, intelligence gaps and tactics, techniques and procedures [TTP] development and implementation to mitigate effects on warfighter operations in the anticipated theater NAVWAR threat environments. JNWC assesses department wide PNT posture through the PNT Biennial assessment IAW DoDI 4650.08. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In 2023 $0 was expended for civilian pay expenses in the program element and in FY2024 $0 is forecasted for civilian pay expenses in this program element.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203001SF_673035$$, $$1203001SF$$, $$673035$$, $$Presidential and National Voice$$, 303000, $$The Presidential and National Voice Conferencing (PNVC) Integrator project is a critical element of the Nuclear Command, Control, and Communications (NC3) System. PNVC integrator replaces the Survivable Emergency Conferencing Network (SECN) capability, and will provide anti-jam, anti-scintillation, survivable, and enduring voice communications via Milstar, Advanced EHF, and ESS satellite constellations for national and strategic users. There are several components being developed, procured and updated by other organizations that must be synchronized to expeditiously field this capability. The PNVC Integrator is responsible for end-to-end integration of these components, to include requirements traceability, end-to-end system testing, configuration and checkout activities, training and technical manuals, network transition support, identification of deficiencies in overall PNVC system capability, enterprise, and life cycle support for PNVC components. The AFPEO/SP approved entry into the acquisition life-cycle as a post MS-A Acquisition Category (ACAT) III Program of Record in January 2016. In March 2019 the AFPEO/NC3 declared the PNVC Integrator an ACAT II Program based on updated approved budget request. Starting in December 2018 PNVC Integrator became responsible for the funding requests of all program elements related to the Defense Information Systems and Agency (DISA) components of the PNVC System in accordance with FY 2018 National Defense Authorization Act, Sec. 1661. In October 2021, PNVC completed Milestone B/C.$$, 303000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203001SF_673040$$, $$1203001SF$$, $$673040$$, $$Force Element Terminal$$, 0, $$The FAB-T - Force Element Terminal (FAB-T FET) program replaces the Ultra High Frequency (UHF) Milstar terminal and provides secure, protected, and survivable communications for the strategic warfighter through airborne-based Military Satellite Communication (MILSATCOM) terminals. The FAB-T FET will provide worldwide nuclear and non-nuclear, survivable, anti-jam Low Probability of Detect (LPD)/ Low Probability of Intercept (LPI) data and voice communications. The FAB-T FET will be interoperable with Advanced Extremely High Frequency (AEHF), Enhanced Polar Systems - Recapitalization (EPS-R), and satellite constellations utilizing waveforms and will be installed on the B-52 aircraft (threshold). FAB-T FET was designated as a Middle Tier of Acquisition (MTA) in February 2019 and is expected to be designated as Major Capability Acquisition at Milestone C.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203010SF_645620$$, $$1203010SF$$, $$645620$$, $$Digital Engineering$$, 32527000, $$Project 645620, Digital Engineering (DE), is delivering the Digital Engineering Ecosystem (DEE). DEE is a cloud-based, remotely accessible, Multi-Level-Security (MLS) suite of applications, environments, and infrastructure that is easily scalable and provides the means to develop capabilities, store, access, architect, analyze, and visualize data and models throughout the acquisition life cycle, from requirements planning, development, and production, through sustainment. DEE provides a unified enterprise environment for Space Systems Command (SSC) program offices, operations squadrons, other government stakeholders, and hardware and software vendors, enabling responsive, threat-informed product development, testing, deployment, training, mission planning, and on-orbit anomaly resolution. Key capabilities include: (1) Connecting multiple Digital Threads—a framework to link all the digital information about a space system, from initial design to operations, into a single, accessible system—integrating organizations such as members of the intel community, Space Warfighting Analysis Center (SWAC), and Space Operations Command (SpOC) to leverage threat models for smarter force design, requirements development, solution design, acquisition, and operations planning; (2) Connecting Classified Systems—facilitating seamless multi-domain engineering activities across multiple classification levels (e.g., CUI to TS, SCI, SAP); (3) Eliminating Redundant Systems—standardizing tools to enhance inte.g.ration and collaboration; (4) Achieving Cost Efficiencies— reducing costs through enterprise- level capabilities and economies of scale; (5) Enhancing Data-Driven Decisions—providing real-time accurate, relevant information for informed leadership decisions; and (6) Supporting Space Force's Digital Transformation—providing the applications and environment to advance the Chief of Space Operations' (CSO) vision of the Space Force as a "Digital Service," as outlined in the May 2021, U.S. Space Force Vision for a Digital Service. DEE supports DE by connecting acquisition, test, training, and operational data, models, and activities at the speed of relevance through the delivery of a hybrid cloud MLS modeling and data ecosystem. DEE establishes Authoritative Sources of Truth (ASOTs) and Single Sources of Truth (SSOTs) by incorporating data integration across multiple trusted sources. DEE is designed to connect engineers, program managers, force designers, requirements managers, logisticians, developmental and operational testers, training instructors and schoolhouses, operational commanders, senior decision makers, mission partners, industry and academia, and all other participants in the Capability Development Lifecycle. The DEE is designed to integrate information technology (IT), system security, software development, and data/network modernization to accelerate and modernize the USSF capability development lifecycle. It equips users with tools to enhance collaboration, user experience, and integration with mission partners and industry. DEE helps to assess technical risks posed by adversary threats by analyzing system and enterprise-level risks and incorporates agile software practices to scale platforms and infrastructure based on digital thread mission needs. The DEE provides deliberate data exposure and "normalizes” the data to make it meaningful and useful for any business or mission use cases. The DEE effort includes multiple DEE prototype solutions collectively known as the Digital Engineering Integrated Cloud-based Environment (DEICE) Tech Stack. These prototypes currently serve as the interim Digital Services Ecosystem (DSE) for USSF Capability Development as a cloud-based, remotely accessible, interconnected$$, 32527000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203010SF_646017$$, $$1203010SF$$, $$646017$$, $$SSC Developmental IT$$, 20966000, $$Project 646017, Space Systems Command (SSC) Developmental Information Technology Infrastructure (DITI) provides support to enterprise cybersecurity integration, cyber capability development, and vulnerability management across SSC program offices. The project provides program offices support through their Authorizing Official (AO) and Risk Management Framework (RMF) cyber assessment team, Zero Trust (ZT), cryptography program alignment, data and information availability, supply chain risk management capabilities, and software management. Until FY 2026 when it transitions to a separate project, DITI also supported United States Space Force (USSF) operational needs with the Integrated Operations Networking (ION) effort. The USSF's ION effort is a critical component of the Space Force's mission to enable the Battle Management, Command, Control and Communications (BMC3) warfighter missions. ION will provide a secure, reliable, multi-classification data transport backbone across critical kill webs designed to defend against adversary operations. DITI develops and implements cybersecurity tools and processes and alignment of cybersecurity policies and guidance though several efforts. The DITI project Directorate provides support to cybersecurity AOs and RMF cyber assessment teams for Authorization to Operate (ATO) decisions. DITI develops ZT strategies and architectures, executing a ZT pilot program to address legacy and future space systems that establish and mitigate threats against infrastructure. The Cryptography Modernization effort builds a central repository to track all crypto requirements to identify gaps, program risks, mitigation plans, and status tracking across SSC, per Department of the Air Force Manual (DAFMAN) 17-1302. This project's efforts focus on developmental cybersecurity and support generation and alignment of cybersecurity policy and guidance, cyber resiliency capability development, vulnerability management, data accessibility with automation, and program protection. DITI helps assess technical risks that operational users experience in SSC program offices or encounter by understanding the System and Enterprise-level risks posed by threats based on deployment and gathered feedback across SSC. Cybersecurity regulation and directives are synthesized, deconstructed, and applied to best determine implementation and standardization across various functions and mission sets. Capability development efforts include implementation of DoD cybersecurity policies and guidance such as DoD's Cyber Strategy, ZT Strategy, and capabilities. This includes efforts for enabling ZT capabilities in Space Systems and implementation of SSC ZT Guidance and Policy via pilot programs for both legacy and future ground and space systems in accordance with Executive Order 14028, "Improving the Nation's Cybersecurity,”, which requires federal agencies to establish plans to drive adoption of ZT Architecture. The projects pursued for ZT keeps pace with increasing cyber threats and modernizes existing infrastructure into SSC programs for mitigation against existing and future vulnerabilities. DITI Developmental Cybersecurity effort will deploy and enhance SSC Supply Chain Risk Management (SCRM) capabilities through development of SCRM AI/ML tools that will illuminate and monitor the space defense industrial base and provide real-time risk analysis to SSC Program Executive Offices (PEOs).$$, 20966000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203010SF_646602$$, $$1203010SF$$, $$646602$$, $$Integrated Operations Networking$$, 35113000, $$In FY 2026, all funds for Integrated Operations Networking (ION) are transferred from Project 646017 to 646602. The USSF's Integrated Operations Networking (ION) effort is a critical component of the Space Force's mission to enable the Battle Management, Command, Control, and Communications (BMC3) warfighter missions. ION will provide a secure, reliable, multi-classification data transport backbone across critical kill webs designed to defend against adversary operations. This ION communications backbone will provide high bandwidth with low latency for essential capabilities, connecting with the data platform, Unified Data Library, to ensure data exposure and dissemination occur using ION's resilient connectivity from sensors to C2 centers and tactical units. ION will integrate commercially available information technology (IT) capabilities to minimize government-unique tools, reducing technology debt and increasing agility against cyber threats. The ION program will prioritize the closure of priority kill-web gaps, as identified in the Space Force's Digital Services Ecosystem Strategic Requirements Document. The program will focus on developing a secure, reliable, and multi-classification transport layer to support space missions, with a emphasis on direct connection between all elements of force packages, establishing a special access program (SAP)-level network with overlays, and developing high-speed connectivity and high resilience to C2S. The ION program will also investigate opportunities to leverage existing efforts, such as MeshONE-T to support the development of ION. The ION program will be executed in accordance with the DoD's Cyber Strategy and the Space Force's cyber security policies and guidance. The program will implement Zero Trust (ZT) capabilities, cryptography modernization, and supply chain risk management (SCRM) to ensure the security and resilience of the ION network. The program will also explore the use of Artificial Intelligence (AI) applications to provide decision aids, automation, and computer decision support to make effective decisions in a complicated environment and reduce cognitive load. The increased funding in FY 2026 will enable the program to maintain a steady pace of execution throughout the year, ensuring that the Space Force can leverage the ION capability to enhance its mission effectiveness. The ION program will provide a critical capability to the Space Force, enabling the service to operate in a contested environment and to defend against adversary operations. The program will be executed in a manner that is consistent with the Space Force's priorities, including the development of a digital engineering ecosystem, the implementation of zero trust capabilities, and the modernization of cryptography and supply chain risk management.$$, 35113000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203040SF_673070$$, $$1203040SF$$, $$673070$$, $$Defensive Cyber Ops -$$, 102439000, $$Defensive Cyberspace Operations Space (DCO-S) provides defensive cyber capabilities that protect United States Space Force (USSF) mission systems, to include their associated computer systems, software applications and sensitive operational information against unauthorized intrusion, corruption, and/or destruction. The emphasis of the program is directed toward defensive cyberspace capabilities; computer and network systems security; damage assessment and recovery; cyber threat recognition, attribution, and mitigation; and active response methodologies to respond to evolving threats and changes to the cyber environment. These areas of emphasis are realized through research and development, test and acquisition in the areas of proactive defense, defensive counter cyberspace, cyberspace intelligence, surveillance and reconnaissance, command and control situational awareness, persistent network operations, as well as decision support, recovery, and digital forensics. The development of DCO-S tools for the ground segment implements a combined Development/Security/Operations (DEVSECOPS) framework, using the Software Acquisition Pathway (SWP) Adaptative Acquisition Framework, which incorporates methodologies, technologies, and tools to deeply embed security best practices into the modern development workflow and tool-chain. This effort primarily institutes two product lines: Manticore (Detect & Identify) and Kraken (Protect & Respond). It will endeavor to identify shared/common platform, infrastructure, and data layer solutions to support open frameworks and architectures across the enterprise ground portfolio. Manticore and Kraken make use of open source and commercial tools to create the platform used to defend space mission systems with some of the content customized to address space-unique requirements such as protocol analytics. There are no commercial off-the-shelf solutions that address the threat to unique USSF systems, so tailored content is required to support the DCO-S mission.. DCO-S enables Space Delta (DEL) 6 and the mission Deltas to perform cyber-integrated space operations that identify, detect, protect against, respond to, and recover from malicious threats to space mission systems. These developments deploy both out-of-band (Manticore) and in-band (Kraken) cyber defense tool suites for the ground mission systems to Space Delta 6 (Cyber Ops) protecting the following mission sets: Protected Communications, Missile Warning, Military Strategic Communications (MILSATCOM), Position Navigation and Timing (PNT), Ballistic Missile Command and Control, Space Domain Awareness (SDA), Nuclear Command Control and Communications (NC3), and Command and Control Satellite Operations (C2 Sat Ops). DCO-S software development must also increase and adapt to support software development to on-board classified mission systems and new data types not in the baseline software to keep pace with the cyber threat. DCO-S evolves Wide Area Network development to meet security, sustainment, and reach-back requirements for the USSF Cybersecurity Service Provider. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:            PE 1203040SF / DCO-Space Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 102439000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203109SF_673109$$, $$1203109SF$$, $$673109$$, $$SATCOM MUOS$$, 421847000, $$Narrowband Satellite Communications provides a worldwide, multi-service population of mobile and fixed-site terminal users with Ultra High Frequency (UHF) Narrowband, beyond line of sight satellite communications (SATCOM). Mobile User Objective System (MUOS) significantly increases performance and capacity in support of critical Combatant Command SATCOM priorities. MUOS is the replacement system for the UHF Follow-on (UFO) system, which is currently beyond its design life. MUOS is comprised of Space, Ground, and User Entry Segments. The Space Segment consists of five geosynchronous satellites to support a four satellite constellation over the intended service life. Each satellite provides a legacy UHF payload that is backward compatible with UFO, and a Wideband Code Division Multiple Access (WCDMA) payload that provides cellular-like capability. MUOS reached full operational capability in October 2019. The Ground Segment consists of four world-wide Radio Access Facilities (RAFs) and two satellite control facilities. Each RAF includes three 60 ft. antennas and numerous equipment racks. The RAFs in Hawaii and Virginia each include a Switching Facility (SF), and the RAF in Hawaii includes a Network Management Facility (NMF). The User Entry Segment consists of the MUOS waveform that is ultimately integrated into MUOS-capable terminals which are fielded by the services. In addition to providing UHF SATCOM for the Department of Defense, the USSF has the overall responsibility to deliver the End-to-End (E2E) MUOS capability to the warfighter. This responsibility involves systems engineering, integration, network management, and test management of all MUOS system-of-system components. A Department of Defense Chief Information Officer assessment of anticipated narrowband satellite communication availability led to the Office of Under Secretary of Defense (OUSD) Acquisitions & Sustainment recommendation and OUSD Cost Assessment and Program Evaluation (CAPE) direction to initiate MUOS Service Life Extension (SLE) to acquire and launch two additional MUOS satellites (without legacy payloads). MUOS SLE is projected to extend worldwide WCDMA constellation availability to at least FY 2035 and the supporting ground segment service life to at least FY 2040. This PE funds systems optimization and modernization to address the dynamic, worldwide electromagnetic and cybersecurity environment in which MUOS operates and MUOS SLE. The PE includes a MUOS Baseline effort, and a MUOS SLE effort. Cost to complete is "Continuing” in the cost table, as the USSF is in the process to determine the cost estimate for this post Milestone C program. This program element may include necessary civilian pay expenses required to manage, execute, and deliver the MUOS system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:               PE 1203109SF / Narrowband Satellite Communications Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 421847000, NULL, NULL, NULL, NULL, 204862000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203110SF_673276$$, $$1203110SF$$, $$673276$$, $$Satellite Control$$, 93780000, $$The Satellite Control Network (SCN) is a satellite ground terminal network comprised of two communication nodes (Schriever SFB & Vandenberg SFB) and 15 antenna systems. The antennas are distributed around the globe at seven locations -- Vandenberg Tracking Station (VTS), Diego Garcia Station (DGS), Guam Tracking Station (GTS), Hawaii Tracking Station (HTS), New Hampshire Tracking Station (NHS), Thule Tracking Station (TTS) and Telemetry and Commanding Station (TCS) at RAF Oakhanger, England -- to ensure global coverage for over 170 satellites in various orbits operating in a congested and contested environment. The SCN conducts an average of 450+ satellite contacts per day supporting Positioning, Navigation and Timing (PNT), Intelligence, Surveillance and Reconnaissance (ISR), Missile Warning and Missile Defense, Communications, Weather, Launch Vehicle Support, and Research and Development (R&D) for Department of Defense (DoD), Intelligence Community (IC), and National Aeronautics and Space Administration (NASA) operations. While most of the 450+ daily satellite contacts are routine command and control (C2) activities, the SCN is also used during satellite emergencies (e.g. a tumbling satellite) because its high-power antennas are often the only terrestrial assets that can re-establish contact with a non-responsive satellite. During each Fiscal Year, the SCN typically supports multiple space vehicle emergencies, resulting in the preservation of over 4B worth of satellites. In addition to routine and emergency satellite operations C2, the SCN provides support to launch and early orbit operations, ensuring worldwide telemetry during launch vehicle ascent, staging, and orbital insertion, and data transmit and receive for new satellites completing early orbit checkout. During each Fiscal Year, the SCN supports multiple launches delivering an average of 14B worth of satellites to their operational orbits. Finally, the SCN provides Factory Compatibility Testing (FCT) to ensure satellites and launch vehicles can communicate via the SCN before the satellite is launched. The meshONE-Terrestrial (meshONE-T) system, like the SCN ground terminal network, provides an enterprise capability for USSF and other customers. meshONE-T nodes, located at USSF and other mission partner military installations (e.g., USSF and USAF bases), remote sensor, operational, and system development locations, utilize diversified long-haul communication circuits to provide high speed, scalable, resilient, cyber-secure transport services for mission data producers and consumers. These services are operated and managed via Enterprise Service Desk (ESD) / Network Operation Center (NOC) sites. The multi-tenant, mission-agnostic system uses Commercial Off The Shelf (COTS)-based solutions and industry standard protocols to move data traffic quickly, efficiently, and securely across the Internet Protocol (IP)-based network architecture. The meshONE-T effort proliferates nodes, long-haul communications links, and cloud services connections, to mission partners and locations around the globe, in accordance with warfighter priorities. To meet the needs of the Combatant Commands—with specific focus on USINDOPACOM and USEUCOM—modern mission data transport services will support Next-Gen and Future Operationally Resilient Ground Evolution (FORGE) Overhead Persistent Infrared (OPIR), Advanced Battle Management System (ABMS), Missile Track Custody (MTC), Space Domain Awareness (SDA), SCN, USSF Integrated Operations Network (ION), Launch and Test Range System (LTRS), and other mission partners. Supplementary/backup NOCs, communication links, bandwidth upgrades, and system improvements increase global operational reach, resiliency, and responsiveness to support warfighter operations through all phases of conflict. Software- defined networking capabilities accelerate onboarding of new mission partners and the delivery of transport services, providing the agility necessary to counter emerging Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:           PE 1203110SF / Satellite Control Network (SPACE) Operational Systems Development threats. meshONE-T resolves current space mission network shortfalls including antiquated protocols, bandwidth constraints, lack of resiliency, cyber vulnerability, and excessive fielding times. All mission partners using meshONE-Terrestrial (meshONE-T) will become part of the USSF ground network enterprise, with access to every node and network-provided cyber-secure services. These funds are utilized to meet evolving future space demands for Data Transmit Receive Network (DTRN), to include transmit, receive and data transport to ensure capabilities are available to support Department of Defense (DoD), Intelligence Community (IC), and civil users. This includes efforts to provide more capable ground- based antennas, augment the existing Satellite Control Network (SCN) with Federal and commercial antennas to both diversify space-ground link resources and increase capacity for spacecraft communication, modernize satellite scheduling, and develop infrastructure network solutions for long-haul terrestrial communications compatible with Air Force and Space Force missions. Other activities include identifying shared/common platform, infrastructure and data layer solutions to support open frameworks and architectures across the enterprise ground portfolio. Funds are also used for requirements management, system planning, enterprise analysis and architecture support, Systems Engineering and Integration (SE&I), cyber security, test, system enhancement and deficiency resolution, and system resiliency. This program element may include necessary civilian pay expenses required to manage, execute, and deliver SCN weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 93780000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203154SF_671112$$, $$1203154SF$$, $$671112$$, $$Moving Target Indicator$$, 0, $$The space-based GMTI system will replace a portion of the aging E-8C JSTARS sensing capability, based upon the Space Warfighting Analysis Center's (SWAC's) analysis of alternatives assessment completed in September 2022. Proper funding is critical to ensure this system is in place to support the warfighter before all JSTARS aircraft retire. Space-based GMTI is not a one-for-one swap for the E-8 JSTARS slated to retire, but rather an evolved weapon system that serves as the next generation moving target indicator for the warfighter. GMTI capability will be critical to tracking surface targets in Competition, Crisis, and Conflict environments. This will be accomplished from space, instead of from JSTARS aircraft which will not be capable of operating in a contested/non-permissive environment. Space-based GMTI will provide another way to harness data from the space domain and incorporate it into the secure cloud environment underpinning the ABMS to sense, make sense, and act faster than our adversaries. The Department of the Air Force will maximize partnerships with the Intelligence Community (IC) and use of mature commercial technologies to accelerate the acquisition timeline and meet the GMTI needs of the warfighter. Moved to PE 1203155SF to align with the rest of the program's budget.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203154SF_671113$$, $$1203154SF$$, $$671113$$, $$Auxiliary Payloads$$, 1916000, $$In FY 2026, Project 67113 Auxiliary Payloads was erroneously transferred to Program Element 1203609SF. This funding will be realigned back to PE 1203154SF for proper execution following enactment. The Auxiliary Payloads project provides the additional communication relay space vehicles required to increase system access and capacity to the levels required to enable warfighters with the capability to rapidly move target data around the globe and execute long range kill chains.$$, 1916000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203155SF_671120$$, $$1203155SF$$, $$671120$$, $$Ground Moving Target$$, 1063384000, $$The space-based Ground Moving Target Indicator (GMTI) project provides resources to acquire the next generation radar satellite system, providing resilient day-night, all weather detection, tracking, and imagery of ground and maritime targets. The GMTI project focuses on improving target detection, custody, and sensor-to-shooter timelines necessary for dynamic targeting and long-range strike within highly contested and non-permissive environments. The Space Force is working collaboratively with the military services, Combatant Commands, and the Intelligence Community to deliver and field the GMTI project. Additional details can be provided under separate cover. Note: this effort was previously completed under 1203154SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 1063384000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203164SF_643833$$, $$1203164SF$$, $$643833$$, $$MILITARY GLOBAL$$, 175304000, $$The Global Positioning System (GPS) is a space-based radio Positioning, Navigation, and Timing (PNT) distribution system. GPS User Equipment (UE) consists of standardized receivers, antennas, antenna electronics, and other related equipment, grouped together in sets to derive navigation and time information transmitted from GPS satellites. These receiver sets are used by the Department of Defense (DoD). Research, Development, Test and Evaluation (RDT&E) funds UE development, integration, test, and analysis for new PNT receiver capabilities in Navigation Warfare (NAVWAR) across all military platforms using GPS services. The Military Global Positioning System User Equipment (MGUE) Increment (Inc) 1 program is responsible for the development of standard modernized receiver form factors for the lead platforms. The MGUE Inc 1 Capability Development Document (CDD) was approved by the Joint Requirements Oversight Council (JROC) on 24 July 2014. MGUE Inc 1 is initiating a new family of modernized GPS receivers that will deliver significantly improved capability to counter current and emerging PNT threats and enable military operations in a NAVWAR environment where current legacy receiver performance would be compromised. MGUE Inc 1 received a Milestone A decision in April 2012. The program received direction in February 2014, from the Under Secretary of Defense for Acquisition, Technology, and Logistics (USD(AT&L)) to execute a new acquisition strategy, accelerating the program to provide test units faster to facilitate military end users. The MGUE program received a Milestone B decision in January 2017. The MGUE Inc 2 effort will continue to expand Military-Code (M-Code) receiver technology into additional applications (precision guided munitions) and develop a Joint Modernized Handheld (JMHH) device and Aviation/Maritime receiver to meet Service requirements and address obsolescence. This effort leverages the MGUE Inc 1 technology to the maximum extent while addressing the production of M-Code integrated circuits far into the future. The MGUE Inc 2 is being executed in four parts: 1) Risk Reduction Activities, 2) Miniature Serial Interface (MSI) Receiver Card Middle Tier Acquisition (MTA) rapid prototyping followed by 3) Software Acquisition Pathway (SWP) and 4) Joint Modernized GPS HH Receiver Middle Tier Acquisition (MTA) rapid prototyping effort. The JROC approved the MGUE Inc 2 CDD on 6 April 2018. The Air Force Service Acquisition Executive approved the MGUE Inc 2 Acquisition Strategy to include designation of two MTA Rapid Prototype efforts: 1) MSI Receiver Cards to include Next-Generation (Next Gen) Application Specific Integrated Circuit (ASIC) and 2) Joint, Modernized Handheld Receiver. The SAE has approved the transition to a SWP following completion of MSI MTA to finish MSI development. Additionally, the MGUE Inc 2 program received direction for the study of an MGUE Inc 2 Aviation/Maritime receiver program and development of an acquisition strategy based on ASIC obsolescence for Inc 1. The MGUE Inc 2 MSI RP program is not fully funded across the Future Years Defense Program. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:         PE 1203164SF / NAVSTAR Global Positioning System (User Equipment) (SPACE) Advanced Component Development & Prototypes (ACD&P) This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 175304000, NULL, NULL, NULL, NULL, 1158922000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203174SF_674671$$, $$1203174SF$$, $$674671$$, $$Enterprise Training Services$$, 72164000, $$In concert with PE 1206759F, Project 664598, NSTTC, Enterprise Training Services Development (ETSD) builds combat-ready forces by delivering enterprise training capabilities in alignment with the OTTI SRD. ETSD capabilities enable Guardians to train and develop tactics in an operationally relevant environment. Capabilities are delivered via technology such as: - mission-specific simulators for weapons system operations training and threat/scenario-driven training and tactics development - threat-representative models of adversary capabilities - synthetic, physics-based digital environments capable of conducting multi-mission and multi-user full-force distributed combat training and exercises - artificial intelligence to augment Guardians playing aggressor roles in training and exercise scenarios - synthetic environment visualizations and friendly/adversary/integrated operational pictures - networks and Information Technology (IT) required to deliver the above capabilities and interoperate with other joint acquisition, test, training, exercise, and exercise platforms and tools Rapidly respond to implement system resiliency and situational awareness necessary to operate in the contested space domain. Activities may include, but are not limited to program office support, studies, technical analysis, experimentation, risk reduction, prototyping, and activities that may leverage commercial, U.S. Government partnership, and international opportunities to respond to existing and emerging adversarial threats with speed and agility.$$, 72164000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203176F_654522$$, $$1203176F$$, $$654522$$, $$CSAR EMD$$, 0, $$The Combat Survivor Evader Locator (CSEL) System provides aircrews with end-to-end global satellite secure emergency communication capability during combat and peace-time flying operations. CSEL provides a hand held radio as part of the mandatory aircrew survival gear. CSEL is a joint program (Air Force, Army, Navy, and US Marine Corps) and is the DoD program of record for personnel recovery survival radios. CSEL supports four of five Personnel Mission Phases: Report, Locate, Support, and Recover. A National Security Agency (NSA) Cryptographic Modernization mandate and the Ultra High Frequency Follow-On satellite constellation are at the end of life and are driving upgrades to base stations. This effort includes development to modernize the system to integrate common waveforms, integrate broadcast reception for non- CSEL devices. A portable interrogator will precisely locate the IP using the CSEL architecture without extensive audio communications that could compromise both rescue forces and IP. The portable interrogator will enable communication between IP and any designated aircraft not equipped with a AN/ARS-6 PLS Lightweight Airborne Radio System (LARS) or similar device as a Rescue Support Force (F-35, F-16, F-15E, Ground Teams etc.) asset. This program element may include necessary civilian pay expenses required to manage, execute, and deliver CSEL capabilities. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605826F, 0605827F, 0605828F, 0605829F, 0605830F, 0605831F, 0605832F, 0605898F, and 0605833F. In FY 2024, $0.000M was expended for civilian pay expenses in this program element and in FY 2025 $0.000M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System      PE 1203176F / Combat Survivor Evader Locator Development & Demonstration (SDD)$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203182SF_674137$$, $$1203182SF$$, $$674137$$, $$Launch and Test Range$$, 54996000, $$The Spacelift Range System (SLRS), also known as the Launch and Test Range System (LTRS), provides public safety and assured access to space. LTRS operates at the Eastern Range (ER) at Patrick SFB/Cape Canaveral SFS, FL and the Western Range (WR) at Vandenberg SFB, CA. LTRS provides tracking, telemetry, communications, flight safety, and other capabilities to support launch of national security space (NSS), civil and commercial space payloads, Intercontinental and Sea Launched ballistic missile and missile defense evaluations, and aeronautical and guided weapon tests. LTRS ensures ability to meet the national launch requirement, safely supports the launch cadence of ER/WR launch requirement holders and provides assured access to space for the nation. The ER and WR are designated as Department of Defense Major Range and Test Facility Bases (MRTFB). To meet evolving technological requirements and Spaceport of the Future guidance, LTRS rebalanced funding from a predominantly Procurement focused appropriation to a balanced appropriation mix of Procurement and RDT&E funding through a Zero Baseline Transfer FY 2025 and beyond. This realignment of appropriations ensures requirements expend against the appropriation most suited for the type of development work required for mission fulfillment. No requirements planned for Procurement obligations were sacrificed to achieve this shift in funding profile, but a large subset of these requirements to modernize Range Instrumentation and associated services were moved to the software acquisition pathway effort as core capabilities. LTRS is comprised of 12 subsystems that together provide this capability to the ranges. The Range Safety, Command Destruct, and Positive Control subsystems provide the capability to destroy an errant rocket, if necessary to protect public safety. These subsystems rely on the Telemetry, Radar, and Optics subsystems to provide tracking data. The Weather and Surveillance subsystems allow range operators and customers to determine if conditions are safe for launch. The Communications, Data Handling, and Timing & Sequencing subsystems ensure critical data is expeditiously routed from remote sensors (e.g., radars, optics) to range operators and customers. Finally, the Planning and Scheduling subsystem ensures all assets are available when needed for a launch or test operation. The shift from the LTRS program into the Spaceports of the Future (SOTF) will be accomplished over the coming years through capability transformation. The Space Force requires RDT&E funds to conduct LTRS Digital Transformation studies, prototype experimentation, and developmental test activities to meet evolving technological requirements. These activities will constitute the shift from Range systems alone, to integrated Spaceports while remaining operational. The Commander's SOTF vision supports the increased launch tempo and volume, while meeting technological demands of the Spaceport customer base. The transformation will entail data capability pathfinding, integrating existing systems to emerging technologies through prototype activities, and development of unique-fit solutions. Specifically, funds will provide engineering analyses for insertion of promising technology, provide opportunity to test Cloud infrastructure and software development strategies to drive state-of-the-art applications into LTRS development, validate pathfinder concepts to meet an accelerating launch capacity and cadence, improve system cyber Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:             PE 1203182SF / Spacelift Range System (SPACE) Operational Systems Development survivability and resilience, and continue to evaluate promising technology beyond current industry standards. Digital Transformation drives automation and system autonomy into LTRS operations for seamless launch and return operations and accelerates capability to Range users through adoption of modern systems, platforms and processes. This program element may include necessary civilian pay expenses required to manage, execute, and deliver LTRS Critical Space Operations capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 54996000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203269SF_653170$$, $$1203269SF$$, $$653170$$, $$GPS IIIF$$, 116829000, $$The Global Positioning System (GPS) is a space-based navigation system that fills validated Joint Service requirements for worldwide, accurate, common grid three- dimensional positioning/navigation for military aircraft, ships, and ground personnel. The consistent accuracy, unaffected by location or weather and available in real time, significantly improves effectiveness of reconnaissance, weapons delivery, mine countermeasures and rapid deployment for all services. GPS must comply with Title 10 United States Code (USC) Sec. 2281, which requires that the Secretary of Defense ensures the continued sustainment and operation of GPS for military and civilian purposes, and 51 USC Sec. 50112, which requires that GPS complies with certain standards and facilitates international cooperation. The system is composed of three segments: User Equipment (funded under Program Element (PE) 1203164F, 1203164SF), Space (funded under PE 1203165F, 1203265F, 1203265SF, 1203269F, and 1203269SF), and a Control Network (funded under PE 1206423F, 1206423SF and 1203165F). The satellites broadcast high accuracy data using precisely synchronized signals that are received and processed by user equipment installed in military platforms. The user equipment computes the platform position and velocity and provides steering vectors to target locations or navigation waypoints. The control segment provides daily updates to the navigation messages broadcast from the satellites to maintain system precision in three dimensions to 16 meters (spherical error probable) worldwide. Additionally, GPS supports the United States (US) Nuclear Detonation (NUDET) Detection System (USNDS) mission and provides strategic and tactical support to the following Department of Defense (DoD) missions: Joint Operations by providing capabilities for Positioning, Navigation, and Timing (PNT); Command, Control, Communications, and Intelligence (C3I); Special Operations; Military Operations in Urban Terrain (MOUT); Defense-Wide Mission Support (DWMS); Air Mobility; and Space Launch Orbital Support. GPS III Follow On (GPS IIIF) delivers improved satellites beyond the first ten GPS III Space Vehicles (SVs) being delivered (funded in PE 1203265SF GPS III Space Segment). While GPS IIIF satellites maintain the same capabilities as the GPS III satellites, they deliver significant enhancements to include: potential on-ramping of advanced PNT technology from efforts such as the Navigation Technology Satellite 3 (NTS-3), backward compatibility, Unified S-Band (USB) interface compliance, integration of hosted payloads including a redesigned USNDS payload, Laser Retro-reflector Arrays (LRAs), Search and Rescue/GPS (SAR/GPS), and Regional Military Protection (RMP) capabilities that provide the ability to deliver high-power regional Military Code (M-Code) signals in specific areas of intended effect. Implementation of RMP into the GPS Enterprise requires integration with the ground and user segments, executed by the GPS Next Generation Operational Control System (OCX), along with the Military GPS User Equipment (MGUE) programs, respectively. The SAR/GPS payload provided by Canada fills a validated National Search and Rescue Committee requirement to provide enduring, space-based distress alerting capability to detect, locate, and relay distress alerts to fulfill its responsibilities under international agreements for Search and Rescue. LRA, built by the Naval Research Lab (NRL), is a passive reflector that improves accuracy and provides better ephemeris data. National Geospatial-Intelligence Agency (NGA) funds the integration costs of the LRA.$$, 116829000, NULL, NULL, NULL, NULL, 696676000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203269SF_653171$$, $$1203269SF$$, $$653171$$, $$GPS Enterprise Integration$$, 62420000, $$The Global Positioning System (GPS) Program Office established and maintains the technical baseline and is responsible for the successful fielding of all the GPS Segments (space, control, and user). In order to successfully execute these responsibilities, GPS Enterprise Integrator (EI) creates an enterprise architecture, integrates segment products, verifies the enterprise requirements are adequately met, develops and implements various Systems Engineering documents, defines methods of verification, conducts integrated system test and test analysis, develops and manages the Enterprise technical baseline which reflect multiple stakeholder requirements; stakeholders include the Department of Defense (DoD), foreign governments, industry, and the general public (through four public interface specifications). Furthermore, GPS EI ensures Positioning, Navigation, and Timing (PNT) capabilities meet the warfighter's, civil agencies, commercial entities, international treaties, and over four billion global GPS users needs. Moreover, GPS EI is responsible for delivering a reliable PNT signal capability to military operators, the civil user community, and international partners. In addition, GPS EI validates the system performance in various mission threat scenarios during its development as well as provides in-depth technical expertise to enhance government control, oversight and program accountability. GPS EI is also responsible for all aspects of schedule and technical alignment across the GPS segments (space, control, and user equipment). In order to assist in achieving program milestones, GPS EI is responsible for technical baseline management, integration, synchronizing, testing, and verifying GPS III, GPS III Follow-on (IIIF), Operational Control System (OCS), Next Generation Operational Control System (OCX), Military GPS User Equipment (MGUE) Increment (Inc) 1 and Inc 2, and other PNT investment projects. Additionally, GPS EI is responsible for creating and managing plans that provide early exercise of the products under development, compatibility analysis, and inter-segment testing. The inter-segment tests are required to prove OCX interoperability with GPS III satellites and Modernized User Equipment. More importantly, it ensures backwards compatibility with legacy systems such as GPS Block II satellites, OCS, and legacy user equipment. The GPS EI also manages the process through which the Joint Requirements Oversight Council validated requirements are matured and flowed down to the system segments, while remaining consistent with various interfaces. This enables the GPS system to meet Title 10 of the USC, Sec 2281, mandated PNT capabilities, and various other obligations to the international community that provide inter-operable PNT signals. GPS EI also supports GPS spectrum protection at international forums such as the International Telecommunications Union. Such support consists of providing technical support to the Departments of State and Defense to advocate on behalf of the US Government when negotiating with foreign partners. In addition, GPS EI provides technical expertise to maintain relationships with other US government agencies that include the Federal Aviation Administration, National Geospatial- Intelligence Agency (NGA), National Aeronautics and Space Administration, and Departments of State, Transportation, Homeland Security, and Commerce. GPS EI Spectrum also ensures GPS priority for eight essential spectrum signals, including those required for civil air navigation and safety of life. Spectrum Protection prevents encroachment from commercial or foreign entities, which results in the preservation of warfighter's reliable signal. As a result, military operations and the integrity of the global economic infrastructure are protected.$$, 62420000, NULL, NULL, NULL, NULL, 57816000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203609SF_670009$$, $$1203609SF$$, $$670009$$, $$Auxillary Payloads$$, 236720000, $$In FY 2026, funds were erroneously transferred into Program Element (PE) 1203609SF, pLEO SATCOM (MILNET) from PEs 1203154SF, Long Rang Kill Chains & 1206427SF Space Systems Prototype Transitions. This funding will be realigned back to PE 1203154SF & 1206427SF for proper execution following enactment.$$, 236720000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203609SF_670010$$, $$1203609SF$$, $$670010$$, $$Space-to-Space Communications$$, 40687000, $$In FY 2026, funds were erroneously transferred into Program Element (PE) 1203609SF, pLEO SATCOM (MILNET) from PEs 1203154SF, Long Rang Kill Chains & 1206427SF Space Systems Prototype Transitions. This funding will be realigned back to PE 1203154SF & 1206427SF for proper execution following enactment.$$, 40687000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203610K_NS01$$, $$1203610K$$, $$NS01$$, $$Resilient Ground Infrastructure$$, 24319000, $$The Department of Defense (DoD) relies heavily on satellite communications (SATCOM) and DISA is committed to improving the resilience of the ground infrastructure for this critical capability. A key component of this effort is strategic investment in Research, Development, Test & Evaluation (RDT&E) to develop innovative solutions that enhance the resiliency, and redundancy of the DoD SATCOM ground infrastructure. RDT&E funding is required for developing the ground infrastructure management and control capability with and its interface to Enterprise Satellite Management and Control (ESC-MC), Medium Earth Orbit (MEO) integration, and Low Earth Orbit (LEO) integration. To realize the promise of the ESC-MC Reference Architecture, DISA will invest in developing the ground management and control capability for the Joint SATCOM Teleports and interfacing it with the Enterprise Satellite Management and Control (ESC-MC) capability. This will provide a common operating picture, improve network orchestration, and enable automated SATCOM resource allocation. The integration of MEO satellite services offers the potential for increased bandwidth, reduced latency, and improved coverage. To capitalize on these advantages, RDT&E funding will be allocated to research and determine the best methods for integration of commercial MEO services into the DoD SATCOM Enterprise through the Joint SATCOM Teleports. Similar to MEO, the integration of LEO satellite services offers unique advantages, including low latency and with some systems, coverage over the Arctic and Antarctic that is at best marginal when using satellites in geosynchrous orbit. To leverage these capabilities, RDT&E funding will be used to research and determine the optimal methods for facilitating the integration of commercial LEO services into the DoD SATCOM Enterprise.$$, 24319000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203622SF_646021$$, $$1203622SF$$, $$646021$$, $$Space Warfighting$$, 0, $$This Program Element (PE) 1203622, Space Warfighting Analysis Center (SWAC) funds increased scope towards capability area analyses and integration, modeling, integrated modeling & analysis, and experimentation to create operational concepts and force design guidance for existing and emerging USSF missions. These analyses efforts team with relevant stakeholders across the National Security Space enterprise from an independent perspective and will provide analytic insight to the Service to inform and/or validate solutions to operational needs and provide a basis for future capability development programs. USSF force design analyses are organized into three focus areas: Multi-Domain Sensing, Spectrum Warfare, and Force Design Integration which are aligned to USSF priorities, and follow a disciplined approach to discover, analyze, and validate concepts and the associated family of systems required to satisfy current/future mission needs while including comprehensive threat analysis. The resulting force design products will help define and inform future USSF mission requirements, capabilities/architectures, priorities and funding needs, and interface standards. This program element includes necessary emergent/unanticipated civilian pay expenses required to manage and execute the force design mission assigned to the SWAC and/or deliver products for evolving weapon system capabilities. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 6:          PE 1203622SF / Space Warfighting Analysis RDT&E Management Support$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203710SF_643730$$, $$1203710SF$$, $$643730$$, $$EO/IR Weather System$$, 77135000, $$In compliance with the 2015, 2016, 2017, and 2020 National Defense Authorization Act (NDAA) and Joint Requirements Oversight Council (JROC) Memos 092-14, 062-17, and 031-22, EWS will provide global 24/7 persistent coverage to meet Space-Based Environmental Monitoring (SBEM) Electro-Optical/Infrared (EO/IR) Gaps 1) Cloud Characterization (CC) and 2) Theatre Weather Imagery (TWI). This capability will operationally replace the obsolete and aging Defense Meteorological Satellite Program (DMSP) projected end-of-life Sep 2026 due to insufficient ops and sustainment funding for continued operations, and the EWS-Geostationary (EWS-G) projected end-of-life Sep 2030. Without the CC and TWI data, production of global predictive cloud and terrestrial weather data will be severely impacted, affecting daily air operations and intelligence gathering for strategic mission planning. Moreover, INDOPACOM, CENTCOM, and AFRICOM will be unable to forecast and monitor adverse weather conditions over eastern Africa and the Indian Ocean. Lastly, the US will not meet the DoD responsibility of maintaining the SBEM civil/international partnership for the Family of Systems architecture without timely delivery of a replacement system. Based on SBEM Capability Assessment and Strategy Review (CASR) in April 2019, the current EWS acquisition strategy focuses on a distributed LEO architecture, for scalability and increased operational resilience. The Space Force will pursue prototyping of latest industry capabilities for simplified sensor designs, while meeting CC and TWI requirements and data latencies in a distributed architecture. This program element may include necessary civilian pay expenses required to manage, execute, and deliver EWS for weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. Rapidly respond to implement system resiliency and situational awareness necessary to operate in the contested space domain. Activities may include, but are not limited to program office support, studies, technical analysis, experimentation, risk reduction, prototyping, and activities that may leverage commercial, U.S. Government partnership, and international opportunities to respond to existing and emerging adversarial threats with speed and agility. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:             PE 1203710SF / EO/IR Weather Systems Advanced Component Development & Prototypes (ACD&P)$$, 77135000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203873SF_674820$$, $$1203873SF$$, $$674820$$, $$Sensor Development$$, 0, $$COBRA DANE (CD) radar is located 200 miles from Russia, at Eareckson AS, AK (Shemya Island, AK). CD is the most powerful, sensitive, and accurate Ground-based Mid-course Defense (GMD) radar and the premier Ballistic Missile Defense (BMD) radar. At the same time, it is the most accurate and capable phased array available to the Space Surveillance Network (SSN) for cataloging hazardous and difficult-to-track satellites and space debris objects that clutter the near-earth orbital regime that cannot be detected by most other SSN tracking assets. CD detects Intercontinental Ballistic Missiles (ICBMs) and Sea-Launched Ballistic Missiles (SLBMs), classifies reentry vehicles (RVs) and other missile objects, provides real-time information to the GMD Fire Control (GFC), and provides tracking of threat ballistic missiles with sufficient accuracy to commit the launch of interceptors and to update the target tracks to the interceptor while the interceptor is in flight. CD's other primary mission is to support US Space Command's (USSPACECOM) Space Domain Awareness (SDA) mission by detecting, tracking, correlating, and characterizing man-made resident space objects, primarily in the Low-Earth Orbit (LEO) regime, including space debris and early observation of New Foreign Launches (NFLs). It operates as part of the larger SSN and provides metric observation data to its command and control nodes: the Combined Space Operations Center (CSpOC) and the Distributed Space Command and Control - Dahlgren (DSC2-D). CD also supports USSPACECOM's Space Object Identification (SOI) mission by providing narrow-band radar data of man- made resident space objects in the LEO regime. SOI information is used to ascertain the mission and operational status of various payloads and aids in forecasting maneuvers or deorbits. CD will acquire a modern architecture through design, development, integration, and test. This architecture enhances mission capability, providing warfighter and stakeholder customers direct operational benefit. CD utilizes Federally Funded Research and Development Centers (FFRDC), Systems Engineering and Integration (SE&I), University Affiliated Research Center (UARC), and Assistance and Advisory Services (A&AS) contractors to support programmatic and technical activities. Activities include studies and analysis to support both current program planning and execution and future program planning. Specifically, the Automated Data Processing Equipment (ADPE) Rehost program upgrades the CD system's radar back-end mission data processing, radar management and control, and signal processing capabilities to a modern architecture that facilitates long-term mission resiliency, cyber security, system viability, high operational availability, and rapid hardware and software development and deployment capability. RDT&E funds were provided to the Missile Defense Agency (MDA) to accelerate the joint Department of the Air Force and MDA modernization program of the CD radar. In addition to funds being used to modernize this back end of the radar, these funds will also be used for out-year planning of front-end component modernization including enhancement of communication elements. The PARCS Radar Digitization Upgrade Study will determine the requirement to modernize the radar through a systematic re-architecture from an analog infrastructure to a digital phased array radar to keep up with modern threats. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:              PE 1203873SF / Ballistic Missile Defense Radars Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver Ballistic Missile Defense Radars weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203913SF_672808$$, $$1203913SF$$, $$672808$$, $$Nuc Detonation Det Sys$$, 96836000, $$Universal Ground NDS Terminal (UGNTs) 7 modernization effort, a FY26 new start, is the USG's only Survivable/Endurable (S/E) system capable of processing United States Nuclear Detonation (NUDET) data from the next-gen NDS payloads on GPS IIIF. Obsolete hardware and software will be replaced within the UGNT trailers. Integrated Correlation and Display Systems (ICADS 7) will be installed on the system enabling UGNT to be fully mission capable (FMC) and to download nuclear detonation data from GPS IIIF satellites enabling DoD and COCOM decision makers to have near-real time decision quality data for nuclear force management in support of the NC3 mission set. The NUDET Detection System (USNDS) provides a near real-time worldwide, highly survivable/endurable capability to detect, locate, and report any nuclear detonations in the earth's atmosphere or in near space. USNDS supports NUDET detection requirements across five mission areas: Integrated Tactical Warning and Attack Assessment (ITW/AA), Nuclear Force Management (NFM), Space Control, Treaty Monitoring, and a classified mission. The USNDS program is jointly sponsored and funded by the Department of Defense (DoD), through the Space Force, and the Department of Energy (DOE), through the National Nuclear Security Administration (NNSA) and its Nuclear Detonation Detection (NA-22) office, respectively. NNSA/NA-22 supplies USNDS space sensors as Government Furnished Equipment to the Space Force's USNDS Program Office, which is responsible for all acquisition and Systems Engineering, Integration and Test activities on Space Vehicles (SVs), to include Global Positioning System (GPS) and additional hosts, and their supporting ground control segments. The AF directly funds the development of the USNDS ground segment (described below). DoD funds their contribution to the USNDS program in Program Element 1203913SF, Research, Development, Test and Evaluation, Space Force (RDT&E, SF), Procurement, Space Force, and Operations and Maintenance. USNDS consists of space sensors and complex ground segments. The space segment sensors, funded by DOE, consists of three nuclear detection sensor payloads: the Radiation Detection Capability (RADEC) payload for Defense Support Program (DSP) satellites, the Global Burst Detection (GBD) payload for Medium Earth Orbit platforms (GPS satellites), and the Space Atmospheric Burst Reporting System (SABRS) payload for Geosynchronous Earth Orbit (GEO) platforms (classified GEO host), and Space Test Platform 3. Together, these sensors and associated communications capability provided by the host satellites comprise the global NUDET space segment detection capability for the USNDS. Space sensors communicate NUDET indications to the fixed ground segment, the RADEC Data Processor, and the Integrated Correlation and Display System (ICADS), the five deployable mobile ground segment survivable Ground Nuclear Detonation Detection System Terminals Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:          PE 1203913SF / NUDET Detection System (SPACE) Operational Systems Development (GNTs), and the survivable/endurable UGNTs, when operationally accepted. The ground segment provides ground receiving analysis and reporting capabilities to national authorities, commands, and forward users as well as Department of State for the Treaty Monitoring and Verification mission. The ground control segment is being modernized and continuously improved through an incremental, evolutionary acquisition approach. The upgrades to the GNTs are the survivable/endurable UGNT which are funded with RDT&E in this program. The UGNT provides NUDET Detection Reports to end users through survivable/endurable USNDS communications via MilStar/Future Communication Systems (FCS)/Advanced Extremely High Frequency (AEHF) circuits. The GNT supports ITW/AA and NFM missions. The UGNT program modifies the baseline of the GNT subsystem and deploys as an integral part of the Space Based Infrared System Survivable (SBIRS) / Endurable Evolution (S2E2) Mobile Ground System (MGS) (SMGS) units also in support of ITW/AA and NFM. The UGNT, when integrated with the SMGS, will perform NUDET event processing with fused NDS data from GPS and DSP. SMGS capability refers to the result of the S2E2 upgrade program for the MGS mission processing capability, including the integration of UGNT. The intended end state of UGNT integration is delivery of enhanced NUDET detection capabilities which meet survivable/endurable attack assessment requirements directed by the President, Secretary of Defense, Joint Staff, USSPACECOM, and USSTRATCOM, delivering long-term, cost effective, multi-role, multi-mission space effects to warfighters across the range of military operations. ICADS 7 upgrades the ICADS 6 baseline necessary to process future GPS IIIF satellites GBD USNDS messages, address technology obsolescence, and meet updated cybersecurity requirements for system resiliency. Universal Ground NDS Terminal (UGNTs) 7 are a component of the S2E2 Force Package (FPAK). UGNT upgrades will be of the S2E2 system. The UGNT hardware and software (ICADS 6) requires an upgrade to be compatible with GPS IIIF satellites. USNDS detect, identify, locate, and report nuclear detonations in earth's atmosphere or near-space in near real time from peacetime through nuclear conflict. UGNTs provide mobile S/E NUDET reporting capability. USNDS has five missions per operational requirement document (ORD); ITW/AA, Space Control, Nuclear Force Management, Treaty Monitoring & Classified Mission. UGNT 7 is dependent on firm CONOPS being established. This budget line includes systems engineering, research and development, on-orbit and field testing and end-to-end verification of USNDS space sensors, ground analysis and reporting systems in support of the five USNDS mission areas. Sensor integration for GPS III and GPS III Follow-on (IIIF) are funded in their respective programs. This program may include necessary civilian pay expenses required to manage, execute, and deliver NUDET Detection System (SPACE) weapon system capability. The use of such program funds is in addition to the civilian pay expenses budgeted in programs 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:         PE 1203913SF / NUDET Detection System (SPACE) Operational Systems Development$$, 96836000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203940SF_673940$$, $$1203940SF$$, $$673940$$, $$Space Data Fusion$$, 53959000, $$In FY 2026, Project 673942, Joint Commercial Operations efforts were transferred from Project 673940, Space Data Fusion to increase transparency. In FY 2026, Project 673943, Space Domain Awareness Network (SDANet) efforts were transferred from Project 673940, Space Data Fusion to increase transparency. Space Domain Awareness (SDA) is one of four U.S. Space Force Enterprise Functions and is defined as the ability to detect, characterize, attribute, predict, and target activities in the space domain to inform decision making. SDA is comprised of the following Enterprise Activities: Reconnaissance, Surveillance, Conjunction Assessment, Collision on Launch Assessment, Breakups, and Rendezvous and Proximity Operations Support. As the foundation for space control, SDA encompasses surveillance of all space objects and activities; detailed surveillance of specific space assets; monitoring space environmental conditions; monitoring cooperative space assets; gathering indications and warning on adversary space operations; and conducting integrated command and control (C2), communications, processing, analysis, dissemination, and archiving activities. Space Situation Awareness Operations (SSAO, 1203940SF) fields, upgrades, operationalizes, operates, and maintains Space Force sensors and information/data integration capabilities within the SDA network while companion program element Space Situational Awareness Systems (SSAS, 1206425SF) develops new network sensors and associated information integration capabilities across the network. Activities funded in this program (1203940SF) focus on surveillance of objects in earth orbit and beyond to aid tasks including satellite tracking; space object identification; tracking and cataloging; satellite attack warning; notification of satellite flyovers to U.S. forces; space treaty monitoring; and technical intelligence gathering. As a whole, this program upgrades, modifies, modernizes, operationalizes, fields, operates, and maintains sensors and information integration capabilities for an integrated, end-to-end SDA architecture that provides critical national security space solutions on tactical operational timelines. The Space Data Fusion (SDF) effort (673940) includes the Global Sensor Watch (GSW) program, which develops and/or upgrades SDA data collection and exploitation capabilities, including artificial intelligence/machine learning (AI/ML), as modernization and improvement efforts to operational SDA capability. GSW prototypes and provides initial operational capabilities enabling an integrated, end-to-end, SDA tip and cue capability that implements a resilient architecture providing overlapping, assured, and viable surveillance options for executing event response; SDA data processing at multiple classification levels; and automated, worldwide, cross-sensor tipping and cueing. The Space Communications Upgrades (SCU) Lighthouse project is a partnership effort with the Missile Defense Agency (MDA) for targeted sensor upgrades providing dynamic tasking integration and tactical data exposure to MDA systems focused on closure of specific near-earth SDA kill chains. This program may include necessary civilian pay expenses required to manage, execute, and deliver the weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF.$$, 53959000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203940SF_673941$$, $$1203940SF$$, $$673941$$, $$Unified Data Library (UDL)$$, 42945000, $$The Unified Data Library project (673941) supports integration, exploitation, and delivery of Space Domain Awareness (SDA) data sources for Command and Control (C2) and battle management of space forces. It focuses on enabling data sharing, establishing the data architecture required to aggregate multi-sensor data for broader use at different classification levels, transforming any-source data into normalized, usable information via data exploitation tools, followed by data hand off to Battle Management Command and Control mission systems to support actual space operations. The UDL will directly connect to dedicated USSF collateral, contributing and non-traditional sensors and systems with modernized interfaces and transport options to broadly expose data. The UDL will be the single source for accessing and managing all data in support of the USSF, providing a central location to find and access data, enabling superior analytics. This program may include necessary civilian pay expenses required to manage, execute, and deliver the weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF.$$, 42945000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203940SF_673942$$, $$1203940SF$$, $$673942$$, $$Joint Commercial Operations$$, 34381000, $$In FY 2026, Project 673942, Joint Commercial Operations efforts were transferred from Project 673940, Space Data Fusion to increase transparency. This is not a new start. The Joint Commercial Operations (673942) effort supports the Joint Commercial Operations (JCO) cell. The JCO's mission is to provide persistent and rapid SDA coverage to maximize decision making space and reduce reaction time in support of Protect & Defend missions. Joint Commercial Operations executes commercial data buys beyond protect and defend missions and supports existing capabilities through improvements to architecture and system efficiency, cybersecurity, migration to cloud computing, building on artificial intelligence and machine learning (Al/ML) initiatives, and expanding agile software development, delivery, and integration practices.$$, 34381000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203940SF_673943$$, $$1203940SF$$, $$673943$$, $$Space Domain Awareness Mesh$$, 47998000, $$In FY 2026, Project 673943, Space Domain Awareness Network efforts were transferred from Project 673940, Space Data Fusion to increase transparency. This is not a new start. The Space Domain Awareness Network (SDANet, 673943) effort was declared a Middle Tier Acquisition (MTA) rapid fielding program of record in FY 2024. It is deploying a modern end-to-end data delivery capability via resilient, distributed mesh network capability for the Space Surveillance Network (SSN) and other associated sensor, C2 and data nodes. SDANet supports existing capabilities through improvements to end-to-end architecture and data delivery efficiency and resiliency to enable modern C2 and Al/ML initiatives. SDANet enables Sensor-to-Sensor, Sensor-to-C2, and Sensor-to-Unified Data Library (UDL) end-to-end data flows revolutionizing the traditional vertical Sensor-to-C2 data flows to incorporate the ability to send and receive data laterally enabling space domain operations.$$, 47998000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203955SF_640016$$, $$1203955SF$$, $$640016$$, $$On Orbit Servicing, Mobility, and$$, 0, $$On-Orbit Servicing, Mobility, and Logistics advances neglected support capabilities in the space domain, ensuring asset availability to the warfighter. The initial thrust for On-Orbit SML is a service architecture ensuring prepared systems can replenish energy, as needed, to maintain operator proficiency and sustained readiness in a contested domain with flexibility to meet the increased challenges of conflict. This capability provides USSPACECOM the requisite supply chain to de-constrain operations currently limited by a fixed fuel budget, enabling movement and maneuver Dynamic Space Operations for critical National Security Space assets. Advancing an on-orbit refueling architecture enables a prepared architecture for subsequent On-Orbit SML lines of effort including mobility, relocation, repair and disposal. Additionally, as refueling requires the application of Rendezvous, Proximity Operations and Docking (RPOD) technology, the techniques, tactics and procedures (TTPs) attained through refueling simplify and accelerate subsequent capabilities. In tandem with efforts to qualify and onboard refueling onto a "services contract” for ongoing propellent replenishment missions, On-Orbit SML will maintain connectivity to the burgeoning commercial market to capitalize on industry advancement to qualify and onboard additional on-orbit capabilities as they mature. As an "anchor tenant” this may include providing last-mile development funding for government purpose modifications, demonstrations, landscape assessments and architecture development. Due to client variations in mission, orbit, configuration and security, On-Orbit SML services will not be a "one size fits all” approach and will require an enduring programmatic and systems engineering investment to meet customer requirements.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1203955SF_646601$$, $$1203955SF$$, $$646601$$, $$Point to Point Delivery (P2D)$$, 14478000, $$Point-to-Point Delivery (P2D) project builds upon prior S&T work within AFRL's Rocket Cargo Vanguard program, to develop and integrate P2D prototype systems to meet unique military use cases. The project seeks to influence and integrate relevant component technologies and systems from S&T to high-TRL prototypes that demonstrate military-unique applications and early operational capability. The project will also study and deliver initial concepts of operation and tactics development recommendations for future operational applications. This project matures game-changing technology to close space mobility and logistics capability gaps and promotes a strong resilient national space industrial base. The near-term focus of the P2D program is to establish the foundational capability areas through study and develop Point-to-Point Delivery (P2D) reference missions. The P2D project seeks to leverage commercially developed technology and integrate systems developed within the Rocket Cargo Vanguard program. P2D will identify and evaluate multiple Point to Point Delivery service and support providers including but not limited to responsive spacelift, precision downmass, ground support equipment, and both facilities and infrastructure upgrades to increase security, capacity, and readiness for emerging needs. The SML program provides a cost-effective investment method to cultivate relevant commercial space systems that have achieved high Technical Readiness Level (TRL) and can be leveraged to meet the needs of DoD components. Activities include Advanced Integrated Mission Studies (AIMS), system engineering technology maturation, tactics development required for operational integration, prototyping and test and evaluation required for technology transition to enable effective operational employment. The SML program will mature, integrate, and transition space system demonstrations and prototypes in order to: - Rapidly address identified capability gaps with emergent technologies - Focus and integrate Science & Technology (S&T) innovations into operational capabilities and transition those capabilities to space acquisition programs of record - Accelerate technical maturation of emerging technologies to close high-priority capability gaps to secure US overmatch against pacing threats - Provide targeted investment in the space industrial base to support U.S. National Security under Great Power Competition (GPC).$$, 14478000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206310SF_634869$$, $$1206310SF$$, $$634869$$, $$Space Science and$$, 459989000, $$The Space Development Agency (SDA) is developing and demonstrating next generation space capabilities for the joint warfighter enabled by proliferation of satellites and a new acquisition model utilizing rapid spiral development. SDA is developing capabilities to address a wide range of Department of Defense (DoD) space needs as stated in the National Defense Strategy and DoD Space Vision, including low-latency tactical communication, beyond line of sight targeting, and advanced missile tracking. Specifically, SDA will demonstrate and field persistent, resilient capabilities needed to be responsive to emerging multi-domain threats against the U.S. national interest. SDA is responsible for the overall programmatic development and execution of a Proliferated Warfighter Space Architecture (PWSA). In coordination with other DoD Space stakeholders, SDA will drive the development of space capabilities to achieve the DoD Space Vision and reduce overlap and inefficiency. SDA will expand the DoD's space warfighting capability and foster growth in the U.S. space industrial base, by developing enhanced government-commercial relationships and international collaborations with key allies and partners. While SDA is not responsible for building and fielding all capabilities within the PWSA, the Agency is responsible for orchestrating and architecting the PWSA and ensuring capability delivery to the warfighter following a spiral development approach. As part of the PWSA, SDA is building and fielding the Transport Layer, a proliferated constellation of satellites to provide low-latency, beyond line of sight (BLOS), high-volume data transport for the warfighter. This Transport Layer will provide the space-based connectivity backbone for Joint All-Domain Command and Control (JADC2). The establishment of a proliferated data Transport Layer is essential to developing a new and responsive space architecture. SDA will integrate additional constellations with this Transport Layer to provide multiple warfighting capabilities, such as advanced missile warning, 24/7/365 custody of time critical targets, and alternative position, navigation and timing (APNT) capabilities in navigation warfare (NAVWAR) resilient environments. This program element funds the research and development activity to deliver capabilities to U.S. joint warfighting forces in two-year tranches, which began in FY 2022, including performing trade studies, technical analyses, or modeling and simulation; identifying and maturing enabling technologies; defining and conducting risk reduction experiments and demonstrations, prototyping hardware or software systems; and exploring novel concepts for future warfighting capabilities. This program element may include necessary civilian pay expenses and contractor support required to facilitate delivery of the PWSA capability. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 3:           PE 1206310SF / Space Science and Technology Research and Development Advanced Technology Development (ATD) The FY 2026 cost of the Tranche 1 (T1) Transport Layer Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program funding in a future budget submission. The FY 2026 cost of the Tranche 2 (T2) Transport Layer Middle Tier of Acquisition effort is included in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program funding in a future budget submission. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, 459989000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206392SF_664280$$, $$1206392SF$$, $$664280$$, $$SMC Civilian Pay$$, 269162000, $$Space Systems Command (SSC) equips US and allied forces with operational space and missile systems, launch systems, and command and control infrastructure in support of global military and national security operations. SSC operates with over 6,300 people and an annual budget exceeding 6.4B providing joint warfighters navigation, communication, weather, warning, force application, and space control capabilities. SSC is authorized to employ approximately 1,611 civilian acquisition professionals providing the management, tools, and technical capabilities needed to oversee acquisition programs to include materiel solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel supporting the SBD3 at Los Angeles AFB. Funding SSC civilian payroll from the RDT&E appropriation provides program managers the flexibility to hire additional civilian personnel with program dollars versus additional contractors in concert with initiatives in response to the Defense Acquisition Workforce Improvement Act. This program element supports both civilian pay and non-pay support requirements. The FY 2026 projection is 269.162M. The projection is sufficient based on End-Strength, premium pay, performance, awards, and projected hires.$$, 269162000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206398SF_664280$$, $$1206398SF$$, $$664280$$, $$SMC Civilian Pay$$, 15356000, $$The Space Systems Command (SSC) equips US and allied forces with operational space and missile systems, launch systems, and command and control infrastructure in support of global military and national security operations. SSC operates with over 6,300 people and an annual budget exceeding 6.4B providing joint warfighters navigation, communication, weather, warning, force application, and space control capabilities. Program Element 1206398SF, Project: 664280 Space Systems Command - Major Headquarters Activities (MHA) was established to improve overall performance, strengthen business operations, and achieve efficiencies, effectives and cost savings that can be transferred to higher priority needs. PE adds approximately 80 acquisition professionals. In FY 2026 15.356 is forecasted to expense for civilian pay expenses in this program element. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, 15356000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206399SF_664111$$, $$1206399SF$$, $$664111$$, $$SSC Enterprise$$, 110598000, $$In 2021, the Space Force stood up Space Systems Command (SSC), including establishing the SSIO. In July 2024, the Assistant Secretary of the Air Force for Space Acquisition and Integration (ASAF) broadened SSIO's mission and designated SSIO as the responsible organization for integration across all Space Force Program Executive Officer (PEO) portfolios to include SSC, Space Development Agency (SDA), and the Space Rapid Capabilities Office (SpRCO). In April 2025, the ASAF also appointed the Senior Advisor to the Service Acquisition Executive, and in response to a 2025 NDAA requirement, the Senior Advisor for Space Command, Control, and Integration (SASC2I). The SASAE is the USSF lead for space enterprise system-of-systems engineering across the space acquisition enterprise and is responsible to drive engineering and assess all acquisition efforts under the authority of the ASAF portfolio and applicable mission partner organizations, to include the advisement of the SAE on matters of enforcement needed to enable and drive integrated enterprise capability delivery. The SASC2I is responsible for conducting oversight of all acquisition efforts within the authority of the ASAF with respect to developing, upgrading, deploying, and sustaining space command, control, and integration to meet the space command, control, and integration requirements of the combatant commands. SSIO conducts systems engineering analysis and integration for space programs and vastly increases collaboration across the entire USSF space enterprise to deliver fully integrated space warfighting capability. SSIO orchestrates end-to-end capability delivery and warfighter operations across all Space Force PEOs, Space Force Field Commands, Combatant Commands, and mission partners such as Department of the Air Force Rapid Capabilities Office (DAFRCO), the Missile Defense Agency (MDA), and the National Reconnaissance Office (NRO), and advises the ASAF on strategy to optimize PEO portfolios across all mission areas to meet warfighting needs. These efforts also provide systems engineering for the space component of the Command Control Communications and Battle Management (C3BM) program to deliver an integrated Command and Control architecture to support the joint fight. SSIO enterprise-level integration includes three lines of effort. The first is Enterprise Mission Integration and Analysis which supports a multitude of Space Force programs at all classification levels needed to close mission threads and kill chains across the USSF and deliver a cohesive warfighting technical baseline for the Nation. The second is Enterprise Technical Governance and Requirements management. The third is Space Futures which will define the future operating environment, prioritize science and technology initiatives, and wargaming required to refine operational concepts. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 6:            PE 1206399SF / SSC Enterprise Engineering & Integration RDT&E Management Support This program element may include necessary civilian pay expenses required to manage, execute, and deliver SSIO enterprise system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. FY 2026: Reduces contracts for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, 110598000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206410SF_643729$$, $$1206410SF$$, $$643729$$, $$Integration and Battle$$, 175037000, $$SDA is developing and demonstrating next generation space capabilities for the joint warfighter enabled by proliferation of satellites in Low Earth Orbit (LEO) and a new acquisition model utilizing rapid spiral development. SDA is developing capabilities to address a wide range of Department of Defense (DoD) space needs as stated in the National Defense Strategy and DoD Space Vision, including space-based battle management and a ground support infrastructure. SDA will orchestrate the rapid development and fielding of the Proliferated Warfighter Space Architecture (PWSA), a resilient military sensing and data transport capability via a proliferated space architecture in LEO. This program element funds the development and demonstration of space technologies to deliver space-based command and control, tasking, mission processing and dissemination capabilities, as well as an integrated, resilient network of ground support capabilities, to U.S. joint warfighting forces in bi-annual tranches, which began in FY 2022.$$, 175037000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206410SF_643731$$, $$1206410SF$$, $$643731$$, $$Transport$$, 1044112000, $$SDA is developing and demonstrating next generation space capabilities for the joint warfighter enabled by proliferation of satellites in Low Earth Orbit (LEO) and a new acquisition model utilizing rapid spiral development. SDA is developing capabilities to address a wide range of Department of Defense (DoD) space needs as stated in the National Defense Strategy and DoD Space Vision, including low-latency tactical communication enabling beyond line of sight targeting and advanced missile tracking. SDA is orchestrating the rapid development and fielding of the Proliferated Warfighter Space Architecture (PWSA), a resilient military sensing and data transport capability via a proliferated space architecture in LEO. This program element funds the development and demonstration of space technologies to deliver low- latency data transport and alternate position, navigation, and timing capabilities to U.S. joint warfighting forces in bi-annual tranches, which began in FY 2022.$$, 1044112000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206410SF_643732$$, $$1206410SF$$, $$643732$$, $$Sensing$$, 88821000, $$SDA is developing and demonstrating next generation space capabilities for the joint warfighter enabled by proliferation of satellites in Low Earth Orbit (LEO) and a new acquisition model utilizing rapid spiral development. SDA is developing capabilities to address a wide range of Department of Defense (DoD) space needs as stated in the National Defense Strategy and DoD Space Vision, including advanced missile tracking and global surveillance enabling beyond-line-of-sight targeting. SDA will orchestrate the rapid development and fielding of the Proliferated Warfighter Space Architecture (PWSA), a resilient military sensing and data transport capability via a proliferated space architecture in LEO. This program element funds the development and demonstration of space technologies to deliver advanced missile tracking, global surveillance and surface moving target custody, and enhanced space domain awareness and deterrence capabilities to U.S. joint warfighting forces in bi-annual tranches, which began in FY 2022.$$, 88821000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206415F_641234$$, $$1206415F$$, $$641234$$, $$USSPACECOM Rapid Prototype$$, 36913000, $$U.S. Space Command Research and Development support program integrates existing space-based capabilities from the Services and the Intelligence Community, overlaid with national laboratory and Commercial/Industry innovations, leveraging Joint Space rapid experimentation and demonstrations to build a comprehensive military advantage in Space. Promoting responsible behaviors in space, advocating for greater space capabilities, and collaborating with Industry partners are foundational to achieving National Space objectives. This shall be accomplished by accelerating technology demonstrations and rapid operational prototyping, plus assessing current and future space-based effects via model-based analysis. Moreover, this program supports the National Space Policy of the United States of America, "to demonstrate United States leadership in space-related fora and activities to strengthen deterrence and assure allies and partners of its commitment to preserving the safety, stability, security, and long-term sustainability of space activities." NAVWAR, the management of PNT information, requires a coordinated employment of space, cyberspace, and electromagnetic warfare (EW) capabilities, enabled by intelligence, surveillance, and reconnaissance (ISR) and electromagnetic spectrum (EMS) management. Funds are used to develop and integrate NAVWAR offensive and defensive capabilities and to create and maintain NAVWAR knowledge, and tactics, techniques and procedures (TTP) to ensure NAVWAR superiority across the DoD. Additional responsibilities include advocating for and providing space capabilities such as PNT information to CCMDs, allies, partners and other entities, as directed. The Lighthouse program shall integrate SDA net with all of the space domain awareness (SDA) sensors required to increase SDA data availability for kill chain closure. This includes upgrades to SDA coverage to reduce coverage gaps. Lack of funding for Lighthouse will result in sensors remaining on the legacy 1980s communication infrastructure whose data rates and data formats do not support timely transfer of information required to address.$$, 36913000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206425SF_656565$$, $$1206425SF$$, $$656565$$, $$Ground Based SDA$$, 0, $$Space Domain Awareness (SDA) is one of five core competencies of the Space Force and is the effective identification, characterization, and understanding of any factor, passive or active, associated with the space domain that could affect space operations and thereby impact the security, safety, economy, or environment of our nation. As the foundation for space control, SDA encompasses surveillance of all space objects and activities; detailed surveillance of specific space assets; monitoring space environmental conditions; monitoring cooperative space assets; gathering indications and warning on adversary space operations; and conducting integrated command, control, communications, processing, analysis, dissemination, and archiving activities. This program element develops, tests, upgrades and fields new SDA capabilities across the space surveillance network (SSN) while companion program element 1203940SF develops, fields, and operationalizes sensor networks and information integration capabilities. Activities funded in this program element (1206425SF) also support efforts such as engineering studies and analyses, architectural engineering studies, trade studies, technology needs forecasting, modernization initiatives, systems engineering, system development, and test & evaluation. Activities may include prototyping and technology demonstration(s). Deep Space Advanced Radar Capability (DARC) is a ground-based, SDA radar system that detects, tracks, and maintains custody of deep space objects 24/7 in all weather and through the solar exclusion gap. DARC will augment the Space Surveillance Network as an additional sensor with increased capacity and capability for deep space object custody, providing full global coverage. DARC Site 1 was initially awarded as a Middle Tier Acquisition (MTA) Rapid Prototype. On 22 May 2024, the Service Acquisition Executive (SAE) approved successful completion of the DARC Site 1 prototype and transitioned the program to be a Major Capability Acquisition (MCA) to complete development and operationally field DARC Sites 1 (Australia), Site 2 (United Kingdom), and Site 3 (United States). The FY 2026 request for DARC includes $0 thousand discretionary funds and $281,861 thousand of mandatory (reconciliation) for a total of $281,861 thousand. The mandatory funds continue construction and integration of Site 1, and development of Site 2. Further information for this reconciliation request is provided in Section 20009 (INDOPACOM Capabilities) of the Reconciliation Exhibit. This program element may include necessary civilian pay expenses required to manage, execute, and deliver DARC weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206427SF_645601$$, $$1206427SF$$, $$645601$$, $$Space-to-Space Communications$$, 65246000, $$The Space Defense Capabilities project prototypes technologies for insertion into programs of record and provides platforms to operate prototypes in space. The Long Duration Propulsive Evolved Expendable Launch Vehicle Secondary Payload Adapter (abbreviated LDPE) and Rapid On-Orbit Space Technology Evaluation Ring (ROOSTER) provide a low-cost, rapid, and flexible on-orbit capability to host and deploy numerous prototypes and payloads in order to mature critical technologies and enable investment or divestment decisions. Each LDPE/ROOSTER on-orbit platform is designed to fly multiple payloads per mission, thus fully utilizing launch potential and providing the only recurring rideshare option for prototypes, demonstrations, and experiments to geosynchronous orbit. LDPE, consisting of the LDPE-1, -2, and -3A missions, concluded in FY 2024. The objectives of the ROOSTER program are to enable rapid and cost-effective technology insertion into operational programs of record through the on-orbit checkout and testing of prototypes, demonstrations, and experimental payloads. Additionally, ROOSTER will work to mature operational concepts and TTPs, such as on-obit refueling, for use within the United States Space Force (USSF) space enterprise architecture. Tetra provides a pathfinder to define future system architectures and operational concepts for several Space Domain Awareness (SDA) and Space Control programs and other mission partners, as well as prove prototype and experiment technologies for Air Force Research Laboratory (AFRL) and other DoD labs. It serves as an additional platform to host prototype and experiment payloads that need to operate in concert with LDPEs or ROOSTERS. As a secondary mission, it provides a training platform for operators to develop and demonstrate tactics, techniques, and procedures for the evolution of operations and training in alignment with objectives from organizations such as the National Space Test and Training Complex (NSTTC) and USSF Space Training and Readiness Command (STARCOM). Quasi-Zenith Satellite System-Hosted Payload (QZSS-HP) has dual goals of enhancing the US-Japan alliance and proving the feasibility and capability of a SDA sensor payload able to be proliferated and hosted on US and non-US satellites. In addition to prototyping such a capability, it will serve as a dedicated sensor in the Space Surveillance Network, enhancing SDA in Geostationary Earth Orbit (GEO) over the Eurasian theater. Space-to-Space (S2S) Comms (funding transferring to PE 1203609SF in FY 2026) includes development of communications technologies to synchronize space-to- space Command and Control (C2) and data transport needs across the space community and enable system-agnostic communication pathways via a mobile ad-hoc network. It enhances the Defense Advanced Research Projects Agency (DARPA) Space-Based Adaptive Communication Node (SpaceBACN) modem design to support long-range crosslinks and incorporate emerging optical waveform standards. In cooperation with AFRL, it develops networking systems to manage the space data network. It also develops and maintains a communications testbed to mature communication waveforms and validate hardware. In 2024, Congress added funding for GEO SmallSat communications technology.$$, 65246000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206427SF_645611$$, $$1206427SF$$, $$645611$$, $$Assault Breaker II$$, 2000000, $$ABII is an all-Service, classified, multi-year effort, led by the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) to analyze, research, and recommend material and non-material solutions to the Joint Requirements Oversight Council (JROC).$$, 2000000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206431SF_657104$$, $$1206431SF$$, $$657104$$, $$MILSATCOM Space$$, 13825000, $$The Space Modernization Initiative (SMI) evolves current and future SATCOM systems to develop a more affordable and resilient integrated enterprise capable of meeting near-term and emerging requirements. SMI will demonstrate technologies and Concepts of Operations (CONOPS) supporting the Protected Anti-jam Tactical SATCOM (PATS) family-of-systems capability that provides tactical-level military SATCOM (MILSATCOM) users protected, anti-jam SATCOM while operating in a contested environment. PATS is an integrated approach that includes the Protected Tactical Satellite Communications (PTS) and Protected Tactical Enterprise Service (PTES) programs to mitigate adversarial jamming effects by using the Protected Tactical Waveform (PTW). For this effort, SMI includes the Air Force - Army Anti-Jam Modem (A3M) to develop PTW-capable modems, providing high throughput and enhanced anti-jam capability in benign and contested environments. Finally, Global Broadcast Service (GBS) functionality will be added to the PATS modems. GBS implements a worldwide high-capacity satellite broadcast information system to provide a continuous, one-way, high-speed, high-volume flow of classified and unclassified intelligence products (full motion video, imagery, data) to garrisoned, deployed or moving forces. This program element may include necessary civilian pay expenses required to manage, execute, and deliver AEHF and SMI capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:          PE 1206431SF / Advanced EHF MILSATCOM (SPACE) System Development & Demonstration (SDD)$$, 13825000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206432SF_654215$$, $$1206432SF$$, $$654215$$, $$EPS Recap$$, 0, $$This program element acquires the Polar Military Satellite Communications (MILSATCOM) system that provides protected communications (anti-jam and low probability of intercept and detection) for users in the North Polar Region. In FY 2006, the Department of Defense (DoD) began funding Enhanced Polar System (EPS). The host spacecraft and the polar communications packages took advantage of the Advanced Extremely High Frequency (AEHF) technology including the extended Data Rate (XDR) waveform. The EPS Capability Development Document (CDD), approved by the Joint Requirements Oversight Council in September 2006, is based on a two-package, hosted XDR program with operational availability in CY 2015 and CY 2017. EPS is comprised of four segments: Payload, Ground Control, Gateway, and Terminal (acquired by each Service's Terminal Program Office). Milestone B review was completed April 2, 2014. In FY 2019, the United States Air Force (USAF) and Norwegian Ministry of Defense signed the Arctic Memorandum of Agreement (MOA), which enforces the international collaboration with Norway to host two EPS-Recapitalization (EPS-R) payloads on Space Norway-procured spacecraft. EPS-R developed and acquired two Extremely High Frequency (EHF) payloads that are hosted on Space Norway-procured spacecraft and to upgrade/modify the existing EPS Ground Control and Gateway. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Polar MILSATCOM weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                               Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:       PE 1206432SF / Polar MILSATCOM (SPACE) System Development & Demonstration (SDD)$$, 0, NULL, NULL, NULL, NULL, 250856000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206433SF_657107$$, $$1206433SF$$, $$657107$$, $$WGS Space Systems$$, 29609000, $$The Wideband Global SATCOM (WGS) System provides the Department of Defense (DoD) with high data rate military satellite communication (MILSATCOM) services in accordance with the Joint Space Management Board-approved MILSATCOM architecture (August 1996), the Joint Requirements Oversight Council (JROC)-approved MILSATCOM Capstone Requirements Document (October 1997), and JROC-approved WGS Operational Requirements Document (May 2000). Dual-frequency WGS satellites augment, then replace the DoD's Defense Satellite Communications System X-band service and augment one-way Global Broadcast Service Ka-band capabilities. In addition, WGS provides a high capacity two-way Ka-band Service. This program was originally conceived to augment the near-term "bandwidth gap" in warfighter communications needs but it remains to be the DoD's primary wideband system. WGS has 10 operational legacy satellites and WGS-11 and WGS-12 (WGS-11 & 12) are in development as the first modern digital payloads using commercial technologies providing more coverage beams than their existing WGS predecessors combined and delivering twice the operational capacity than previous WGS analog satellites. Funding for this effort supports the advanced capabilities for WGS-11 & 12 under development for launch in FY 2026 and FY 2027, respectively. Project 657107, WGS Space Systems Resiliency Upgrade, enables the addition of WGS-12 to the constellation due to the increase in required capability on the core WGS ground system, Global SATCOM Configuration Control Element (GSCCE), to support both WGS-11 and 12 simultaneously from the same operational site. In May 2024, the DoD Chief Information Office endorsed re-direction of Beam Optimization & Operational Management (BOOM) funds towards GSCCE modernization. In FY2026 the program will restart WGS-BOOM. The objective of the WGS-BOOM effort is for the development, integration, and test of advanced beam management to enhance WGS-11 & 12 baseline beam management tools in support of rapid planning and control. This effort will develop and deploy capabilities across the WGS enterprise to provide WGS-11 & 12 management and control (M&C) ground enhancements with responsive end-to-end mission planning, protection, and terminal synchronized capabilities. WGS BOOM development includes upgrades to the WGS-11 & 12 payload control system, Global SATCOM Configuration Control Element (GSCCE), to decrease operational timelines to be able to better track and support airborne ISR missions as they move through the theater. The 10 operational legacy WGS satellites on-orbit were each developed by building on heritage WGS capabilities. Continually improving WGS capability and leveraging advances in Boeing commercial technology, in FY 2018 the DoD has procured a more advanced single WGS-11 satellite (previously referenced as WGS-11+ to designate meeting the Congressional intent of two satellites, herein referenced as WGS-11 with the new Congressional add of WGS-12) enhancing support to the US military, DoD, and allied nations with more flexibility and mission capacity to support dispersed users than previous WGS spacecraft. The new capabilities allow operators to create unique coverage anywhere within the satellite's field of view and custom designed for the mission at hand. In FY 2024, the DoD contracted for WGS-12, a clone of the WGS-11 spacecraft with the Protected Tactical SATCOM (PTS) as a hosted payload. WGS-12 was added to the WGS Block II Follow On Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                             Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:           PE 1206433SF / Wideband Global SATCOM (SPACE) System Development & Demonstration (SDD) (B2FO) contract. The advanced beam management capabilities of WGS-11 & 12 payloads will produce more coverage beams (over 1500) than the entire existing WGS constellation and deliver twice the mission capacity than WGS-10 can, thereby operationally increases the availability of military-grade communications. The objective of the GSCCE modernization effort is to integrate GSCCE architecture utilized to manage and control both the legacy 10 WGS satellites and additional WGS-11 & 12 satellites in production into the modern Wideband SATCOM Operational Management System (WSOMS) Mediated Interoperability Infrastructure (WMII) hardware. This effort will develop and deploy modern hardware and software capabilities across the WGS enterprise to provide payload management tools in support of planning and control to all WGS satellites, to include the advanced capabilities of WGS-11 & 12. This funding will also be utilized to integrate and deploy the full suite of Mitigation and Anti-Jam Enhancements (MAJE) nodes for WGS 1-10 X-band interference mitigation capabilities. WGS Block I consists of satellites 1-3, Block II consists of satellites 4-6 and Block II Follow On (B2FO) includes satellites 7-12. WGS satellites 1-10 have been funded, procured and launched in previous budget cycles. With the operation of WGS-5, the constellation provided global coverage and Full Operational Capability (FOC) was declared on 12 May 2014. In the Consolidated Appropriations Act, FY 2018, Congress added 600M Space Force Procurement in FY 2018 for "full funding for WGS-11 and WGS-12." A sole source Request for Proposal was released to Boeing in June 2018. A final decision was made to procure a single satellite (once designated as WGS-11+ but will herein forward be referenced as WGS-11) with twice the operational capacity of WGS-10 as the best approach to delivering the directed additional WGS capacity in a cost- effective manner. WGS-11 will host a PTS payload providing robust anti-jam capability to tactical warfighters, funded by the Protected Tactical SATCOM (PTS) program in PE 1206761SF. In the Consolidated Defense Appropriations Act, FY 2023, Congress added 442M Space Force Procurement in FY 2023 for "Protected Wideband Satellite" to procure a protected wideband satellite providing resilient, jam resistant tactical communications to support warfighter needs. The United States Space Force (USSF) has interpreted the Congressional add is intended to procure a WGS-12 satellite equipped with the tactical anti-jam capabilities identical with WGS-11 including the PTS hosted payload. The funding will cover costs for a WGS-12 spacecraft clone of the WGS-11 to include a PTS hosted payload. The current B2FO Acquisition Program Baseline (APB) allows for procurement of a WGS-12 and the acquisition is a Firm Fixed Price effort with integration of PTS in FY 2026 and launch in FY 2027. Since the Congressional add did not include funding for a launch vehicle, ground activities and other Government costs, the USSF is pursuing International Partner (IP) sources to cover additional funding required by FY 2025 these additional requirements. IPs receive constellation-wide WGS resources commensurate with their financial contributions to the WGS system. Investment from IPs to cooperatively enhance the system started in November 2007 through a bilateral Memorandum of Understanding (MOU) with Australia to fund WGS space vehicle (SV)-6, launch and launch services. Five countries (Canada, Denmark, Netherlands, Luxembourg, New Zealand) signed a new multilateral WGS MOU in CY 2012 and funded the procurement of WGS SV-9. In CY 2017, Amendment One to the WGS MOU leveraged additional funding for resiliency enhancements from two new IPs (Czech Republic and Norway). In CY 2022, nine countries signed Amendment Two to the multilateral MOU (adds Belgium and United Kingdom) to cover necessary ground upgrades and launch costs for WGS-11 not covered by the FY 2018 Congressional add, and extends the duration of the WGS MOU, as amended, through September 2039. There … [truncated]$$, 29609000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206438SF_642611$$, $$1206438SF$$, $$642611$$, $$Technology Insertion Planning and$$, 34754000, $$This program supports a range of activities including systems engineering, technology planning, development, demonstrations and prototyping, and testing, as well as modeling, simulations and exercises to support development and maturation of tactics and procedures for responsive and resilient Space Superiority capabilities. This includes technology development and prototyping for Offensive and Defensive Space Operations and the necessary systems engineering for the warfighter to effectively employ such systems. Specifically supported are Defensive Space Operations(DSO) and Space Domain Awareness (SDA) activities, which include developing threat warning payloads for monitoring, detecting, identifying, tracking, assessing, verifying, categorizing, and characterizing objects and events in space. Additionally, Integration and Technology Futures project supports the development of payload prototypes and space defense force packages for protecting U.S. space systems, resources, and operations from enemy attempts to negate, interfere, or destroy them. Specific Offensive Space Operations (OSO) include disruption, denial, or degradation (and associated Electronic Support) of adversary space systems that may be used for purposes hostile to U.S. national security interests. Rapid Reaction Capabilities in response to immediate warfighter needs in the Space Superiority mission area are developed within the Rapid Reaction Branch (RRB). Depending on the magnitude of Combatant Command Urgent Operational Needs (UON), this program may not include necessary funding for all contingency deployments. As required, necessary funding will be requested through established Joint Urgent Operational Need (JUON) and Overseas Contingency Operations (OCO) processes. This program element may include necessary civilian pay expenses required to manage, execute, and deliver SCT weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. For Technology Insertion Planning and Analysis in FY 2025 $0.200 million was expended for civilian pay expenses in this program element, and in FY 2026 $0.200 million is forecasted for civilian pay expenses in this program element.$$, 34754000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206438SF_646438$$, $$1206438SF$$, $$646438$$, $$Joint Space Integration$$, 25352000, $$Joint Space Integration Technology leverages knowledge of the space environment and impacts on weapon systems to prototype, develop, test, and field joint multi- domain software and modeling solutions to fill capability gaps for Combatant Commanders. Military Application of the Space Environment (MASE) project consolidates and integrates current space environment science and technology advancements to provide capability for joint force systems in all domains to address immediate and evolving threats to U.S. forces operating in harm's way. The data provided supports rapid and agile demonstrations, exercises, and war games that provide essential validation of delivered capabilities to improve operational effectiveness. This program element may include necessary civilian pay expenses required to manage, execute, and deliver SCT weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF.$$, 25352000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206440SF_657106$$, $$1206440SF$$, $$657106$$, $$Next-Gen OPIR-Ground$$, 358330000, $$Next-Generation Overhead Persistent Infrared (Next-Gen OPIR) Ground (Project 657106): Next-Gen OPIR Ground, also known as Future Operationally Resilient Ground Evolution (FORGE), consists of a modern Command and Control (C2) capability, modernization of Mission Data Processing (MDP) to implement an open framework and develop mission applications, required development and upgrades to Relay Ground Stations (RGS), to provide a modern survivable and endurable architecture to meet USSF current and future space domain needs. FORGE will provide the flexibility and scalability to integrate new satellites, sensors and capabilities more rapidly and efficiently in order to meet evolving threats and warfighter needs. The Next-Gen OPIR Ground efforts enable cyber enhancements for both space and ground systems. FORGE C2 will introduce infrastructure and common platform services, mission unique software such as Telemetry, Tracking, and Commanding (TT&C), and mission management to support initial Next-Gen OPIR Space satellite launches without driving risk into the FORGE development schedule. The program has established a risk reduction ground capability, Next-Gen OPIR Interim Operations (NIO), based on a limited Space Based Infrared System (SBIRS) Block 20 solution. The total cost of the FORGE Rapid Prototype Middle Tier of Acquisition (MTA) effort is 2,301.9 million. The RGS development and fielding is not contained in the MTA effort, as it consists of stand-alone Acquisition Category (ACAT) III efforts. The FORGE Rapid Prototype MTA is fully funded across the Future Years Defense Program. The FY 2026 request for Next-Gen OPIR -- Ground includes 358,330 thousand of discretionary and 194,600 thousand of mandatory (reconciliation) for a total of 552,930. The mandatory funds reinstate Next-Generation Polar (NGP) as part of the overall FORGE development. This ensures a modern, survivable, and enduring architecture that meets USSF's current and future domain needs. Further information for this reconciliation request is provided in Section 20003 (Missile Defense) of the Reconciliation Exhibit. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Next-Gen OPIR Ground system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 126398SF This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:         PE 1206440SF / Next-Gen OPIR -- Ground System Development & Demonstration (SDD)$$, 358330000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206442SF_657009$$, $$1206442SF$$, $$657009$$, $$Space Mod Initiative$$, 160113000, $$Next-Generation Overhead Persistent Infrared (OPIR) Space Modernization Initiative (SMI) (Project 657009): To better enable response to emerging global missile threats, SMI advances critical capabilities and reduces risk through four major thrust areas: Demonstrations/Prototypes, Technology Maturation, Data Exploitation, and Wide Field of View (WFOV) On-Orbit Testbed Mission Integration, each with a flagship investment. Demonstrations rapidly prototype new game-changing technologies for the broader mission warning enterprise by delivering ground and on-orbit prototypes. Demonstrations advance OPIR capabilities for missile warning and tracking ensuring a low risk, smooth transition of advanced technology to future operational systems. Technology Maturation focuses investments on high pay-off critical components to reduce production risks and development costs. Technology Maturation focuses development on advanced Infrared (IR) sensing optics and electronics, resiliency hardware and software, and on-board processing algorithms and on-board computers. Data Exploitation provides return-on-investment aimed at ingestion and fusion of current and future proliferated sensor program data to enhance missile warning, missile defense, battlespace awareness and technical intelligence mission capabilities. This includes the processing and exploitation of legacy Space Based Infrared Systems (SBIRS) wideband data and its fusion with Wide Field of View (WFOV) Geosynchronous Earth Orbit (GEO) wideband sensor. Subsequently, this work will expand to include the ingestion and fusion of WFOV Low Earth Orbit (LEO), Next-Gen GEO, Resilient Missile Warning/Missile Tracking (MW/MT) Medium-Earth Orbit (MEO) and other data as it becomes available as well as overcoming the proliferated sensor challenges expected with the large volumes of data and tracks that could overwhelm the enterprise and operators. Data Exploitation will focus on automation and innovation to overcome these challenges to include Artificial Intelligence and Machine Learning (AI/ML) that reduce cognitive workload reduction of the operators. Data Exploitation includes maintaining the Boulder Ground Innovation Facility (BGIF) and associated Overhead Persistent Infrared (OPIR) Tool, Applications, and Processing (TAP) Lab infrastructure and DevSecOps Continuous Integration/Continuous Delivery (CI/CD) pipeline used for advanced software application and algorithm development. WFOV On-Orbit Testbed Mission Integration advances the capability of the OPIR enterprise by augmenting it with data from the Wide Field of View (WFOV) system. Testbed system will provide data to operations, as available, demonstrate the value of new OPIR system Concept of Operations (CONOPS) and work to integrate MW/MT data into new mission areas. SMI funds engineering activities to reduce both production and future system costs through manufacturing and producibility enhancements, and technology insertion. SMI includes studies and risk reduction activities to evolve the current Program of Record (PoR) constellation and/or simultaneously mature breakthrough technologies to create a leap in capability for follow- on systems to include Future Operationally Resilient Ground Evolution (FORGE), Next-Gen GEO and Polar, and Resilient Missile Warning/Missile Tracking (MW/MT), Medium-Earth Orbit (MEO).$$, 160113000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206442SF_657123$$, $$1206442SF$$, $$657123$$, $$Integration$$, 29508000, $$The Government works with the Enterprise System Engineering & Integration (SE&I) contractor as a team to define the Next-Gen OPIR enterprise architecture, control and validate interfaces, ensure compatibility of Next-Gen OPIR systems, and develop/manage plans for fielding the Next-Gen OPIR segments. Further, the Enterprise SE&I executes system-level integration requirements between segments such as Space to Ground. This differs from integration within each segment; integration within segments refers to subsystem-level integration between subsystems such as a spacecraft bus to the mission payload. The Government Integrator is responsible for defining the Next-Gen OPIR enterprise architecture, controls and validates interfaces, ensures compatibility of Next-Gen OPIR systems, and develops/manages plans for fielding the Next-Gen OPIR Enterprise. Further, the Integrator executes Model Based System Engineering (MBSE) through modeling, simulation, and technical analyses of Government-directed enterprise level trades among the Next-Gen OPIR segments. These trades lead to definition, management, maintenance, and evolution of the Next-Gen OPIR Enterprise technical requirements and interface documents to ensure the integrity of the enterprise technical baseline.$$, 29508000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206443SF_657120$$, $$1206443SF$$, $$657120$$, $$Next-Gen OPIR Space$$, 432073000, $$Next-Generation Overhead Persistent Infrared (Next-Gen OPIR) Geosynchronous Earth Orbit (GEO) (Project 657120): The primary mission is to provide initial missile warning of a strategic missile attack on the US, deployed forces and allies. The Next-Gen OPIR GEO (NGG) missile warning satellites enhance detection and improve reporting of intercontinental ballistic missile launches, submarine ballistic missile launches, and tactical ballistic missile launches. Development consists of new payloads in a highly resilient bus, providing real-time persistent global infrared coverage to meet validated Joint Requirements Oversight Council (JROC) requirements on current and future space domain demands. The Program Office is acquiring the NGG capability in two contract actions. Phase 1 awarded in August 2018 encompasses requirements analysis, design/development, critical path flight hardware procurement, and risk reduction efforts leading to a System Critical Design Review (CDR) in October 2021. Phase 2 was awarded in January 2021 for the manufacturing, assembly, system integration and test, launch, and early on-orbit test through operational acceptance of NGG satellites 1-3. The Department has assessed the third Space Vehicle (SV) is not required as a result of continued positive performance of the Space-Based Infrared System (SBIRS) constellation and the anticipated full operational capability of the Medium Earth Orbit (MEO), Program Element 1206447SF/ Low Earth Orbit (LEO), Program Element 1206446SF missile tracking constellation. As a result, the program has removed the third satellite development efforts. NGG is now a 2 SV baseline. The NGG program has been designated as a Major Capability Acquisition. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Next-Gen OPIR GEO system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:           PE 1206443SF / Next-Gen OPIR -- GEO System Development & Demonstration (SDD)$$, 432073000, NULL, NULL, NULL, NULL, 2854126000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206444SF_657121$$, $$1206444SF$$, $$657121$$, $$Next-Gen OPIR Space,$$, 0, $$Next-Generation Overhead Persistent Infrared (OPIR) Space, Block 0 Polar (Project 657121): The primary mission is to provide initial missile warning of a ballistic missile attack on the US, its deployed forces, and its allies. Next-Gen OPIR Space enhances detection and improves reporting of intercontinental ballistic missile launches, submarine launched ballistic missile launches, and tactical ballistic missile launches. Development consists of the Next-Gen OPIR Polar (NGP) missile warning satellites with new payloads in a highly resilient bus, providing real-time persistent global infrared coverage to meet validated Joint Requirements Oversight Council (JROC) requirements on current and future space domain demands. The Program Office is acquiring the NGP capability through three contract phases. Phase 0, awarded in June 2018, encompassed system requirements analysis and risk reduction efforts, which led to a March 2020 System Requirements Review (SRR). Phase 1, awarded in May 2020, encompasses engineering design, unit hardware procurement, component and subsystem qualification and design, critical path flight hardware procurement, and risk reduction efforts, and culminated in a System Critical Design Review (CDR) in August 2024. Phase 2 was awarded in October 2024, encompassing manufacture, assembly, integration, test and launch of two satellites. The NGP program has been designated as a Major Capability Acquisition. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Next-Gen OPIR Polar system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. The FY 2026 request for Next-Gen OPIR Polar (NGP) includes $0 of discretionary and $723,700 thousands of mandatory (reconciliation) for a total of $723,700 thousand. The mandatory funds fully fund NGP. Further information for this reconciliation request is provided in Section 20003 (Missile Defense) of the Reconciliation Exhibit. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:              PE 1206444SF / Next-Gen OPIR -- Polar System Development & Demonstration (SDD)$$, 0, NULL, NULL, NULL, NULL, 1320594000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206445SF_650140$$, $$1206445SF$$, $$650140$$, $$COMSATCOM$$, 132060000, $$The backbone of Fighting SATCOM is a SATCOM EM&C capability for an Integrated SATCOM Enterprise. This is the foundation for SATCOM integration into an operational level Command and Control (C2) system that enables the end-to-end sensor-to-shooter execution serving to protect and defend, as well as theatre support missions for United States Space Command (USSPACECOM) and the Theater Combatant Commands. SATCOM EM&C applications will provide critical services to warfighters to facilitate timely, quality driven battlespace decisions for SATCOM allocation and use. The effort leverages a Development Security Operations (DevSecOps) platform to rapidly prototype and deliver EM&C mission applications enabling responsive, resilient SATCOM as prioritized by Space Operations Command (SpOC), Delta 8, SATCOM Integrated Operations Division (SIOD), and four Consolidated SATCOM Systems Experts (CSSEs). The four CSSEs cover Wideband, Narrowband, Protected, and Commercial SATCOM bands. SATCOM EM&C applications are delivered in capability categories identified in the DoD Chief Information Officer's (CIO) Enterprise SATCOM Management and Control (ESC-MC) Implementation Plan. Capabilities are incrementally developed using agile methodology and delivered into subsets identified in the DoD CIO's Implementation Plan, which will support the three imperatives (integrate data management, automate resource allocation, fuse situational awareness) and seven core capabilities (mobility and continuous communications, management common operating environment, enterprise SATCOM situational awareness/common operating picture, automated resource allocation, electromagnetic interference mitigation, continuity of operations, element/ enterprise network interface) across the four SATCOM bands. In addition to USSF developed EM&C capabilities, USSF will demonstrate the onboarding of MEO commercial SATCOM services into the SATCOM architecture and Space Data Transport Force Design. The LUX MEO activity is an initial effort for the USSF to partner, explore, prototype, and integrate an international commercial SATCOM service into the DoD SATCOM enterprise. Demonstrations will include utilizing EM&C for provisioning and planning, usage of PTW over MEO Commercial SATCOM, and integration of PTES hubs into commercial satellite capable gateways. Early adoption of capability will also be used to prototype and demonstrate fiber resiliency for large gateway backhaul via space. Capacity will further be used to demonstrate platforms use of multi-orbital terminals for AISR, maritime communications and communications on the move. Luxembourg government is also procuring commercial SATCOM services to contribute to international demonstration and testing of integrated and interoperable ground and space architecture elements. This international partnership intends to demonstrate the ability to jointly procure communication capacity services that will result in a higher return on US DoD SATCOM investment and potentially lead to future international partnering opportunities. Activity priorities are subject to change as determined by the operational user, SpOC, Delta 8.$$, 132060000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206445SF_651126$$, $$1206445SF$$, $$651126$$, $$COMSATCOM Infrastructure$$, 0, $$In accordance with the FY 2018 National Defense Authorization Act 1601(a), as amended, and on behalf of the CSO and in consultation with the DoD CIO, the USSF Commercial Satellite Communications Office (CSCO), serves as the sole authority for the procurement of COMSATCOM services for the DoD; this responsibility was previously held by DISA. In order to provide the joint warfighter with modernized access to COMSATCOM services and ensure combat effectiveness across all domains, the CSCO requires a comprehensive COMSATCOM Enterprise Technology (COMET) Systems of Systems to provide required business suite financial management and customer and contract support systems. The COMET programs implementation of the COMSATCOM Business Suite (CBS) tool is also critical to complete the Congressionally mandated COMSATCOM mission transition from DISA to USSF. The CBS tool will have multiple components including: (1) Business Suite & Marketplace designed to automate and streamline requests for work and customer interaction, thereby replacing manual processes for over 100 different contracts valued at $5 billion over the future year defense program; (2) Financial Management System required to operate a new and cutting-edge Enterprise Space Activity Group (ESAG) under the Air Force Working Capital Funds (AFWCF); (3) Integration with third party systems and capabilities, including cloud-based hosting and EM&C - the nexus of future USSF space-based SATCOM C2.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206458SF_649493$$, $$1206458SF$$, $$649493$$, $$Resilient Architecture Design and$$, 107472000, $$The Resilient Architecture Design and Evaluation project conducts experimentation within an interconnected hybrid SATCOM architecture to validate the performance, scalability and resilience of providing the Joint Force with multiple separate communications paths. To achieve these resiliency gains, the hybrid network requires 1) on-demand management of multi-band, multi-orbit DoD, allied and commercial data links; and 2) management and control capabilities to orchestrate paths through the space and ground networks. The effort validates the "Resilience by Design” approach in the Space Warfighting Analysis Center (SWAC) Space Data Transport Force Design recommendations through a combination of 1) modeling and simulation; 2) hardware- and software-in-the-loop analysis; and 3) terrestrial and on-orbit demonstration. The project leverages Hybrid SATCOM terminal prototyping in the Experimentation (Space) project along with direct relationships with commercial terrestrial and space data transport providers to demonstrate dynamic networking, understand commercial offerings, assess security and resiliency, and jump-start future acquisition approaches that enable a pivot to a more resilient architecture.$$, 107472000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206601SF_620200$$, $$1206601SF$$, $$620200$$, $$Enterprise Transformational Appld$$, 7005000, $$This project develops multidisciplinary applied research efforts to accelerate the technology pipeline of transformational capabilities by reducing risk and maturing technologies so they can transition in support of larger advanced technology development capability investments. These activities are selected to enable solutions to the Department of the Air Force (DAF) highest priorities. The Explore effort engages traditional & non-traditional industry, government laboratories, and academia through 12-24 month feasibility studies and demonstrations. The Seedlings for Disruptive Capabilities Program (SDCP) facilitates Air Force Research Laboratory (AFRL) cross- disciplinary applied research to provide leap-ahead, high risk technology development. Applied research efforts span a broad spectrum of activities, and established processes allow agility and flexibility to meet higher demand signals. AFRL will plan and manage these funds at the enterprise level to achieve a high level of collaboration executed across all the applicable Technology Directorates and will apply the research toward disruptive capabilities. Building off the technology competencies and ecosystems of the Technology Directorates brings together the needed expertise and components to develop the transformational capabilities.$$, 7005000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206601SF_621010$$, $$1206601SF$$, $$621010$$, $$Space Survivability & Surveillance$$, 47111000, $$This project develops technologies to understand and control the space environment for warfighter's future capabilities. The focus is on characterizing and forecasting the battlespace environment for more realistic space system design, modeling, and simulation, as well as the battlespace environment's effect on space systems' performance. This includes technologies to specify and forecast the space environment for planning operations, ensure uninterrupted system performance, optimize space-based surveillance operations, and provide capability to mitigate or exploit the space environment for both offensive and defensive operations.$$, 47111000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206601SF_624846$$, $$1206601SF$$, $$624846$$, $$Spacecraft Payload Technologies$$, 36197000, $$This project develops advanced technologies that enhance spacecraft payload operations by improving materials/component, networking, analysis tools, and subsystem capabilities. The project focuses on development of advanced space data generation and exploitation technologies, including infrared sensors; and development of high- fidelity space simulation models that support space-based surveillance and space asset protection research and development for the warfighter.$$, 36197000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206601SF_624847$$, $$1206601SF$$, $$624847$$, $$Rocket Propulsion Technology$$, 27291000, $$This project develops and demonstrates rocket propulsion technologies for space access and space maneuver. Analytical and experimental areas of emphasis are propellants, propellant management, combustion, rocket material applications, and innovative space access and in space propulsion concepts. Technologies of interest will improve reliability, performance, survivability, affordability, and environmental compatibility of these systems. Develop technologies to reduce the weight and cost of components using new materials and improved designs and manufacturing techniques. All efforts in this project contribute to the sustainment and growth of the space and rocket propulsion industry, providing space access and in space propulsion technology for the entire Department of Defense (DoD). Technologies under this project enable capabilities of interest to DoD, National Aeronautics and Space Administration (NASA) and growing Space community. Tasks include proof of concept tests of critical components; advanced component development; and ground-based tests. This project develops next generation of physics-based modeling, simulation, and analysis (MS&A) tools for rapid and agile space access and in-space propulsion design, analysis, and production, as well as the digital engineering concepts to manage the entire process of design, test, and validation of space access and in-space systems. This project also secures National Unique Testing Assets, providing unmatched capabilities that underpin technological leadership and ensure the safety and security of our nation. All thrusts are reviewed by a DoD level steering committee yearly for relevance to DoD missions, and the associated support costs.$$, 27291000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206601SF_624866$$, $$1206601SF$$, $$624866$$, $$Lasers & Imaging Technology$$, 36956000, $$This project conducts research advancing ground-based optical space domain awareness, techniques to counter laser threats to space craft, and laser applications towards ground-to-space quantum communication.$$, 36956000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206601SF_625018$$, $$1206601SF$$, $$625018$$, $$Spacecraft Protection Technology$$, 45637000, $$This project develops the technologies to perform faster, well-informed decision making for space operations, enhanced mission assurance of critical space services, and integrate space with joint operational picture for protecting United States space assets, in potentially hostile environments, to assure continued space system operation. The project provides transitionable technology and knowledge to enable speed-of-light protection, many-on-many engagement and defense, and new orbit regimes despite growing threat impunity. This project also encompasses efforts to expand the University Consortium for Space Research to address research needs unique to the USSF.$$, 45637000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206601SF_628809$$, $$1206601SF$$, $$628809$$, $$Spacecraft Vehicle Technologies$$, 45300000, $$This project is a pervasive portfolio pursuing a broad range of emerging technologies targeted for application and insertion in the future national space architecture. The project focuses on spacecraft components including, structures, power, thermal management, electronics, and robotics/logistics modules. Leap-ahead capability is provided utilizing in-house expertise and laboratories, and by leveraging the creativity and innovation of the Nation's industry, universities, and national laboratories to conduct applied research. The project maintains core competencies in astrodynamics, controls, electronics, materials, power, structures, and thermal, and provides foundational technologies supporting all space mission areas.$$, 45300000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206616SF_630321$$, $$1206616SF$$, $$630321$$, $$Space Warfighter Technologist$$, 35961000, $$This Project is a concentrated effort to improve Air Force Research Laboratory (AFRL) business practices to accelerate moving emerging technologies into the hands of the warfighter. Vanguard efforts draw the operational, acquisitions, and technology communities together into coherent teams to solve the hard Science & Technology (S&T) problems based on Department of the Air Force (DAF) strategic priorities which do not have readily available emerging technology solutions. Teams follow a disciplined process tailorable to accelerate efforts as deemed necessary by the department. This process (known as WARTECH, for WARfighter / TECHnologist) leverages discrete progress gates to deliver S&T efforts organized as Vanguard Pathfinders, Vanguard Prospects, and Vanguards. This construct organizes these multi- disciplinary, capability-focused investments based on characteristics such as effort maturity, established military utility, technical viability and transitionability. Each have built-in off-ramps to promote transition. The process is overseen by an Executive Committee.$$, 35961000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206616SF_633834$$, $$1206616SF$$, $$633834$$, $$Integrated Space Technology$$, 41626000, $$This project is a series of advanced technology demonstrations designed to address mission needs by applying emerging technologies from the Air Force Research Laboratory, other United States government laboratories, and industry. These technologies are integrated into system-level demonstrations that are used to test, evaluate, and validate the technologies in a relevant environment. This project includes the development and demonstration of programs addressing Department of the Air Force (DAF) capability gaps and provides technologies for transformational future force capabilities. Transformational efforts will be identified through a competitive process and be responsive to DAF design priorities. Selected efforts will be designated as transformational, indicating enterprise-level priority.$$, 41626000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206616SF_634868$$, $$1206616SF$$, $$634868$$, $$Maui Space Surveillance System$$, 29108000, $$This program funds ground-based optical space situational awareness technology development and demonstration at the Maui Space Surveillance System (MSSS) in Hawaii, as well as the operation and upgrade of the experimental equipment and facilities. Efforts in this program have been coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication.$$, 29108000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206616SF_634922$$, $$1206616SF$$, $$634922$$, $$Space & Missile Rocket Propulsion$$, 16914000, $$This project develops and demonstrates advanced liquid rocket engine technologies, components, engines, and integrated systems for launch vehicles. Characteristics such as environmental acceptability, affordability, reliability, responsiveness, reduced weight, and reduced operation and launch costs are emphasized. The objective is to reduce costs, simplify manufacturability, increase performance and life/reusability, as well as payload lift capability. Additionally, this project investigates and demonstrates technologies that will improve responsiveness and resiliency of space access systems and launch infrastructure. This project also develops and demonstrates solar electric, electric, chemical, and advanced propulsion technologies, for station-keeping, repositioning, and orbit transfer for satellites and satellite constellations. This effort develops technologies for flexible, responsive in-space maneuver in all orbit regimes. These technologies are critical to expanding Space Force's capability to deliver capabilities resiliently and responsively in, to, and through space. This project further develops and demonstrates the next generation of physics-based modeling, simulation, and analysis (MS&A) tools for rapid and agile space access and in-space propulsion design, analysis, and production, as well as the digital engineering concepts to manage the entire process of design, test, and validation of space access and in-space systems. This project secures National Unique Testing Assets, providing unmatched capabilities that underpin technological leadership and ensure the safety and security of our nation. All efforts in this project contribute to the sustainment and growth of the space and rocket propulsion industry, providing space access and in-space propulsion technology for the entire Department of Defense (DoD). Technologies under this project enable capabilities of interest to DoD, National Aeronautics and Space Administration (NASA), and growing Space community. The efforts in this project are reviewed by a DoD level steering committee annually for relevance to DoD missions, and the associated support costs.$$, 16914000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206759SF_660191$$, $$1206759SF$$, $$660191$$, $$660191 - Space Systems$$, 42374000, $$Space Operational Test and Evaluation refers to Congressionally mandated Space Initial Operational Test and Evaluation (IOT&E) to support major weapon system acquisition decisions beyond Low-Rate Initial Production (LRIP), Milestone C, full-rate production (FRP), fielding, and declaration of Initial Operational Capability (IOC). For Major Defense Acquisition Programs (MDAP), Title 10 USC 2399 requires IOT&E be completed under realistic operating conditions before proceeding beyond LRIP. IOT&E will be planned to answer all Critical Operational Issues (COI) as thoroughly as possible. IOT&E is conducted to determine the operational effectiveness and suitability and resolve overall mission capability of systems undergoing research and development (R&D) efforts. It is an evaluation of a system's performance when the complete system is tested and evaluated against operational criteria by personnel with the same qualifications as those who will operate, maintain and support the system when deployed. In general, IOT&E is performed on new systems in development, major modifications, and other systems as directed. This project provides funding for the USSF Operational Test Agency's participation in Integrated Test and Evaluation (IT&E). Additionally, it funds the Multi-service Operational Test and Evaluation (MOT&E) and Follow-on Operational Test and Evaluation (FOT&E) when it is the continuation of IOT&E activities past the FRP decision. FOT&E answers specific questions about unresolved COIs and test issues or completes areas not finished during the IOT&E. This effort also funds related operational test and evaluation (OT&E) activities such as Early Influence, Operational Utility Evaluations (OUE), Early Operational Assessments (EOA), and Operational Assessments (OA) which are independent OT&Es supporting major milestones and decision points, FRP, fielding, or declaration of IOC for USSF programs. USSF schedules and executes tests according to the forecasted test readiness of the MDAP program offices.$$, 42374000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206759SF_664597$$, $$1206759SF$$, $$664597$$, $$664597 - Professional Test$$, 4874000, $$This project provides funding for the organizations, training, and activities required to develop a professional space T&E workforce, in conjunction with the USSF Chief Human Capital Officer. Funding primarily supports the development of the Space Test Course (STC) as the United States Air Force (USAF) Test Pilot School (TPS). The STC at USAF TPS will provide graduate-level education for the core space T&E workforce.$$, 4874000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206759SF_664598$$, $$1206759SF$$, $$664598$$, $$664598 - National Space Test and$$, 141835000, $$Provide space warfighters interconnected, scalable, high-fidelity and distributed physical and digital ranges for full-spectrum test and training to develop, validate, and sharpen joint warfighting capabilities necessary to prevail and enable space superiority that is essential to achieve peace through strength.$$, 141835000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206760SF_643726$$, $$1206760SF$$, $$643726$$, $$PTES$$, 66935000, $$Protected Tactical Waveform (PTW) over Wideband Global Satellite (WGS) Initial Operational Capability (IOC) is expected in FY 2027. IOC will be achieved through Joint Hub (JH) installation at two WGS teleport sites at separate locations, which utilize one WGS satellite, in addition to nominal operations using the PTES Mission Management System (MMS) and Key Management System (KMS). Full Operational Capability (FOC) is projected for FY 2028, at which time PTES will provide worldwide PTW operations using JHs installed in at least eight different WGS teleport sites and utilizing ten WGS satellites. Research, Development, Test & Evaluation funding is required for continued architecture development, software development, and test and evaluation of PTES systems and segments.$$, 66935000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206760SF_643733$$, $$1206760SF$$, $$643733$$, $$PTW Over Commercial$$, 47495000, $$PTW over Commercial (PTWoC) Initial Operational Capability (IOC) is targeted for when Protected Tactical Waveform (PTW) operations are provided to users via a single Joint Hub over one commercial satellite, or International Partner (IP) satellite, including full Mission Management System (MMS) and Key Management System (KMS) support functions. PTWoC is expected to reach Full Operational Capability (FOC) after providing the ability to support geostationary, medium earth or highly inclined orbit PTW satellite communications from nine separate locations and for all equatorial longitudes. Highly inclined orbits are necessary in order to provide SATCOM coverage over the Earth's polar regions. Research, Development, Test & Evaluation funding is required for architecture development, acquisition strategy development, system requirements and system trades analysis, engineering, manufacturing, software development, and test and evaluation of PTES systems and segments. Initial PTWoC efforts are focused on providing additional, cost-effective SATCOM capacity to Joint and Allied warfighters via an international partnership with Luxembourg. Future efforts will focus on enabling Protected Tactical Waveform SATCOM operations over the O3b mPOWER Medium Earth Orbit constellation, as well as over commercial SATCOM constellations in other orbits.$$, 47495000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206761SF_643722$$, $$1206761SF$$, $$643722$$, $$Protected Tactical SATCOM -$$, 239639000, $$In CY 2022 the Space Warfighting Analysis Center (SWAC) identified gaps in protected SATCOM capabilities relative to existing and planned capabilities against current and predicted user needs, with consideration of current and emerging challenges to both operating environments and system deployment. SWAC developed a Force Design (FD) to address these gaps, realigning capabilities and disaggregating mission sets. Protected Tactical SATCOM - Global (PTS-G) is a key and enabling capability of the USSF Force Design (FD) that bridges the gap between the more focused capabilities provided by Protected Tactical SATCOM - Resilient (PTS-R), and the broadly-available but also the lower assured access capabilities provided by existing / emerging MILSATCOM and commercial services. PTS-G also augments current and future warfighter capability with increased global capacity. PTS-G is a moderate degree of assured access communications across military Ka-band and X-band using a disaggregated and proliferated sets of lower-complexity satellites. Space Systems Command (SSC) will develop the PTS-G space and ground systems to provide worldwide assured-access communications for tactical warfighters. PTS-G will consist of two types of space vehicles (PTS-G-Ka and PTS-G-X), and ground infrastructure (system controller/hub with gateways), and will connect to existing Protected Tactical SATCOM Family of Systems ground infrastructure (mission management system and cryptographic key management system) developed under the Protected Tactical Enterprise Service (PTES) program. PTS-G will consist of multiple satellites that can provide either X-band or mil Ka-band transponded capability while also supporting the utilization of the PTW Waveform. PTW modems for user terminals will be acquired by each Service and by international partners. Initially, PTS-G will provide capabilities in select regions. PTS-G will target a solution that can provide worldwide coverage. PTS-G will be interoperable with the PTES program to perform management and cryptographic key management for PTW users, but PTS-G will procure and install the associated PTES Joint Hubs and other ground infrastructure to operate the satellites, anchor the data, and perform O&S. In addition, the PTS-R system will be integrated with components of PTES and will be complementary to PTS-G. PTS-G addresses the gap in protected communications capability identified in the USSF FD and in the Joint Space Communications Layer (JSCL) Initial Capabilities Document (ICD). To meet the warfighter requirements for protected tactical MILSATCOM and the capability gaps identified in these studies in a timely and cost-effective manner, use and modification of existing capabilities and Commercial Off the Shelf (COTS) products will be leveraged to the maximum extent, to develop the PTS-G capabilities. SSC will strategically execute prototyping and risk reduction as needed to develop and deploy PTS-G capabilities.$$, 239639000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206761SF_643728$$, $$1206761SF$$, $$643728$$, $$Protected Tactical SATCOM$$, 332282000, $$For the initial Protected Tactical Satellite Communications (PTS) phase, USSF is utilizing FY 2016 National Defense Authorization Act (NDAA), Middle Tier of Acquisition (MTA) for Rapid Prototyping (RP) authority and Section 815, Other Transaction Authority (OTA), to achieve an affordable, rapid, operational capability for the tactical warfighter. This strategy employs rapid payload development to progressively and incrementally deploy prototypes with residual capabilities demonstrated in an operational environment. These prototyping payloads (PTS-P) demonstrate innovative Anti-Jam (AJ) technologies with modular and scalable payloads to meet validated military needs for protected tactical communications. This includes technical baseline development, systems engineering trade analyses, internal/external system integration and development, candidate system architecture evaluations, risk reduction demonstrations, prototyping concepts development, system testing, and enabling technologies maturation. The PTS-Resilient (PTS-R) project will follow the PTS-P prototyping activity to develop purpose-built "hub in space” satellites with full signal processing and switching capability that allows direct connectivity between users. The Milestone Decision Authority has designated PTS-R as an ACAT I, pre-Milestone B program in the Technology Maturation and Risk Reduction (TMRR) acquisition phase. The PTS-P and PTS-R systems include a Space Segment, Ground Segment, and Gateway Segment. For the Space Segment, the USSF strategy utilizes a payload- centric focus to enable an affordable, resilient space architecture. This enables hosting and rideshare opportunities with other US government, commercial, International Partner (IP) satellites or integration onto a commodity satellite bus. For the Ground Segment, PTS develops satellite command and control (C2) and leverages the Protected Tactical Enterprise Service (PTES) RP activity for mission and key management planning. The PTS Gateway Segment enables tactical warfighters reach back to global DoD Information Network. The PTS user Terminal Segment, not included in this PTS acquisition, will be procured by the military services utilizing low-cost Protected Tactical Waveform (PTW) modem upgrades enabled by the Air Force-Army Anti-Jam Modem (A3M) ACAT III program and the Navy Wideband Anti-Jam Modem System (WAMS) technology demonstration program. PTS also develops the National Security Agency (NSA)-certified and space-flight qualified production-ready Space Hub End Cryptographic Unit (ECU). Starting the ECU as a single, early risk-reduction effort targets a high-risk area of the PTS development and enables PTS program success.$$, 332282000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206770SF_673140$$, $$1206770SF$$, $$673140$$, $$Enterprise Ground$$, 0, $$The Assistant Secretary of the Air Force for Space Acquisition and Integration directed the formation of a Combined Program Office (CPO) by merging Enterprise Ground Services (EGS) from Space Systems Command (SSC) and Ground Command, Control, and Communications (GC3) from the Space Rapid Capabilities Office (Space RCO). The CPO is called the Rapid Resilient Command and Control (R2C2) CPO and utilizes the Space RCO acquisition authorities under the Space RCO Program Executive Officer to execute funding in the EGS and GC3 program elements to develop an extensible, scalable, modular ground segment solution capable of supporting protect and defend missions of the United States Space Force. Combined EGS and GC3 funding will be used wholly and directly to support CPO activities. R2C2 will continue development and integration of the satellite operations ground segment solution (SatOps) to support the protect and defend mission set, including, but not limited to, capabilities and services needed to perform mission control. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:           PE 1206770SF / Enterprise Ground Services Operational Systems Development$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206771SF_650008$$, $$1206771SF$$, $$650008$$, $$Commercial Augmentation Space$$, 23671000, $$CASR is a contractually managed framework that ensures DoD has access to commercial space capabilities throughout the spectrum of conflict. CASR ensures that commercial capabilities, integrated during peacetime, can be leveraged throughout the spectrum of conflict and that they remain secure, reliable, and available to support the warfighter. This funding supports CASR baseline operating costs as well as threat sharing; wargaming/exercises; a CASR readiness and inspection program; and additional incentive structures. Near-term funding (FY 2026) supports participation of approximately 10 CASR companies. Specific surge capacity within CASR may include: Leveraging commercial capabilities already on orbit; augmenting existing USSF missions with added capacity (e.g., SATCOM); reach back into existing production lines to rapidly acquire satellites, payloads, and launch vehicles; denial of service over a region or to a certain customer set; and other potential concepts. Rapidly delivers impactful commercial solutions to the warfighter by identifying viable capabilities, implementing development contracts, and integrating them into the USSF ecosystem$$, 23671000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206771SF_650009$$, $$1206771SF$$, $$650009$$, $$Commercial Capability Integration$$, 12957000, $$Commercial Capability integration funds Commercial Space Office (COMSO) efforts to deliver expedited, game-changing commercial capabilities to the warfighter. Primary efforts will identify commercial capabilities with viability to solve gaps in several USSF mission areas, implement commercial contracts to develop late-stage capabilities and integrate those capabilities into the USSF ecosystem, then present those commercial capabilities, products or services to operations. The near-term focus is to expand commercial integration in areas such as space sensing and multi-domain awareness; Space-Based Environmental Monitoring (SBEM); alternate forms of Positioning, Navigation and Timing (alternate PNT); Space Domain Awareness (SDA), and Space Access, Mobility and Logistics (SAML). Commercial Capability Integration efforts will encompass all USSF mission areas to identify and integrate commercial capabilities necessary to meet warfighter needs.$$, 12957000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206853SF_650006$$, $$1206853SF$$, $$650006$$, $$Next Generation$$, 6595000, $$The National Security Space Launch (NSSL) program provides a space launch service that satisfies the government's National Launch Forecast (NLF) requirements to place National Security Space (NSS) space vehicles on orbit. NSSL is a launch service, not a weapon system, which is primarily funded with production funds. NSSL Phase 2 development, started late FY 2014, funds research and development activities and related studies, to include, but not limited to, investments in new and/ or upgraded launch systems and associated launch facilities to meet NSS launch needs leveraging domestic commercial launch providers. The Space Force continues to provide support to monitor and close out the remaining activities for the Launch Service Agreement (LSA) public-private partnership with United Launch Alliance Vulcan Centaur. Future development to capitalize on new technology and innovations developed by industry may continue to utilize public- private partnerships. The FY 2026 request was reduced by $0.065 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. In PY 2.246M was expended for civilian pay expenses in this program element, and in CY 2.650M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:           PE 1206853SF / National Security Space Launch Program (SPACE) - EMD System Development & Demonstration (SDD)$$, 6595000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206855SF_643725$$, $$1206855SF$$, $$643725$$, $$Evolved Strategic$$, 1229929000, $$ESS is the backbone for Joint All Domain Nuclear Command, Control and Communications (NC3). The system will replace Advanced Extremely High Frequency (AEHF) Strategic Satellite Communications (SATCOM) services to provide global, integrated, survivable, resilient, and dynamic ground and satellite communications for assured strategic capabilities across the conflict continuum. The ESS program underwent a resiliency architecture shift to address emerging sophisticated threats and to ensure strategic SATCOM capabilities are available to the National Command Authority (NCA), Combatant Commanders, and joint warfighters in any potential future conflict. It will provide the only arctic DoD strategic communication capability across the joint enterprise, and will provide worldwide secure, jam-resistant communications for strategic ground, sea, and air assets. ESS will support existing strategic user terminals in all operational environments. ESS is acquired and developed in several parallel efforts to accelerate delivery of capability to warfighters by the strategic need date in FY 2032. The ESS System includes a Space Segment (ACAT-I), Ground, User, and Integration Segment (ACAT-I equiv), and a Crypto Segment (ACAT-III). The Space Segment is converting to a Major Capability Acquisition (MCA) from a Middle-Tier Acquisition (MTA) in FY 2025. The Ground Segment, also known as GRIFFON - Ground Resilient Integration & Framework for Operational NC3, is comprised of the Ground Integration and Framework (GIF), System of Systems Integration (SoSI), and Mission Software Applications. This enables a resilient and modular cybersecure architecture that bridges the gap between modern software best practices and legacy user terminal capability. The GIF/SoSI is leveraging Software Acquisition Pathway Other Transactional Authority for rapid prototyping of ground software. The ESS Ground Framework creates the cybersecure software development, integration, and operational environments utilizing agile Modular Open Systems Approach (MOSA) principles and onboards hosted external mission applications and services. The SoSI ensures all ESS segments that are acquired in parallel, in addition to external entities, work together to accomplish the mission. Additional mission-unique capabilities, like In-Band Command and Control (C2), Out-of-Band C2, Strategic Mission Planning, Test, Evaluation, Training, and other similar mission capabilities will be acquired modularly as applications that will be hosted on the ESS Ground Framework. The Crypto Segment is focused on the development, integration and testing of National Security Agency (NSA)-certified End-Cryptographic Units (ECUs) that are required for secure strategic communications encryption in the ESS payloads, bus, and test terminals. The modular acquisition approach allows the program to avoid "vendor lock” in all segments and creates opportunities for industry competition and teaming with small innovative non-traditional partners for the Ground Segment on the Space Enterprise Consortium (SpEC) Other Transactional Authority (OTA). SpEC requires ESS ground segment primary contractors that are developing software to utilize small businesses for a significant portion of the prototyping work, allowing the program to integrate innovative best practices, increase agility, reduce costs and development lifecycles, while also expanding the resilient and strategic SATCOM capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:            PE 1206855SF / Evolved Strategic SATCOM (ESS) Advanced Component Development & Prototypes (ACD&P) The ESS system adheres to NC3 classification requirements. ESS will meet the requirements for strategic communications and capability gaps identified in the Protected Satellite Communications Services (PSCS) Analysis of Alternatives (AoA), the Protected Follow-on for Resiliency (PAFR) Study and the Strategic Tiger Team. The ESS architecture and functionality will be designed in accordance with the United States Space Command's signed ESS Concept of Operations and the Joint Requirements Oversight Council's validated Capability Development Document (CDD) satisfying the legacy Advanced Extremely High Frequency (AEHF) strategic requirements and mission performance with enhancements for increased resiliency and cybersecurity. The ESS system will satisfy emerging requirements using modular open system approaches to support incremental enhancements. This program element may include necessary civilian pay expenses required to manage, execute, and deliver ESS weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF, 1206398SF. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 1229929000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206860SF_661023$$, $$1206860SF$$, $$661023$$, $$Rocket System Launch$$, 19857000, $$Rocket Systems Launch Program (RSLP) provides responsive space and Research, Development, Test and Evaluation (RDT&E) launch vehicle support to DoD and other government agencies using commercial launch systems and excess ballistic missile assets. The RSLP mission was established by the Secretary of Defense in 1972. The small launch program complements the National Security Space Launch (NSSL) program with multiple options to acquire dedicated spacelift and rideshare services for developmental, demonstration, and small operational space vehicles. It provides mission planning, payload integration, vehicle acquisition, processing, launch operations, booster storage and disposition, aging surveillance, maintenance and logistics support for selected DoD responsive space and RDT&E launches. Costs directly attributable to a specific launch or program (e.g., reliability of flight testing, maintenance of launch vehicle processing infrastructure) are paid by non-Space Force users (Navy, Army, Missile Defense Agency (MDA), Defense Advanced Research Project Agency (DARPA), National Reconnaissance Office (NRO), etc.). RSLP maintains exclusive control of decommissioned Minuteman and Peacekeeper assets used in testing to include refurbishment, transportation and handling, storage, aging surveillance, and launch services. RSLP enhances capacity to provide mid-to-low & polar-to-high inclination orbits as a part of support for national security space programs through Spaceports that are commercially licensed by the Federal Aviation Administration and received funding from the local or State government. RSLP also funds general research, development, prototyping, integration, and supplemental reliability of flight testing efforts for launch to enhance the reliability of a variety of launch vehicles using RSLP motors for suborbital and orbital missions (e.g., updates to the Modular Mechanical Ordnance Destruct System). While the corresponding RSLP Procurement, Space Force line is set to $0 due to no planned procurements of Space Force funded missions, the activities funded by this RDT&E line are still required to safely store and maintain the RSLP inventory of launch assets. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. In PY $0.0M was expended for civilian pay expenses in this program element, and in CY $0.180M is forecasted for civilian pay expenses in this program element. The FY 2026 request was reduced by $0.195 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 6:          PE 1206860SF / Rocket Systems Launch Program (SPACE) RDT&E Management Support$$, 19857000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206862SF_643835$$, $$1206862SF$$, $$643835$$, $$Tactically Responsive$$, 33282000, $$Tactically Responsive Space (TacRS) rapidly integrates and deploys space-based end-to-end capabilities in response to Combatant Commander (CCMD) urgent needs for power projection and characterization. TacRS missions will be capable of entering operations and generating effects on tactically relevant timelines. The near- term focus of TacRS is to establish these foundational concepts enabling the Space Force to establish the necessary capabilities, processes, concept of operations, and tactics, techniques and procedures to enable a rapid response. In FY 2026, funding will be used to finalize an early operational Space Domain Awareness (SDA) capability that will involve a rapid call-up, launch, and space vehicle operations. In addition, funding will be used to develop the maneuverable, prepositioned SDA TacRS missions. Furthermore, funding will be used to support follow-on SDA operational missions requiring both rapid launch and maneuverable, prepositioned capabilities. Finally, funding will be used to mature new TacRS concepts including, but not limited to, the ability to quickly utilize commercial capabilities. The FY 2026 request for TacRS includes $33,282 thousands of discretionary and $135,000 thousands of mandatory (reconciliation) for a total of $168,282 thousands. The mandatory funds additional TacRS space and launch vehicles in FY 2026. Further information for this reconciliation request is provided in Section 20009 (INDOPACOM Capabilities) of the Reconciliation Exhibit. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Tactically Responsive Space weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:           PE 1206862SF / Tactically Responsive Space Advanced Component Development & Prototypes (ACD&P)$$, 33282000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206864SF_662617$$, $$1206864SF$$, $$662617$$, $$Free-Flyer Spacecraft$$, 28787000, $$America secures peace through strength, and that strength is built on an unyielding technological edge in space - an edge forged through strategic investments in the Department of Defense's (DoD) Space Test Program (STP). As the DoD's primary gateway for space experimentation to lead to space superiority, STP is a critical enabler of national security and a direct investment in deterring adversaries like China. The DoD Space Experiments Review Board (SERB) is central to STP's mission, conducting a rigorous annual review to evaluate and prioritize space experiment proposals. After being reviewed by the SERB, STP provides these cutting-edge technologies with rapid access to the demanding environment of space, accelerating their maturation into operational capabilities. This ensures our troops maintain a decisive advantage across all domains by: • Providing Access for Rigorous Testing and Evaluation: STP enables space access to test technologies, raise Technology Readiness Levels, and validate research. • Ensuring Warfighter Relevance: Through the DoD SERB prioritization, STP focuses on space technologies with direct military applications, benefiting warfighters across all domains. • Developing Future Operational Capabilities: STP matures promising space technologies into operational systems, strengthening the United States Space Force and ensuring its advantage. • Fostering Cross-Service Collaboration and Innovation: STP, DoD's space experimentation hub, fosters cross-service/agency collaboration, aligning tech priorities and minimizing redundancy. • Maximizing Value Through Collaboration: STP partners with government, commercial, and international entities to maximize taxpayer value, broaden space access, and optimize launch opportunities. STP adheres to Executive Orders 10521 and 13185, and the requirement from the Office of the Under Secretary of Defense for Research and Engineering (OUSD (R&E)) to support research, per DoD Instruction 3210.1, Administration and Support of Basic Research. In addition, the Deputy Secretary of Defense Space Test Program Management & Funding Policy, issued in July 2002, reaffirmed STP as the primary provider of spaceflight for the DoD space research community. The July 2002 policy statement also reaffirmed STP's role as the single manager for all DoD payloads on the International Space Station (ISS). This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 6:        PE 1206864SF / Space Test Program (STP) RDT&E Management Support The FY 2026 request was reduced by $0.283M for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, 28787000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206895C_MC33$$, $$1206895C$$, $$MC33$$, $$MD Space Exp Center (MDSEC)$$, 2053000, $$Ballistic Missile Defense System Space Programs Cyber Operations sustain the Missile Defense Agency Risk Management Framework (RMF) and Security Controls Assessments/Controls Validation Testing activities, analysis of validation results, risk assessments, and reviews of proposed Program Manager/Information System Security Manager Plans of Action and Milestones (POA&Ms) for Ballistic Missile Defense System Space Program mission systems. Activities in this project are necessary to comply with the Federal Information Security Management Act.$$, 2053000, NULL, NULL, NULL, NULL, 14086000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206895C_MD33$$, $$1206895C$$, $$MD33$$, $$MD Space Exp Center (MDSEC)$$, 34454000, $$The SKA system is composed of two segments: a space segment and a ground segment. The space segment is composed of a network of small infrared sensors (sensors, processor cards and cabling), each mated to a different satellite. The total number of sensors and their network placement are specifically tailored for the hit and kill assessment missions. The space segment includes key design features to improve its resiliency. The ground segment monitors the health and status of the on-orbit sensors, commands the sensors to perform the hit and kill assessment mission, and analyzes the data to make a hit/kill assessment determination. The ground segment also includes the equipment necessary for communications security and information assurance. The Missile Defense Space Center (MDSC) provides the critical infrastructure for SKA data, routing SKA data between the commercial payload integrator and the multi- mission Missile Defense Space Enterprise Architecture (MDSEA). Due to higher Department of Defense priorities, the SKA experiment will be cancelled in FY 2026 after successfully demonstrating hit-assessment capabilities from space. Space Applications for Missile Defense (SAMD) provides for the functional elements of the Missile Defense Agency (MDA) Contractor Support Services, Federally Funded Research and Development Center/University Affiliated Research Center, and civilian manpower into a single entity that provides acquisition, financial, and technical support across the MDA Space Sensors enterprise. SAMD also provides the MDSEA platform and MDSC infrastructure which provides multi-mission ground segment support for current and future Missile Defense System Space Programs. MDSEA is a highly scalable compute platform that provides mission commanding, data processing, and data storage services for the missile defense space architecture.$$, 34454000, NULL, NULL, NULL, NULL, 174764000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206895C_MD40$$, $$1206895C$$, $$MD40$$, $$Program-Wide Support$$, 3355000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year.$$, 3355000, NULL, NULL, NULL, NULL, 13819000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1206895C_MD42$$, $$1206895C$$, $$MD42$$, $$Hypersonic & Ballistic Tracking$$, 57199000, $$HBTSS will demonstrate a resilient, flexible, and global capability to detect and track hypersonic missiles and detect and track ballistic missiles in the boost phase of flight. The fire-control quality tracking data will allow long range engagement of the threat while enhanced tracking accuracy through missile burn out will provide the Warfighting community increased capability in missile defense weapons systems engagement and higher accuracy impact predictions. The HBTSS prototype demonstration's priority is to maintain the pace of the development schedule given the urgent Warfighter need to address rapidly developing threats. To meet this priority, HBTSS must use high technology readiness level components, take advantage of existing government capabilities to minimize development, use a management culture that does not slow down the pace of development, and use the Other Transaction Authority (OTA) to minimize contracting cycle times. OTAs allow the government to work with traditional, non-traditional, and new space businesses to identify and implement innovative solutions. The HBTSS prototype demonstration seeks to demonstrate the ability to meet requirements derived from United States Strategic Command Prioritized Capabilities List, the National Defense Authorization Act for Fiscal Year 2019, and the Joint Requirements Oversight Council Capability Development Document for Missile Warning (MW)/Missile Defense (MD) Overhead Persistent Infrared (OPIR). The HBTSS developed target detection algorithms and evaluated them in a Signal-chain Processing Demonstration, providing insight into the constellation architecture, communications approach, and preliminary command and control design aspects. These results informed the development of the HBTSS prototype demonstration Space Vehicles (SVs) and demonstrated the ability to detect and track dim targets in a cluttered background along with the sensitivity necessary to support the hypersonic kill chain. Operationally, the HBTSS fire-control capability will be part of Space Development Agency's Proliferated Warfighter Space Architecture and will detect hypersonic, ballistic, and other advanced threats much sooner than terrestrial radars, providing hypersonic threat-tracking data for hand off through linked missile defense weapons.$$, 57199000, NULL, NULL, NULL, NULL, 577993000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$1208053SF_676760$$, $$1208053SF$$, $$676760$$, $$Joint Tactical Ground$$, 6698000, $$The Joint Tactical Ground Station (JTAGS) is a post-production, Acquisition Category (ACAT) III program. JTAGS provides missile warning message data for the Air and Missile Defense (AMD) architecture and improves performance for Integrated Air and Missile Defense Fire Control Systems/Composite Army Air and Missile Defense Brigades. JTAGS disseminates near real time warning, alerting, and cueing information on ballistic missile launches and other tactical events of interest throughout the theater using existing communication networks, providing critical support to Combatant Commanders in their Areas of Responsibility (AOR). JTAGS consist of two sheltered operation rooms, one equipment room, and three antennas. Four outside contiguous United States (OCONUS) deployed JTAGS units, which are deployed in three theaters (United States Pacific Command (PACOM), United States Central Command (CENTCOM), United States European Command (EUCOM)), constitute DoD's in-theater system providing space-based missile warning. The fifth contiguous United States (CONUS) system is used as an institutional trainer but is available as a deployable asset. JTAGS is designated as the in-theater element of the United States Strategic Command's Theater Event System (TES), supporting all Theater Missile Defense pillars, affording the shortest sensor-to-shooter connectivity. On 14 January 2016, the Army Acquisition Executive designated the JTAGS Pre-Planned Product Improvement (JTAGS P3I) program as a separate ACAT III modification program. The JTAGS Program Element (PE) supports development and testing of the JTAGS Block II P3I program based on the JTAGS Operational Requirements Document (ORD), additive Joint Requirements Oversight Council - Memorandum (JROC-M) requirements, and the formal JTAGS Block II Capability Development Document (CDD) thresholds. P3I upgraded JTAGS to a Block II configuration for operation with the next generation of Space Based Infrared System (SBIRS) satellites, and improved warning tactical parameters and timeliness. The JTAGS Block II P3I program based on the 2009 JTAGS ORD is on contract as a two-phase development effort. JTAGS Block II Phase 2 activities seek to develop and test capabilities identified in 2009 JTAGS ORD. Joint Requirements Oversight Council (JROC) Memos 197-12, 113-13, and 042-19 and PL 111-383(Ike Skelton National Defense Authorization Act for FY 2011) support the requirements to develop and field JTAGS Block II capabilities as soon as possible. JTAGS Block II Phase 2 Spiral 3 fielding was completed during FY 2024 and FY 2025. The continued JTAGS Block II CDD addresses evolving User-driven needs such as emerging threats and interface efforts that were not known at the time the JTAGS ORD was validated. Developmental efforts to achieve JTAGS Block II CDD threshold requirements continue through FY 2029. FY 2026 requests funds to continue development for cyber compliance, defense against emerging threats, Assured Positioning, Navigation and Timing (APNT) and M- code GPS compliance, addresses obsolescence mitigation with Commercial Off The Shelf (COTS) hardware/software upgrades, and research and develop prototypes for various system modifications for Red Hat Linux, the next generation Joint Tactical Terminals. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:          PE 1208053SF / Joint Tactical Ground System Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver the Joint Tactical Ground Stations (JTAGS) system capability. The sue of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 6698000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
